--
-- Tabellenstruktur für Tabelle `bpmn_dokumente`
--

CREATE TABLE `bpmn_dokumente` (
  `id` int(11) NOT NULL,
  `Nummer` varchar(50) NOT NULL DEFAULT '',
  `Titel` varchar(255) NOT NULL DEFAULT '',
  `bpmn_xml` longtext NOT NULL,
  `Status` varchar(50) NOT NULL DEFAULT 'Entwurf',
  `Ersteller` int(11) NOT NULL DEFAULT 0,
  `erstellt` date NOT NULL,
  `Änderer` int(11) NOT NULL DEFAULT 0,
  `geändert` date DEFAULT NULL,
  `Typ` varchar(100) NOT NULL DEFAULT 'BPMN'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Daten für Tabelle `bpmn_dokumente`
--

INSERT INTO `bpmn_dokumente` (`id`, `Nummer`, `Titel`, `bpmn_xml`, `Status`, `Ersteller`, `erstellt`, `Änderer`, `geändert`, `Typ`) VALUES
(1, 'bpm-0001', 'Vorfallbearbeitung', '<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n<definitions xmlns=\"http://www.omg.org/spec/BPMN/20100524/MODEL\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\" xmlns:bpmndi=\"http://www.omg.org/spec/BPMN/20100524/DI\" xmlns:omgdc=\"http://www.omg.org/spec/DD/20100524/DC\" xmlns:omgdi=\"http://www.omg.org/spec/DD/20100524/DI\" targetNamespace=\"http://www.wolfisms.de/irp\">\r\n  <process id=\"IRP_Process\" name=\"Incident-Response-Plan\" isExecutable=\"false\">\r\n    <startEvent id=\"start\" name=\"Sicherheitsvorfall&#10;entdeckt\">\r\n      <outgoing>flow_start_melden</outgoing>\r\n    </startEvent>\r\n    <endEvent id=\"end_abgeschlossen\" name=\"Vorfall&#10;abgeschlossen\">\r\n      <incoming>flow_nachbereitung_end</incoming>\r\n    </endEvent>\r\n    <endEvent id=\"end_fehlalarm\" name=\"Fehlalarm&#10;dokumentiert\">\r\n      <incoming>flow_gw_fehlalarm</incoming>\r\n    </endEvent>\r\n    <userTask id=\"task_melden\" name=\"Phase 1:&#10;Vorfall melden\">\r\n      <documentation>Mitarbeitender meldet Vorfall sofort an IT-Helpdesk oder Incident Lead. Betroffenes Gerät NICHT neu starten oder ausschalten. Keine externe Kommunikation.</documentation>\r\n      <incoming>flow_start_melden</incoming>\r\n      <outgoing>flow_melden_bewerten</outgoing>\r\n    </userTask>\r\n    <userTask id=\"task_bewerten\" name=\"Phase 2:&#10;Erstbewertung &#38; Klassifizierung\">\r\n      <documentation>Incident Lead bewertet: Echter Vorfall oder Fehlalarm? Kategorie (Malware, Datenpanne, Phishing …) und Schweregrad S1–S4 festlegen. IRT aktivieren. DSGVO-Prüfung starten.</documentation>\r\n      <incoming>flow_melden_bewerten</incoming>\r\n      <outgoing>flow_bewerten_gw</outgoing>\r\n    </userTask>\r\n    <exclusiveGateway id=\"gw_echt\" name=\"Echter Vorfall?\">\r\n      <incoming>flow_bewerten_gw</incoming>\r\n      <outgoing>flow_gw_fehlalarm</outgoing>\r\n      <outgoing>flow_gw_echt</outgoing>\r\n    </exclusiveGateway>\r\n    <userTask id=\"task_eindaemmen\" name=\"Phase 3:&#10;Eindämmung\">\r\n      <documentation>Sofortmaßnahmen: Betroffene Systeme vom Netz isolieren (NICHT ausschalten). Kompromittierte Konten sperren. Backups vom Netz trennen. Beweise sichern: Memory-Dump, Logs, Screenshots, Netzwerktraffic.</documentation>\r\n      <incoming>flow_gw_echt</incoming>\r\n      <outgoing>flow_eindaemmen_parallel</outgoing>\r\n    </userTask>\r\n    <parallelGateway id=\"gw_parallel_split\" name=\"\">\r\n      <incoming>flow_eindaemmen_parallel</incoming>\r\n      <outgoing>flow_parallel_analyse</outgoing>\r\n      <outgoing>flow_parallel_dsgvo</outgoing>\r\n      <outgoing>flow_parallel_komm</outgoing>\r\n    </parallelGateway>\r\n    <userTask id=\"task_analyse\" name=\"Phase 4:&#10;Analyse &#38; Untersuchung\">\r\n      <documentation>Angriffsvektor identifizieren. Betroffene Systeme, Daten und Nutzer bestimmen. Zeitlinie rekonstruieren. Auf Datenexfiltration prüfen. Persistenz-Mechanismen suchen (Backdoors, geplante Tasks). Bei Bedarf externe Forensik hinzuziehen.</documentation>\r\n      <incoming>flow_parallel_analyse</incoming>\r\n      <outgoing>flow_analyse_join</outgoing>\r\n    </userTask>\r\n    <userTask id=\"task_dsgvo\" name=\"DSGVO-Prüfung &#38;&#10;Meldepflichten\">\r\n      <documentation>Sind personenbezogene Daten betroffen? Meldepflicht an Aufsichtsbehörde innerhalb 72 Stunden prüfen. Cyberversicherung informieren. Bei hohem Risiko: Betroffene unverzüglich informieren. NIS-2: Frühwarnung 24h, Meldung 72h.</documentation>\r\n      <incoming>flow_parallel_dsgvo</incoming>\r\n      <outgoing>flow_dsgvo_join</outgoing>\r\n    </userTask>\r\n    <userTask id=\"task_kommunikation\" name=\"Interne &#38; externe&#10;Kommunikation\">\r\n      <documentation>Interne Kommunikation: Mitarbeitende nur über das Nötigste informieren. Externe Kommunikation: AUSSCHLIESSLICH durch Geschäftsführung. Keine Aussagen an Presse ohne Freigabe. Bei Ransomware: Kein Kontakt mit Angreifern ohne Anwalt.</documentation>\r\n      <incoming>flow_parallel_komm</incoming>\r\n      <outgoing>flow_komm_join</outgoing>\r\n    </userTask>\r\n    <parallelGateway id=\"gw_parallel_join\" name=\"\">\r\n      <incoming>flow_analyse_join</incoming>\r\n      <incoming>flow_dsgvo_join</incoming>\r\n      <incoming>flow_komm_join</incoming>\r\n      <outgoing>flow_join_beseitigen</outgoing>\r\n    </parallelGateway>\r\n    <userTask id=\"task_beseitigen\" name=\"Phase 5a:&#10;Beseitigung\">\r\n      <documentation>Schadsoftware vollständig entfernen (Neuaufsetzen bevorzugt). Alle kompromittierten Konten und Zugangsdaten systemweit zurücksetzen. Schwachstelle schließen (Patch, Konfiguration). Persistenz-Mechanismen entfernen. System auf vollständige Bereinigung prüfen.</documentation>\r\n      <incoming>flow_join_beseitigen</incoming>\r\n      <outgoing>flow_beseitigen_wiederherstellen</outgoing>\r\n    </userTask>\r\n    <userTask id=\"task_wiederherstellen\" name=\"Phase 5b:&#10;Wiederherstellung\">\r\n      <documentation>Systeme aus geprüften, sauberen Backups wiederherstellen (Datum vor dem Vorfall). Wiederhergestellte Systeme auf Kompromittierung prüfen. Schrittweise Wiederinbetriebnahme. Intensives Monitoring 72 Stunden. Nutzer informieren und neue Zugangsdaten ausgeben.</documentation>\r\n      <incoming>flow_beseitigen_wiederherstellen</incoming>\r\n      <outgoing>flow_wiederherstellen_freigabe</outgoing>\r\n    </userTask>\r\n    <userTask id=\"task_freigabe\" name=\"Freigabe zur&#10;Rückkehr Normalbetrieb\">\r\n      <documentation>Incident Lead und Geschäftsführung erteilen gemeinsam die Freigabe. Systeme werden wieder vollständig in Betrieb genommen. Erhöhtes Monitoring bleibt für weitere 72 Stunden aktiv.</documentation>\r\n      <incoming>flow_wiederherstellen_freigabe</incoming>\r\n      <outgoing>flow_freigabe_nachbereitung</outgoing>\r\n    </userTask>\r\n    <userTask id=\"task_nachbereitung\" name=\"Phase 6:&#10;Nachbereitung &#38; Lessons Learned\">\r\n      <documentation>Post-Incident-Review (spätestens 2 Wochen nach Abschluss): Vollständige Zeitlinie dokumentieren. Ursachenanalyse. Maßnahmenplan mit Verantwortlichen und Fristen. Incident-Protokoll finalisieren. Abschlussbericht an Geschäftsführung. Diesen Plan aktualisieren.</documentation>\r\n      <incoming>flow_freigabe_nachbereitung</incoming>\r\n      <outgoing>flow_nachbereitung_end</outgoing>\r\n    </userTask>\r\n    <sequenceFlow id=\"flow_start_melden\" sourceRef=\"start\" targetRef=\"task_melden\" />\r\n    <sequenceFlow id=\"flow_melden_bewerten\" sourceRef=\"task_melden\" targetRef=\"task_bewerten\" />\r\n    <sequenceFlow id=\"flow_bewerten_gw\" sourceRef=\"task_bewerten\" targetRef=\"gw_echt\" />\r\n    <sequenceFlow id=\"flow_gw_fehlalarm\" name=\"Fehlalarm\" sourceRef=\"gw_echt\" targetRef=\"end_fehlalarm\" />\r\n    <sequenceFlow id=\"flow_gw_echt\" name=\"Echter Vorfall\" sourceRef=\"gw_echt\" targetRef=\"task_eindaemmen\" />\r\n    <sequenceFlow id=\"flow_eindaemmen_parallel\" sourceRef=\"task_eindaemmen\" targetRef=\"gw_parallel_split\" />\r\n    <sequenceFlow id=\"flow_parallel_analyse\" sourceRef=\"gw_parallel_split\" targetRef=\"task_analyse\" />\r\n    <sequenceFlow id=\"flow_parallel_dsgvo\" sourceRef=\"gw_parallel_split\" targetRef=\"task_dsgvo\" />\r\n    <sequenceFlow id=\"flow_parallel_komm\" sourceRef=\"gw_parallel_split\" targetRef=\"task_kommunikation\" />\r\n    <sequenceFlow id=\"flow_analyse_join\" sourceRef=\"task_analyse\" targetRef=\"gw_parallel_join\" />\r\n    <sequenceFlow id=\"flow_dsgvo_join\" sourceRef=\"task_dsgvo\" targetRef=\"gw_parallel_join\" />\r\n    <sequenceFlow id=\"flow_komm_join\" sourceRef=\"task_kommunikation\" targetRef=\"gw_parallel_join\" />\r\n    <sequenceFlow id=\"flow_join_beseitigen\" sourceRef=\"gw_parallel_join\" targetRef=\"task_beseitigen\" />\r\n    <sequenceFlow id=\"flow_beseitigen_wiederherstellen\" sourceRef=\"task_beseitigen\" targetRef=\"task_wiederherstellen\" />\r\n    <sequenceFlow id=\"flow_wiederherstellen_freigabe\" sourceRef=\"task_wiederherstellen\" targetRef=\"task_freigabe\" />\r\n    <sequenceFlow id=\"flow_freigabe_nachbereitung\" sourceRef=\"task_freigabe\" targetRef=\"task_nachbereitung\" />\r\n    <sequenceFlow id=\"flow_nachbereitung_end\" sourceRef=\"task_nachbereitung\" targetRef=\"end_abgeschlossen\" />\r\n  </process>\r\n  <bpmndi:BPMNDiagram id=\"BPMNDiagram_IRP\">\r\n    <bpmndi:BPMNPlane id=\"BPMNPlane_IRP\" bpmnElement=\"IRP_Process\">\r\n      <bpmndi:BPMNShape id=\"shape_start\" bpmnElement=\"start\">\r\n        <omgdc:Bounds x=\"82\" y=\"312\" width=\"36\" height=\"36\" />\r\n        <bpmndi:BPMNLabel>\r\n          <omgdc:Bounds x=\"60\" y=\"355\" width=\"80\" height=\"27\" />\r\n        </bpmndi:BPMNLabel>\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_end_abgeschlossen\" bpmnElement=\"end_abgeschlossen\">\r\n        <omgdc:Bounds x=\"2062\" y=\"312\" width=\"36\" height=\"36\" />\r\n        <bpmndi:BPMNLabel>\r\n          <omgdc:Bounds x=\"2040\" y=\"355\" width=\"80\" height=\"27\" />\r\n        </bpmndi:BPMNLabel>\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_end_fehlalarm\" bpmnElement=\"end_fehlalarm\">\r\n        <omgdc:Bounds x=\"562\" y=\"192\" width=\"36\" height=\"36\" />\r\n        <bpmndi:BPMNLabel>\r\n          <omgdc:Bounds x=\"540\" y=\"163\" width=\"80\" height=\"27\" />\r\n        </bpmndi:BPMNLabel>\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_melden\" bpmnElement=\"task_melden\">\r\n        <omgdc:Bounds x=\"170\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_bewerten\" bpmnElement=\"task_bewerten\">\r\n        <omgdc:Bounds x=\"360\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_gw_echt\" bpmnElement=\"gw_echt\" isMarkerVisible=\"true\">\r\n        <omgdc:Bounds x=\"555\" y=\"305\" width=\"50\" height=\"50\" />\r\n        <bpmndi:BPMNLabel>\r\n          <omgdc:Bounds x=\"535\" y=\"362\" width=\"90\" height=\"14\" />\r\n        </bpmndi:BPMNLabel>\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_eindaemmen\" bpmnElement=\"task_eindaemmen\">\r\n        <omgdc:Bounds x=\"660\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_parallel_split\" bpmnElement=\"gw_parallel_split\">\r\n        <omgdc:Bounds x=\"855\" y=\"305\" width=\"50\" height=\"50\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_analyse\" bpmnElement=\"task_analyse\">\r\n        <omgdc:Bounds x=\"960\" y=\"180\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_dsgvo\" bpmnElement=\"task_dsgvo\">\r\n        <omgdc:Bounds x=\"960\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_komm\" bpmnElement=\"task_kommunikation\">\r\n        <omgdc:Bounds x=\"960\" y=\"400\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_parallel_join\" bpmnElement=\"gw_parallel_join\">\r\n        <omgdc:Bounds x=\"1155\" y=\"305\" width=\"50\" height=\"50\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_beseitigen\" bpmnElement=\"task_beseitigen\">\r\n        <omgdc:Bounds x=\"1260\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_wiederherstellen\" bpmnElement=\"task_wiederherstellen\">\r\n        <omgdc:Bounds x=\"1460\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_freigabe\" bpmnElement=\"task_freigabe\">\r\n        <omgdc:Bounds x=\"1660\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNShape id=\"shape_nachbereitung\" bpmnElement=\"task_nachbereitung\">\r\n        <omgdc:Bounds x=\"1860\" y=\"290\" width=\"140\" height=\"80\" />\r\n      </bpmndi:BPMNShape>\r\n      <bpmndi:BPMNEdge id=\"edge_start_melden\" bpmnElement=\"flow_start_melden\">\r\n        <omgdi:waypoint x=\"118\" y=\"330\" />\r\n        <omgdi:waypoint x=\"170\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_melden_bewerten\" bpmnElement=\"flow_melden_bewerten\">\r\n        <omgdi:waypoint x=\"310\" y=\"330\" />\r\n        <omgdi:waypoint x=\"360\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_bewerten_gw\" bpmnElement=\"flow_bewerten_gw\">\r\n        <omgdi:waypoint x=\"500\" y=\"330\" />\r\n        <omgdi:waypoint x=\"555\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_gw_fehlalarm\" bpmnElement=\"flow_gw_fehlalarm\">\r\n        <omgdi:waypoint x=\"580\" y=\"305\" />\r\n        <omgdi:waypoint x=\"580\" y=\"228\" />\r\n        <bpmndi:BPMNLabel>\r\n          <omgdc:Bounds x=\"588\" y=\"270\" width=\"52\" height=\"14\" />\r\n        </bpmndi:BPMNLabel>\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_gw_echt\" bpmnElement=\"flow_gw_echt\">\r\n        <omgdi:waypoint x=\"605\" y=\"330\" />\r\n        <omgdi:waypoint x=\"660\" y=\"330\" />\r\n        <bpmndi:BPMNLabel>\r\n          <omgdc:Bounds x=\"610\" y=\"310\" width=\"44\" height=\"27\" />\r\n        </bpmndi:BPMNLabel>\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_eindaemmen_parallel\" bpmnElement=\"flow_eindaemmen_parallel\">\r\n        <omgdi:waypoint x=\"800\" y=\"330\" />\r\n        <omgdi:waypoint x=\"855\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_parallel_analyse\" bpmnElement=\"flow_parallel_analyse\">\r\n        <omgdi:waypoint x=\"880\" y=\"305\" />\r\n        <omgdi:waypoint x=\"880\" y=\"220\" />\r\n        <omgdi:waypoint x=\"960\" y=\"220\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_parallel_dsgvo\" bpmnElement=\"flow_parallel_dsgvo\">\r\n        <omgdi:waypoint x=\"905\" y=\"330\" />\r\n        <omgdi:waypoint x=\"960\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_parallel_komm\" bpmnElement=\"flow_parallel_komm\">\r\n        <omgdi:waypoint x=\"880\" y=\"355\" />\r\n        <omgdi:waypoint x=\"880\" y=\"440\" />\r\n        <omgdi:waypoint x=\"960\" y=\"440\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_analyse_join\" bpmnElement=\"flow_analyse_join\">\r\n        <omgdi:waypoint x=\"1100\" y=\"220\" />\r\n        <omgdi:waypoint x=\"1180\" y=\"220\" />\r\n        <omgdi:waypoint x=\"1180\" y=\"305\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_dsgvo_join\" bpmnElement=\"flow_dsgvo_join\">\r\n        <omgdi:waypoint x=\"1100\" y=\"330\" />\r\n        <omgdi:waypoint x=\"1155\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_komm_join\" bpmnElement=\"flow_komm_join\">\r\n        <omgdi:waypoint x=\"1100\" y=\"440\" />\r\n        <omgdi:waypoint x=\"1180\" y=\"440\" />\r\n        <omgdi:waypoint x=\"1180\" y=\"355\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_join_beseitigen\" bpmnElement=\"flow_join_beseitigen\">\r\n        <omgdi:waypoint x=\"1205\" y=\"330\" />\r\n        <omgdi:waypoint x=\"1260\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_beseitigen_wiederherstellen\" bpmnElement=\"flow_beseitigen_wiederherstellen\">\r\n        <omgdi:waypoint x=\"1400\" y=\"330\" />\r\n        <omgdi:waypoint x=\"1460\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_wiederherstellen_freigabe\" bpmnElement=\"flow_wiederherstellen_freigabe\">\r\n        <omgdi:waypoint x=\"1600\" y=\"330\" />\r\n        <omgdi:waypoint x=\"1660\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_freigabe_nachbereitung\" bpmnElement=\"flow_freigabe_nachbereitung\">\r\n        <omgdi:waypoint x=\"1800\" y=\"330\" />\r\n        <omgdi:waypoint x=\"1860\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n      <bpmndi:BPMNEdge id=\"edge_nachbereitung_end\" bpmnElement=\"flow_nachbereitung_end\">\r\n        <omgdi:waypoint x=\"2000\" y=\"330\" />\r\n        <omgdi:waypoint x=\"2062\" y=\"330\" />\r\n      </bpmndi:BPMNEdge>\r\n    </bpmndi:BPMNPlane>\r\n  </bpmndi:BPMNDiagram>\r\n</definitions>', '2', 1, '2026-03-06', 1, '2026-07-18', 'BPMN');

