INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(1, 'DOK-0001', 'Informationssicherheitsrichtlinie', 'Richtlinien', '1', 0, 'öffentlich', '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Diese Informationssicherheitsrichtlinie legt die strategischen Grundsätze und Ziele zum Schutz der Informationen der Organisation fest. Ziel ist es, die <strong>Vertraulichkeit</strong>, <strong>Integrität</strong> und <strong>Verfügbarkeit</strong> aller informationsverarbeitenden Systeme, Prozesse und Daten sicherzustellen – unabhängig von Form, Medium oder Standort.</p>\n<p>Die Richtlinie dient als verbindliche Vorgabe der obersten Leitung und bildet die Grundlage für alle untergeordneten Sicherheitsrichtlinien, Verfahrensanweisungen und Maßnahmen des Informationssicherheitsmanagementsystems (ISMS).</p>\n\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Die Richtlinie gilt für:</p>\n<ul>\n<li><p>Alle <strong>Informationen</strong>, IT-Systeme, Netz- und Informationssysteme sowie Kommunikationsmittel der Organisation</p></li>\n<li><p><strong>Alle Mitarbeiter*innen</strong>, Dienstleister, Auftragnehmer und externen Partner, die mit Informationen der Organisation umgehen oder Zugang zu Systemen haben</p></li>\n<li><p><strong>Alle Standorte</strong>, Tochterunternehmen und externen Betriebsstätten, sofern nicht abweichend geregelt</p></li>\n<li><p>Alle <strong>Lieferketten und Abhängigkeiten</strong> zu direkten Anbietern und Diensteanbietern</p></li>\n</ul>\n<p>Der Geltungsbereich wird im Rahmen des ISMS dokumentiert und mindestens jährlich auf Aktualität geprüft (vgl. ISO 27001:2022, Abschnitt 4.3).</p>\n\n<h2><strong>3. Informationssicherheitsziele</strong></h2>\n<p>Die Organisation verpflichtet sich, ein angemessenes Sicherheitsniveau zu gewährleisten durch:</p>\n<ul>\n<li><p>Schutz vertraulicher Informationen vor unbefugtem Zugriff (<strong>Vertraulichkeit</strong>)</p></li>\n<li><p>Sicherstellung der Korrektheit und Vollständigkeit von Informationen (<strong>Integrität</strong>)</p></li>\n<li><p>Sicherstellung der rechtzeitigen Verfügbarkeit von Informationen und IT-Systemen (<strong>Verfügbarkeit</strong>)</p></li>\n<li><p>Gewährleistung der <strong>Authentizität</strong> und <strong>Nachweisbarkeit</strong> von Informationen und Transaktionen</p></li>\n<li><p>Einhaltung gesetzlicher, vertraglicher und regulatorischer Anforderungen, insbesondere der <strong>NIS2-Richtlinie (EU) 2022/2555</strong></p></li>\n<li><p>Etablierung und kontinuierliche Verbesserung eines ISMS nach <strong>ISO/IEC 27001:2022</strong></p></li>\n<li><p>Sicherstellung der <strong>Resilienz</strong> kritischer Geschäftsprozesse und Systeme</p></li>\n</ul>\n<p>Die Informationssicherheitsziele werden messbar definiert, regelmäßig überwacht und im Rahmen der Managementbewertung evaluiert (vgl. ISO 27001:2022, Abschnitt 6.2).</p>\n\n<h2><strong>4. Grundsätze der Informationssicherheit</strong></h2>\n<ul>\n<li><p><strong>Informationssicherheit ist Führungsaufgabe</strong> und wird durch die oberste Leitung aktiv getragen und verantwortet (vgl. ISO 27001:2022, Abschnitt 5.1; NIS2 Art. 20).</p></li>\n<li><p><strong>Sicherheit betrifft alle</strong> – jede Person in der Organisation trägt Verantwortung für den Schutz von Informationen.</p></li>\n<li><p>Sicherheitsmaßnahmen basieren auf <strong>systematischen Risikoanalysen</strong> und <strong>Schutzbedarfsfeststellungen</strong> gemäß einem dokumentierten Risikomanagementprozess (vgl. ISO 27001:2022, Abschnitt 6.1; NIS2 Art. 21).</p></li>\n<li><p>Informationssicherheit wird im Rahmen des <strong>PDCA-Zyklus</strong> (Plan-Do-Check-Act) <strong>kontinuierlich überprüft, verbessert und angepasst</strong>.</p></li>\n<li><p>Es gilt das Prinzip des <strong>\"Need-to-know\"</strong> und <strong>\"Least Privilege\"</strong> – Zugriffe erfolgen nur bei berechtigtem Bedarf und mit minimalen erforderlichen Rechten.</p></li>\n<li><p>Der Schutz personenbezogener Daten wird gemäß der <strong>DSGVO</strong> sichergestellt.</p></li>\n<li><p>Ein <strong>risikobasierter Ansatz</strong> wird verfolgt, um Maßnahmen verhältnismäßig zum Schutzbedarf und zur Bedrohungslage zu gestalten.</p></li>\n</ul>\n\n<h2><strong>5. Rollen und Verantwortlichkeiten</strong></h2>\n<p>Die Verantwortlichkeiten für Informationssicherheit sind wie folgt festgelegt (vgl. ISO 27001:2022, Abschnitt 5.3; Anhang A.5.2, A.5.3, A.5.4):</p>\n\n<h3><strong>5.1 Geschäftsführung / Oberste Leitung</strong></h3>\n<ul>\n<li><p>Trägt die <strong>Gesamtverantwortung</strong> für Informationssicherheit und Cyberresilienz (vgl. NIS2 Art. 20)</p></li>\n<li><p>Genehmigt diese Richtlinie und stellt angemessene <strong>Ressourcen</strong> bereit</p></li>\n<li><p>Definiert strategische <strong>Zielvorgaben</strong> und überwacht deren Erreichung</p></li>\n<li><p>Nimmt an <strong>Schulungen</strong> zur Informationssicherheit teil (vgl. NIS2 Art. 20 Abs. 2)</p></li>\n<li><p>Trägt die Verantwortung für die <strong>Genehmigung von Risikomanagementmaßnahmen</strong> und deren Umsetzungsüberwachung</p></li>\n</ul>\n\n<h3><strong>5.2 Informationssicherheitsbeauftragte*r (ISB)</strong></h3>\n<ul>\n<li><p><strong>Steuerung und Koordination</strong> des ISMS</p></li>\n<li><p><strong>Beratung</strong> der Geschäftsführung und Fachbereiche in Sicherheitsfragen</p></li>\n<li><p><strong>Überwachung</strong> der Einhaltung von Sicherheitsrichtlinien</p></li>\n<li><p>Koordination von <strong>Risikoanalysen</strong> und <strong>Sicherheitsvorfällen</strong></p></li>\n<li><p><strong>Berichterstattung</strong> an die oberste Leitung</p></li>\n<li><p>Koordination der <strong>Meldepflichten</strong> gemäß NIS2 Art. 23</p></li>\n</ul>\n\n<h3><strong>5.3 IT-Leitung / IT-Sicherheit</strong></h3>\n<ul>\n<li><p><strong>Technische Umsetzung</strong> der Schutzmaßnahmen</p></li>\n<li><p>Betrieb sicherer IT-Infrastrukturen und <strong>Netz- und Informationssysteme</strong></p></li>\n<li><p>Implementierung von <strong>Sicherheitskontrollen</strong> gemäß Anhang A der ISO 27001:2022</p></li>\n<li><p><strong>Schwachstellenmanagement</strong> und <strong>Patch-Management</strong></p></li>\n</ul>\n\n<h3><strong>5.4 Datenschutzbeauftragte*r</strong></h3>\n<ul>\n<li><p>Sicherstellung der Einhaltung der <strong>DSGVO</strong> und des <strong>BDSG</strong></p></li>\n<li><p><strong>Zusammenarbeit</strong> mit dem ISB bei datenschutzrelevanten Sicherheitsthemen</p></li>\n</ul>\n\n<h3><strong>5.5 Fachbereichsleitungen</strong></h3>\n<ul>\n<li><p><strong>Umsetzung</strong> der Sicherheitsvorgaben in ihrem Verantwortungsbereich</p></li>\n<li><p><strong>Asset-Verantwortung</strong> für Informationswerte ihres Bereichs</p></li>\n<li><p>Sicherstellung der <strong>Schulung</strong> ihrer Mitarbeiter*innen</p></li>\n</ul>\n\n<h3><strong>5.6 Alle Mitarbeiter*innen</strong></h3>\n<ul>\n<li><p><strong>Einhaltung</strong> der Sicherheitsrichtlinien und Verfahrensanweisungen</p></li>\n<li><p><strong>Unverzügliches Melden</strong> von Sicherheitsvorfällen, Schwachstellen und verdächtigen Aktivitäten</p></li>\n<li><p>Teilnahme an <strong>Schulungen</strong> und Sensibilisierungsmaßnahmen</p></li>\n</ul>\n\n<h2><strong>6. Organisation der Informationssicherheit</strong></h2>\n<p>Die Organisation der Informationssicherheit erfolgt im Rahmen des ISMS (vgl. ISO 27001:2022, Anhang A.5.1 ff.):</p>\n<ul>\n<li><p>Informationssicherheit ist <strong>organisatorisch verankert</strong> und in die Geschäftsprozesse integriert.</p></li>\n<li><p>Sicherheitsrichtlinien, -verfahren und -prozesse werden <strong>dokumentiert, freigegeben und kommuniziert</strong>.</p></li>\n<li><p>Es finden <strong>regelmäßige Schulungen</strong> und <strong>Sensibilisierungsmaßnahmen</strong> für alle Mitarbeiter*innen statt (vgl. ISO 27001:2022, Anhang A.6.3).</p></li>\n<li><p>Verstöße gegen Richtlinien werden gemäß einem <strong>Disziplinarverfahren</strong> verfolgt und können arbeitsrechtliche Konsequenzen haben (vgl. ISO 27001:2022, Anhang A.6.4).</p></li>\n<li><p>Die <strong>Trennung von Aufgaben</strong> (Segregation of Duties) wird berücksichtigt, um Interessenkonflikte und Missbrauch zu verhindern (vgl. ISO 27001:2022, Anhang A.5.3).</p></li>\n<li><p>Der <strong>Kontakt zu Behörden</strong> und relevanten <strong>Interessengruppen</strong> wird gepflegt (vgl. ISO 27001:2022, Anhang A.5.5, A.5.6).</p></li>\n</ul>\n\n<h2><strong>7. Risikomanagement</strong></h2>\n<p>Die Organisation betreibt ein systematisches Risikomanagement für Informationssicherheit (vgl. ISO 27001:2022, Abschnitt 6.1; NIS2 Art. 21):</p>\n<ul>\n<li><p><strong>Risikoidentifikation</strong>: Systematische Erfassung von Bedrohungen und Schwachstellen für Informationswerte</p></li>\n<li><p><strong>Risikoanalyse</strong>: Bewertung von Eintrittswahrscheinlichkeit und potenziellen Auswirkungen</p></li>\n<li><p><strong>Risikobewertung</strong>: Priorisierung anhand definierter Risikoakzeptanzkriterien</p></li>\n<li><p><strong>Risikobehandlung</strong>: Auswahl geeigneter Maßnahmen (Vermeidung, Verminderung, Transfer, Akzeptanz)</p></li>\n<li><p>Erstellung und Pflege einer <strong>Erklärung zur Anwendbarkeit</strong> (Statement of Applicability)</p></li>\n<li><p>Regelmäßige <strong>Überprüfung und Aktualisierung</strong> der Risikoeinschätzungen</p></li>\n</ul>\n<p>Die Geschäftsführung genehmigt die Risikobehandlungspläne und akzeptiert verbleibende Restrisiken formal.</p>\n\n<h2><strong>8. Sicherheitsmaßnahmen</strong></h2>\n<p>Die Organisation setzt auf <strong>präventive, detektive und reaktive</strong> Maßnahmen entsprechend den Kontrollen des Anhang A der ISO 27001:2022 und den Anforderungen nach NIS2 Art. 21:</p>\n\n<h3><strong>8.1 Organisatorische Maßnahmen</strong></h3>\n<ul>\n<li><p><strong>Richtlinien für Informationssicherheit</strong> (A.5.1)</p></li>\n<li><p><strong>Informationssicherheit im Projektmanagement</strong> (A.5.8)</p></li>\n<li><p><strong>Klassifizierung und Kennzeichnung</strong> von Informationen (A.5.12, A.5.13)</p></li>\n<li><p><strong>Lieferantenmanagement</strong> und Sicherheit in der <strong>Lieferkette</strong> (A.5.19-A.5.23; NIS2 Art. 21 Abs. 2 lit. d)</p></li>\n</ul>\n\n<h3><strong>8.2 Personenbezogene Maßnahmen</strong></h3>\n<ul>\n<li><p><strong>Sicherheitsüberprüfungen</strong> vor Einstellung (A.6.1)</p></li>\n<li><p><strong>Schulung und Sensibilisierung</strong> (A.6.3)</p></li>\n<li><p><strong>Verantwortlichkeiten bei Beendigung</strong> des Arbeitsverhältnisses (A.6.5)</p></li>\n</ul>\n\n<h', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-04-19', 0, 0, 0, 0, NULL, 0, 'Information Security Policy', '<h2><strong>1. Purpose of the Policy</strong></h2>\n<p>This Information Security Policy establishes the strategic principles and objectives for protecting the organization\'s information. The goal is to ensure the <strong>confidentiality</strong>, <strong>integrity</strong>, and <strong>availability</strong> of all information processing systems, processes, and data – regardless of form, medium, or location.</p>\n<hr/>\n<h2><strong>2. Scope</strong></h2>\n<p>This policy applies to:</p>\n<ul>\n<li>\n<p>All <strong>information</strong>, IT systems, and communication tools of the organization</p>\n</li>\n</ul>\n<p><strong>All employees, service providers, and external partners who handle information of the organization</strong></p>\n<p><strong>All locations, subsidiaries, and external operating sites, unless otherwise stipulated</strong></p>\n<p><strong><strong> </strong></strong></p>\n<hr/>\n<h2><strong>3. Information Security Objectives</strong></h2>\n<p>The organization is committed to ensuring an appropriate level of security by:</p>\n<ul>\n<li>\n<p>Protecting confidential information from unauthorized access (confidentiality)</p>\n</li>\n<li>\n<p>Ensuring the accuracy and completeness of information (integrity)</p>\n</li>\n<li>\n<p>Ensuring the timely availability of information and IT systems (availability)</p>\n</li>\n<li>\n<p>Compliance with legal, contractual, and regulatory requirements</p>\n</li>\n<li>\n<p>Establishing and continuously improving an ISMS according to ISO/IEC 27001</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>4. Principles of Information Security</strong></h2>\n<ul>\n<li>\n<p><strong>Information security is a management responsibility and is supported by top management.</strong></p>\n<strong> </strong></li>\n</ul>\n<p><strong>Security concerns everyone</strong> – every person in the organization bears responsibility.</p>\n<p>Security measures are based on <strong>risk analyses</strong> and <strong>assessments of protection requirements</strong>.</p>\n<p>Information security is <strong>continuously reviewed, improved, and adapted</strong>.</p>\n<p>The principle of <strong>\"need-to-know\"</strong> applies – Access is granted only when legitimately required.</p>\n<p><strong>The protection of personal data is ensured in accordance with the <strong>GDPR</strong>.</strong></p>\n<hr/>\n<h2><strong>5. Roles and Responsibilities</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Role</th>\n<th>Tasks</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Management</strong></td>\n<td>Overall responsibility, resource allocation, target setting</td>\n</tr>\n<tr>\n<td><strong>Information Security Officer (ISO)</strong></td>\n<td>Steering the ISMS, consulting, Control</td>\n</tr>\n<tr>\n<td><strong>IT Management / IT Security</strong></td>\n<td>Technical implementation of security measures</td>\n</tr>\n<tr>\n<td><strong>Data Protection Officer</strong></td>\n<td>Ensuring compliance with the GDPR</td>\n</tr>\n<tr>\n<td><strong>Department Heads</strong></td>\n<td>Implementation of security guidelines in the line organization</td>\n</tr>\n<tr>\n<td><strong>All employees</strong></td>\n<td>Compliance with security guidelines and reporting of security incidents</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>6. Organization of Information Security</strong></h2>\n<ul>\n<li>\n<p>Information security is organizationally regulated within the framework of the ISMS.</p>\n</li>\n<li>\n<p>Security policies, procedures, and processes are documented and communicated.</p>\n</li>\n<li>\n<p>Regular training sessions and awareness-raising activities are held.</p>\n</li>\n<li>\n<p>Violations of policies are investigated and may result in disciplinary action.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>7. Security Measures </strong></h2>\n<p><strong>The organization relies on preventive, detective, and reactive measures: </strong></p>\n<ul>\n<li>Access Controls (physical and logical)</li>\n<li>Protection against malware and cyberattacks</li>\n<li>Patch and Change Management</li>\n<li>Data Backup and Recovery</li>\n<li>Disaster Management and Business</li>\n<li>Continuity Process-Integrated Risk Analyses</li>\n<li>Monitoring and Logging of Critical Systems</li>\n</ul>\n<hr/>\n<h2><strong>8. Handling Security Incidents</strong></h2>\n<p><strong>Security incidents must be reported <strong>immediately</strong> to the ISB or Service Desk.</strong></p>\n<ul>\n<li><strong> </strong>\n<p><strong>ItA defined incident management process exists. All incidents are documented, evaluated, and used for continuous improvement. 9. Compliance with legal requirements</strong></p>\n</li>\n</ul>\n<p>The organization is committed to complying with all relevant legal and regulatory requirements, in particular:</p>\n<ul>\n<li>\n<p><strong>GDPR / BDSG</strong></p>\n</li>\n<li>\n<p><strong>ISO/IEC 27001</strong></p>\n</li>\n<li>\n<p><strong>BSI IT Baseline Protection Compendium</strong></p>\n</li>\n<li>\n<p><strong>Contractual agreements with customers, suppliers, and partners</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Communication and Training</strong></h2>\n<ul>\n<li>\n<p>The policy is actively communicated to <strong>all employees</strong>.</p>\n</li>\n<li>\n<p>Information security training takes place at least <strong>once a year</strong>.</p>\n</li>\n<li>\n<p>New employees receive an <strong>information security commitment</strong> as part of their onboarding.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>11. Control and Audit</strong></h2>\n<ul>\n<li>\n<p>The implementation of the policy is regularly reviewed through internal and, where necessary, external audits.</p>\n</li>\n</ul>\n<p>Compliance is monitored by the Information Security Officer (ISB), IT security managers, and specialist departments.</p>\n<p>Results are incorporated into the continuous improvement of the Information Security Management System (ISMS).</p>\n<hr/>\n<h2><strong>12. Continuous Improvement</strong></h2>\n<ul>\n<li>\n<p>Information security is understood as a <strong>living process</strong>.</p>\n</li>\n</ul>\n<p>Insights from incidents, audits, tests, and feedback are regularly incorporated into the further development of security measures.</p>\n<hr/>\n<h2><strong>13. Relation to norms and standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Standard / Norm</th>\n<th>Relevant content</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001</strong></td>\n<td>A.5.1.1 - Information Security Guidelines</td>\n</tr>\n<tr>\n<td><strong>BSI IT Baseline Protection Compendium</strong></td>\n<td>ORP.1, ORP.3, ORP.4, ISMS.1.1</td>\n</tr>\n<tr>\n<td><strong>EU GDPR / BDSG</strong></td>\n<td>Protection of Personal Data</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>14. Entry into Force and Review</strong></h2>\n<p>This policy enters into force on <strong>[date]</strong>. It must be reviewed and, if necessary, adapted at least once a year or whenever there are relevant changes in the threat situation, infrastructure, or legal requirements.</p>', NULL, NULL, '1', 0, 'NULL,1', NULL, NULL, 0, 0, NULL),
(2, 'DOK-0002', 'Prozess zur Kontrolle der dokumentierten Informationen', 'Verfahren', '1', 0, 'öffentlich', '<h2><strong>1. Zweck</strong></h2>\n<p>Dieses Verfahren beschreibt die Vorgehensweise zur <strong>Erstellung, Lenkung und Pflege dokumentierter Informationen</strong> im Rahmen des Informationssicherheitsmanagementsystems (ISMS). Es stellt sicher, dass:</p>\n<ul>\n<li>\n<p>nur <strong>freigegebene, aktuelle und gültige Dokumente</strong> im Umlauf sind,</p>\n</li>\n<li>\n<p><strong>Zugriff, Versionierung und Archivierung</strong> nachvollziehbar geregelt sind,</p>\n</li>\n<li>\n<p><strong>ISO 27001-konforme Nachweise und Dokumentationen</strong> sicher verwaltet werden.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>2. Anwendungsbereich</strong></h2>\n<p>Dieses Verfahren gilt für alle dokumentierten Informationen im ISMS, insbesondere:</p>\n<ul>\n<li>\n<p>Richtlinien und Verfahrensanweisungen</p>\n</li>\n<li>\n<p>ISMS-Ziele, Pläne, Risikoanalysen</p>\n</li>\n<li>\n<p>Audit- und Vorfallberichte</p>\n</li>\n<li>\n<p>Protokolle und Schulungsnachweise</p>\n</li>\n<li>\n<p>Nachweise zur Umsetzung von Maßnahmen</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Definitionen</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Begriff</th>\n<th>Bedeutung</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Dokumentierte Information</strong></td>\n<td>Überbegriff für Dokumente (z. B. Richtlinien) und Nachweise (z. B. Auditprotokolle) gemäß ISO 27001</td>\n</tr>\n<tr>\n<td><strong>Lenkung</strong></td>\n<td>Maßnahmen zur Erstellung, Freigabe, Verteilung, Änderung und Archivierung</td>\n</tr>\n<tr>\n<td><strong>gültige Version</strong></td>\n<td>jeweils aktuelle und offiziell freigegebene Fassung eines Dokuments</td>\n</tr>\n<tr>\n<td><strong>ISMS-Dokumentationssystem</strong></td>\n<td>z. B. Confluence, SharePoint, ISMS-Tool, DMS-System</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>4. Verantwortlichkeiten</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Informationssicherheitsbeauftragte*r (ISB)</strong></td>\n<td>Koordination der Dokumentenlenkung, Prüfung auf Konsistenz &amp; Konformität</td>\n</tr>\n<tr>\n<td><strong>Dokumenteneigner / Fachverantwortliche</strong></td>\n<td>Erstellung und Aktualisierung der Inhalte</td>\n</tr>\n<tr>\n<td><strong>Geschäftsführung / ISMS-Leitung</strong></td>\n<td>Freigabe strategischer Dokumente (z. B. IS-Richtlinie)</td>\n</tr>\n<tr>\n<td><strong>Qualitätsmanagement (optional)</strong></td>\n<td>Unterstützung bei Lenkungs- und Freigabeprozessen</td>\n</tr>\n<tr>\n<td><strong>Alle Nutzer*innen</strong></td>\n<td>Nutzung ausschließlich freigegebener Dokumente; Meldepflicht bei Fehlern</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>5. Ablauf: Lebenszyklus dokumentierter Informationen</strong></h2>\n<h3>5.1 Erstellung</h3>\n<ul>\n<li>\n<p>Dokumente werden auf Basis interner Anforderungen, Normen oder Vorfälle erstellt</p>\n</li>\n<li>\n<p>Verantwortlich ist jeweils die benannte Rolle im <strong>Dokumentenverzeichnis</strong></p>\n</li>\n<li>\n<p>Vorlagen (Format, Gliederung, Fußzeile, Versionierung) sind zu verwenden</p>\n</li>\n</ul>\n<h3>5.2 Prüfung</h3>\n<ul>\n<li>\n<p>Inhaltliche Prüfung durch eine zweite, fachlich geeignete Person</p>\n</li>\n<li>\n<p>ISB prüft bei sicherheitsrelevanten Dokumenten auf <strong>ISMS-Konformität</strong></p>\n</li>\n</ul>\n<h3>5.3 Freigabe</h3>\n<ul>\n<li>\n<p>Erfolgt durch berechtigte Rolle gemäß <strong>Freigabematrix</strong></p>\n</li>\n<li>\n<p>Dokumente erhalten Status:</p>\n<ul>\n<li>\n<p>„<strong>Entwurf</strong>“</p>\n</li>\n<li>\n<p>„<strong>In Prüfung</strong>“</p>\n</li>\n<li>\n<p>„<strong>Freigegeben</strong>“</p>\n</li>\n<li>\n<p>„<strong>Veraltet / ersetzt</strong>“</p>\n</li>\n</ul>\n</li>\n</ul>\n<h3>5.4 Veröffentlichung / Verteilung</h3>\n<ul>\n<li>\n<p>Veröffentlichung nur im zentralen ISMS-Dokumentationssystem</p>\n</li>\n<li>\n<p>Zugriff wird nach <strong>Need-to-know-Prinzip</strong> geregelt</p>\n</li>\n<li>\n<p>Sensible Dokumente können zusätzlich verschlüsselt werden</p>\n</li>\n</ul>\n<h3>5.5 Änderung</h3>\n<ul>\n<li>\n<p>Änderungen erfolgen mit Änderungsvermerk (Version, Änderungsgrund)</p>\n</li>\n<li>\n<p>Historie bleibt nachvollziehbar erhalten</p>\n</li>\n<li>\n<p>Bei größeren Änderungen wird der gesamte <strong>Freigabeprozess erneut durchlaufen</strong></p>\n</li>\n</ul>\n<h3>5.6 Archivierung</h3>\n<ul>\n<li>\n<p>Veraltete Versionen werden <strong>dokumentiert archiviert</strong> (mind. 3–6 Jahre, je nach rechtlicher Vorgabe)</p>\n</li>\n<li>\n<p>Archivierte Dokumente sind klar als „ungültig“ gekennzeichnet und <strong>nicht produktiv nutzbar</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>6. Dokumentenverzeichnis</strong></h2>\n<p>Ein zentrales <strong>ISMS-Dokumentenverzeichnis</strong> wird geführt mit folgenden Angaben:</p>\n<ul>\n<li>\n<p>Titel</p>\n</li>\n<li>\n<p>Dokumenten-ID</p>\n</li>\n<li>\n<p>Version</p>\n</li>\n<li>\n<p>Autor / Verantwortlicher</p>\n</li>\n<li>\n<p>Freigabedatum</p>\n</li>\n<li>\n<p>Status (aktiv / archiviert)</p>\n</li>\n<li>\n<p>Gültigkeitsbereich</p>\n</li>\n<li>\n<p>nächstes Review-Datum</p>\n</li>\n</ul>\n<p>👉 Format: Excel-Tabelle oder ISMS-Tool</p>\n<hr/>\n<h2><strong>7. Zugriffsschutz und Vertraulichkeit</strong></h2>\n<ul>\n<li>\n<p>Zugriffe werden über Rollen- &amp; Berechtigungskonzepte gesteuert</p>\n</li>\n<li>\n<p>Dokumente mit hohem Schutzbedarf (z. B. Risikoanalysen, Vorfallprotokolle) sind besonders zu schützen:</p>\n<ul>\n<li>\n<p>Zugriff nur für berechtigte Personen</p>\n</li>\n<li>\n<p>ggf. Verschlüsselung oder Speicherung in geschützten Bereichen</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Änderungen an Zugriffsrechten sind zu dokumentieren</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Review und Aktualisierungspflichten</strong></h2>\n<ul>\n<li>\n<p><strong>Alle dokumentierten Informationen</strong> sind regelmäßig zu überprüfen – mindestens <strong>alle 12 Monate</strong></p>\n</li>\n<li>\n<p>Review-Protokolle enthalten:</p>\n<ul>\n<li>\n<p>Name des Prüfers</p>\n</li>\n<li>\n<p>Datum der Prüfung</p>\n</li>\n<li>\n<p>Ergebnis / Änderungsbedarf</p>\n</li>\n<li>\n<p>ggf. neu freigegebene Version</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Nichtkonformitäten</strong></h2>\n<ul>\n<li>\n<p>Falsche oder nicht freigegebene Dokumente im Umlauf müssen <strong>unverzüglich gemeldet</strong> und entfernt werden</p>\n</li>\n<li>\n<p>Verstöße gegen diese Regelung gelten als <strong>ISMS-relevante Abweichung</strong> und werden im Review behandelt</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Bezug zu Normen und Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Bezug</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001:2022</strong></td>\n<td>Kapitel 7.5 – Kontrolle dokumentierter Informationen</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>ORP.4.1 – ISMS initiieren und betreiben<br/>ISMS.1.A7 – Dokumentation des ISMS</td>\n</tr>\n<tr>\n<td><strong>ISO 9001 / QM (optional)</strong></td>\n<td>7.5 – dokumentierte Information</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-02-28', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 1, '', NULL, NULL, 0, 0, NULL),
(3, 'DOK-0003', 'Asset & Datenklassifizierung', 'Richtlinien', '1', 0, 'öffentlich', '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Ziel dieser Richtlinie ist es, ein einheitliches Verfahren zur <strong>Klassifizierung von Assets und Informationen</strong> festzulegen. Die Klassifizierung dient als fundamentale Grundlage für das Informationssicherheits-Managementsystem (ISMS) und unterstützt dabei:</p>\n<ul>\n<li><p>angemessene <strong>technische und organisatorische Schutzmaßnahmen</strong> risikobasiert festzulegen</p></li>\n<li><p><strong>gesetzliche, vertragliche und regulatorische Anforderungen</strong> zu erfüllen, insbesondere die Anforderungen der NIS2-Richtlinie (EU) 2022/2555 an das Risikomanagement (Art. 21)</p></li>\n<li><p>die <strong>Vertraulichkeit, Integrität und Verfügbarkeit</strong> sensibler Informationen zu wahren</p></li>\n<li><p>eine Grundlage für die <strong>Meldung von Sicherheitsvorfällen</strong> gemäß NIS2 Art. 23 zu schaffen, indem kritische Assets eindeutig identifiziert sind</p></li>\n<li><p>die <strong>Geschäftskontinuität</strong> durch Priorisierung kritischer Informationswerte sicherzustellen</p></li>\n</ul>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Diese Richtlinie gilt für:</p>\n<ul>\n<li><p><strong>Alle Arten von Informationen</strong> (digital, physisch, mündlich), unabhängig vom Speichermedium oder der Verarbeitungsform</p></li>\n<li><p><strong>Alle Assets</strong>, die Informationen speichern, verarbeiten oder übertragen (z. B. IT-Systeme, Netzwerkkomponenten, Speichermedien, Anwendungen, Dokumente)</p></li>\n<li><p><strong>Alle Mitarbeiter*innen</strong>, Partner, Auftragnehmer und Dienstleister, die mit diesen Informationen arbeiten</p></li>\n<li><p><strong>Alle Standorte und Organisationseinheiten</strong>, die dem ISMS-Geltungsbereich unterliegen</p></li>\n<li><p><strong>Lieferketten und externe Schnittstellen</strong> gemäß den Anforderungen der NIS2-Richtlinie zur Sicherheit in der Lieferkette</p></li>\n</ul>\n<h2><strong>3. Begriffe und Definitionen</strong></h2>\n<table>\n<thead>\n<tr>\n<th>Begriff</th>\n<th>Definition</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Information</strong></td>\n<td>Daten in beliebiger Form mit geschäftlichem, rechtlichem oder operativem Wert für die Organisation</td>\n</tr>\n<tr>\n<td><strong>Asset (Informationswert)</strong></td>\n<td>Wertgegenstand der Organisation, der für die Informationsverarbeitung relevant ist (z. B. Informationen, Systeme, Geräte, Dienste, Personal, Standorte)</td>\n</tr>\n<tr>\n<td><strong>Klassifizierung</strong></td>\n<td>Systematische Einstufung nach Schutzbedarf hinsichtlich Vertraulichkeit, Integrität und Verfügbarkeit</td>\n</tr>\n<tr>\n<td><strong>Schutzbedarf</strong></td>\n<td>Grad der potenziellen Auswirkungen bei Kompromittierung eines Informationswerts auf Geschäftsprozesse, rechtliche Anforderungen oder betroffene Personen</td>\n</tr>\n<tr>\n<td><strong>Asset Owner</strong></td>\n<td>Verantwortliche Person oder Organisationseinheit für ein Asset, zuständig für Klassifizierung und Schutzmaßnahmen</td>\n</tr>\n<tr>\n<td><strong>Labeling (Kennzeichnung)</strong></td>\n<td>Sichtbare oder technische Kennzeichnung der Klassifizierungsstufe zur Identifikation des Schutzbedarfs</td>\n</tr>\n<tr>\n<td><strong>Kritische Assets</strong></td>\n<td>Assets, deren Beeinträchtigung erhebliche Auswirkungen auf wesentliche Dienste oder die Geschäftskontinuität hätte (relevant für NIS2)</td>\n</tr>\n</tbody>\n</table>\n<h2><strong>4. Grundsätze der Klassifizierung</strong></h2>\n<p>Die folgenden Grundsätze sind bei der Klassifizierung verbindlich anzuwenden:</p>\n<ul>\n<li><p><strong>Vollständigkeit:</strong> Jede Information ist ein Asset und muss systematisch erfasst und bewertet werden.</p></li>\n<li><p><strong>Risikobasierung:</strong> Klassifizierungen basieren auf dem <strong>Schutzbedarf</strong> gemäß dem <strong>CIA-Prinzip</strong> (Confidentiality, Integrity, Availability) und berücksichtigen die Ergebnisse der Risikobewertung.</p></li>\n<li><p><strong>Verantwortlichkeit:</strong> Die Klassifizierung erfolgt durch die <strong>verantwortliche Fachabteilung bzw. den Asset Owner</strong> in Abstimmung mit dem ISB.</p></li>\n<li><p><strong>Höchste Kritikalität:</strong> Die <strong>höchste Klassifizierung eines Teils bestimmt die Klassifizierung des Gesamtsystems</strong> (Aggregationsprinzip).</p></li>\n<li><p><strong>Aktualität:</strong> <strong>Reklassifizierung</strong> ist bei Änderungen des Inhalts, Kontextes, der Nutzung oder gesetzlicher Anforderungen unverzüglich vorzunehmen.</p></li>\n<li><p><strong>Verhältnismäßigkeit:</strong> Schutzmaßnahmen müssen dem festgestellten Schutzbedarf angemessen sein.</p></li>\n<li><p><strong>Dokumentation:</strong> Alle Klassifizierungsentscheidungen sind nachvollziehbar zu dokumentieren.</p></li>\n</ul>\n<h2><strong>5. Klassifizierungsstufen</strong></h2>\n<h3><strong>5.1 Vertraulichkeit</strong></h3>\n<table>\n<thead>\n<tr>\n<th>Stufe</th>\n<th>Beschreibung</th>\n<th>Beispiele</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Öffentlich (C0)</strong></td>\n<td>Freigegeben für jedermann, keine Einschränkungen bei der Weitergabe</td>\n<td>Pressemitteilungen, Webseiteninhalte, Marketingmaterial</td>\n</tr>\n<tr>\n<td><strong>Intern (C1)</strong></td>\n<td>Für interne Zwecke, keine Veröffentlichung ohne Genehmigung</td>\n<td>Interne Richtlinien, Organigramme, allgemeine Projektinformationen</td>\n</tr>\n<tr>\n<td><strong>Vertraulich (C2)</strong></td>\n<td>Schaden bei unbefugtem Zugriff möglich, eingeschränkter Personenkreis</td>\n<td>Kundenlisten, Angebote, Projektdaten, Vertragsdetails</td>\n</tr>\n<tr>\n<td><strong>Streng vertraulich (C3)</strong></td>\n<td>Schwerwiegender Schaden bei Offenlegung, höchster Schutz erforderlich</td>\n<td>Gesundheitsdaten, Gehaltsdaten, Sicherheitsarchitektur, Betriebsgeheimnisse, kryptografische Schlüssel</td>\n</tr>\n</tbody>\n</table>\n<h3><strong>5.2 Integrität</strong></h3>\n<table>\n<thead>\n<tr>\n<th>Stufe</th>\n<th>Beschreibung</th>\n<th>Beispiele</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Niedrig (I1)</strong></td>\n<td>Manipulation hat geringe Auswirkungen, leicht korrigierbar</td>\n<td>Entwurfsdokumente, interne Notizen</td>\n</tr>\n<tr>\n<td><strong>Mittel (I2)</strong></td>\n<td>Manipulation kann zu spürbaren Beeinträchtigungen führen</td>\n<td>Prozessdokumentation, Konfigurationsdaten</td>\n</tr>\n<tr>\n<td><strong>Hoch (I3)</strong></td>\n<td>Manipulation kann erheblichen Schaden verursachen</td>\n<td>Finanzdaten, Vertragsdokumente, Audit-Logs</td>\n</tr>\n<tr>\n<td><strong>Sehr hoch (I4)</strong></td>\n<td>Manipulation kann kritische Auswirkungen auf Sicherheit oder Compliance haben</td>\n<td>Sicherheitskonfigurationen, Zugriffsberechtigungen, rechtlich bindende Dokumente</td>\n</tr>\n</tbody>\n</table>\n<h3><strong>5.3 Verfügbarkeit</strong></h3>\n<table>\n<thead>\n<tr>\n<th>Stufe</th>\n<th>Beschreibung</th>\n<th>Maximale tolerierbare Ausfallzeit</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Niedrig (A1)</strong></td>\n<td>Ausfall hat geringe Auswirkungen</td>\n<td>&gt; 72 Stunden</td>\n</tr>\n<tr>\n<td><strong>Mittel (A2)</strong></td>\n<td>Ausfall führt zu spürbaren Beeinträchtigungen</td>\n<td>24–72 Stunden</td>\n</tr>\n<tr>\n<td><strong>Hoch (A3)</strong></td>\n<td>Ausfall führt zu erheblichen Geschäftsunterbrechungen</td>\n<td>4–24 Stunden</td>\n</tr>\n<tr>\n<td><strong>Sehr hoch (A4)</strong></td>\n<td>Ausfall hat kritische Auswirkungen, sofortige Wiederherstellung erforderlich</td>\n<td>&lt; 4 Stunden</td>\n</tr>\n</tbody>\n</table>\n<h3><strong>5.4 Kombinierte Schutzbedarfsbewertung</strong></h3>\n<p>Der Gesamtschutzbedarf eines Assets ergibt sich aus der <strong>kombinierten Bewertung aller drei Dimensionen</strong> (CIA). Der höchste Einzelwert bestimmt das Gesamtschutzniveau für die Festlegung von Schutzmaßnahmen.</p>\n<h2><strong>6. Verantwortlichkeiten</strong></h2>\n<h3><strong>6.1 Rollenmatrix</strong></h3>\n<table>\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben und Verantwortlichkeiten</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Geschäftsführung / Top-Management</strong></td>\n<td>Genehmigung der Richtlinie, Bereitstellung von Ressourcen, Gesamtverantwortung für die Informationssicherheit gemäß NIS2 Art. 20</td>\n</tr>\n<tr>\n<td><strong>Asset Owner</strong></td>\n<td>Klassifikation und regelmäßige Überprüfung der zugewiesenen Assets, Genehmigung von Zugriffsrechten, Sicherstellung angemessener Schutzmaßnahmen</td>\n</tr>\n<tr>\n<td><strong>Fachabteilungen</strong></td>\n<td>Unterstützung bei der Einstufung von Informationen, Meldung von Änderungen am Schutzbedarf</td>\n</tr>\n<tr>\n<td><strong>Informationssicherheitsbeauftragter (ISB)</strong></td>\n<td>Vorgabe von Klassifizierungsregeln, Kontrolle der Umsetzung, Beratung, Berichterstattung an die Geschäftsführung</td>\n</tr>\n<tr>\n<td><strong>Datenschutzbeauftragte*r (DSB)</strong></td>\n<td>Beratung bei personenbezogenen Daten, Sicherstellung der DSGVO-Konformität bei der Klassifizierung</td>\n</tr>\n<tr>\n<td><strong>IT-Abteilung</strong></td>\n<td>Technische Umsetzung (Kennzeichnung, Zugriffsschutz, Verschlüsselung), Pflege des Asset-Inventars</td>\n</tr>\n<tr>\n<td><strong>Alle Mitarbeiter*innen</strong></td>\n<td>Einhaltung der Klassifizierungsvorgaben, sachgemäßer Umgang mit klassifizierten Informationen</td>\n</tr>\n</tbody>\n</table>\n<h3><strong>6.2 Governance-Anforderungen (NIS2)</strong></h3>\n<p>Gemäß NIS2 Art. 20 trägt die Geschäftsführung die Gesamtverantwortung für die Umsetzung von Risikomanagementmaßnahmen. Die Asset-Klassifizierung ist ein wesentlicher Bestandteil dieser Verantwortung. Die Geschäftsführung muss:</p>\n<ul>\n<li><p>die Klassifizierungsrichtlinie genehmigen und deren Umsetzung überwachen</p></li>\n<li><p>an Schulungen zur Informationssicherheit teilnehmen</p></li>\n<li><p>ausreichende Ressourcen für die Klassifizierung und den Schutz kritischer Assets bereitstellen</p></li>\n</ul>\n<h2><strong>7. Verfahren zur Klassifizierung</strong></h2>\n<h3><strong>7.1 Schrittweises Vorgehen</strong></h3>\n<ol>\n<li><p><strong>Identifikation</strong> des Informationswertes: Systematische Erfassung aller Informationen und Assets im Geltungsbereich</p></li>\n<li><p><strong>Zuweisung eines Asset Owners:</strong> Benennung einer verantwortlichen Person oder Organisationseinheit</p></li>\n<li><p><strong>Schutzbedarfsfeststellung:</strong> Bewertung von Vertraul</p></li></ol>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-04-19', 0, 0, 0, 0, NULL, 0, 'Asset & Data Classification', '<h2><strong>1. Purpose of the Directive</strong></h2>\n<p>The aim of this policy is to establish a uniform procedure for <strong>classifying assets and information</strong> . Classification helps to:</p>\n<ul>\n<li>\n<p>to establish appropriate <strong>technical and organizational protective measures</strong></p>\n</li>\n<li>\n<p>to meet <strong>legal, contractual and operational requirements</strong></p>\n</li>\n<li>\n<p>to maintain the <strong>confidentiality, integrity and availability of sensitive information</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>2. Scope</strong></h2>\n<p>This policy applies to:</p>\n<ul>\n<li>\n<p><strong>All types of information</strong> (digital, physical, oral)</p>\n</li>\n<li>\n<p><strong>All assets</strong> that store, process or transmit information (e.g., IT systems, storage, documents)</p>\n</li>\n<li>\n<p><strong>All employees</strong> , partners and service providers who work with this information</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Terms and Definitions</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Expression</th>\n<th>definition</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>information</strong></td>\n<td>Data in any form with business value</td>\n</tr>\n<tr>\n<td><strong>Asset</strong></td>\n<td>Assets of the organization (e.g., information, systems, equipment, services)</td>\n</tr>\n<tr>\n<td><strong>Classification</strong></td>\n<td>Classification according to protection requirements (confidentiality, integrity, availability)</td>\n</tr>\n<tr>\n<td><strong>Protection needs</strong></td>\n<td>Degree of impact when an information asset is compromised</td>\n</tr>\n<tr>\n<td><strong>Labeling (marking)</strong></td>\n<td>Visible or technical marking of the classification level</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>4. Principles of classification</strong></h2>\n<ul>\n<li>\n<p><strong>Every piece of information is an asset</strong> and must be evaluated.</p>\n</li>\n<li>\n<p>Classifications are based on the <strong>protection requirements</strong> according to the <strong>CIA principle</strong> (Confidentiality, Integrity, Availability).</p>\n</li>\n<li>\n<p>The classification is carried out by the <strong>responsible department or the asset owner</strong> .</p>\n</li>\n<li>\n<p>The <strong>highest classification of a part determines the classification of the entire system</strong> (principle of highest criticality).</p>\n</li>\n<li>\n<p><strong>Reclassification</strong> should be carried out when there are changes to the content, context, or legal requirements.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>5. Classification levels</strong></h2>\n<h3><strong>5.1 Confidentiality</strong></h3>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Level</th>\n<th>Description</th>\n<th>Examples</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Public</strong></td>\n<td>Open to everyone</td>\n<td>Press releases, website content</td>\n</tr>\n<tr>\n<td><strong>Internal</strong></td>\n<td>For internal use only, not for publication</td>\n<td>Internal guidelines, organizational charts</td>\n</tr>\n<tr>\n<td><strong>Confidential</strong></td>\n<td>Damage possible in case of unauthorized access</td>\n<td>Customer lists, offers, project data</td>\n</tr>\n<tr>\n<td><strong>Strictly confidential</strong></td>\n<td>Serious damage upon disclosure</td>\n<td>Health data, salary data, security architecture, trade secrets</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<h3><strong>5.2 Integrity and availability (optionally supplementary)</strong></h3>\n<p>Security levels can be categorized analogously to confidentiality as \"low\", \"medium\", \"high\", and \"very high\". Recommendation: <strong>Combined Security Assessment</strong> (CIA).</p>\n<hr/>\n<h2><strong>6. Responsibilities</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>role</th>\n<th>Tasks</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Asset Owner</strong></td>\n<td>Classification and regular review of the assigned assets</td>\n</tr>\n<tr>\n<td><strong>Specialist departments</strong></td>\n<td>Support in classifying information</td>\n</tr>\n<tr>\n<td><strong>ISB</strong></td>\n<td>Setting classification rules, control and advice</td>\n</tr>\n<tr>\n<td><strong>Data Protection Officer (DPO)</strong></td>\n<td>Advice on personal data</td>\n</tr>\n<tr>\n<td><strong>IT department</strong></td>\n<td>Technical implementation (labeling, access protection)</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>7. Classification procedures</strong></h2>\n<h3>7.1 Step-by-step procedure</h3>\n<ol>\n<li>\n<p><strong>Identification</strong> of the information value (What needs to be classified?)</p>\n</li>\n<li>\n<p><strong>Assignment of an asset owner</strong></p>\n</li>\n<li>\n<p><strong>Assessment of protection requirements</strong> (confidentiality, integrity, availability)</p>\n</li>\n<li>\n<p><strong>Assignment of the classification level</strong></p>\n</li>\n<li>\n<p><strong>Documentation</strong> in the asset inventory / information register</p>\n</li>\n<li>\n<p><strong>Identification / Labeling</strong> (physical or electronic)</p>\n</li>\n<li>\n<p><strong>Implementation of protective measures</strong> (according to protection needs)</p>\n</li>\n</ol>\n<hr/>\n<h2><strong>8. Labeling</strong></h2>\n<h3>8.1 Physical Documents</h3>\n<ul>\n<li>\n<p><strong>Stamp or header</strong> with classification level (e.g. \"Confidential\")</p>\n</li>\n<li>\n<p>Use of standardized templates and print forms</p>\n</li>\n</ul>\n<h3>8.2 Electronic documents</h3>\n<ul>\n<li>\n<p>Classification in the <strong>metadata</strong> or in the <strong>file name</strong></p>\n</li>\n<li>\n<p>Use of <strong>classification systems</strong> (e.g., DMS, Microsoft Purview / Sensitivity Labels)</p>\n</li>\n<li>\n<p>Automatic labeling is recommended for centralized systems.</p>\n</li>\n</ul>\n<h3>8.3 Systems and Data Carriers</h3>\n<ul>\n<li>\n<p>Classification in asset inventories and databases</p>\n</li>\n<li>\n<p>Technical protection measures depending on classification (e.g. encryption, access controls)</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Implementation of protective measures</strong></h2>\n<p>The classification determines the <strong>technical and organizational measures</strong> , e.g.:</p>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>classification</th>\n<th>Possible measures</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Internal</strong></td>\n<td>User access restricted, no external sharing</td>\n</tr>\n<tr>\n<td><strong>Confidential</strong></td>\n<td>Access only on \"need-to-know\" basis, secure authentication, logging</td>\n</tr>\n<tr>\n<td><strong>Strictly confidential</strong></td>\n<td>Encryption, access only by specially authorized persons, no sending via email</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>10. Review and update</strong></h2>\n<ul>\n<li>\n<p>The asset owners must review the classifications <strong>at least once a year.</strong></p>\n</li>\n<li>\n<p><strong>Adaptation to changes</strong> in usage, legal framework or threat situation</p>\n</li>\n<li>\n<p>The classification guideline is <strong>regularly reviewed by the ISB.</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>11. Reference to ISO/IEC 27001 and BSI IT Baseline Protection</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Standard / Measure</th>\n<th>Contents</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001 A.5.12</strong></td>\n<td>Classification of information</td>\n</tr>\n<tr>\n<td><strong>ISO/IEC 27001 A.8.2.1–3</strong></td>\n<td>Responsibility for values, classification, labeling</td>\n</tr>\n<tr>\n<td><strong>BSI IT Baseline Protection: ORP.4.1</strong></td>\n<td>Inventory of information assets</td>\n</tr>\n<tr>\n<td><strong>BSI: INF.5 / INF.6 / CON.4</strong></td>\n<td>Handling of information, classification and labeling</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<h2> </h2>', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(4, 'DOK-0004', 'Asset Management', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"730\" data-end=\"760\"><strong data-start=\"733\" data-end=\"760\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"762\" data-end=\"1016\">Ziel dieser Richtlinie ist die <strong data-start=\"793\" data-end=\"866\">systematische Verwaltung von informationssicherheitsrelevanten Assets</strong> (Werten), um deren Schutzbedarf zu bestimmen, Verantwortlichkeiten festzulegen und geeignete Schutzma&szlig;nahmen gem&auml;&szlig; dem Schutzbedarf zu gew&auml;hrleisten.</p>\r\n<hr data-start=\"1018\" data-end=\"1021\">\r\n<h2 data-start=\"1023\" data-end=\"1048\"><strong data-start=\"1026\" data-end=\"1048\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1050\" data-end=\"1076\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1077\" data-end=\"1331\">\r\n<li data-start=\"1077\" data-end=\"1150\">\r\n<p data-start=\"1079\" data-end=\"1150\"><strong data-start=\"1079\" data-end=\"1112\">Physische und digitale Assets</strong>: Hardware, Software, Daten, Dokumente</p>\r\n</li>\r\n<li data-start=\"1151\" data-end=\"1215\">\r\n<p data-start=\"1153\" data-end=\"1215\"><strong data-start=\"1153\" data-end=\"1175\">Immaterielle Werte</strong>: Know-how, Lizenzen, geistiges Eigentum</p>\r\n</li>\r\n<li data-start=\"1216\" data-end=\"1331\">\r\n<p data-start=\"1218\" data-end=\"1331\"><strong data-start=\"1218\" data-end=\"1249\">Alle Organisationseinheiten</strong>, Mitarbeiter*innen sowie <strong data-start=\"1275\" data-end=\"1300\">externe Dienstleister</strong>, die mit diesen Assets umgehen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1333\" data-end=\"1336\">\r\n<h2 data-start=\"1338\" data-end=\"1368\"><strong data-start=\"1341\" data-end=\"1368\">3. Begriffsdefinitionen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1370\" data-end=\"1952\">\r\n<thead data-start=\"1370\" data-end=\"1400\">\r\n<tr data-start=\"1370\" data-end=\"1400\">\r\n<th data-start=\"1370\" data-end=\"1384\" data-col-size=\"sm\">Begriff</th>\r\n<th data-start=\"1384\" data-end=\"1400\" data-col-size=\"lg\">Beschreibung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1432\" data-end=\"1952\">\r\n<tr data-start=\"1432\" data-end=\"1534\">\r\n<td data-start=\"1432\" data-end=\"1446\" data-col-size=\"sm\"><strong data-start=\"1434\" data-end=\"1443\">Asset</strong></td>\r\n<td data-start=\"1446\" data-end=\"1534\" data-col-size=\"lg\">Alles, was f&uuml;r die Organisation von Wert ist (z. B. Daten, Ger&auml;te, Systeme, Dienste)</td>\r\n</tr>\r\n<tr data-start=\"1535\" data-end=\"1681\">\r\n<td data-start=\"1535\" data-end=\"1573\" data-col-size=\"sm\"><strong data-start=\"1537\" data-end=\"1572\">Asset Owner (Verantwortliche*r)</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1573\" data-end=\"1681\">Person oder Funktion, die f&uuml;r ein Asset verantwortlich ist (u. a. Klassifikation, Schutzbedarf, Nutzung)</td>\r\n</tr>\r\n<tr data-start=\"1682\" data-end=\"1816\">\r\n<td data-start=\"1682\" data-end=\"1701\" data-col-size=\"sm\"><strong data-start=\"1684\" data-end=\"1700\">Schutzbedarf</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1701\" data-end=\"1816\">Einstufung der Anforderungen an Vertraulichkeit, Integrit&auml;t und Verf&uuml;gbarkeit (z. B. normal / hoch / sehr hoch)</td>\r\n</tr>\r\n<tr data-start=\"1817\" data-end=\"1952\">\r\n<td data-start=\"1817\" data-end=\"1838\" data-col-size=\"sm\"><strong data-start=\"1819\" data-end=\"1837\">Asset-Inventar</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1838\" data-end=\"1952\">Zentrale Liste aller relevanten Informationswerte mit Attributen wie Eigent&uuml;mer, Klassifikation, Standort etc.</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"1954\" data-end=\"1957\">\r\n<h2 data-start=\"1959\" data-end=\"2000\"><strong data-start=\"1962\" data-end=\"2000\">4. Grunds&auml;tze der Asset-Verwaltung</strong></h2>\r\n<ul data-start=\"2002\" data-end=\"2542\">\r\n<li data-start=\"2002\" data-end=\"2115\">\r\n<p data-start=\"2004\" data-end=\"2115\"><strong data-start=\"2004\" data-end=\"2023\">Vollst&auml;ndigkeit</strong>: Alle sicherheitsrelevanten Assets sind zu erfassen und im Asset-Inventar zu dokumentieren.</p>\r\n</li>\r\n<li data-start=\"2116\" data-end=\"2188\">\r\n<p data-start=\"2118\" data-end=\"2188\"><strong data-start=\"2118\" data-end=\"2135\">Verantwortung</strong>: Jedem Asset ist ein/e Verantwortliche/r zugeordnet.</p>\r\n</li>\r\n<li data-start=\"2189\" data-end=\"2274\">\r\n<p data-start=\"2191\" data-end=\"2274\"><strong data-start=\"2191\" data-end=\"2207\">Schutzbedarf</strong>: F&uuml;r jedes Asset ist eine Schutzbedarfsfeststellung durchzuf&uuml;hren.</p>\r\n</li>\r\n<li data-start=\"2275\" data-end=\"2417\">\r\n<p data-start=\"2277\" data-end=\"2417\"><strong data-start=\"2277\" data-end=\"2308\">Kontrollierter Lebenszyklus</strong>: Assets werden von der Beschaffung bis zur Aussonderung nach definierten Sicherheitsanforderungen behandelt.</p>\r\n</li>\r\n<li data-start=\"2418\" data-end=\"2542\">\r\n<p data-start=\"2420\" data-end=\"2542\"><strong data-start=\"2420\" data-end=\"2443\">Nachvollziehbarkeit</strong>: &Auml;nderungen an Assets (z. B. &Uuml;bergaben, Umz&uuml;ge, Entsorgung) sind nachvollziehbar zu dokumentieren.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2544\" data-end=\"2547\">\r\n<h2 data-start=\"2549\" data-end=\"2579\"><strong data-start=\"2552\" data-end=\"2579\">5. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2581\" data-end=\"3171\">\r\n<thead data-start=\"2581\" data-end=\"2620\">\r\n<tr data-start=\"2581\" data-end=\"2620\">\r\n<th data-start=\"2581\" data-end=\"2608\" data-col-size=\"md\">Rolle</th>\r\n<th data-start=\"2608\" data-end=\"2620\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2660\" data-end=\"3171\">\r\n<tr data-start=\"2660\" data-end=\"2763\">\r\n<td data-start=\"2660\" data-end=\"2687\" data-col-size=\"md\"><strong data-start=\"2662\" data-end=\"2677\">Asset Owner</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2687\" data-end=\"2763\">Schutzbedarf feststellen, Nutzung &uuml;berwachen, Klassifikation durchf&uuml;hren</td>\r\n</tr>\r\n<tr data-start=\"2764\" data-end=\"2861\">\r\n<td data-start=\"2764\" data-end=\"2791\" data-col-size=\"md\"><strong data-start=\"2766\" data-end=\"2782\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2791\" data-end=\"2861\">Technische Erfassung, Verwaltung von Hardware- und Software-Assets</td>\r\n</tr>\r\n<tr data-start=\"2862\" data-end=\"2977\">\r\n<td data-start=\"2862\" data-end=\"2911\" data-col-size=\"md\"><strong data-start=\"2864\" data-end=\"2910\">Informationssicherheitsbeauftragte*r (ISB)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2911\" data-end=\"2977\">Bewertung der Risiken, Kontrolle der Schutzma&szlig;nahmen, Beratung</td>\r\n</tr>\r\n<tr data-start=\"2978\" data-end=\"3065\">\r\n<td data-start=\"2978\" data-end=\"3005\" data-col-size=\"md\"><strong data-start=\"2980\" data-end=\"2996\">Fachbereiche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3005\" data-end=\"3065\">Mitwirkung bei Klassifikation und Pflege der Asset-Daten</td>\r\n</tr>\r\n<tr data-start=\"3066\" data-end=\"3171\">\r\n<td data-start=\"3066\" data-end=\"3093\" data-col-size=\"md\"><strong data-start=\"3068\" data-end=\"3088\">DSB / Compliance</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3093\" data-end=\"3171\">Einbindung bei Assets mit personenbezogenen oder rechtlich sensiblen Daten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3173\" data-end=\"3176\">\r\n<h2 data-start=\"3178\" data-end=\"3218\"><strong data-start=\"3181\" data-end=\"3218\">6. Asset-Kategorien und Beispiele</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3220\" data-end=\"3687\">\r\n<thead data-start=\"3220\" data-end=\"3252\">\r\n<tr data-start=\"3220\" data-end=\"3252\">\r\n<th data-start=\"3220\" data-end=\"3239\" data-col-size=\"sm\">Kategorie</th>\r\n<th data-start=\"3239\" data-end=\"3252\" data-col-size=\"md\">Beispiele</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3286\" data-end=\"3687\">\r\n<tr data-start=\"3286\" data-end=\"3353\">\r\n<td data-start=\"3286\" data-end=\"3306\" data-col-size=\"sm\"><strong data-start=\"3288\" data-end=\"3300\">Hardware</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3306\" data-end=\"3353\">Server, Laptops, Drucker, Router, Firewalls</td>\r\n</tr>\r\n<tr data-start=\"3354\" data-end=\"3416\">\r\n<td data-start=\"3354\" data-end=\"3374\" data-col-size=\"sm\"><strong data-start=\"3356\" data-end=\"3368\">Software</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3374\" data-end=\"3416\">Betriebssysteme, Anwendungen, Lizenzen</td>\r\n</tr>\r\n<tr data-start=\"3417\" data-end=\"3495\">\r\n<td data-start=\"3417\" data-end=\"3437\" data-col-size=\"sm\"><strong data-start=\"3419\" data-end=\"3436\">Informationen</strong></td>\r\n<td data-start=\"3437\" data-end=\"3495\" data-col-size=\"md\">Kundendaten, Quellcode, Vertr&auml;ge, Gesch&auml;ftsgeheimnisse</td>\r\n</tr>\r\n<tr data-start=\"3496\" data-end=\"3552\">\r\n<td data-start=\"3496\" data-end=\"3516\" data-col-size=\"sm\"><strong data-start=\"3498\" data-end=\"3511\">Netzwerke</strong></td>\r\n<td data-start=\"3516\" data-end=\"3552\" data-col-size=\"md\">Switches, Firewalls, WLAN-Ger&auml;te</td>\r\n</tr>\r\n<tr data-start=\"3553\" data-end=\"3613\">\r\n<td data-start=\"3553\" data-end=\"3573\" data-col-size=\"sm\"><strong data-start=\"3555\" data-end=\"3566\">Dienste</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3573\" data-end=\"3613\">Cloud-Dienste, gehostete Anwendungen</td>\r\n</tr>\r\n<tr data-start=\"3614\" data-end=\"3687\">\r\n<td data-start=\"3614\" data-end=\"3637\" data-col-size=\"sm\"><strong data-start=\"3616\" data-end=\"3636\">Physische Medien</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3637\" data-end=\"3687\">USB-Sticks, Backup-B&auml;nder, externe Festplatten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3689\" data-end=\"3692\">\r\n<h2 data-start=\"3694\" data-end=\"3726\"><strong data-start=\"3697\" data-end=\"3726\">7. Asset-Inventarisierung</strong></h2>\r\n<h3 data-start=\"3728\" data-end=\"3749\">7.1 Anforderungen</h3>\r\n<ul data-start=\"3751\" data-end=\"4048\">\r\n<li data-start=\"3751\" data-end=\"3828\">\r\n<p data-start=\"3753\" data-end=\"3828\">Alle Assets mit Relevanz f&uuml;r Informationssicherheit sind zu inventarisieren</p>\r\n</li>\r\n<li data-start=\"3829\" data-end=\"4048\">\r\n<p data-start=\"3831\" data-end=\"3861\">Attribute des Asset-Inventars:</p>\r\n<ul data-start=\"3864\" data-end=\"4048\">\r\n<li data-start=\"3864\" data-end=\"3874\">\r\n<p data-start=\"3866\" data-end=\"3874\">Asset-ID</p>\r\n</li>\r\n<li data-start=\"3877\" data-end=\"3896\">\r\n<p data-start=\"3879\" data-end=\"3896\">Name/Beschreibung</p>\r\n</li>\r\n<li data-start=\"3899\" data-end=\"3910\">\r\n<p data-start=\"3901\" data-end=\"3910\">Kategorie</p>\r\n</li>\r\n<li data-start=\"3913\" data-end=\"3926\">\r\n<p data-start=\"3915\" data-end=\"3926\">Asset Owner</p>\r\n</li>\r\n<li data-start=\"3929\" data-end=\"3939\">\r\n<p data-start=\"3931\" data-end=\"3939\">Standort</p>\r\n</li>\r\n<li data-start=\"3942\" data-end=\"3962\">\r\n<p data-start=\"3944\" data-end=\"3962\">Schutzbedarf (CIA)</p>\r\n</li>\r\n<li data-start=\"3965\" data-end=\"3983\">\r\n<p data-start=\"3967\" data-end=\"3983\">Verwendungszweck</p>\r\n</li>\r\n<li data-start=\"3986\" data-end=\"4007\">\r\n<p data-start=\"3988\" data-end=\"4007\">Technischer Zustand</p>\r\n</li>\r\n<li data-start=\"4010\" data-end=\"4048\">\r\n<p data-start=\"4012\" data-end=\"4048\">Klassifikation (z. B. &bdquo;vertraulich&ldquo;)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4050\" data-end=\"4083\">7.2 Pflege und Aktualisierung</h3>\r\n<ul data-start=\"4085\" data-end=\"4349\">\r\n<li data-start=\"4085\" data-end=\"4201\">\r\n<p data-start=\"4087\" data-end=\"4201\">Inventar ist <strong data-start=\"4100\" data-end=\"4121\">aktuell zu halten</strong> &ndash; &Auml;nderungen durch Umz&uuml;ge, Aussonderung oder Defekte sind umgehend einzupflegen</p>\r\n</li>\r\n<li data-start=\"4202\" data-end=\"4265\">\r\n<p data-start=\"4204\" data-end=\"4265\"><strong data-start=\"4204\" data-end=\"4229\">J&auml;hrliche &Uuml;berpr&uuml;fung</strong> auf Vollst&auml;ndigkeit und Korrektheit</p>\r\n</li>\r\n<li data-start=\"4266\" data-end=\"4349\">\r\n<p data-start=\"4268\" data-end=\"4349\">Schnittstelle zum <strong data-start=\"4286\" data-end=\"4306\">Risikomanagement</strong>: Schutzbedarf beeinflusst Ma&szlig;nahmenauswahl</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4351\" data-end=\"4354\">\r\n<h2 data-start=\"4356\" data-end=\"4397\"><strong data-start=\"4359\" data-end=\"4397\">8. Klassifikation und Schutzbedarf</strong></h2>\r\n<ul data-start=\"4399\" data-end=\"4672\">\r\n<li data-start=\"4399\" data-end=\"4503\">\r\n<p data-start=\"4401\" data-end=\"4503\">Assets sind anhand ihrer Bedeutung f&uuml;r Vertraulichkeit, Integrit&auml;t und Verf&uuml;gbarkeit zu klassifizieren</p>\r\n</li>\r\n<li data-start=\"4504\" data-end=\"4574\">\r\n<p data-start=\"4506\" data-end=\"4574\">Schutzbedarfseinstufung gem&auml;&szlig; BSI-Schema (normal / hoch / sehr hoch)</p>\r\n</li>\r\n<li data-start=\"4575\" data-end=\"4672\">\r\n<p data-start=\"4577\" data-end=\"4583\">Z. B.:</p>\r\n<ul data-start=\"4586\" data-end=\"4672\">\r\n<li data-start=\"4586\" data-end=\"4623\">\r\n<p data-start=\"4588\" data-end=\"4623\">Kundendaten: Vertraulichkeit = hoch</p>\r\n</li>\r\n<li data-start=\"4626\" data-end=\"4672\">\r\n<p data-start=\"4628\" data-end=\"4672\">Produktionsserver: Verf&uuml;gbarkeit = sehr hoch</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4674\" data-end=\"4677\">\r\n<h2 data-start=\"4679\" data-end=\"4712\"><strong data-start=\"4682\" data-end=\"4712\">9. Lebenszyklus-Management</strong></h2>\r\n<h3 data-start=\"4714\" data-end=\"4733\">9.1 Beschaffung</h3>\r\n<ul data-start=\"4735\" data-end=\"4880\">\r\n<li data-start=\"4735\" data-end=\"4787\">\r\n<p data-start=\"4737\" data-end=\"4787\">Nur autorisierte Personen d&uuml;rfen Assets beschaffen</p>\r\n</li>\r\n<li data-start=\"4788\" data-end=\"4880\">\r\n<p data-start=\"4790\" data-end=\"4880\">IT-Sicherheitsanforderungen m&uuml;ssen in Ausschreibungen / Bestellungen ber&uuml;cksichtigt werden</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4882\" data-end=\"4897\">9.2 Nutzung</h3>\r\n<ul data-start=\"4899\" data-end=\"5019\">\r\n<li data-start=\"4899\" data-end=\"4940\">\r\n<p data-start=\"4901\" data-end=\"4940\">Nutzung nur durch autorisierte Personen</p>\r\n</li>\r\n<li data-start=\"4941\" data-end=\"5019\">\r\n<p data-start=\"4943\" data-end=\"5019\">Einhaltung der Sicherheitsrichtlinien (z. B. Passwortschutz, Zugriffsrechte)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"5021\" data-end=\"5061\">9.3 &Uuml;bergabe &amp; Inventarverantwortung</h3>\r\n<ul data-start=\"5063\" data-end=\"5154\">\r\n<li data-start=\"5063\" data-end=\"5116\">\r\n<p data-start=\"5065\" data-end=\"5116\">Protokollierte &Uuml;bergabe inkl. Schulung (bei Bedarf)</p>\r\n</li>\r\n<li data-start=\"5117\" data-end=\"5154\">\r\n<p data-start=\"5119\" data-end=\"5154\">Verantwortungswechsel dokumentieren</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"5156\" data-end=\"5189\">9.4 Aussonderung &amp; Entsorgung</h3>\r\n<ul data-start=\"5191\" data-end=\"5341\">\r\n<li data-start=\"5191\" data-end=\"5276\">\r\n<p data-start=\"5193\" data-end=\"5276\">Sichere Datenl&ouml;schung gem&auml;&szlig; BSI-Vorgaben (z. B. TR RESISCAN, BSI-Ma&szlig;nahmen M 2.167)</p>\r\n</li>\r\n<li data-start=\"5277\" data-end=\"5341\">\r\n<p data-start=\"5279\" data-end=\"5341\">Entsorgungsprotokoll f&uuml;hren (inkl. Asset-ID, Datum, Verfahren)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5343\" data-end=\"5346\">\r\n<h2 data-start=\"5348\" data-end=\"5384\"><strong data-start=\"5351\" data-end=\"5384\">10. &Uuml;berwachung und Kontrolle</strong></h2>\r\n<ul data-start=\"5386\" data-end=\"5684\">\r\n<li data-start=\"5386\" data-end=\"5444\">\r\n<p data-start=\"5388\" data-end=\"5444\"><strong data-start=\"5388\" data-end=\"5406\">Zugriffsrechte</strong> zu sensiblen Assets regelm&auml;&szlig;ig pr&uuml;fen</p>\r\n</li>\r\n<li data-start=\"5445\" data-end=\"5517\">\r\n<p data-start=\"5447\" data-end=\"5517\">Asset-Inventar durch <strong data-start=\"5468\" data-end=\"5486\">interne Audits</strong> mindestens j&auml;hrlich &uuml;berpr&uuml;fen</p>\r\n</li>\r\n<li data-start=\"5518\" data-end=\"5616\">\r\n<p data-start=\"5520\" data-end=\"5616\"><strong data-start=\"5520\" data-end=\"5545\">Unautorisierte Assets</strong> (z. B. Shadow-IT) sind systematisch zu identifizieren und zu entfernen</p>\r\n</li>\r\n<li data-start=\"5617\" data-end=\"5684\">\r\n<p data-start=\"5619\" data-end=\"5684\">Regelm&auml;&szlig;ige Schulungen zum verantwortungsvollen Umgang mit Assets</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5686\" data-end=\"5689\">\r\n<h2 data-start=\"5691\" data-end=\"5743\"><strong data-start=\"5694\" data-end=\"5743\">11. Bezug zu ISO/IEC 27001 und IT-Grundschutz</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5745\" data-end=\"6075\">\r\n<thead data-start=\"5745\" data-end=\"5792\">\r\n<tr data-start=\"5745\" data-end=\"5792\">\r\n<th data-start=\"5745\" data-end=\"5782\" data-col-size=\"sm\">Norm / Ma&szlig;nahme</th>\r\n<th data-start=\"5782\" data-end=\"5792\" data-col-size=\"md\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5840\" data-end=\"6075\">\r\n<tr data-start=\"5840\" data-end=\"5935\">\r\n<td data-start=\"5840\" data-end=\"5876\" data-col-size=\"sm\"><strong data-start=\"5842\" data-end=\"5875\">ISO 27001 A.5.9 / A.8.1 &ndash; 8.3</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5876\" data-end=\"5935\">Verantwortung, Klassifikation und Behandlung von Assets</td>\r\n</tr>\r\n<tr data-start=\"5936\" data-end=\"6075\">\r\n<td data-start=\"5936\" data-end=\"5972\" data-col-size=\"sm\"><strong data-start=\"5938\" data-end=\"5960\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5972\" data-end=\"6075\">ORP.4.1 (Inventarisierung), INF.6 (IT-Systeme und Datentr&auml;ger), SYS.1.1 (Server), SYS.1.2 (Clients)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2025-12-22', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(5, 'DOK-0005', 'Backup & Wiederherstellung', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"660\" data-end=\"690\"><strong data-start=\"663\" data-end=\"690\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"692\" data-end=\"1027\">Diese Richtlinie legt die Anforderungen und Verfahren f&uuml;r die Datensicherung (Backup) und -wiederherstellung (Recovery) von informationsverarbeitenden Systemen der Organisation fest. Ziel ist es, sicherzustellen, dass im Falle von Datenverlust, Systemfehlern oder Notf&auml;llen eine zeitnahe und verl&auml;ssliche Wiederherstellung m&ouml;glich ist.</p>\r\n<hr data-start=\"1029\" data-end=\"1032\">\r\n<h2 data-start=\"1034\" data-end=\"1059\"><strong data-start=\"1037\" data-end=\"1059\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1061\" data-end=\"1087\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1088\" data-end=\"1367\">\r\n<li data-start=\"1088\" data-end=\"1159\">\r\n<p data-start=\"1090\" data-end=\"1159\">Alle Server, Datenbanken, virtuellen Systeme und kritischen Endger&auml;te</p>\r\n</li>\r\n<li data-start=\"1160\" data-end=\"1207\">\r\n<p data-start=\"1162\" data-end=\"1207\">Anwendungen mit sch&uuml;tzenswerten Informationen</p>\r\n</li>\r\n<li data-start=\"1208\" data-end=\"1289\">\r\n<p data-start=\"1210\" data-end=\"1289\">Speicherorte mit personenbezogenen, gesch&auml;ftskritischen oder gesetzlichen Daten</p>\r\n</li>\r\n<li data-start=\"1290\" data-end=\"1367\">\r\n<p data-start=\"1292\" data-end=\"1367\">Verantwortliche Personen in IT, Fachabteilungen und externen Dienstleistern</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1369\" data-end=\"1372\">\r\n<h2 data-start=\"1374\" data-end=\"1394\"><strong data-start=\"1377\" data-end=\"1394\">3. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"1396\" data-end=\"1761\">\r\n<li data-start=\"1396\" data-end=\"1481\">\r\n<p data-start=\"1398\" data-end=\"1481\"><strong data-start=\"1398\" data-end=\"1430\">Verf&uuml;gbarkeit sicherstellen:</strong> Alle kritischen Daten werden regelm&auml;&szlig;ig gesichert.</p>\r\n</li>\r\n<li data-start=\"1482\" data-end=\"1578\">\r\n<p data-start=\"1484\" data-end=\"1578\"><strong data-start=\"1484\" data-end=\"1511\">Vertraulichkeit wahren:</strong> Backups werden verschl&uuml;sselt und vor unbefugtem Zugriff gesch&uuml;tzt.</p>\r\n</li>\r\n<li data-start=\"1579\" data-end=\"1669\">\r\n<p data-start=\"1581\" data-end=\"1669\"><strong data-start=\"1581\" data-end=\"1610\">Integrit&auml;t gew&auml;hrleisten:</strong> Backups sind auf Vollst&auml;ndigkeit und Lesbarkeit zu pr&uuml;fen.</p>\r\n</li>\r\n<li data-start=\"1670\" data-end=\"1761\">\r\n<p data-start=\"1672\" data-end=\"1761\"><strong data-start=\"1672\" data-end=\"1705\">Wiederherstellbarkeit testen:</strong> Regelm&auml;&szlig;ige Wiederherstellungstests sind verpflichtend.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1763\" data-end=\"1766\">\r\n<h2 data-start=\"1768\" data-end=\"1809\"><strong data-start=\"1771\" data-end=\"1809\">4. Rollen und Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1811\" data-end=\"2256\">\r\n<thead data-start=\"1811\" data-end=\"1857\">\r\n<tr data-start=\"1811\" data-end=\"1857\">\r\n<th data-start=\"1811\" data-end=\"1833\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"1833\" data-end=\"1857\" data-col-size=\"md\">Verantwortlichkeiten</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1904\" data-end=\"2256\">\r\n<tr data-start=\"1904\" data-end=\"1998\">\r\n<td data-start=\"1904\" data-end=\"1926\" data-col-size=\"sm\"><strong data-start=\"1906\" data-end=\"1922\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1926\" data-end=\"1998\">Umsetzung der Backup- und Wiederherstellungsverfahren, Dokumentation</td>\r\n</tr>\r\n<tr data-start=\"1999\" data-end=\"2068\">\r\n<td data-start=\"1999\" data-end=\"2026\" data-col-size=\"sm\"><strong data-start=\"2001\" data-end=\"2025\">Datenverantwortliche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2026\" data-end=\"2068\">Identifikation der zu sichernden Daten</td>\r\n</tr>\r\n<tr data-start=\"2069\" data-end=\"2147\">\r\n<td data-start=\"2069\" data-end=\"2092\" data-col-size=\"sm\"><strong data-start=\"2071\" data-end=\"2085\">ISB / CISO</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2092\" data-end=\"2147\">Pr&uuml;fung auf Einhaltung der Sicherheitsanforderungen</td>\r\n</tr>\r\n<tr data-start=\"2148\" data-end=\"2256\">\r\n<td data-start=\"2148\" data-end=\"2176\" data-col-size=\"sm\"><strong data-start=\"2150\" data-end=\"2175\">Externe Dienstleister</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2176\" data-end=\"2256\">Vertraglich gebundene Durchf&uuml;hrung von Backup-Leistungen unter ISMS-Vorgaben</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2258\" data-end=\"2261\">\r\n<h2 data-start=\"2263\" data-end=\"2297\"><strong data-start=\"2266\" data-end=\"2297\">5. Anforderungen an Backups</strong></h2>\r\n<h3 data-start=\"2299\" data-end=\"2323\">5.1 Sicherungsumfang</h3>\r\n<ul data-start=\"2325\" data-end=\"2524\">\r\n<li data-start=\"2325\" data-end=\"2398\">\r\n<p data-start=\"2327\" data-end=\"2398\">Alle gesch&auml;ftskritischen Systeme, Datenbanken und Konfigurationsdateien</p>\r\n</li>\r\n<li data-start=\"2399\" data-end=\"2450\">\r\n<p data-start=\"2401\" data-end=\"2450\">Benutzerverzeichnisse mit arbeitsrelevanten Daten</p>\r\n</li>\r\n<li data-start=\"2451\" data-end=\"2497\">\r\n<p data-start=\"2453\" data-end=\"2497\">Log-Dateien gem&auml;&szlig; gesetzlichen Anforderungen</p>\r\n</li>\r\n<li data-start=\"2498\" data-end=\"2524\">\r\n<p data-start=\"2500\" data-end=\"2524\">Metadaten und Protokolle</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2526\" data-end=\"2554\">5.2 Sicherungsh&auml;ufigkeit</h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2556\" data-end=\"2954\">\r\n<thead data-start=\"2556\" data-end=\"2606\">\r\n<tr data-start=\"2556\" data-end=\"2606\">\r\n<th data-start=\"2556\" data-end=\"2583\" data-col-size=\"sm\">Datenart</th>\r\n<th data-start=\"2583\" data-end=\"2606\" data-col-size=\"md\">Backup-Frequenz</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2658\" data-end=\"2954\">\r\n<tr data-start=\"2658\" data-end=\"2738\">\r\n<td data-start=\"2658\" data-end=\"2685\" data-col-size=\"sm\">Produktivdatenbanken</td>\r\n<td data-col-size=\"md\" data-start=\"2685\" data-end=\"2738\">T&auml;glich (inkrementell), w&ouml;chentlich (vollst&auml;ndig)</td>\r\n</tr>\r\n<tr data-start=\"2739\" data-end=\"2817\">\r\n<td data-start=\"2739\" data-end=\"2766\" data-col-size=\"sm\">Dateiserver</td>\r\n<td data-col-size=\"md\" data-start=\"2766\" data-end=\"2817\">T&auml;glich (inkrementell), monatlich (vollst&auml;ndig)</td>\r\n</tr>\r\n<tr data-start=\"2818\" data-end=\"2890\">\r\n<td data-start=\"2818\" data-end=\"2845\" data-col-size=\"sm\">Systemkonfigurationen</td>\r\n<td data-col-size=\"md\" data-start=\"2845\" data-end=\"2890\">Nach jeder &Auml;nderung, mindestens monatlich</td>\r\n</tr>\r\n<tr data-start=\"2891\" data-end=\"2954\">\r\n<td data-start=\"2891\" data-end=\"2918\" data-col-size=\"sm\">Virtuelle Maschinen</td>\r\n<td data-col-size=\"md\" data-start=\"2918\" data-end=\"2954\">Nach &Auml;nderungen oder w&ouml;chentlich</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<h3 data-start=\"2956\" data-end=\"2982\">5.3 Aufbewahrungsdauer</h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2984\" data-end=\"3291\">\r\n<thead data-start=\"2984\" data-end=\"3028\">\r\n<tr data-start=\"2984\" data-end=\"3028\">\r\n<th data-start=\"2984\" data-end=\"3003\" data-col-size=\"sm\">Backup-Typ</th>\r\n<th data-start=\"3003\" data-end=\"3028\" data-col-size=\"md\">Aufbewahrungszeit</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3075\" data-end=\"3291\">\r\n<tr data-start=\"3075\" data-end=\"3120\">\r\n<td data-start=\"3075\" data-end=\"3094\" data-col-size=\"sm\">T&auml;gliches Backup</td>\r\n<td data-col-size=\"md\" data-start=\"3094\" data-end=\"3120\">7&ndash;14 Tage</td>\r\n</tr>\r\n<tr data-start=\"3121\" data-end=\"3166\">\r\n<td data-start=\"3121\" data-end=\"3140\" data-col-size=\"sm\">W&ouml;chentliches</td>\r\n<td data-col-size=\"md\" data-start=\"3140\" data-end=\"3166\">4&ndash;6 Wochen</td>\r\n</tr>\r\n<tr data-start=\"3167\" data-end=\"3212\">\r\n<td data-start=\"3167\" data-end=\"3186\" data-col-size=\"sm\">Monatliches</td>\r\n<td data-col-size=\"md\" data-start=\"3186\" data-end=\"3212\">6&ndash;12 Monate</td>\r\n</tr>\r\n<tr data-start=\"3213\" data-end=\"3291\">\r\n<td data-start=\"3213\" data-end=\"3232\" data-col-size=\"sm\">Archiv-Backups</td>\r\n<td data-col-size=\"md\" data-start=\"3232\" data-end=\"3291\">Bis zu 10 Jahre (je nach gesetzl. Vorgaben, z. B. GoBD)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<h3 data-start=\"3293\" data-end=\"3322\">5.4 Medien &amp; Speicherorte</h3>\r\n<ul data-start=\"3324\" data-end=\"3567\">\r\n<li data-start=\"3324\" data-end=\"3456\">\r\n<p data-start=\"3326\" data-end=\"3456\">Verwendung von gesicherten Netzwerkfreigaben, LTO-B&auml;ndern oder Cloud-Speichern mit zertifizierter Sicherheit (z. B. ISO 27001, C5)</p>\r\n</li>\r\n<li data-start=\"3457\" data-end=\"3500\">\r\n<p data-start=\"3459\" data-end=\"3500\">Georedundante Sicherungskopien bei Bedarf</p>\r\n</li>\r\n<li data-start=\"3501\" data-end=\"3567\">\r\n<p data-start=\"3503\" data-end=\"3567\"><strong data-start=\"3503\" data-end=\"3567\">Kein Speichern von produktiven Backups auf demselben System!</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3569\" data-end=\"3572\">\r\n<h2 data-start=\"3574\" data-end=\"3618\"><strong data-start=\"3577\" data-end=\"3618\">6. Verschl&uuml;sselung und Zugriffsschutz</strong></h2>\r\n<ul data-start=\"3620\" data-end=\"3905\">\r\n<li data-start=\"3620\" data-end=\"3705\">\r\n<p data-start=\"3622\" data-end=\"3705\">Alle Backup-Daten sind mit einem starken Verfahren (z. B. AES-256) zu verschl&uuml;sseln</p>\r\n</li>\r\n<li data-start=\"3706\" data-end=\"3745\">\r\n<p data-start=\"3708\" data-end=\"3745\">Zugriff nur f&uuml;r autorisierte Personen</p>\r\n</li>\r\n<li data-start=\"3746\" data-end=\"3810\">\r\n<p data-start=\"3748\" data-end=\"3810\">Speicherung von Zugangsdaten/Passw&ouml;rtern in einem Passwortsafe</p>\r\n</li>\r\n<li data-start=\"3811\" data-end=\"3905\">\r\n<p data-start=\"3813\" data-end=\"3905\">Bei physischen Medien: Lagerung in einem gesicherten Brandschutzschrank oder externen Tresor</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3907\" data-end=\"3910\">\r\n<h2 data-start=\"3912\" data-end=\"3950\"><strong data-start=\"3915\" data-end=\"3950\">7. Wiederherstellung (Recovery)</strong></h2>\r\n<h3 data-start=\"3952\" data-end=\"3985\">7.1 Wiederherstellungsklassen</h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3987\" data-end=\"4429\">\r\n<thead data-start=\"3987\" data-end=\"4072\">\r\n<tr data-start=\"3987\" data-end=\"4072\">\r\n<th data-start=\"3987\" data-end=\"4014\" data-col-size=\"sm\">Wiederherstellungsklasse</th>\r\n<th data-start=\"4014\" data-end=\"4048\" data-col-size=\"sm\">Zielsysteme / Daten</th>\r\n<th data-start=\"4048\" data-end=\"4072\" data-col-size=\"sm\">RTO / RPO</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4160\" data-end=\"4429\">\r\n<tr data-start=\"4160\" data-end=\"4248\">\r\n<td data-start=\"4160\" data-end=\"4187\" data-col-size=\"sm\">Hochkritisch</td>\r\n<td data-col-size=\"sm\" data-start=\"4187\" data-end=\"4221\">ERP, Produktionsdatenbanken</td>\r\n<td data-col-size=\"sm\" data-start=\"4221\" data-end=\"4248\">RTO: &lt; 4 h / RPO: &lt; 1 h</td>\r\n</tr>\r\n<tr data-start=\"4249\" data-end=\"4337\">\r\n<td data-start=\"4249\" data-end=\"4276\" data-col-size=\"sm\">Kritisch</td>\r\n<td data-col-size=\"sm\" data-start=\"4276\" data-end=\"4310\">E-Mail, Fileserver, CRM</td>\r\n<td data-col-size=\"sm\" data-start=\"4310\" data-end=\"4337\">RTO: &lt; 8 h / RPO: &lt; 4 h</td>\r\n</tr>\r\n<tr data-start=\"4338\" data-end=\"4429\">\r\n<td data-start=\"4338\" data-end=\"4365\" data-col-size=\"sm\">Standard</td>\r\n<td data-col-size=\"sm\" data-start=\"4365\" data-end=\"4399\">Archive, Projektverzeichnisse</td>\r\n<td data-col-size=\"sm\" data-start=\"4399\" data-end=\"4429\">RTO: &lt; 24 h / RPO: &lt; 1 Tag</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<h3 data-start=\"4431\" data-end=\"4462\">7.2 Wiederherstellungstests</h3>\r\n<ul data-start=\"4464\" data-end=\"4665\">\r\n<li data-start=\"4464\" data-end=\"4539\">\r\n<p data-start=\"4466\" data-end=\"4539\">Mindestens <strong data-start=\"4477\" data-end=\"4496\">viertelj&auml;hrlich</strong> sind Wiederherstellungstests durchzuf&uuml;hren</p>\r\n</li>\r\n<li data-start=\"4540\" data-end=\"4624\">\r\n<p data-start=\"4542\" data-end=\"4624\">Tests m&uuml;ssen dokumentiert und ausgewertet werden (inkl. Dauer, Probleme, Ergebnis)</p>\r\n</li>\r\n<li data-start=\"4625\" data-end=\"4665\">\r\n<p data-start=\"4627\" data-end=\"4665\">Fehlerquellen sind umgehend zu beheben</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4667\" data-end=\"4670\">\r\n<h2 data-start=\"4672\" data-end=\"4695\"><strong data-start=\"4675\" data-end=\"4695\">8. Dokumentation</strong></h2>\r\n<p data-start=\"4697\" data-end=\"4738\">Folgende Dokumentation ist verpflichtend:</p>\r\n<ul data-start=\"4740\" data-end=\"4991\">\r\n<li data-start=\"4740\" data-end=\"4786\">\r\n<p data-start=\"4742\" data-end=\"4786\">Backup-Konzept inkl. Zeitpl&auml;ne und Verfahren</p>\r\n</li>\r\n<li data-start=\"4787\" data-end=\"4841\">\r\n<p data-start=\"4789\" data-end=\"4841\">Protokolle &uuml;ber jede Sicherung und Wiederherstellung</p>\r\n</li>\r\n<li data-start=\"4842\" data-end=\"4885\">\r\n<p data-start=\"4844\" data-end=\"4885\">Dokumentation der Testwiederherstellungen</p>\r\n</li>\r\n<li data-start=\"4886\" data-end=\"4941\">\r\n<p data-start=\"4888\" data-end=\"4941\">&Uuml;bersicht der Verantwortlichkeiten und Zugriffsrechte</p>\r\n</li>\r\n<li data-start=\"4942\" data-end=\"4991\">\r\n<p data-start=\"4944\" data-end=\"4991\">Beschreibung der eingesetzten Software/Hardware</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4993\" data-end=\"4996\">\r\n<h2 data-start=\"4998\" data-end=\"5031\"><strong data-start=\"5001\" data-end=\"5031\">9. &Uuml;berwachung &amp; Kontrolle</strong></h2>\r\n<ul data-start=\"5033\" data-end=\"5318\">\r\n<li data-start=\"5033\" data-end=\"5154\">\r\n<p data-start=\"5035\" data-end=\"5154\">Die ordnungsgem&auml;&szlig;e Durchf&uuml;hrung wird durch <strong data-start=\"5078\" data-end=\"5113\">automatisierte Monitoring-Tools</strong> sowie <strong data-start=\"5120\" data-end=\"5144\">manuelle Stichproben</strong> &uuml;berpr&uuml;ft</p>\r\n</li>\r\n<li data-start=\"5155\" data-end=\"5201\">\r\n<p data-start=\"5157\" data-end=\"5201\">Backup-Protokolle werden t&auml;glich ausgewertet</p>\r\n</li>\r\n<li data-start=\"5202\" data-end=\"5252\">\r\n<p data-start=\"5204\" data-end=\"5252\">Abweichungen sind zu dokumentieren und zu melden</p>\r\n</li>\r\n<li data-start=\"5253\" data-end=\"5318\">\r\n<p data-start=\"5255\" data-end=\"5318\">Interne Audits pr&uuml;fen die Einhaltung mindestens einmal j&auml;hrlich</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5320\" data-end=\"5323\">\r\n<h2 data-start=\"5325\" data-end=\"5373\"><strong data-start=\"5328\" data-end=\"5373\">10. Bezug zu ISO 27001 und IT-Grundschutz</strong></h2>\r\n<p data-start=\"5375\" data-end=\"5416\">Diese Richtlinie adressiert insbesondere:</p>\r\n<ul data-start=\"5418\" data-end=\"5691\">\r\n<li data-start=\"5418\" data-end=\"5544\">\r\n<p data-start=\"5420\" data-end=\"5438\"><strong data-start=\"5420\" data-end=\"5438\">ISO/IEC 27001:</strong></p>\r\n<ul data-start=\"5441\" data-end=\"5544\">\r\n<li data-start=\"5441\" data-end=\"5475\">\r\n<p data-start=\"5443\" data-end=\"5475\">A.12.3.1 &ndash; Informationssicherung</p>\r\n</li>\r\n<li data-start=\"5478\" data-end=\"5544\">\r\n<p data-start=\"5480\" data-end=\"5544\">A.17.1 &ndash; Sicherstellung der Informationssicherheit bei St&ouml;rungen</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"5545\" data-end=\"5691\">\r\n<p data-start=\"5547\" data-end=\"5581\"><strong data-start=\"5547\" data-end=\"5581\">BSI IT-Grundschutz-Kompendium:</strong></p>\r\n<ul data-start=\"5584\" data-end=\"5691\">\r\n<li data-start=\"5584\" data-end=\"5616\">\r\n<p data-start=\"5586\" data-end=\"5616\"><strong data-start=\"5586\" data-end=\"5599\">OPS.1.1.5</strong> &ndash; Datensicherung</p>\r\n</li>\r\n<li data-start=\"5619\" data-end=\"5659\">\r\n<p data-start=\"5621\" data-end=\"5659\"><strong data-start=\"5621\" data-end=\"5639\">CON.9 / CON.10</strong> &ndash; Notfallmanagement</p>\r\n</li>\r\n<li data-start=\"5662\" data-end=\"5691\">\r\n<p data-start=\"5664\" data-end=\"5691\"><strong data-start=\"5664\" data-end=\"5673\">APP.4</strong> &ndash; Backup-Software</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2025-12-22', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(6, 'DOK-0006', 'Business Continuity & Disaster Recovery', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"658\" data-end=\"688\"><strong data-start=\"661\" data-end=\"688\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"690\" data-end=\"1118\">Diese Richtlinie legt die Grunds&auml;tze und Anforderungen zur Planung, Umsetzung, Pflege und Pr&uuml;fung von Ma&szlig;nahmen zur <strong data-start=\"806\" data-end=\"857\">Betrieblichen Kontinuit&auml;t (Business Continuity)</strong> und zur <strong data-start=\"866\" data-end=\"927\">Wiederherstellung im Katastrophenfall (Disaster Recovery)</strong> fest. Ziel ist es, die Fortf&uuml;hrung gesch&auml;ftskritischer Prozesse auch in au&szlig;ergew&ouml;hnlichen Situationen sicherzustellen und die Auswirkungen von St&ouml;rungen auf ein akzeptables Ma&szlig; zu begrenzen.</p>\r\n<hr data-start=\"1120\" data-end=\"1123\">\r\n<h2 data-start=\"1125\" data-end=\"1150\"><strong data-start=\"1128\" data-end=\"1150\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1152\" data-end=\"1393\">Diese Richtlinie gilt f&uuml;r alle Organisationseinheiten, Systeme, Gesch&auml;ftsprozesse und Dienstleistungen, deren Ausfall erhebliche Auswirkungen auf die Gesch&auml;ftst&auml;tigkeit, die Informationssicherheit oder die gesetzlichen Verpflichtungen h&auml;tte.</p>\r\n<hr data-start=\"1395\" data-end=\"1398\">\r\n<h2 data-start=\"1400\" data-end=\"1435\"><strong data-start=\"1403\" data-end=\"1435\">3. Begriffe und Definitionen</strong></h2>\r\n<ul data-start=\"1437\" data-end=\"2066\">\r\n<li data-start=\"1437\" data-end=\"1564\">\r\n<p data-start=\"1439\" data-end=\"1564\"><strong data-start=\"1439\" data-end=\"1468\">Business Continuity (BC):</strong> F&auml;higkeit der Organisation, kritische Gesch&auml;ftsprozesse bei erheblichen St&ouml;rungen fortzuf&uuml;hren.</p>\r\n</li>\r\n<li data-start=\"1565\" data-end=\"1706\">\r\n<p data-start=\"1567\" data-end=\"1706\"><strong data-start=\"1567\" data-end=\"1594\">Disaster Recovery (DR):</strong> Technische und organisatorische Ma&szlig;nahmen zur Wiederherstellung der IT-Systeme nach einem gravierenden Ausfall.</p>\r\n</li>\r\n<li data-start=\"1707\" data-end=\"1836\">\r\n<p data-start=\"1709\" data-end=\"1836\"><strong data-start=\"1709\" data-end=\"1744\">BCP (Business Continuity Plan):</strong> Dokumentierter Plan zur Aufrechterhaltung oder Wiederaufnahme kritischer Gesch&auml;ftsprozesse.</p>\r\n</li>\r\n<li data-start=\"1837\" data-end=\"1916\">\r\n<p data-start=\"1839\" data-end=\"1916\"><strong data-start=\"1839\" data-end=\"1872\">DRP (Disaster Recovery Plan):</strong> Plan zur Wiederherstellung der IT-Services.</p>\r\n</li>\r\n<li data-start=\"1917\" data-end=\"1992\">\r\n<p data-start=\"1919\" data-end=\"1992\"><strong data-start=\"1919\" data-end=\"1953\">RTO (Recovery Time Objective):</strong> Maximal tolerierbare Wiederanlaufzeit.</p>\r\n</li>\r\n<li data-start=\"1993\" data-end=\"2066\">\r\n<p data-start=\"1995\" data-end=\"2066\"><strong data-start=\"1995\" data-end=\"2030\">RPO (Recovery Point Objective):</strong> Maximal tolerierbarer Datenverlust.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2068\" data-end=\"2071\">\r\n<h2 data-start=\"2073\" data-end=\"2093\"><strong data-start=\"2076\" data-end=\"2093\">4. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"2095\" data-end=\"2645\">\r\n<li data-start=\"2095\" data-end=\"2195\">\r\n<p data-start=\"2097\" data-end=\"2195\"><strong data-start=\"2097\" data-end=\"2123\">Verf&uuml;gbarkeit sichern:</strong> Schutz der Verf&uuml;gbarkeit von Informationen und Prozessen bei Ausf&auml;llen.</p>\r\n</li>\r\n<li data-start=\"2196\" data-end=\"2324\">\r\n<p data-start=\"2198\" data-end=\"2324\"><strong data-start=\"2198\" data-end=\"2232\">Vorsorge trifft Verantwortung:</strong> Risiken f&uuml;r kritische Prozesse sind zu identifizieren und mit Notfallma&szlig;nahmen abzusichern.</p>\r\n</li>\r\n<li data-start=\"2325\" data-end=\"2440\">\r\n<p data-start=\"2327\" data-end=\"2440\"><strong data-start=\"2327\" data-end=\"2345\">Dokumentation:</strong> Pl&auml;ne f&uuml;r Notfallmanagement, Wiederherstellung und Wiederanlauf sind schriftlich festzuhalten.</p>\r\n</li>\r\n<li data-start=\"2441\" data-end=\"2538\">\r\n<p data-start=\"2443\" data-end=\"2538\"><strong data-start=\"2443\" data-end=\"2465\">Regelm&auml;&szlig;ige Tests:</strong> Notfallpl&auml;ne m&uuml;ssen regelm&auml;&szlig;ig &uuml;berpr&uuml;ft, getestet und angepasst werden.</p>\r\n</li>\r\n<li data-start=\"2539\" data-end=\"2645\">\r\n<p data-start=\"2541\" data-end=\"2645\"><strong data-start=\"2541\" data-end=\"2567\">Mitarbeitereinbindung:</strong> Zust&auml;ndigkeiten und Rollen im Krisenfall sind klar geregelt und kommuniziert.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2647\" data-end=\"2650\">\r\n<h2 data-start=\"2652\" data-end=\"2693\"><strong data-start=\"2655\" data-end=\"2693\">5. Rollen und Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2695\" data-end=\"3277\">\r\n<thead data-start=\"2695\" data-end=\"2745\">\r\n<tr data-start=\"2695\" data-end=\"2745\">\r\n<th data-start=\"2695\" data-end=\"2721\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"2721\" data-end=\"2745\" data-col-size=\"md\">Verantwortlichkeiten</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2796\" data-end=\"3277\">\r\n<tr data-start=\"2796\" data-end=\"2871\">\r\n<td data-start=\"2796\" data-end=\"2821\" data-col-size=\"sm\"><strong data-start=\"2798\" data-end=\"2816\">Top-Management</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2821\" data-end=\"2871\">Verantwortung f&uuml;r strategische Notfallvorsorge</td>\r\n</tr>\r\n<tr data-start=\"2872\" data-end=\"2954\">\r\n<td data-start=\"2872\" data-end=\"2897\" data-col-size=\"sm\"><strong data-start=\"2874\" data-end=\"2888\">ISB / CISO</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2897\" data-end=\"2954\">Integration in ISMS, Bewertung der Sicherheitsrisiken</td>\r\n</tr>\r\n<tr data-start=\"2955\" data-end=\"3031\">\r\n<td data-start=\"2955\" data-end=\"2980\" data-col-size=\"sm\"><strong data-start=\"2957\" data-end=\"2978\">Notfallmanager/in</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2980\" data-end=\"3031\">Koordination der Notfallvorsorge und -ma&szlig;nahmen</td>\r\n</tr>\r\n<tr data-start=\"3032\" data-end=\"3114\">\r\n<td data-start=\"3032\" data-end=\"3057\" data-col-size=\"sm\"><strong data-start=\"3034\" data-end=\"3057\">Fachbereichsleitung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3057\" data-end=\"3114\">Identifikation kritischer Prozesse, Mitwirkung an BIA</td>\r\n</tr>\r\n<tr data-start=\"3115\" data-end=\"3199\">\r\n<td data-start=\"3115\" data-end=\"3140\" data-col-size=\"sm\"><strong data-start=\"3117\" data-end=\"3133\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3140\" data-end=\"3199\">Erstellung, Pflege und Test der Disaster-Recovery-Pl&auml;ne</td>\r\n</tr>\r\n<tr data-start=\"3200\" data-end=\"3277\">\r\n<td data-start=\"3200\" data-end=\"3229\" data-col-size=\"sm\"><strong data-start=\"3202\" data-end=\"3228\">Alle Mitarbeiter*innen</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3229\" data-end=\"3277\">Mitwirkung bei Awareness-Ma&szlig;nahmen und Tests</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3279\" data-end=\"3282\">\r\n<h2 data-start=\"3284\" data-end=\"3330\"><strong data-start=\"3287\" data-end=\"3330\">6. Anforderungen an die Notfallvorsorge</strong></h2>\r\n<h3 data-start=\"3332\" data-end=\"3369\">6.1 Business Impact Analyse (BIA)</h3>\r\n<ul data-start=\"3371\" data-end=\"3581\">\r\n<li data-start=\"3371\" data-end=\"3431\">\r\n<p data-start=\"3373\" data-end=\"3431\">Identifikation kritischer Gesch&auml;ftsprozesse und Ressourcen</p>\r\n</li>\r\n<li data-start=\"3432\" data-end=\"3514\">\r\n<p data-start=\"3434\" data-end=\"3514\">Ermittlung der maximal tolerierbaren Ausfallzeiten (RTO) und Datenverluste (RPO)</p>\r\n</li>\r\n<li data-start=\"3515\" data-end=\"3581\">\r\n<p data-start=\"3517\" data-end=\"3581\">Bewertung finanzieller, rechtlicher und reputativer Auswirkungen</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3583\" data-end=\"3604\">6.2 Risikoanalyse</h3>\r\n<ul data-start=\"3606\" data-end=\"3799\">\r\n<li data-start=\"3606\" data-end=\"3687\">\r\n<p data-start=\"3608\" data-end=\"3687\">Identifikation m&ouml;glicher Gef&auml;hrdungen (z. B. Feuer, Stromausfall, Cyberangriff)</p>\r\n</li>\r\n<li data-start=\"3688\" data-end=\"3748\">\r\n<p data-start=\"3690\" data-end=\"3748\">Bewertung der Eintrittswahrscheinlichkeit und Schadensh&ouml;he</p>\r\n</li>\r\n<li data-start=\"3749\" data-end=\"3799\">\r\n<p data-start=\"3751\" data-end=\"3799\">Grundlage f&uuml;r Notfallma&szlig;nahmen und Priorisierung</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3801\" data-end=\"3839\">6.3 Notfall- und Wiederanlaufpl&auml;ne</h3>\r\n<ul data-start=\"3841\" data-end=\"4075\">\r\n<li data-start=\"3841\" data-end=\"3910\">\r\n<p data-start=\"3843\" data-end=\"3910\">Erstellung von BCP und DRP f&uuml;r alle kritischen Prozesse und Systeme</p>\r\n</li>\r\n<li data-start=\"3911\" data-end=\"4075\">\r\n<p data-start=\"3913\" data-end=\"3929\">Enthalten u. a.:</p>\r\n<ul data-start=\"3932\" data-end=\"4075\">\r\n<li data-start=\"3932\" data-end=\"3965\">\r\n<p data-start=\"3934\" data-end=\"3965\">Kontaktlisten (intern &amp; extern)</p>\r\n</li>\r\n<li data-start=\"3968\" data-end=\"3994\">\r\n<p data-start=\"3970\" data-end=\"3994\">Kommunikationsstrategien</p>\r\n</li>\r\n<li data-start=\"3997\" data-end=\"4027\">\r\n<p data-start=\"3999\" data-end=\"4027\">Wiederherstellungsprozeduren</p>\r\n</li>\r\n<li data-start=\"4030\" data-end=\"4052\">\r\n<p data-start=\"4032\" data-end=\"4052\">Verantwortlichkeiten</p>\r\n</li>\r\n<li data-start=\"4055\" data-end=\"4075\">\r\n<p data-start=\"4057\" data-end=\"4075\">Alternativprozesse</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4077\" data-end=\"4080\">\r\n<h2 data-start=\"4082\" data-end=\"4109\"><strong data-start=\"4085\" data-end=\"4109\">7. Tests und &Uuml;bungen</strong></h2>\r\n<ul data-start=\"4111\" data-end=\"4427\">\r\n<li data-start=\"4111\" data-end=\"4180\">\r\n<p data-start=\"4113\" data-end=\"4180\">Notfallpl&auml;ne m&uuml;ssen <strong data-start=\"4133\" data-end=\"4163\">mindestens einmal j&auml;hrlich</strong> getestet werden.</p>\r\n</li>\r\n<li data-start=\"4181\" data-end=\"4294\">\r\n<p data-start=\"4183\" data-end=\"4193\">Testarten:</p>\r\n<ul data-start=\"4196\" data-end=\"4294\">\r\n<li data-start=\"4196\" data-end=\"4228\">\r\n<p data-start=\"4198\" data-end=\"4228\">Dokumentenpr&uuml;fung / Planspiele</p>\r\n</li>\r\n<li data-start=\"4231\" data-end=\"4267\">\r\n<p data-start=\"4233\" data-end=\"4267\">Teil- oder Vollunterbrechungstests</p>\r\n</li>\r\n<li data-start=\"4270\" data-end=\"4294\">\r\n<p data-start=\"4272\" data-end=\"4294\">IT-Restaurierungstests</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"4295\" data-end=\"4356\">\r\n<p data-start=\"4297\" data-end=\"4356\">Ergebnisse der Tests sind zu dokumentieren und auszuwerten.</p>\r\n</li>\r\n<li data-start=\"4357\" data-end=\"4427\">\r\n<p data-start=\"4359\" data-end=\"4427\">Lessons Learned sind in die Planaktualisierung einflie&szlig;en zu lassen.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4429\" data-end=\"4432\">\r\n<h2 data-start=\"4434\" data-end=\"4473\"><strong data-start=\"4437\" data-end=\"4473\">8. Schulung und Sensibilisierung</strong></h2>\r\n<ul data-start=\"4475\" data-end=\"4718\">\r\n<li data-start=\"4475\" data-end=\"4572\">\r\n<p data-start=\"4477\" data-end=\"4572\">Alle betroffenen Mitarbeiter*innen erhalten regelm&auml;&szlig;ig Schulungen zu ihren Aufgaben im Notfall.</p>\r\n</li>\r\n<li data-start=\"4573\" data-end=\"4639\">\r\n<p data-start=\"4575\" data-end=\"4639\">Neue Mitarbeiter*innen werden in die Notfallvorsorge eingef&uuml;hrt.</p>\r\n</li>\r\n<li data-start=\"4640\" data-end=\"4718\">\r\n<p data-start=\"4642\" data-end=\"4718\">Notfallkontakte und -pl&auml;ne sind f&uuml;r relevante Personen zug&auml;nglich zu halten.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4720\" data-end=\"4723\">\r\n<h2 data-start=\"4725\" data-end=\"4759\"><strong data-start=\"4728\" data-end=\"4759\">9. Dokumentation und Pflege</strong></h2>\r\n<ul data-start=\"4761\" data-end=\"5011\">\r\n<li data-start=\"4761\" data-end=\"4840\">\r\n<p data-start=\"4763\" data-end=\"4840\">Notfallpl&auml;ne sind versionskontrolliert, aktuell und zug&auml;nglich aufzubewahren.</p>\r\n</li>\r\n<li data-start=\"4841\" data-end=\"4936\">\r\n<p data-start=\"4843\" data-end=\"4936\">&Auml;nderungen an Gesch&auml;ftsprozessen oder IT-Systemen f&uuml;hren zur Aktualisierung der Notfallpl&auml;ne.</p>\r\n</li>\r\n<li data-start=\"4937\" data-end=\"5011\">\r\n<p data-start=\"4939\" data-end=\"5011\">Alle relevanten Dokumente unterliegen dem ISMS-Dokumentationsmanagement.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5013\" data-end=\"5016\">\r\n<h2 data-start=\"5018\" data-end=\"5070\"><strong data-start=\"5021\" data-end=\"5070\">10. Bezug zu ISO/IEC 27001 und IT-Grundschutz</strong></h2>\r\n<p data-start=\"5072\" data-end=\"5137\">Diese Richtlinie unterst&uuml;tzt insbesondere folgende Anforderungen:</p>\r\n<ul data-start=\"5139\" data-end=\"5436\">\r\n<li data-start=\"5139\" data-end=\"5273\">\r\n<p data-start=\"5141\" data-end=\"5159\"><strong data-start=\"5141\" data-end=\"5159\">ISO/IEC 27001:</strong></p>\r\n<ul data-start=\"5162\" data-end=\"5273\">\r\n<li data-start=\"5162\" data-end=\"5227\">\r\n<p data-start=\"5164\" data-end=\"5227\">A.17.1 &ndash; Informationssicherheitsaspekte der Business Continuity</p>\r\n</li>\r\n<li data-start=\"5230\" data-end=\"5273\">\r\n<p data-start=\"5232\" data-end=\"5273\">A.17.2 &ndash; Wiederherstellung nach St&ouml;rungen</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"5274\" data-end=\"5436\">\r\n<p data-start=\"5276\" data-end=\"5310\"><strong data-start=\"5276\" data-end=\"5310\">BSI IT-Grundschutz-Kompendium:</strong></p>\r\n<ul data-start=\"5313\" data-end=\"5436\">\r\n<li data-start=\"5313\" data-end=\"5340\">\r\n<p data-start=\"5315\" data-end=\"5340\">CON.9 &ndash; Notfallmanagement</p>\r\n</li>\r\n<li data-start=\"5343\" data-end=\"5376\">\r\n<p data-start=\"5345\" data-end=\"5376\">CON.10 &ndash; Notfallvorsorgekonzept</p>\r\n</li>\r\n<li data-start=\"5379\" data-end=\"5407\">\r\n<p data-start=\"5381\" data-end=\"5407\">OPS.1.1.5 &ndash; Datensicherung</p>\r\n</li>\r\n<li data-start=\"5410\" data-end=\"5436\">\r\n<p data-start=\"5412\" data-end=\"5436\">OPS.1.3.3 &ndash; Wiederanlauf</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2025-12-22', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(7, 'DOK-0007', 'Changemanagement', 'Richtlinien', '1', 0, 'öffentlich', '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Diese Richtlinie definiert verbindliche Vorgaben für die Planung, Genehmigung, Umsetzung und Dokumentation von Änderungen an IT-Systemen, Anwendungen, Netzwerken und Sicherheitsmaßnahmen innerhalb der Organisation. Ziel ist es, Risiken durch unkontrollierte oder fehlerhafte Änderungen zu minimieren und die Verfügbarkeit, Vertraulichkeit und Integrität der Informationen sicherzustellen.</p>\n<hr/>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Diese Richtlinie gilt für alle geplanten Änderungen an informationsverarbeitenden Systemen, Komponenten der IT-Infrastruktur, Applikationen sowie organisatorischen Prozessen, die Auswirkungen auf die Informationssicherheit haben können. Sie gilt für alle Mitarbeiter*innen, Dienstleister und sonstige Dritte, die Änderungen im Auftrag der Organisation vornehmen.</p>\n<hr/>\n<h2><strong>3. Definitionen</strong></h2>\n<ul>\n<li>\n<p><strong>Change:</strong> Eine geplante Änderung an der IT-Umgebung oder an Prozessen.</p>\n</li>\n<li>\n<p><strong>Notfall-Change (Emergency Change):</strong> Eine unvorhergesehene Änderung, die zur schnellen Behebung kritischer Probleme notwendig ist.</p>\n</li>\n<li>\n<p><strong>Change-Advisory-Board (CAB):</strong> Ein Gremium zur Bewertung, Genehmigung und Priorisierung von Changes.</p>\n</li>\n<li>\n<p><strong>Change Request (CR):</strong> Ein formaler Antrag auf Durchführung eines Changes.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>4. Grundsätze</strong></h2>\n<ul>\n<li>\n<p><strong>Kontrollierte Änderungen:</strong> Alle Änderungen sind geplant, dokumentiert, bewertet und autorisiert durchzuführen.</p>\n</li>\n<li>\n<p><strong>Risikobewertung:</strong> Jede Änderung ist im Hinblick auf potenzielle Risiken für die Informationssicherheit zu bewerten.</p>\n</li>\n<li>\n<p><strong>Nachvollziehbarkeit:</strong> Änderungen müssen vollständig dokumentiert und nachvollziehbar sein.</p>\n</li>\n<li>\n<p><strong>Test und Validierung:</strong> Vor der produktiven Umsetzung ist die Änderung zu testen und auf unbeabsichtigte Nebenwirkungen zu prüfen.</p>\n</li>\n<li>\n<p><strong>Rollback-Plan:</strong> Für jede Änderung ist ein Rückfallplan (Rollback) zu erstellen.</p>\n</li>\n<li>\n<p><strong>Genehmigungspflicht:</strong> Änderungen dürfen nur nach expliziter Freigabe durchgeführt werden.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>5. Rollen und Verantwortlichkeiten</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Verantwortung</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Change Manager</strong></td>\n<td>Gesamtverantwortung für den Change-Prozess, Koordination der Changes, Dokumentation</td>\n</tr>\n<tr>\n<td><strong>Anforderer (Requestor)</strong></td>\n<td>Einreichen und Beschreibung des Change Requests</td>\n</tr>\n<tr>\n<td><strong>CAB</strong></td>\n<td>Bewertung und Freigabe von Changes</td>\n</tr>\n<tr>\n<td><strong>IT-Betrieb / Admins</strong></td>\n<td>Durchführung genehmigter Changes, Test, Rollback</td>\n</tr>\n<tr>\n<td><strong>ISB / CISO</strong></td>\n<td>Bewertung sicherheitsrelevanter Auswirkungen, Beratung im CAB</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>6. Ablauf des Change-Management-Prozesses</strong></h2>\n<ol>\n<li>\n<p><strong>Antragstellung:</strong></p>\n<ul>\n<li>\n<p>Ausfüllen und Einreichen eines Change Requests (CR)</p>\n</li>\n<li>\n<p>Angabe: Beschreibung, Ziel, betroffene Systeme, Risiko, gewünschter Zeitraum</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Bewertung:</strong></p>\n<ul>\n<li>\n<p>Risikobewertung in Zusammenarbeit mit Informationssicherheitsbeauftragten (ISB)</p>\n</li>\n<li>\n<p>Einschätzung des Einflusses auf Verfügbarkeit, Vertraulichkeit, Integrität</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Genehmigung:</strong></p>\n<ul>\n<li>\n<p>Freigabe durch Change Manager / CAB</p>\n</li>\n<li>\n<p>Notfalländerungen benötigen nachträgliche CAB-Validierung</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Test &amp; Implementierung:</strong></p>\n<ul>\n<li>\n<p>Durchführung in Testumgebung</p>\n</li>\n<li>\n<p>Dokumentation der Testergebnisse</p>\n</li>\n<li>\n<p>Umsetzung gemäß Rollout-Plan und ggf. Rollback-Plan</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Nachbereitung &amp; Dokumentation:</strong></p>\n<ul>\n<li>\n<p>Review der Umsetzung</p>\n</li>\n<li>\n<p>Lessons Learned (bei Bedarf)</p>\n</li>\n<li>\n<p>Änderungshistorie in zentralem System dokumentieren</p>\n</li>\n</ul>\n</li>\n</ol>\n<hr/>\n<h2><strong>7. Notfalländerungen (Emergency Changes)</strong></h2>\n<p>Notfalländerungen sind in Ausnahmefällen erlaubt (z. B. bei akuten Sicherheitslücken oder Systemausfällen). Sie müssen schnellstmöglich dokumentiert und innerhalb von 48 Stunden nachträglich vom CAB bewertet und genehmigt werden.</p>\n<hr/>\n<h2><strong>8. Dokumentation</strong></h2>\n<p>Alle Änderungen sind zentral in einem Change-Management-System zu dokumentieren. Die Dokumentation muss enthalten:</p>\n<ul>\n<li>\n<p>Change Request ID</p>\n</li>\n<li>\n<p>Datum / Zeit der Umsetzung</p>\n</li>\n<li>\n<p>Verantwortliche Personen</p>\n</li>\n<li>\n<p>Betroffene Systeme / Komponenten</p>\n</li>\n<li>\n<p>Risikoanalyse</p>\n</li>\n<li>\n<p>Testnachweise</p>\n</li>\n<li>\n<p>Genehmigungen</p>\n</li>\n<li>\n<p>Durchgeführte Maßnahmen</p>\n</li>\n<li>\n<p>ggf. aufgetretene Probleme und Rollback-Aktivitäten</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Überwachung und Auditierung</strong></h2>\n<p>Der Change-Management-Prozess wird regelmäßig durch interne Audits überprüft. Verstöße gegen diese Richtlinie können disziplinarische Maßnahmen nach sich ziehen.</p>\n<hr/>\n<h2><strong>10. Bezug zu ISO 27001 und IT-Grundschutz</strong></h2>\n<p>Diese Richtlinie unterstützt insbesondere folgende Anforderungen:</p>\n<ul>\n<li>\n<p><strong>ISO/IEC 27001:</strong></p>\n<ul>\n<li>\n<p>A.12.1.2 - Änderungskontrollen</p>\n</li>\n<li>\n<p>A.14.2.2 - Änderungen an Systemen in der Entwicklung und Produktion</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>BSI IT-Grundschutz-Kompendium:</strong></p>\n<ul>\n<li>\n<p>OPS.1.3.4 - Patch- und Änderungsmanagement</p>\n</li>\n<li>\n<p>SYS.1.1 - Server</p>\n</li>\n<li>\n<p>INF.1 - Netzwerke</p>\n</li>\n</ul>\n</li>\n</ul>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-01-18', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(8, 'DOK-0008', 'Datenmanagement', 'Richtlinien', '1', 0, 'öffentlich', '<h2 data-start=\"637\" data-end=\"667\"><strong data-start=\"640\" data-end=\"667\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"669\" data-end=\"964\">Ziel dieser Richtlinie ist es, einheitliche Vorgaben f&uuml;r den <strong data-start=\"730\" data-end=\"794\">sicheren, gesetzeskonformen und effizienten Umgang mit Daten</strong> in der Organisation zu schaffen. Sie definiert Standards f&uuml;r <strong data-start=\"856\" data-end=\"963\">Datenerhebung, -verarbeitung, -klassifizierung, -speicherung, -&uuml;bertragung, -archivierung und -l&ouml;schung</strong>.</p>\r\n<hr data-start=\"966\" data-end=\"969\">\r\n<h2 data-start=\"971\" data-end=\"996\"><strong data-start=\"974\" data-end=\"996\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"998\" data-end=\"1024\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1026\" data-end=\"1368\">\r\n<li data-start=\"1026\" data-end=\"1161\">\r\n<p data-start=\"1028\" data-end=\"1161\"><strong data-start=\"1028\" data-end=\"1052\">Alle Arten von Daten</strong>, unabh&auml;ngig von Format (z. B. digital, physisch) und Inhalt (z. B. personenbezogen, vertraulich, &ouml;ffentlich)</p>\r\n</li>\r\n<li data-start=\"1162\" data-end=\"1279\">\r\n<p data-start=\"1164\" data-end=\"1279\"><strong data-start=\"1164\" data-end=\"1187\">Alle Mitarbeitenden</strong>, Dienstleister und Dritte, die Daten im Auftrag oder im Rahmen der Organisation verarbeiten</p>\r\n</li>\r\n<li data-start=\"1280\" data-end=\"1368\">\r\n<p data-start=\"1282\" data-end=\"1368\"><strong data-start=\"1282\" data-end=\"1298\">Alle Systeme</strong>, Anwendungen und Speichermedien, die Daten speichern oder verarbeiten</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1370\" data-end=\"1373\">\r\n<h2 data-start=\"1375\" data-end=\"1410\"><strong data-start=\"1378\" data-end=\"1410\">3. Begriffe und Definitionen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1412\" data-end=\"2033\">\r\n<thead data-start=\"1412\" data-end=\"1446\">\r\n<tr data-start=\"1412\" data-end=\"1446\">\r\n<th data-start=\"1412\" data-end=\"1430\" data-col-size=\"sm\">Begriff</th>\r\n<th data-start=\"1430\" data-end=\"1446\" data-col-size=\"lg\">Beschreibung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1481\" data-end=\"2033\">\r\n<tr data-start=\"1481\" data-end=\"1561\">\r\n<td data-start=\"1481\" data-end=\"1499\" data-col-size=\"sm\"><strong data-start=\"1483\" data-end=\"1492\">Daten</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1499\" data-end=\"1561\">Informationen in strukturierter oder unstrukturierter Form</td>\r\n</tr>\r\n<tr data-start=\"1562\" data-end=\"1666\">\r\n<td data-start=\"1562\" data-end=\"1586\" data-col-size=\"sm\"><strong data-start=\"1564\" data-end=\"1585\">Datenlebenszyklus</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1586\" data-end=\"1666\">Von der Erhebung &uuml;ber Speicherung, Nutzung und Archivierung bis zur L&ouml;schung</td>\r\n</tr>\r\n<tr data-start=\"1667\" data-end=\"1819\">\r\n<td data-start=\"1667\" data-end=\"1709\" data-col-size=\"sm\"><strong data-start=\"1669\" data-end=\"1708\">Verantwortliche Stelle / Data Owner</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1709\" data-end=\"1819\">Einheit, die f&uuml;r die inhaltliche Richtigkeit, Zul&auml;ssigkeit und Klassifikation der Daten verantwortlich ist</td>\r\n</tr>\r\n<tr data-start=\"1820\" data-end=\"1922\">\r\n<td data-start=\"1820\" data-end=\"1854\" data-col-size=\"sm\"><strong data-start=\"1822\" data-end=\"1853\">Datenschutzrechtliche Daten</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1854\" data-end=\"1922\">Daten, die dem Schutz der DSGVO oder anderer Gesetze unterliegen</td>\r\n</tr>\r\n<tr data-start=\"1923\" data-end=\"2033\">\r\n<td data-start=\"1923\" data-end=\"1949\" data-col-size=\"sm\"><strong data-start=\"1925\" data-end=\"1948\">Datenklassifikation</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1949\" data-end=\"2033\">Schutzbedarfsbasierte Einstufung nach Vertraulichkeit, Integrit&auml;t, Verf&uuml;gbarkeit</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2035\" data-end=\"2038\">\r\n<h2 data-start=\"2040\" data-end=\"2081\"><strong data-start=\"2043\" data-end=\"2081\">4. Grunds&auml;tze des Datenmanagements</strong></h2>\r\n<ul data-start=\"2083\" data-end=\"2637\">\r\n<li data-start=\"2083\" data-end=\"2191\">\r\n<p data-start=\"2085\" data-end=\"2191\"><strong data-start=\"2085\" data-end=\"2103\">Rechtm&auml;&szlig;igkeit</strong>: Datenverarbeitung erfolgt stets im Rahmen gesetzlicher Vorgaben (z. B. DSGVO, HGB, AO)</p>\r\n</li>\r\n<li data-start=\"2192\" data-end=\"2255\">\r\n<p data-start=\"2194\" data-end=\"2255\"><strong data-start=\"2194\" data-end=\"2216\">Verantwortlichkeit</strong>: Jeder Datensatz hat eine/n Data Owner</p>\r\n</li>\r\n<li data-start=\"2256\" data-end=\"2364\">\r\n<p data-start=\"2258\" data-end=\"2364\"><strong data-start=\"2258\" data-end=\"2278\">Datenminimierung</strong>: Es werden nur so viele Daten erhoben und verarbeitet, wie f&uuml;r den Zweck erforderlich</p>\r\n</li>\r\n<li data-start=\"2365\" data-end=\"2468\">\r\n<p data-start=\"2367\" data-end=\"2468\"><strong data-start=\"2367\" data-end=\"2389\">Zugriffsprinzipien</strong>: Zugriff erfolgt nach dem &bdquo;Need-to-know&ldquo;-Prinzip und ist technisch abzusichern</p>\r\n</li>\r\n<li data-start=\"2469\" data-end=\"2538\">\r\n<p data-start=\"2471\" data-end=\"2538\"><strong data-start=\"2471\" data-end=\"2495\">Sicherheitsma&szlig;nahmen</strong>: Daten sind gem&auml;&szlig; Schutzbedarf zu sch&uuml;tzen</p>\r\n</li>\r\n<li data-start=\"2539\" data-end=\"2637\">\r\n<p data-start=\"2541\" data-end=\"2637\"><strong data-start=\"2541\" data-end=\"2580\">Dokumentation &amp; Nachvollziehbarkeit</strong>: &Auml;nderungen und Verarbeitung m&uuml;ssen nachvollziehbar sein</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2639\" data-end=\"2642\">\r\n<h2 data-start=\"2644\" data-end=\"2692\"><strong data-start=\"2647\" data-end=\"2692\">5. Lebenszyklusbasierter Umgang mit Daten</strong></h2>\r\n<h3 data-start=\"2694\" data-end=\"2719\">5.1 <strong data-start=\"2702\" data-end=\"2719\">Datenerhebung</strong></h3>\r\n<ul data-start=\"2721\" data-end=\"2866\">\r\n<li data-start=\"2721\" data-end=\"2748\">\r\n<p data-start=\"2723\" data-end=\"2748\">Nur durch befugte Stellen</p>\r\n</li>\r\n<li data-start=\"2749\" data-end=\"2798\">\r\n<p data-start=\"2751\" data-end=\"2798\">Zweckbindung muss gegeben und dokumentiert sein</p>\r\n</li>\r\n<li data-start=\"2799\" data-end=\"2866\">\r\n<p data-start=\"2801\" data-end=\"2866\">Transparenzpflichten (insb. bei personenbezogenen Daten) beachten</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2868\" data-end=\"2899\">5.2 <strong data-start=\"2876\" data-end=\"2899\">Datenklassifikation</strong></h3>\r\n<ul data-start=\"2901\" data-end=\"3158\">\r\n<li data-start=\"2901\" data-end=\"3026\">\r\n<p data-start=\"2903\" data-end=\"3026\">Daten sind gem&auml;&szlig; der <strong data-start=\"2924\" data-end=\"2954\">Informationsklassifikation</strong> (z. B. &ouml;ffentlich, intern, vertraulich, streng vertraulich) einzustufen</p>\r\n</li>\r\n<li data-start=\"3027\" data-end=\"3091\">\r\n<p data-start=\"3029\" data-end=\"3091\">Die Schutzbedarfsfeststellung erfolgt durch den <strong data-start=\"3077\" data-end=\"3091\">Data Owner</strong></p>\r\n</li>\r\n<li data-start=\"3092\" data-end=\"3158\">\r\n<p data-start=\"3094\" data-end=\"3158\">Ergebnisse sind im <strong data-start=\"3113\" data-end=\"3141\">Asset- und Datenregister</strong> zu dokumentieren</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3160\" data-end=\"3188\">5.3 <strong data-start=\"3168\" data-end=\"3188\">Datenspeicherung</strong></h3>\r\n<ul data-start=\"3190\" data-end=\"3537\">\r\n<li data-start=\"3190\" data-end=\"3297\">\r\n<p data-start=\"3192\" data-end=\"3297\">Speicherung erfolgt nur in <strong data-start=\"3219\" data-end=\"3245\">autorisierten Systemen</strong> (z. B. zugelassene Cloud- oder On-Premises-Dienste)</p>\r\n</li>\r\n<li data-start=\"3298\" data-end=\"3382\">\r\n<p data-start=\"3300\" data-end=\"3382\">Speicherorte m&uuml;ssen den <strong data-start=\"3324\" data-end=\"3354\">gesetzlichen Anforderungen</strong> (z. B. DSGVO, GoBD) gen&uuml;gen</p>\r\n</li>\r\n<li data-start=\"3383\" data-end=\"3537\">\r\n<p data-start=\"3385\" data-end=\"3401\">Schutzma&szlig;nahmen:</p>\r\n<ul data-start=\"3404\" data-end=\"3537\">\r\n<li data-start=\"3404\" data-end=\"3442\">\r\n<p data-start=\"3406\" data-end=\"3442\">Zugriffskontrolle (IAM, Rollen, MFA)</p>\r\n</li>\r\n<li data-start=\"3445\" data-end=\"3486\">\r\n<p data-start=\"3447\" data-end=\"3486\">Verschl&uuml;sselung bei vertraulichen Daten</p>\r\n</li>\r\n<li data-start=\"3489\" data-end=\"3537\">\r\n<p data-start=\"3491\" data-end=\"3537\">Protokollierung sicherheitsrelevanter Zugriffe</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3539\" data-end=\"3568\">5.4 <strong data-start=\"3547\" data-end=\"3568\">Datenverarbeitung</strong></h3>\r\n<ul data-start=\"3570\" data-end=\"3763\">\r\n<li data-start=\"3570\" data-end=\"3614\">\r\n<p data-start=\"3572\" data-end=\"3614\">Nur durch berechtigte Personen und Systeme</p>\r\n</li>\r\n<li data-start=\"3615\" data-end=\"3713\">\r\n<p data-start=\"3617\" data-end=\"3713\">Datenverarbeitung in Drittstaaten nur bei Angemessenheitsbeschluss oder Standardvertragsklauseln</p>\r\n</li>\r\n<li data-start=\"3714\" data-end=\"3763\">\r\n<p data-start=\"3716\" data-end=\"3763\">Schutz vor Verlust, Manipulation und Missbrauch</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3765\" data-end=\"3793\">5.5 <strong data-start=\"3773\" data-end=\"3793\">Daten&uuml;bertragung</strong></h3>\r\n<ul data-start=\"3795\" data-end=\"4019\">\r\n<li data-start=\"3795\" data-end=\"3864\">\r\n<p data-start=\"3797\" data-end=\"3864\">Externe &Uuml;bertragungen m&uuml;ssen verschl&uuml;sselt und nachvollziehbar sein</p>\r\n</li>\r\n<li data-start=\"3865\" data-end=\"3952\">\r\n<p data-start=\"3867\" data-end=\"3952\">Einsatz sicherer &Uuml;bertragungsverfahren (z. B. SFTP, TLS, VPN, E-Mail-Verschl&uuml;sselung)</p>\r\n</li>\r\n<li data-start=\"3953\" data-end=\"4019\">\r\n<p data-start=\"3955\" data-end=\"4019\">Freigabe durch den Data Owner erforderlich (bei sensiblen Daten)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4021\" data-end=\"4045\">5.6 <strong data-start=\"4029\" data-end=\"4045\">Archivierung</strong></h3>\r\n<ul data-start=\"4047\" data-end=\"4252\">\r\n<li data-start=\"4047\" data-end=\"4129\">\r\n<p data-start=\"4049\" data-end=\"4129\">Langzeitarchivierung erfolgt gem&auml;&szlig; gesetzlichen oder vertraglichen Anforderungen</p>\r\n</li>\r\n<li data-start=\"4130\" data-end=\"4179\">\r\n<p data-start=\"4132\" data-end=\"4179\">Nur in zugelassenen Systemen mit Zugriffsschutz</p>\r\n</li>\r\n<li data-start=\"4180\" data-end=\"4252\">\r\n<p data-start=\"4182\" data-end=\"4252\">Archivdaten sind zu klassifizieren (z. B. steuerrelevant, vertraulich)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4254\" data-end=\"4288\">5.7 <strong data-start=\"4262\" data-end=\"4288\">L&ouml;schung / Vernichtung</strong></h3>\r\n<ul data-start=\"4290\" data-end=\"4646\">\r\n<li data-start=\"4290\" data-end=\"4378\">\r\n<p data-start=\"4292\" data-end=\"4378\">Daten sind nach Ablauf der Aufbewahrungsfristen oder bei Wegfall des Zwecks zu l&ouml;schen</p>\r\n</li>\r\n<li data-start=\"4379\" data-end=\"4443\">\r\n<p data-start=\"4381\" data-end=\"4443\"><strong data-start=\"4381\" data-end=\"4397\">L&ouml;schpflicht</strong> ist gesetzlich geregelt (insb. Art. 17 DSGVO)</p>\r\n</li>\r\n<li data-start=\"4444\" data-end=\"4646\">\r\n<p data-start=\"4446\" data-end=\"4504\">L&ouml;schung erfolgt sicher, dokumentiert und nachvollziehbar:</p>\r\n<ul data-start=\"4507\" data-end=\"4646\">\r\n<li data-start=\"4507\" data-end=\"4579\">\r\n<p data-start=\"4509\" data-end=\"4579\">Digital: z. B. durch zertifizierte Tools oder Verfahren (BSI TR-02102)</p>\r\n</li>\r\n<li data-start=\"4582\" data-end=\"4646\">\r\n<p data-start=\"4584\" data-end=\"4646\">Physisch: z. B. durch Schreddern oder zertifizierte Entsorgung</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4648\" data-end=\"4651\">\r\n<h2 data-start=\"4653\" data-end=\"4683\"><strong data-start=\"4656\" data-end=\"4683\">6. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4685\" data-end=\"5149\">\r\n<thead data-start=\"4685\" data-end=\"4718\">\r\n<tr data-start=\"4685\" data-end=\"4718\">\r\n<th data-start=\"4685\" data-end=\"4706\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"4706\" data-end=\"4718\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4753\" data-end=\"5149\">\r\n<tr data-start=\"4753\" data-end=\"4822\">\r\n<td data-start=\"4753\" data-end=\"4774\" data-col-size=\"sm\"><strong data-start=\"4755\" data-end=\"4769\">Data Owner</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4774\" data-end=\"4822\">Einstufung, Pflege und &Uuml;berwachung der Daten</td>\r\n</tr>\r\n<tr data-start=\"4823\" data-end=\"4888\">\r\n<td data-start=\"4823\" data-end=\"4844\" data-col-size=\"sm\"><strong data-start=\"4825\" data-end=\"4841\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4844\" data-end=\"4888\">Technische Umsetzung von Schutzma&szlig;nahmen</td>\r\n</tr>\r\n<tr data-start=\"4889\" data-end=\"4969\">\r\n<td data-start=\"4889\" data-end=\"4910\" data-col-size=\"sm\"><strong data-start=\"4891\" data-end=\"4898\">ISB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4910\" data-end=\"4969\">Informationssicherheitsvorgaben, Kontrolle und Beratung</td>\r\n</tr>\r\n<tr data-start=\"4970\" data-end=\"5048\">\r\n<td data-start=\"4970\" data-end=\"5007\" data-col-size=\"sm\"><strong data-start=\"4972\" data-end=\"5006\">Datenschutzbeauftragte*r (DSB)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5007\" data-end=\"5048\">Kontrolle bei personenbezogenen Daten</td>\r\n</tr>\r\n<tr data-start=\"5049\" data-end=\"5149\">\r\n<td data-start=\"5049\" data-end=\"5075\" data-col-size=\"sm\"><strong data-start=\"5051\" data-end=\"5074\">Alle Mitarbeitenden</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5075\" data-end=\"5149\">Sorgf&auml;ltiger Umgang, Meldung von Vorf&auml;llen, Einhaltung der Richtlinien</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5151\" data-end=\"5154\">\r\n<h2 data-start=\"5156\" data-end=\"5201\"><strong data-start=\"5159\" data-end=\"5201\">7. Schutzma&szlig;nahmen nach Klassifikation</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5203\" data-end=\"5579\">\r\n<thead data-start=\"5203\" data-end=\"5255\">\r\n<tr data-start=\"5203\" data-end=\"5255\">\r\n<th data-start=\"5203\" data-end=\"5228\" data-col-size=\"sm\">Klassifikation</th>\r\n<th data-start=\"5228\" data-end=\"5255\" data-col-size=\"md\">Beispiele f&uuml;r Ma&szlig;nahmen</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5309\" data-end=\"5579\">\r\n<tr data-start=\"5309\" data-end=\"5381\">\r\n<td data-start=\"5309\" data-end=\"5334\" data-col-size=\"sm\"><strong data-start=\"5311\" data-end=\"5321\">Intern</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5334\" data-end=\"5381\">Zugangsbeschr&auml;nkung, kein Versand an Dritte</td>\r\n</tr>\r\n<tr data-start=\"5382\" data-end=\"5467\">\r\n<td data-start=\"5382\" data-end=\"5407\" data-col-size=\"sm\"><strong data-start=\"5384\" data-end=\"5399\">Vertraulich</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5407\" data-end=\"5467\">Rollenbasierte Zugriffe, Verschl&uuml;sselung bei &Uuml;bertragung</td>\r\n</tr>\r\n<tr data-start=\"5468\" data-end=\"5579\">\r\n<td data-start=\"5468\" data-end=\"5493\" data-col-size=\"sm\"><strong data-start=\"5470\" data-end=\"5492\">Streng vertraulich</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5493\" data-end=\"5579\">Verschl&uuml;sselung bei Speicherung + Transport, restriktiver Zugriff, Protokollierung</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5581\" data-end=\"5584\">\r\n<h2 data-start=\"5586\" data-end=\"5625\"><strong data-start=\"5589\" data-end=\"5625\">8. Datenqualit&auml;t und -konsistenz</strong></h2>\r\n<ul data-start=\"5627\" data-end=\"5822\">\r\n<li data-start=\"5627\" data-end=\"5704\">\r\n<p data-start=\"5629\" data-end=\"5704\">Verantwortliche Stellen sorgen f&uuml;r <strong data-start=\"5664\" data-end=\"5694\">Richtigkeit und Aktualit&auml;t</strong> der Daten</p>\r\n</li>\r\n<li data-start=\"5705\" data-end=\"5755\">\r\n<p data-start=\"5707\" data-end=\"5755\">Redundanzen und Inkonsistenzen sind zu vermeiden</p>\r\n</li>\r\n<li data-start=\"5756\" data-end=\"5822\">\r\n<p data-start=\"5758\" data-end=\"5822\">Systeme sollen &uuml;ber Funktionen zur <strong data-start=\"5793\" data-end=\"5813\">Datenvalidierung</strong> verf&uuml;gen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5824\" data-end=\"5827\">\r\n<h2 data-start=\"5829\" data-end=\"5863\"><strong data-start=\"5832\" data-end=\"5863\">9. Datenmanagement und ISMS</strong></h2>\r\n<p data-start=\"5865\" data-end=\"5923\">Diese Richtlinie ist Teil des ISMS und wird erg&auml;nzt durch:</p>\r\n<ul data-start=\"5925\" data-end=\"6114\">\r\n<li data-start=\"5925\" data-end=\"5968\">\r\n<p data-start=\"5927\" data-end=\"5968\">Richtlinie zur Informationsklassifikation</p>\r\n</li>\r\n<li data-start=\"5969\" data-end=\"6003\">\r\n<p data-start=\"5971\" data-end=\"6003\">Richtlinie f&uuml;r Zugriffskontrolle</p>\r\n</li>\r\n<li data-start=\"6004\" data-end=\"6027\">\r\n<p data-start=\"6006\" data-end=\"6027\">Datenschutzrichtlinie</p>\r\n</li>\r\n<li data-start=\"6028\" data-end=\"6070\">\r\n<p data-start=\"6030\" data-end=\"6070\">Backup- und Wiederherstellungsrichtlinie</p>\r\n</li>\r\n<li data-start=\"6071\" data-end=\"6114\">\r\n<p data-start=\"6073\" data-end=\"6114\">Richtlinie zur Nutzung von Cloud-Diensten</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6116\" data-end=\"6119\">\r\n<h2 data-start=\"6121\" data-end=\"6178\"><strong data-start=\"6124\" data-end=\"6178\">10. Bezug zu Normen und gesetzlichen Anforderungen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6180\" data-end=\"6598\">\r\n<thead data-start=\"6180\" data-end=\"6220\">\r\n<tr data-start=\"6180\" data-end=\"6220\">\r\n<th data-start=\"6180\" data-end=\"6210\" data-col-size=\"sm\">Norm / Gesetz</th>\r\n<th data-start=\"6210\" data-end=\"6220\" data-col-size=\"md\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6261\" data-end=\"6598\">\r\n<tr data-start=\"6261\" data-end=\"6367\">\r\n<td data-start=\"6261\" data-end=\"6303\" data-col-size=\"sm\"><strong data-start=\"6263\" data-end=\"6302\">ISO/IEC 27001 &ndash; A.5, A.8, A.9, A.18</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6303\" data-end=\"6367\">Organisation, Assetmanagement, Zugriffskontrolle, Compliance</td>\r\n</tr>\r\n<tr data-start=\"6368\" data-end=\"6434\">\r\n<td data-start=\"6368\" data-end=\"6398\" data-col-size=\"sm\"><strong data-start=\"6370\" data-end=\"6392\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6398\" data-end=\"6434\">ORP.4, INF.5, CON.1&ndash;4, OPS.1.2.4</td>\r\n</tr>\r\n<tr data-start=\"6435\" data-end=\"6528\">\r\n<td data-start=\"6435\" data-end=\"6465\" data-col-size=\"sm\"><strong data-start=\"6437\" data-end=\"6449\">EU-DSGVO</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6465\" data-end=\"6528\">Art. 5, 6, 13, 17 (Datenminimierung, L&ouml;schung, Transparenz)</td>\r\n</tr>\r\n<tr data-start=\"6529\" data-end=\"6598\">\r\n<td data-start=\"6529\" data-end=\"6559\" data-col-size=\"sm\"><strong data-start=\"6531\" data-end=\"6548\">GoBD, HGB, AO</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6559\" data-end=\"6598\">Aufbewahrung steuerrelevanter Daten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-01-18', 0, 0, 0, 0, NULL, 0, 'Data management', '<p>Englischer Text</p>', 'Policies', 'public', '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(9, 'DOK-0009', 'Personalsicherheit', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"698\" data-end=\"728\"><strong data-start=\"701\" data-end=\"728\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"730\" data-end=\"940\">Diese Richtlinie dient der Festlegung von Ma&szlig;nahmen zur <strong data-start=\"786\" data-end=\"831\">Informationssicherheit im Personalbereich</strong>. Sie stellt sicher, dass Mitarbeitende, Auftragnehmende und sonstige Personen mit Zugriff auf Informationen:</p>\r\n<ul data-start=\"942\" data-end=\"1130\">\r\n<li data-start=\"942\" data-end=\"1007\">\r\n<p data-start=\"944\" data-end=\"1007\">sich ihrer <strong data-start=\"955\" data-end=\"972\">Verantwortung</strong> f&uuml;r die Sicherheit bewusst sind,</p>\r\n</li>\r\n<li data-start=\"1008\" data-end=\"1075\">\r\n<p data-start=\"1010\" data-end=\"1075\">&uuml;ber notwendige <strong data-start=\"1026\" data-end=\"1040\">Kenntnisse</strong> und <strong data-start=\"1045\" data-end=\"1063\">Zugriffsrechte</strong> verf&uuml;gen,</p>\r\n</li>\r\n<li data-start=\"1076\" data-end=\"1130\">\r\n<p data-start=\"1078\" data-end=\"1130\">und sich <strong data-start=\"1087\" data-end=\"1119\">vertraulich und regelkonform</strong> verhalten.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1132\" data-end=\"1135\">\r\n<h2 data-start=\"1137\" data-end=\"1162\"><strong data-start=\"1140\" data-end=\"1162\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1164\" data-end=\"1188\">Die Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1190\" data-end=\"1530\">\r\n<li data-start=\"1190\" data-end=\"1283\">\r\n<p data-start=\"1192\" data-end=\"1283\"><strong data-start=\"1192\" data-end=\"1214\">Alle Besch&auml;ftigten</strong> (Festangestellte, Praktikant*innen, Werkstudierende, F&uuml;hrungskr&auml;fte)</p>\r\n</li>\r\n<li data-start=\"1284\" data-end=\"1434\">\r\n<p data-start=\"1286\" data-end=\"1434\"><strong data-start=\"1286\" data-end=\"1304\">Externe Dritte</strong>, die im Auftrag der Organisation t&auml;tig sind (z. B. Berater, IT-Dienstleister, Reinigungskr&auml;fte mit Zugang zu sensiblen Bereichen)</p>\r\n</li>\r\n<li data-start=\"1435\" data-end=\"1530\">\r\n<p data-start=\"1437\" data-end=\"1530\"><strong data-start=\"1437\" data-end=\"1464\">Personalverantwortliche</strong> und alle Personen mit sicherheitsrelevanter Entscheidungsbefugnis</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1532\" data-end=\"1535\">\r\n<h2 data-start=\"1537\" data-end=\"1580\"><strong data-start=\"1540\" data-end=\"1580\">3. Grunds&auml;tze der Personalsicherheit</strong></h2>\r\n<ul data-start=\"1582\" data-end=\"2100\">\r\n<li data-start=\"1582\" data-end=\"1666\">\r\n<p data-start=\"1584\" data-end=\"1666\"><strong data-start=\"1584\" data-end=\"1644\">Informationssicherheit ist eine gemeinsame Verantwortung</strong> aller Mitarbeitenden.</p>\r\n</li>\r\n<li data-start=\"1667\" data-end=\"1798\">\r\n<p data-start=\"1669\" data-end=\"1798\">Sicherheitsma&szlig;nahmen gelten <strong data-start=\"1697\" data-end=\"1739\">&uuml;ber den gesamten Besch&auml;ftigungszyklus</strong> (Pre-Employment, w&auml;hrend der T&auml;tigkeit, nach Ausscheiden).</p>\r\n</li>\r\n<li data-start=\"1799\" data-end=\"1934\">\r\n<p data-start=\"1801\" data-end=\"1934\">Mitarbeitende m&uuml;ssen in geeigneter Weise f&uuml;r die Anforderungen der Informationssicherheit <strong data-start=\"1891\" data-end=\"1926\">sensibilisiert und verpflichtet</strong> werden.</p>\r\n</li>\r\n<li data-start=\"1935\" data-end=\"2100\">\r\n<p data-start=\"1937\" data-end=\"2100\">Der Zugang zu Informationen und IT-Systemen erfolgt nach dem <strong data-start=\"1998\" data-end=\"2037\">Prinzip der geringsten Berechtigung</strong> (&bdquo;Least Privilege&ldquo;) und nur mit <strong data-start=\"2070\" data-end=\"2099\">bedarfsgerechter Freigabe</strong>.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2102\" data-end=\"2105\">\r\n<h2 data-start=\"2107\" data-end=\"2170\"><strong data-start=\"2110\" data-end=\"2170\">4. Ma&szlig;nahmen vor Aufnahme der T&auml;tigkeit (Pre-Employment)</strong></h2>\r\n<h3 data-start=\"2172\" data-end=\"2198\">4.1 Personalvorauswahl</h3>\r\n<ul data-start=\"2200\" data-end=\"2464\">\r\n<li data-start=\"2200\" data-end=\"2369\">\r\n<p data-start=\"2202\" data-end=\"2369\">Bei sicherheitskritischen Positionen erfolgt eine <strong data-start=\"2252\" data-end=\"2283\">Zuverl&auml;ssigkeits&uuml;berpr&uuml;fung</strong> (z. B. F&uuml;hrungszeugnis, Bonit&auml;tspr&uuml;fung, Sicherheits&uuml;berpr&uuml;fung nach S&Uuml;G bei Bedarf).</p>\r\n</li>\r\n<li data-start=\"2370\" data-end=\"2464\">\r\n<p data-start=\"2372\" data-end=\"2464\">Verl&auml;sslichkeit, Fachkompetenz und Verantwortungsbewusstsein sind Teil der Auswahlkriterien.</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2466\" data-end=\"2492\">4.2 Vertragsgestaltung</h3>\r\n<ul data-start=\"2494\" data-end=\"2933\">\r\n<li data-start=\"2494\" data-end=\"2615\">\r\n<p data-start=\"2496\" data-end=\"2615\">Arbeits- und Dienstvertr&auml;ge m&uuml;ssen <strong data-start=\"2531\" data-end=\"2604\">Verpflichtungsklauseln zur Informationssicherheit und Vertraulichkeit</strong> enthalten.</p>\r\n</li>\r\n<li data-start=\"2616\" data-end=\"2777\">\r\n<p data-start=\"2618\" data-end=\"2777\">Bei der Verarbeitung personenbezogener Daten: Einhaltung der <strong data-start=\"2679\" data-end=\"2688\">DSGVO</strong> und Verpflichtung auf das <strong data-start=\"2715\" data-end=\"2733\">Datengeheimnis</strong> gem&auml;&szlig; Art. 5 und Art. 32 DSGVO / &sect; 53 BDSG.</p>\r\n</li>\r\n<li data-start=\"2778\" data-end=\"2933\">\r\n<p data-start=\"2780\" data-end=\"2933\">Externe Dienstleister unterzeichnen eine <strong data-start=\"2821\" data-end=\"2859\">Vertraulichkeitsvereinbarung (NDA)</strong> und ggf. eine <strong data-start=\"2874\" data-end=\"2913\">Verarbeitungst&auml;tigkeitsvereinbarung</strong> nach Art. 28 DSGVO.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2935\" data-end=\"2938\">\r\n<h2 data-start=\"2940\" data-end=\"3001\"><strong data-start=\"2943\" data-end=\"3001\">5. Ma&szlig;nahmen w&auml;hrend der Besch&auml;ftigung (In-Employment)</strong></h2>\r\n<h3 data-start=\"3003\" data-end=\"3040\">5.1 Sensibilisierung und Schulung</h3>\r\n<ul data-start=\"3042\" data-end=\"3362\">\r\n<li data-start=\"3042\" data-end=\"3136\">\r\n<p data-start=\"3044\" data-end=\"3136\">Alle Mitarbeitenden erhalten bei Eintritt eine <strong data-start=\"3091\" data-end=\"3135\">Einf&uuml;hrung in die Informationssicherheit</strong>.</p>\r\n</li>\r\n<li data-start=\"3137\" data-end=\"3229\">\r\n<p data-start=\"3139\" data-end=\"3229\">Wiederkehrende Schulungen und Awareness-Ma&szlig;nahmen erfolgen <strong data-start=\"3198\" data-end=\"3228\">mindestens einmal j&auml;hrlich</strong>.</p>\r\n</li>\r\n<li data-start=\"3230\" data-end=\"3362\">\r\n<p data-start=\"3232\" data-end=\"3362\">Inhalte: Passwortverhalten, Umgang mit vertraulichen Informationen, Phishing, Social Engineering, Melden von Sicherheitsvorf&auml;llen.</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3364\" data-end=\"3389\">5.2 Zugriffskontrolle</h3>\r\n<ul data-start=\"3391\" data-end=\"3637\">\r\n<li data-start=\"3391\" data-end=\"3466\">\r\n<p data-start=\"3393\" data-end=\"3466\">Zugriffsrechte werden auf Basis von <strong data-start=\"3429\" data-end=\"3456\">Rollen und Schutzbedarf</strong> vergeben.</p>\r\n</li>\r\n<li data-start=\"3467\" data-end=\"3556\">\r\n<p data-start=\"3469\" data-end=\"3556\">Rechte werden regelm&auml;&szlig;ig &uuml;berpr&uuml;ft und bei Positionswechsel oder Projektende angepasst.</p>\r\n</li>\r\n<li data-start=\"3557\" data-end=\"3637\">\r\n<p data-start=\"3559\" data-end=\"3637\">IT-Zug&auml;nge sind <strong data-start=\"3575\" data-end=\"3594\">personenbezogen</strong> und d&uuml;rfen <strong data-start=\"3606\" data-end=\"3629\">nicht weitergegeben</strong> werden.</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3639\" data-end=\"3663\">5.3 Verhaltensregeln</h3>\r\n<ul data-start=\"3665\" data-end=\"3871\">\r\n<li data-start=\"3665\" data-end=\"3871\">\r\n<p data-start=\"3667\" data-end=\"3699\">Mitarbeitende sind verpflichtet:</p>\r\n<ul data-start=\"3702\" data-end=\"3871\">\r\n<li data-start=\"3702\" data-end=\"3771\">\r\n<p data-start=\"3704\" data-end=\"3771\">Informationen und Systeme nur f&uuml;r autorisierte Zwecke zu verwenden,</p>\r\n</li>\r\n<li data-start=\"3774\" data-end=\"3815\">\r\n<p data-start=\"3776\" data-end=\"3815\">vertrauliche Daten nicht weiterzugeben,</p>\r\n</li>\r\n<li data-start=\"3818\" data-end=\"3871\">\r\n<p data-start=\"3820\" data-end=\"3871\">sicherheitsrelevante Vorf&auml;lle <strong data-start=\"3850\" data-end=\"3870\">sofort zu melden</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3873\" data-end=\"3901\">5.4 Disziplinarma&szlig;nahmen</h3>\r\n<ul data-start=\"3903\" data-end=\"4117\">\r\n<li data-start=\"3903\" data-end=\"4025\">\r\n<p data-start=\"3905\" data-end=\"4025\">Bei Verst&ouml;&szlig;en gegen die Sicherheitsvorgaben sind <strong data-start=\"3954\" data-end=\"3976\">klare Konsequenzen</strong> bis hin zur Abmahnung oder K&uuml;ndigung vorgesehen.</p>\r\n</li>\r\n<li data-start=\"4026\" data-end=\"4117\">\r\n<p data-start=\"4028\" data-end=\"4117\">Die Organisation verfolgt ein <strong data-start=\"4058\" data-end=\"4084\">Zero-Tolerance-Prinzip</strong> bei vors&auml;tzlichem Fehlverhalten.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4119\" data-end=\"4122\">\r\n<h2 data-start=\"4124\" data-end=\"4195\"><strong data-start=\"4127\" data-end=\"4195\">6. Ma&szlig;nahmen nach Beendigung der Besch&auml;ftigung (Post-Employment)</strong></h2>\r\n<h3 data-start=\"4197\" data-end=\"4223\">6.1 Beendigungsprozess</h3>\r\n<ul data-start=\"4225\" data-end=\"4464\">\r\n<li data-start=\"4225\" data-end=\"4464\">\r\n<p data-start=\"4227\" data-end=\"4278\">Bei Austritt sind folgende Ma&szlig;nahmen durchzuf&uuml;hren:</p>\r\n<ul data-start=\"4281\" data-end=\"4464\">\r\n<li data-start=\"4281\" data-end=\"4312\">\r\n<p data-start=\"4283\" data-end=\"4312\"><strong data-start=\"4283\" data-end=\"4312\">Sperrung aller IT-Zug&auml;nge</strong></p>\r\n</li>\r\n<li data-start=\"4315\" data-end=\"4379\">\r\n<p data-start=\"4317\" data-end=\"4379\"><strong data-start=\"4317\" data-end=\"4379\">R&uuml;ckgabe von Hardware, Datentr&auml;gern, Ausweisen, Unterlagen</strong></p>\r\n</li>\r\n<li data-start=\"4382\" data-end=\"4464\">\r\n<p data-start=\"4384\" data-end=\"4464\">Abschlussgespr&auml;ch zur Erinnerung an <strong data-start=\"4420\" data-end=\"4464\">fortbestehende Vertraulichkeitspflichten</strong></p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4466\" data-end=\"4507\">6.2 Dokumentation und Protokollierung</h3>\r\n<ul data-start=\"4509\" data-end=\"4687\">\r\n<li data-start=\"4509\" data-end=\"4596\">\r\n<p data-start=\"4511\" data-end=\"4596\">Der Austrittsprozess wird durch HR und IT begleitet und <strong data-start=\"4567\" data-end=\"4595\">vollst&auml;ndig dokumentiert</strong>.</p>\r\n</li>\r\n<li data-start=\"4597\" data-end=\"4687\">\r\n<p data-start=\"4599\" data-end=\"4687\">Zugangsrechte und E-Mail-Konten werden <strong data-start=\"4638\" data-end=\"4686\">fristgerecht deaktiviert oder weitergeleitet</strong>.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4689\" data-end=\"4692\">\r\n<h2 data-start=\"4694\" data-end=\"4724\"><strong data-start=\"4697\" data-end=\"4724\">7. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4726\" data-end=\"5295\">\r\n<thead data-start=\"4726\" data-end=\"4766\">\r\n<tr data-start=\"4726\" data-end=\"4766\">\r\n<th data-start=\"4726\" data-end=\"4754\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"4754\" data-end=\"4766\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4808\" data-end=\"5295\">\r\n<tr data-start=\"4808\" data-end=\"4909\">\r\n<td data-start=\"4808\" data-end=\"4837\" data-col-size=\"sm\"><strong data-start=\"4810\" data-end=\"4836\">Personalabteilung (HR)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4837\" data-end=\"4909\">Koordination des Onboardings / Offboardings, Schulungen organisieren</td>\r\n</tr>\r\n<tr data-start=\"4910\" data-end=\"5012\">\r\n<td data-start=\"4910\" data-end=\"4939\" data-col-size=\"sm\"><strong data-start=\"4912\" data-end=\"4928\">IT-Abteilung</strong></td>\r\n<td data-start=\"4939\" data-end=\"5012\" data-col-size=\"md\">Bereitstellung und Entzug von Zug&auml;ngen, Verwaltung der Zugriffsrechte</td>\r\n</tr>\r\n<tr data-start=\"5013\" data-end=\"5121\">\r\n<td data-start=\"5013\" data-end=\"5053\" data-col-size=\"sm\"><strong data-start=\"5015\" data-end=\"5052\">ISB / IT-Sicherheitsbeauftragte*r</strong></td>\r\n<td data-start=\"5053\" data-end=\"5121\" data-col-size=\"md\">Schulungskonzepte, Kontrolle sicherheitsrelevanter Anforderungen</td>\r\n</tr>\r\n<tr data-start=\"5122\" data-end=\"5202\">\r\n<td data-start=\"5122\" data-end=\"5151\" data-col-size=\"sm\"><strong data-start=\"5124\" data-end=\"5142\">F&uuml;hrungskr&auml;fte</strong></td>\r\n<td data-start=\"5151\" data-end=\"5202\" data-col-size=\"md\">Umsetzung der Vorgaben im Team, Vorbildfunktion</td>\r\n</tr>\r\n<tr data-start=\"5203\" data-end=\"5295\">\r\n<td data-start=\"5203\" data-end=\"5232\" data-col-size=\"sm\"><strong data-start=\"5205\" data-end=\"5228\">Alle Mitarbeitenden</strong></td>\r\n<td data-start=\"5232\" data-end=\"5295\" data-col-size=\"md\">Einhaltung der Sicherheitsrichtlinien, Melden von Vorf&auml;llen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5297\" data-end=\"5300\">\r\n<h2 data-start=\"5302\" data-end=\"5349\"><strong data-start=\"5305\" data-end=\"5349\">8. Schnittstellen zu anderen Richtlinien</strong></h2>\r\n<p data-start=\"5351\" data-end=\"5394\">Diese Richtlinie steht im Zusammenhang mit:</p>\r\n<ul data-start=\"5396\" data-end=\"5643\">\r\n<li data-start=\"5396\" data-end=\"5435\">\r\n<p data-start=\"5398\" data-end=\"5435\"><strong data-start=\"5398\" data-end=\"5435\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"5436\" data-end=\"5488\">\r\n<p data-start=\"5438\" data-end=\"5488\"><strong data-start=\"5438\" data-end=\"5488\">Zugriffsrichtlinie / Rollen- und Rechtekonzept</strong></p>\r\n</li>\r\n<li data-start=\"5489\" data-end=\"5546\">\r\n<p data-start=\"5491\" data-end=\"5546\"><strong data-start=\"5491\" data-end=\"5546\">Richtlinie zur Nutzung von IT-Systemen und Internet</strong></p>\r\n</li>\r\n<li data-start=\"5547\" data-end=\"5615\">\r\n<p data-start=\"5549\" data-end=\"5615\"><strong data-start=\"5549\" data-end=\"5615\">Richtlinie zum sicheren Arbeiten im Homeoffice / Remote-Arbeit</strong></p>\r\n</li>\r\n<li data-start=\"5616\" data-end=\"5643\">\r\n<p data-start=\"5618\" data-end=\"5643\"><strong data-start=\"5618\" data-end=\"5643\">Datenschutzrichtlinie</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5645\" data-end=\"5648\">\r\n<h2 data-start=\"5650\" data-end=\"5701\"><strong data-start=\"5653\" data-end=\"5701\">9. Bezug zu ISO 27001 und BSI IT-Grundschutz</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5703\" data-end=\"6070\">\r\n<thead data-start=\"5703\" data-end=\"5731\">\r\n<tr data-start=\"5703\" data-end=\"5731\">\r\n<th data-start=\"5703\" data-end=\"5721\" data-col-size=\"md\">Norm / Ma&szlig;nahme</th>\r\n<th data-start=\"5721\" data-end=\"5731\" data-col-size=\"md\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5761\" data-end=\"6070\">\r\n<tr data-start=\"5761\" data-end=\"5861\">\r\n<td data-start=\"5761\" data-end=\"5803\" data-col-size=\"md\"><strong data-start=\"5763\" data-end=\"5802\">ISO/IEC 27001 &ndash; A.6.1.1 bis A.6.1.3</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5803\" data-end=\"5861\">Verantwortlichkeiten, Schulungen, Disziplinarma&szlig;nahmen</td>\r\n</tr>\r\n<tr data-start=\"5862\" data-end=\"5973\">\r\n<td data-start=\"5862\" data-end=\"5911\" data-col-size=\"md\"><strong data-start=\"5864\" data-end=\"5910\">BSI IT-Grundschutz &ndash; ORP.1, ORP.3, ORP.4.1</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5911\" data-end=\"5973\">Sicherheitsorganisation, Sensibilisierung, Personaleinsatz</td>\r\n</tr>\r\n<tr data-start=\"5974\" data-end=\"6070\">\r\n<td data-start=\"5974\" data-end=\"6004\" data-col-size=\"md\"><strong data-start=\"5976\" data-end=\"6003\">EU-DSGVO Art. 5, 32, 28</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6004\" data-end=\"6070\">Datenschutz, Auftragsverarbeitung, Sicherheit der Verarbeitung</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(10, 'DOK-0010', 'Akzeptable Nutzung', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"719\" data-end=\"749\"><strong data-start=\"722\" data-end=\"749\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"751\" data-end=\"1057\">Diese Richtlinie definiert die zul&auml;ssige und unzul&auml;ssige Nutzung der IT-Ressourcen der Organisation. Ziel ist es, <strong data-start=\"865\" data-end=\"924\">die Sicherheit von Informationen und Systemen zu wahren</strong>, <strong data-start=\"926\" data-end=\"954\">Missbrauch zu verhindern</strong> und ein <strong data-start=\"963\" data-end=\"1019\">rechtssicheres und verantwortungsbewusstes Verhalten</strong> im Umgang mit IT-Systemen zu f&ouml;rdern.</p>\r\n<hr data-start=\"1059\" data-end=\"1062\">\r\n<h2 data-start=\"1064\" data-end=\"1089\"><strong data-start=\"1067\" data-end=\"1089\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1091\" data-end=\"1117\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1119\" data-end=\"1469\">\r\n<li data-start=\"1119\" data-end=\"1232\">\r\n<p data-start=\"1121\" data-end=\"1232\"><strong data-start=\"1121\" data-end=\"1144\">Alle Mitarbeitenden</strong>, F&uuml;hrungskr&auml;fte, Aushilfen und Dritte (z. B. externe Berater), die IT-Ressourcen nutzen</p>\r\n</li>\r\n<li data-start=\"1233\" data-end=\"1398\">\r\n<p data-start=\"1235\" data-end=\"1398\"><strong data-start=\"1235\" data-end=\"1250\">Alle Ger&auml;te</strong>, Systeme, Anwendungen und Dienste, die im Eigentum oder unter Kontrolle der Organisation stehen oder f&uuml;r gesch&auml;ftliche Zwecke bereitgestellt werden</p>\r\n</li>\r\n<li data-start=\"1399\" data-end=\"1469\">\r\n<p data-start=\"1401\" data-end=\"1469\"><strong data-start=\"1401\" data-end=\"1423\">Alle Nutzungsarten</strong>: intern, mobil, im Homeoffice oder auf Reisen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1471\" data-end=\"1474\">\r\n<h2 data-start=\"1476\" data-end=\"1510\"><strong data-start=\"1479\" data-end=\"1510\">3. Definition IT-Ressourcen</strong></h2>\r\n<p data-start=\"1512\" data-end=\"1568\">IT-Ressourcen im Sinne dieser Richtlinie umfassen u. a.:</p>\r\n<ul data-start=\"1570\" data-end=\"1845\">\r\n<li data-start=\"1570\" data-end=\"1624\">\r\n<p data-start=\"1572\" data-end=\"1624\">Arbeitsplatzrechner, Laptops, Mobiltelefone, Tablets</p>\r\n</li>\r\n<li data-start=\"1625\" data-end=\"1670\">\r\n<p data-start=\"1627\" data-end=\"1670\">Netzwerke (LAN, WLAN, VPN), Internetzug&auml;nge</p>\r\n</li>\r\n<li data-start=\"1671\" data-end=\"1711\">\r\n<p data-start=\"1673\" data-end=\"1711\">E-Mail, Messaging, Collaboration Tools</p>\r\n</li>\r\n<li data-start=\"1712\" data-end=\"1755\">\r\n<p data-start=\"1714\" data-end=\"1755\">Fachanwendungen, ERP-Systeme, Datenbanken</p>\r\n</li>\r\n<li data-start=\"1756\" data-end=\"1801\">\r\n<p data-start=\"1758\" data-end=\"1801\">Speicherorte (Netzlaufwerke, Cloud-Dienste)</p>\r\n</li>\r\n<li data-start=\"1802\" data-end=\"1845\">\r\n<p data-start=\"1804\" data-end=\"1845\">Zugangsdaten, Benutzerkonten, Zertifikate</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1847\" data-end=\"1850\">\r\n<h2 data-start=\"1852\" data-end=\"1884\"><strong data-start=\"1855\" data-end=\"1884\">4. Grunds&auml;tze der Nutzung</strong></h2>\r\n<ul data-start=\"1886\" data-end=\"2307\">\r\n<li data-start=\"1886\" data-end=\"1946\">\r\n<p data-start=\"1888\" data-end=\"1946\">IT-Ressourcen dienen <strong data-start=\"1909\" data-end=\"1945\">vorrangig gesch&auml;ftlichen Zwecken</strong>.</p>\r\n</li>\r\n<li data-start=\"1947\" data-end=\"2056\">\r\n<p data-start=\"1949\" data-end=\"2056\">Nutzer sind verpflichtet, <strong data-start=\"1975\" data-end=\"2022\">vertraulich, integer und verantwortungsvoll</strong> mit Systemen und Daten umzugehen.</p>\r\n</li>\r\n<li data-start=\"2057\" data-end=\"2217\">\r\n<p data-start=\"2059\" data-end=\"2217\">Die Organisation beh&auml;lt sich das Recht vor, <strong data-start=\"2103\" data-end=\"2160\">Nutzungsverhalten zu &uuml;berwachen und zu protokollieren</strong> (unter Beachtung der geltenden Datenschutzbestimmungen).</p>\r\n</li>\r\n<li data-start=\"2218\" data-end=\"2307\">\r\n<p data-start=\"2220\" data-end=\"2307\">Verst&ouml;&szlig;e gegen diese Richtlinie k&ouml;nnen <strong data-start=\"2259\" data-end=\"2289\">disziplinarische Ma&szlig;nahmen</strong> nach sich ziehen.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2309\" data-end=\"2312\">\r\n<h2 data-start=\"2314\" data-end=\"2341\"><strong data-start=\"2317\" data-end=\"2341\">5. Zul&auml;ssige Nutzung</strong></h2>\r\n<p data-start=\"2343\" data-end=\"2379\">Die zul&auml;ssige Nutzung umfasst u. a.:</p>\r\n<ul data-start=\"2381\" data-end=\"2843\">\r\n<li data-start=\"2381\" data-end=\"2447\">\r\n<p data-start=\"2383\" data-end=\"2447\">Verwendung von IT-Ressourcen zur Erf&uuml;llung dienstlicher Aufgaben</p>\r\n</li>\r\n<li data-start=\"2448\" data-end=\"2535\">\r\n<p data-start=\"2450\" data-end=\"2535\">Kommunikation mit Kolleg*innen, Kunden, Partnern &uuml;ber freigegebene Kommunikationswege</p>\r\n</li>\r\n<li data-start=\"2536\" data-end=\"2584\">\r\n<p data-start=\"2538\" data-end=\"2584\">Nutzung genehmigter Software und Cloud-Dienste</p>\r\n</li>\r\n<li data-start=\"2585\" data-end=\"2843\">\r\n<p data-start=\"2587\" data-end=\"2667\"><strong data-start=\"2587\" data-end=\"2621\">Eingeschr&auml;nkte private Nutzung</strong> (z. B. E-Mail, Internet) ist erlaubt, sofern:</p>\r\n<ul data-start=\"2670\" data-end=\"2843\">\r\n<li data-start=\"2670\" data-end=\"2707\">\r\n<p data-start=\"2672\" data-end=\"2707\">dies in angemessenem Umfang erfolgt</p>\r\n</li>\r\n<li data-start=\"2710\" data-end=\"2759\">\r\n<p data-start=\"2712\" data-end=\"2759\">dienstliche Belange nicht beeintr&auml;chtigt werden</p>\r\n</li>\r\n<li data-start=\"2762\" data-end=\"2799\">\r\n<p data-start=\"2764\" data-end=\"2799\">keine zus&auml;tzlichen Kosten entstehen</p>\r\n</li>\r\n<li data-start=\"2802\" data-end=\"2843\">\r\n<p data-start=\"2804\" data-end=\"2843\">keine Sicherheitsrisiken erzeugt werden</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p data-start=\"2845\" data-end=\"2917\">Die Erlaubnis zur privaten Nutzung kann <strong data-start=\"2885\" data-end=\"2909\">jederzeit widerrufen</strong> werden.</p>\r\n<hr data-start=\"2919\" data-end=\"2922\">\r\n<h2 data-start=\"2924\" data-end=\"2953\"><strong data-start=\"2927\" data-end=\"2953\">6. Unzul&auml;ssige Nutzung</strong></h2>\r\n<p data-start=\"2955\" data-end=\"3050\">Folgende Nutzungen sind <strong data-start=\"2979\" data-end=\"2991\">verboten</strong>, unabh&auml;ngig davon, ob sie privat oder dienstlich erfolgen:</p>\r\n<ul data-start=\"3052\" data-end=\"3826\">\r\n<li data-start=\"3052\" data-end=\"3130\">\r\n<p data-start=\"3054\" data-end=\"3130\">Nutzung illegaler, urheberrechtsverletzender oder jugendgef&auml;hrdender Inhalte</p>\r\n</li>\r\n<li data-start=\"3131\" data-end=\"3199\">\r\n<p data-start=\"3133\" data-end=\"3199\">Installation oder Nutzung nicht genehmigter Software (&bdquo;Shadow IT&ldquo;)</p>\r\n</li>\r\n<li data-start=\"3200\" data-end=\"3289\">\r\n<p data-start=\"3202\" data-end=\"3289\">Umgehung technischer Sicherheitsmechanismen (z. B. Firewalls, Virenschutz, Richtlinien)</p>\r\n</li>\r\n<li data-start=\"3290\" data-end=\"3343\">\r\n<p data-start=\"3292\" data-end=\"3343\">Ver&auml;nderung von Systemkonfigurationen ohne Freigabe</p>\r\n</li>\r\n<li data-start=\"3344\" data-end=\"3427\">\r\n<p data-start=\"3346\" data-end=\"3427\">Nutzung von Tools zum anonymen Surfen oder Verschleiern der Identit&auml;t (z. B. Tor)</p>\r\n</li>\r\n<li data-start=\"3428\" data-end=\"3519\">\r\n<p data-start=\"3430\" data-end=\"3519\">&Uuml;bertragung vertraulicher Informationen &uuml;ber unsichere Kan&auml;le (z. B. private Maildienste)</p>\r\n</li>\r\n<li data-start=\"3520\" data-end=\"3623\">\r\n<p data-start=\"3522\" data-end=\"3623\">Nutzung pers&ouml;nlicher Cloud-Dienste (Dropbox, Google Drive, etc.), sofern nicht ausdr&uuml;cklich genehmigt</p>\r\n</li>\r\n<li data-start=\"3624\" data-end=\"3718\">\r\n<p data-start=\"3626\" data-end=\"3718\">Ver&ouml;ffentlichung gesch&auml;ftsinterner Informationen in sozialen Medien oder Foren ohne Freigabe</p>\r\n</li>\r\n<li data-start=\"3719\" data-end=\"3826\">\r\n<p data-start=\"3721\" data-end=\"3826\">Verwendung von IT-Ressourcen zur Verbreitung beleidigender, diskriminierender oder rechtswidriger Inhalte</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3828\" data-end=\"3831\">\r\n<h2 data-start=\"3833\" data-end=\"3866\"><strong data-start=\"3836\" data-end=\"3866\">7. Schutz von Zugangsdaten</strong></h2>\r\n<ul data-start=\"3868\" data-end=\"4220\">\r\n<li data-start=\"3868\" data-end=\"3956\">\r\n<p data-start=\"3870\" data-end=\"3956\">Passw&ouml;rter sind <strong data-start=\"3886\" data-end=\"3914\">vertraulich zu behandeln</strong> und d&uuml;rfen <strong data-start=\"3926\" data-end=\"3949\">nicht weitergegeben</strong> werden</p>\r\n</li>\r\n<li data-start=\"3957\" data-end=\"4072\">\r\n<p data-start=\"3959\" data-end=\"4072\">Passw&ouml;rter m&uuml;ssen den <strong data-start=\"3981\" data-end=\"4026\">organisationsweit definierten Richtlinien</strong> (z. B. Mindestl&auml;nge, Komplexit&auml;t) entsprechen</p>\r\n</li>\r\n<li data-start=\"4073\" data-end=\"4158\">\r\n<p data-start=\"4075\" data-end=\"4158\">Zwei-Faktor-Authentifizierung (2FA) ist, wo vorgesehen, <strong data-start=\"4131\" data-end=\"4158\">verpflichtend zu nutzen</strong></p>\r\n</li>\r\n<li data-start=\"4159\" data-end=\"4220\">\r\n<p data-start=\"4161\" data-end=\"4220\">Bei Verdacht auf Missbrauch sind Zug&auml;nge umgehend zu melden</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4222\" data-end=\"4225\">\r\n<h2 data-start=\"4227\" data-end=\"4266\"><strong data-start=\"4230\" data-end=\"4266\">8. Umgang mit Ger&auml;ten und Medien</strong></h2>\r\n<ul data-start=\"4268\" data-end=\"4644\">\r\n<li data-start=\"4268\" data-end=\"4367\">\r\n<p data-start=\"4270\" data-end=\"4367\">Mobile Ger&auml;te m&uuml;ssen bei Verlust, Diebstahl oder Verdacht auf Manipulation sofort gemeldet werden</p>\r\n</li>\r\n<li data-start=\"4368\" data-end=\"4441\">\r\n<p data-start=\"4370\" data-end=\"4441\">Ger&auml;te sind bei Verlassen des Arbeitsplatzes zu sperren oder zu sichern</p>\r\n</li>\r\n<li data-start=\"4442\" data-end=\"4563\">\r\n<p data-start=\"4444\" data-end=\"4563\">Wechselmedien (USB-Sticks etc.) d&uuml;rfen nur genutzt werden, wenn sie <strong data-start=\"4512\" data-end=\"4558\">organisationskonform gepr&uuml;ft / freigegeben</strong> sind</p>\r\n</li>\r\n<li data-start=\"4564\" data-end=\"4644\">\r\n<p data-start=\"4566\" data-end=\"4644\">Keine Speicherung sensibler Daten auf privaten Ger&auml;ten oder ungepr&uuml;ften Medien</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4646\" data-end=\"4649\">\r\n<h2 data-start=\"4651\" data-end=\"4687\"><strong data-start=\"4654\" data-end=\"4687\">9. Internetnutzung und E-Mail</strong></h2>\r\n<ul data-start=\"4689\" data-end=\"5007\">\r\n<li data-start=\"4689\" data-end=\"4755\">\r\n<p data-start=\"4691\" data-end=\"4755\">E-Mail-Anh&auml;nge sind nur aus vertrauensw&uuml;rdigen Quellen zu &ouml;ffnen</p>\r\n</li>\r\n<li data-start=\"4756\" data-end=\"4825\">\r\n<p data-start=\"4758\" data-end=\"4825\">Verd&auml;chtige E-Mails (Phishing, Malware) sind unverz&uuml;glich zu melden</p>\r\n</li>\r\n<li data-start=\"4826\" data-end=\"4938\">\r\n<p data-start=\"4828\" data-end=\"4938\">Internetnutzung darf den <strong data-start=\"4853\" data-end=\"4886\">Betrieb nicht beeintr&auml;chtigen</strong> (z. B. durch Streaming, Downloads, Bandbreitenlast)</p>\r\n</li>\r\n<li data-start=\"4939\" data-end=\"5007\">\r\n<p data-start=\"4941\" data-end=\"5007\">Webfilter und Sicherheitsl&ouml;sungen d&uuml;rfen <strong data-start=\"4982\" data-end=\"5000\">nicht umgangen</strong> werden</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5009\" data-end=\"5012\">\r\n<h2 data-start=\"5014\" data-end=\"5054\"><strong data-start=\"5017\" data-end=\"5054\">10. Protokollierung und Kontrolle</strong></h2>\r\n<ul data-start=\"5056\" data-end=\"5406\">\r\n<li data-start=\"5056\" data-end=\"5166\">\r\n<p data-start=\"5058\" data-end=\"5166\">Zugriffe auf zentrale Systeme, vertrauliche Daten und sicherheitsrelevante Aktionen werden <strong data-start=\"5149\" data-end=\"5166\">protokolliert</strong></p>\r\n</li>\r\n<li data-start=\"5167\" data-end=\"5234\">\r\n<p data-start=\"5169\" data-end=\"5234\">Die Organisation f&uuml;hrt regelm&auml;&szlig;ige <strong data-start=\"5204\" data-end=\"5228\">Stichprobenpr&uuml;fungen</strong> durch</p>\r\n</li>\r\n<li data-start=\"5235\" data-end=\"5303\">\r\n<p data-start=\"5237\" data-end=\"5303\">&Uuml;berwachung erfolgt im Rahmen der gesetzlichen Datenschutzvorgaben</p>\r\n</li>\r\n<li data-start=\"5304\" data-end=\"5406\">\r\n<p data-start=\"5306\" data-end=\"5406\">Die IT-Abteilung kann Ger&auml;te und Logs analysieren bei konkretem Verdacht oder im Rahmen eines Audits</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5408\" data-end=\"5411\">\r\n<h2 data-start=\"5413\" data-end=\"5450\"><strong data-start=\"5416\" data-end=\"5450\">11. Konsequenzen bei Verst&ouml;&szlig;en</strong></h2>\r\n<ul data-start=\"5452\" data-end=\"5673\">\r\n<li data-start=\"5452\" data-end=\"5673\">\r\n<p data-start=\"5454\" data-end=\"5541\">Verst&ouml;&szlig;e gegen diese Richtlinie k&ouml;nnen je nach Schweregrad folgende Konsequenzen haben:</p>\r\n<ul data-start=\"5544\" data-end=\"5673\">\r\n<li data-start=\"5544\" data-end=\"5555\">\r\n<p data-start=\"5546\" data-end=\"5555\">Abmahnung</p>\r\n</li>\r\n<li data-start=\"5558\" data-end=\"5581\">\r\n<p data-start=\"5560\" data-end=\"5581\">Sperrung von Zug&auml;ngen</p>\r\n</li>\r\n<li data-start=\"5584\" data-end=\"5620\">\r\n<p data-start=\"5586\" data-end=\"5620\">K&uuml;ndigung des Arbeitsverh&auml;ltnisses</p>\r\n</li>\r\n<li data-start=\"5623\" data-end=\"5673\">\r\n<p data-start=\"5625\" data-end=\"5673\">Strafrechtliche Schritte bei relevanten Delikten</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5675\" data-end=\"5678\">\r\n<h2 data-start=\"5680\" data-end=\"5717\"><strong data-start=\"5683\" data-end=\"5717\">12. Schulung und Verpflichtung</strong></h2>\r\n<ul data-start=\"5719\" data-end=\"5992\">\r\n<li data-start=\"5719\" data-end=\"5828\">\r\n<p data-start=\"5721\" data-end=\"5828\">Alle Nutzer m&uuml;ssen bei Eintritt in die Organisation <strong data-start=\"5773\" data-end=\"5828\">diese Richtlinie zur Kenntnis nehmen und best&auml;tigen</strong></p>\r\n</li>\r\n<li data-start=\"5829\" data-end=\"5926\">\r\n<p data-start=\"5831\" data-end=\"5926\">Regelm&auml;&szlig;ige Awareness-Schulungen und Sicherheitsunterweisungen erfolgen mindestens <strong data-start=\"5914\" data-end=\"5926\">j&auml;hrlich</strong></p>\r\n</li>\r\n<li data-start=\"5927\" data-end=\"5992\">\r\n<p data-start=\"5929\" data-end=\"5992\">Bei &Auml;nderungen der Richtlinie erfolgt eine erneute Unterweisung</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5994\" data-end=\"5997\">\r\n<h2 data-start=\"5999\" data-end=\"6048\"><strong data-start=\"6002\" data-end=\"6048\">13. Schnittstellen zu weiteren Richtlinien</strong></h2>\r\n<p data-start=\"6050\" data-end=\"6097\">Diese Richtlinie ist Teil des ISMS und erg&auml;nzt:</p>\r\n<ul data-start=\"6099\" data-end=\"6293\">\r\n<li data-start=\"6099\" data-end=\"6138\">\r\n<p data-start=\"6101\" data-end=\"6138\"><strong data-start=\"6101\" data-end=\"6138\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6139\" data-end=\"6177\">\r\n<p data-start=\"6141\" data-end=\"6177\"><strong data-start=\"6141\" data-end=\"6177\">Zugriffs- und Passwortrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6178\" data-end=\"6228\">\r\n<p data-start=\"6180\" data-end=\"6228\"><strong data-start=\"6180\" data-end=\"6228\">Mobile-Device-Policy / Homeoffice-Richtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6229\" data-end=\"6256\">\r\n<p data-start=\"6231\" data-end=\"6256\"><strong data-start=\"6231\" data-end=\"6256\">Datenschutzrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6257\" data-end=\"6293\">\r\n<p data-start=\"6259\" data-end=\"6293\"><strong data-start=\"6259\" data-end=\"6293\">Incident-Management-Richtlinie</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6295\" data-end=\"6298\">\r\n<h2 data-start=\"6300\" data-end=\"6340\"><strong data-start=\"6303\" data-end=\"6340\">14. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6342\" data-end=\"6746\">\r\n<thead data-start=\"6342\" data-end=\"6398\">\r\n<tr data-start=\"6342\" data-end=\"6398\">\r\n<th data-start=\"6342\" data-end=\"6377\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6377\" data-end=\"6398\" data-col-size=\"sm\">Relevante Aspekte</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6457\" data-end=\"6746\">\r\n<tr data-start=\"6457\" data-end=\"6525\">\r\n<td data-start=\"6457\" data-end=\"6492\" data-col-size=\"sm\"><strong data-start=\"6459\" data-end=\"6485\">ISO/IEC 27001 &ndash; A.5.10</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"6492\" data-end=\"6525\">Akzeptables Nutzungsverhalten</td>\r\n</tr>\r\n<tr data-start=\"6526\" data-end=\"6599\">\r\n<td data-start=\"6526\" data-end=\"6561\" data-col-size=\"sm\"><strong data-start=\"6528\" data-end=\"6555\">ISO/IEC 27001 &ndash; A.9.2.3</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"6561\" data-end=\"6599\">Verwaltung privilegierter Zugriffe</td>\r\n</tr>\r\n<tr data-start=\"6600\" data-end=\"6676\">\r\n<td data-start=\"6600\" data-end=\"6641\" data-col-size=\"sm\"><strong data-start=\"6602\" data-end=\"6640\">BSI IT-Grundschutz: ORP.3, SYS.1.2</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"6641\" data-end=\"6676\">Sichere Nutzung von IT-Systemen</td>\r\n</tr>\r\n<tr data-start=\"6677\" data-end=\"6746\">\r\n<td data-start=\"6677\" data-end=\"6712\" data-col-size=\"sm\"><strong data-start=\"6679\" data-end=\"6695\">DSGVO / BDSG</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"6712\" data-end=\"6746\">Schutz personenbezogener Daten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(11, 'DOK-0011', 'Zugriffsmanagement', 'Richtlinien', '1', 0, 'öffentlich', '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Diese Richtlinie definiert die Anforderungen und Verfahren zur <strong>Verwaltung von Benutzerzugriffen</strong> auf IT-Systeme, Anwendungen und Daten, um <strong>unbefugten Zugriff zu verhindern</strong> und die <strong>Integrität, Vertraulichkeit und Verfügbarkeit</strong> der Informationen sicherzustellen.</p>\n<hr/>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Diese Richtlinie gilt für:</p>\n<ul>\n<li>\n<p><strong>Alle IT-Systeme</strong>, Anwendungen, Datenbanken, Netzwerke, Cloud-Dienste</p>\n</li>\n<li>\n<p><strong>Alle Benutzer</strong>: interne Mitarbeitende, Externe, Partner, Dienstleister</p>\n</li>\n<li>\n<p><strong>Alle Rollen und Zugriffsebenen</strong> – vom normalen User bis zum Administrator</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Grundsätze des Zugriffsmanagements</strong></h2>\n<ul>\n<li>\n<p><strong>Zugriff nur nach dem Need-to-Know- und Least-Privilege-Prinzip</strong></p>\n</li>\n<li>\n<p><strong>Jeder Zugriff muss autorisiert, dokumentiert und überprüfbar</strong> sein</p>\n</li>\n<li>\n<p>Zugriffsrechte sind an <strong>Rollen und Funktionen</strong> gebunden, nicht an Personen</p>\n</li>\n<li>\n<p><strong>Privilegierte Zugänge</strong> unterliegen besonderen Schutz- und Prüfpflichten</p>\n</li>\n<li>\n<p>Alle Benutzer müssen eindeutig identifizierbar und nachvollziehbar sein</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>4. Rollen und Verantwortlichkeiten</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>IT-Abteilung</strong></td>\n<td>Einrichtung, Änderung und Löschung von Benutzerkonten</td>\n</tr>\n<tr>\n<td><strong>ISB</strong></td>\n<td>Prüfung sicherheitsrelevanter Anforderungen</td>\n</tr>\n<tr>\n<td><strong>HR / Fachbereiche</strong></td>\n<td>Meldung von Eintritt, Änderung, Austritt</td>\n</tr>\n<tr>\n<td><strong>Führungskräfte</strong></td>\n<td>Genehmigung von Zugriffen auf Fachanwendungen</td>\n</tr>\n<tr>\n<td><strong>Alle Nutzer*innen</strong></td>\n<td>Sorgfältiger Umgang mit Zugangsdaten, sofortiges Melden von Auffälligkeiten</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>5. Benutzeridentifikation und -authentifizierung</strong></h2>\n<ul>\n<li>\n<p>Jeder Benutzer erhält <strong>ein persönliches Benutzerkonto</strong></p>\n</li>\n<li>\n<p>Gemeinsame Konten sind <strong>verboten</strong>, außer in technisch begründeten Sonderfällen mit dokumentierter Freigabe</p>\n</li>\n<li>\n<p><strong>Authentifizierung</strong> erfolgt mindestens per Benutzername + Passwort, bei erhöhtem Schutzbedarf mit <strong>2-Faktor-Authentifizierung (2FA)</strong></p>\n</li>\n<li>\n<p>Passwörter unterliegen der <strong>Passwortrichtlinie</strong> (z. B. Komplexität, Änderung, Speicherung)</p>\n</li>\n<li>\n<p>Technische Benutzerkonten (z. B. Dienstkonten, Schnittstellenkonten) sind gesondert zu verwalten</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>6. Zugriffskontrolle auf Systeme und Daten</strong></h2>\n<h3>6.1 Rechtevergabe</h3>\n<ul>\n<li>\n<p>Zugriff erfolgt <strong>rollenbasiert</strong> (Role-Based Access Control, RBAC)</p>\n</li>\n<li>\n<p>Fachbereichsverantwortliche genehmigen Rechtevergabe</p>\n</li>\n<li>\n<p>Neue Zugänge werden <strong>nur auf schriftlichen oder systemgestützten Antrag</strong> vergeben (z. B. ITSM-Ticketsystem)</p>\n</li>\n</ul>\n<h3>6.2 Änderung und Entzug von Rechten</h3>\n<ul>\n<li>\n<p>Änderungen erfolgen bei:</p>\n<ul>\n<li>\n<p>Wechsel der Rolle oder Abteilung</p>\n</li>\n<li>\n<p>temporären Projekten</p>\n</li>\n<li>\n<p>sicherheitsrelevanten Ereignissen</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Entzug von Rechten:</p>\n<ul>\n<li>\n<p><strong>Sofort bei Austritt</strong></p>\n</li>\n<li>\n<p>Dokumentiert durch HR / IT / Vorgesetzte</p>\n</li>\n</ul>\n</li>\n</ul>\n<h3>6.3 Rechteprüfung</h3>\n<ul>\n<li>\n<p>Regelmäßige <strong>Re-Zertifizierung der Rechte</strong> mindestens einmal jährlich</p>\n</li>\n<li>\n<p>Führungskräfte / Fachbereiche prüfen und bestätigen die Notwendigkeit von Berechtigungen</p>\n</li>\n<li>\n<p>Ergebnisse werden dokumentiert</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>7. Besondere Zugriffstypen</strong></h2>\n<h3>7.1 Administrativer Zugriff</h3>\n<ul>\n<li>\n<p>Admin-Rechte sind auf <strong>ein Minimum an Personen</strong> zu beschränken</p>\n</li>\n<li>\n<p>Separate <strong>Admin-Konten</strong> (nicht identisch mit Standard-Benutzerkonten)</p>\n</li>\n<li>\n<p>Alle administrativen Aktivitäten sind zu <strong>protokollieren und zu überwachen</strong></p>\n</li>\n</ul>\n<h3>7.2 Externe Zugriffe / Fernzugriffe</h3>\n<ul>\n<li>\n<p>Nur über <strong>sichere Verbindungen</strong> (z. B. VPN, TLS, Remote Desktop Gateway)</p>\n</li>\n<li>\n<p>Zugänge für externe Partner sind <strong>zeitlich befristet</strong> und regelmäßig zu prüfen</p>\n</li>\n<li>\n<p>Fernzugriffe auf sensible Systeme sind nur mit <strong>2FA und Logging</strong> erlaubt</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Logging und Monitoring</strong></h2>\n<ul>\n<li>\n<p>Alle sicherheitsrelevanten Zugriffe (Admin, Datenschutz-relevant, Kritische Daten) werden <strong>protokolliert</strong></p>\n</li>\n<li>\n<p>Protokolle sind <strong>vor Manipulation zu schützen</strong> und regelmäßig auszuwerten</p>\n</li>\n<li>\n<p>Verdächtige Zugriffsmuster führen zu <strong>Sicherheitsvorfällen gemäß Incident-Management</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Schutz von Zugangsdaten</strong></h2>\n<ul>\n<li>\n<p>Benutzer sind verpflichtet:</p>\n<ul>\n<li>\n<p>Zugangsdaten geheim zu halten</p>\n</li>\n<li>\n<p>Passwörter nicht weiterzugeben</p>\n</li>\n<li>\n<p>Verdachtsfälle sofort zu melden</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Speicherung von Passwörtern nur in <strong>zugelassenen Passwortmanagern</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Deaktivierung und Löschung von Zugängen</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Anlass</th>\n<th>Maßnahme</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Mitarbeiter*innen-Austritt</td>\n<td>Sperrung am letzten Arbeitstag</td>\n</tr>\n<tr>\n<td>Projektende</td>\n<td>Löschung temporärer Rechte</td>\n</tr>\n<tr>\n<td>Inaktivität</td>\n<td>Automatische Deaktivierung nach 90 Tagen</td>\n</tr>\n<tr>\n<td>Missbrauchsverdacht</td>\n<td>Sofortige Sperrung durch IT-Sicherheit</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>11. Schnittstellen zu weiteren Richtlinien</strong></h2>\n<p>Diese Richtlinie ergänzt:</p>\n<ul>\n<li>\n<p><strong>Informationssicherheitsrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>Passwortrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>Personalsicherheitsrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>Incident-Management-Richtlinie</strong></p>\n</li>\n<li>\n<p><strong>Asset-Management-Richtlinie</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>12. Bezug zu Normen und Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Relevante Kapitel</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001</strong></td>\n<td>A.5.15, A.9.1–A.9.4 – Zugriffsrechte, Benutzerzugriffe, System- und Netzwerkzugriffe</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>ORP.4.1, SYS.1.2, OPS.1.2.4, APP.3.1</td>\n</tr>\n<tr>\n<td><strong>EU-DSGVO</strong></td>\n<td>Art. 32 – Zugriffsschutz personenbezogener Daten</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-02-17', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 1, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(12, 'DOK-0012', 'Security Incident Management', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"816\" data-end=\"846\"><strong data-start=\"819\" data-end=\"846\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"848\" data-end=\"1094\">Ziel dieser Richtlinie ist es, einheitliche Vorgaben f&uuml;r die <strong data-start=\"909\" data-end=\"998\">Erkennung, Meldung, Behandlung und Dokumentation von Informationssicherheitsvorf&auml;llen</strong> zu schaffen, um Sch&auml;den zu minimieren, Ursachen zu analysieren und Wiederholungen zu vermeiden.</p>\r\n<hr data-start=\"1096\" data-end=\"1099\">\r\n<h2 data-start=\"1101\" data-end=\"1126\"><strong data-start=\"1104\" data-end=\"1126\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1128\" data-end=\"1154\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1156\" data-end=\"1497\">\r\n<li data-start=\"1156\" data-end=\"1282\">\r\n<p data-start=\"1158\" data-end=\"1282\"><strong data-start=\"1158\" data-end=\"1181\">Alle Mitarbeitenden</strong>, Dienstleister und externen Partner, die IT-Ressourcen nutzen oder Zugriff auf Informationen haben</p>\r\n</li>\r\n<li data-start=\"1283\" data-end=\"1395\">\r\n<p data-start=\"1285\" data-end=\"1395\"><strong data-start=\"1285\" data-end=\"1317\">Alle Systeme und Anwendungen</strong> innerhalb der Organisation (inkl. Cloud-Dienste, Netzwerke, Endger&auml;te etc.)</p>\r\n</li>\r\n<li data-start=\"1396\" data-end=\"1497\">\r\n<p data-start=\"1398\" data-end=\"1497\"><strong data-start=\"1398\" data-end=\"1415\">Alle Vorf&auml;lle</strong>, die Informationssicherheit betreffen: Vertraulichkeit, Integrit&auml;t, Verf&uuml;gbarkeit</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1499\" data-end=\"1502\">\r\n<h2 data-start=\"1504\" data-end=\"1526\"><strong data-start=\"1507\" data-end=\"1526\">3. Definitionen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1528\" data-end=\"2017\">\r\n<thead data-start=\"1528\" data-end=\"1551\">\r\n<tr data-start=\"1528\" data-end=\"1551\">\r\n<th data-start=\"1528\" data-end=\"1538\" data-col-size=\"sm\">Begriff</th>\r\n<th data-start=\"1538\" data-end=\"1551\" data-col-size=\"md\">Bedeutung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1575\" data-end=\"2017\">\r\n<tr data-start=\"1575\" data-end=\"1715\">\r\n<td data-start=\"1575\" data-end=\"1620\" data-col-size=\"sm\"><strong data-start=\"1577\" data-end=\"1619\">Sicherheitsvorfall (Security Incident)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1620\" data-end=\"1715\">Ereignis, das zu einer Verletzung der Informationssicherheit f&uuml;hren k&ouml;nnte oder gef&uuml;hrt hat</td>\r\n</tr>\r\n<tr data-start=\"1716\" data-end=\"1832\">\r\n<td data-start=\"1716\" data-end=\"1759\" data-col-size=\"sm\"><strong data-start=\"1718\" data-end=\"1758\">Sicherheitsereignis (Security Event)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1759\" data-end=\"1832\">Auff&auml;lliges Ereignis ohne (zwingende) sicherheitsrelevante Auswirkung</td>\r\n</tr>\r\n<tr data-start=\"1833\" data-end=\"1930\">\r\n<td data-start=\"1833\" data-end=\"1845\" data-col-size=\"sm\"><strong data-start=\"1835\" data-end=\"1844\">ISIRT</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1845\" data-end=\"1930\">Information Security Incident Response Team &ndash; Gruppe zur Behandlung von Vorf&auml;llen</td>\r\n</tr>\r\n<tr data-start=\"1931\" data-end=\"2017\">\r\n<td data-start=\"1931\" data-end=\"1960\" data-col-size=\"sm\"><strong data-start=\"1933\" data-end=\"1959\">Crisis Management Team</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1960\" data-end=\"2017\">Leitungsebene zur Behandlung schwerwiegender Vorf&auml;lle</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2019\" data-end=\"2022\">\r\n<h2 data-start=\"2024\" data-end=\"2067\"><strong data-start=\"2027\" data-end=\"2067\">4. Beispiele f&uuml;r Sicherheitsvorf&auml;lle</strong></h2>\r\n<ul data-start=\"2069\" data-end=\"2482\">\r\n<li data-start=\"2069\" data-end=\"2140\">\r\n<p data-start=\"2071\" data-end=\"2140\">Verlust oder Diebstahl von IT-Ger&auml;ten, Datentr&auml;gern oder Dokumenten</p>\r\n</li>\r\n<li data-start=\"2141\" data-end=\"2197\">\r\n<p data-start=\"2143\" data-end=\"2197\">Verdacht auf Malware-Infektion, Ransomware, Phishing</p>\r\n</li>\r\n<li data-start=\"2198\" data-end=\"2256\">\r\n<p data-start=\"2200\" data-end=\"2256\">Unbefugter Zugriff auf Systeme, Daten oder Anwendungen</p>\r\n</li>\r\n<li data-start=\"2257\" data-end=\"2343\">\r\n<p data-start=\"2259\" data-end=\"2343\">Versto&szlig; gegen Datenschutz (z. B. E-Mail an falschen Empf&auml;nger mit sensiblen Daten)</p>\r\n</li>\r\n<li data-start=\"2344\" data-end=\"2392\">\r\n<p data-start=\"2346\" data-end=\"2392\">Missbrauch von Benutzerkonten, Admin-Rechten</p>\r\n</li>\r\n<li data-start=\"2393\" data-end=\"2433\">\r\n<p data-start=\"2395\" data-end=\"2433\">Manipulation oder L&ouml;schung von Daten</p>\r\n</li>\r\n<li data-start=\"2434\" data-end=\"2482\">\r\n<p data-start=\"2436\" data-end=\"2482\">Ausfall kritischer Systeme durch Cyberangriffe</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2484\" data-end=\"2487\">\r\n<h2 data-start=\"2489\" data-end=\"2532\"><strong data-start=\"2492\" data-end=\"2532\">5. Grunds&auml;tze im Incident Management</strong></h2>\r\n<ul data-start=\"2534\" data-end=\"2927\">\r\n<li data-start=\"2534\" data-end=\"2612\">\r\n<p data-start=\"2536\" data-end=\"2612\"><strong data-start=\"2536\" data-end=\"2557\">Sofortige Meldung</strong>: Jeder Vorfall muss <strong data-start=\"2578\" data-end=\"2594\">unverz&uuml;glich</strong> gemeldet werden</p>\r\n</li>\r\n<li data-start=\"2613\" data-end=\"2692\">\r\n<p data-start=\"2615\" data-end=\"2692\"><strong data-start=\"2615\" data-end=\"2640\">Keine Schuldzuweisung</strong>: Ziel ist <strong data-start=\"2651\" data-end=\"2690\">Fehleraufkl&auml;rung, nicht -bestrafung</strong></p>\r\n</li>\r\n<li data-start=\"2693\" data-end=\"2776\">\r\n<p data-start=\"2695\" data-end=\"2776\"><strong data-start=\"2695\" data-end=\"2716\">Schnelle Reaktion</strong>: ISIRT reagiert priorit&auml;tsgesteuert gem&auml;&szlig; Eskalationsplan</p>\r\n</li>\r\n<li data-start=\"2777\" data-end=\"2860\">\r\n<p data-start=\"2779\" data-end=\"2860\"><strong data-start=\"2779\" data-end=\"2807\">L&uuml;ckenlose Dokumentation</strong>: Alle Schritte werden nachvollziehbar festgehalten</p>\r\n</li>\r\n<li data-start=\"2861\" data-end=\"2927\">\r\n<p data-start=\"2863\" data-end=\"2927\"><strong data-start=\"2863\" data-end=\"2882\">Lessons Learned</strong>: Jeder Vorfall wird zur Verbesserung genutzt</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2929\" data-end=\"2932\">\r\n<h2 data-start=\"2934\" data-end=\"2975\"><strong data-start=\"2937\" data-end=\"2975\">6. Rollen und Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2977\" data-end=\"3641\">\r\n<thead data-start=\"2977\" data-end=\"2997\">\r\n<tr data-start=\"2977\" data-end=\"2997\">\r\n<th data-start=\"2977\" data-end=\"2985\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"2985\" data-end=\"2997\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3019\" data-end=\"3641\">\r\n<tr data-start=\"3019\" data-end=\"3096\">\r\n<td data-start=\"3019\" data-end=\"3045\" data-col-size=\"sm\"><strong data-start=\"3021\" data-end=\"3044\">Alle Mitarbeitenden</strong></td>\r\n<td data-start=\"3045\" data-end=\"3096\" data-col-size=\"md\">Melden von Vorf&auml;llen an definierte Meldestellen</td>\r\n</tr>\r\n<tr data-start=\"3097\" data-end=\"3184\">\r\n<td data-start=\"3097\" data-end=\"3132\" data-col-size=\"sm\"><strong data-start=\"3099\" data-end=\"3131\">Helpdesk / 1st-Level-Support</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3132\" data-end=\"3184\">Entgegennahme, erste Einsch&auml;tzung, Weiterleitung</td>\r\n</tr>\r\n<tr data-start=\"3185\" data-end=\"3251\">\r\n<td data-start=\"3185\" data-end=\"3197\" data-col-size=\"sm\"><strong data-start=\"3187\" data-end=\"3196\">ISIRT</strong></td>\r\n<td data-start=\"3197\" data-end=\"3251\" data-col-size=\"md\">Untersuchung, Bewertung, Koordination der Reaktion</td>\r\n</tr>\r\n<tr data-start=\"3252\" data-end=\"3328\">\r\n<td data-start=\"3252\" data-end=\"3269\" data-col-size=\"sm\"><strong data-start=\"3254\" data-end=\"3268\">ISB / CISO</strong></td>\r\n<td data-start=\"3269\" data-end=\"3328\" data-col-size=\"md\">&Uuml;berwachung des Prozesses, Dokumentation, Kommunikation</td>\r\n</tr>\r\n<tr data-start=\"3329\" data-end=\"3406\">\r\n<td data-start=\"3329\" data-end=\"3348\" data-col-size=\"sm\"><strong data-start=\"3331\" data-end=\"3347\">IT-Abteilung</strong></td>\r\n<td data-start=\"3348\" data-end=\"3406\" data-col-size=\"md\">Technische Analyse, Wiederherstellung, Protokollierung</td>\r\n</tr>\r\n<tr data-start=\"3407\" data-end=\"3510\">\r\n<td data-start=\"3407\" data-end=\"3438\" data-col-size=\"sm\"><strong data-start=\"3409\" data-end=\"3437\">Datenschutzbeauftragte*r</strong></td>\r\n<td data-start=\"3438\" data-end=\"3510\" data-col-size=\"md\">Bewertung bei Datenschutzvorf&auml;llen, ggf. Meldung an Aufsichtsbeh&ouml;rde</td>\r\n</tr>\r\n<tr data-start=\"3511\" data-end=\"3641\">\r\n<td data-start=\"3511\" data-end=\"3547\" data-col-size=\"sm\"><strong data-start=\"3513\" data-end=\"3546\">Gesch&auml;ftsf&uuml;hrung / Krisenteam</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3547\" data-end=\"3641\">Entscheidung bei schwerwiegenden Vorf&auml;llen (z. B. meldepflichtige Datenschutzverletzungen)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3643\" data-end=\"3646\">\r\n<h2 data-start=\"3648\" data-end=\"3693\"><strong data-start=\"3651\" data-end=\"3693\">7. Meldepflichten und Meldemechanismen</strong></h2>\r\n<h3 data-start=\"3695\" data-end=\"3720\">7.1 Interne Meldewege</h3>\r\n<ul data-start=\"3722\" data-end=\"3873\">\r\n<li data-start=\"3722\" data-end=\"3873\">\r\n<p data-start=\"3724\" data-end=\"3768\">Vorf&auml;lle sind <strong data-start=\"3738\" data-end=\"3764\">unverz&uuml;glich zu melden</strong> an:</p>\r\n<ul data-start=\"3771\" data-end=\"3873\">\r\n<li data-start=\"3771\" data-end=\"3828\">\r\n<p data-start=\"3773\" data-end=\"3828\">IT-Support / Helpdesk (Telefon / Ticketsystem / E-Mail)</p>\r\n</li>\r\n<li data-start=\"3831\" data-end=\"3873\">\r\n<p data-start=\"3833\" data-end=\"3873\">ISB oder IT-Sicherheitsverantwortliche*r</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3875\" data-end=\"3902\">7.2 Inhalte der Meldung</h3>\r\n<ul data-start=\"3904\" data-end=\"4024\">\r\n<li data-start=\"3904\" data-end=\"3925\">\r\n<p data-start=\"3906\" data-end=\"3925\">Was ist passiert?</p>\r\n</li>\r\n<li data-start=\"3926\" data-end=\"3957\">\r\n<p data-start=\"3928\" data-end=\"3957\">Wann wurde es festgestellt?</p>\r\n</li>\r\n<li data-start=\"3958\" data-end=\"4001\">\r\n<p data-start=\"3960\" data-end=\"4001\">Welche Systeme/Personen sind betroffen?</p>\r\n</li>\r\n<li data-start=\"4002\" data-end=\"4024\">\r\n<p data-start=\"4004\" data-end=\"4024\">Wer hat es gemeldet?</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4026\" data-end=\"4073\">7.3 Datenschutzverletzungen (Art. 33 DSGVO)</h3>\r\n<ul data-start=\"4075\" data-end=\"4234\">\r\n<li data-start=\"4075\" data-end=\"4154\">\r\n<p data-start=\"4077\" data-end=\"4154\">Meldung an Aufsichtsbeh&ouml;rde innerhalb von <strong data-start=\"4119\" data-end=\"4133\">72 Stunden</strong> nach Bekanntwerden</p>\r\n</li>\r\n<li data-start=\"4155\" data-end=\"4234\">\r\n<p data-start=\"4157\" data-end=\"4234\">DSB entscheidet in Zusammenarbeit mit ISB und Leitungsebene &uuml;ber Meldepflicht</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4236\" data-end=\"4239\">\r\n<h2 data-start=\"4241\" data-end=\"4291\"><strong data-start=\"4244\" data-end=\"4291\">8. Ablauf des Incident-Management-Prozesses</strong></h2>\r\n<h3 data-start=\"4293\" data-end=\"4325\">1. <strong data-start=\"4300\" data-end=\"4323\">Erkennung &amp; Meldung</strong></h3>\r\n<p data-start=\"4326\" data-end=\"4437\">&ndash; Aufnahme durch Support oder direkt beim ISB / IT<br data-start=\"4376\" data-end=\"4379\">&ndash; Erste Priorisierung und Er&ouml;ffnung eines Incident-Tickets</p>\r\n<h3 data-start=\"4439\" data-end=\"4474\">2. <strong data-start=\"4446\" data-end=\"4472\">Einsch&auml;tzung &amp; Analyse</strong></h3>\r\n<p data-start=\"4475\" data-end=\"4568\">&ndash; Ursachenanalyse durch ISIRT / IT-Security<br data-start=\"4518\" data-end=\"4521\">&ndash; Feststellung von Schweregrad und Auswirkungen</p>\r\n<h3 data-start=\"4570\" data-end=\"4604\">3. <strong data-start=\"4577\" data-end=\"4602\">Reaktion / Eind&auml;mmung</strong></h3>\r\n<p data-start=\"4605\" data-end=\"4683\">&ndash; Sofortma&szlig;nahmen: z. B. Trennung vom Netz, Passwortsperre, Konto deaktivieren</p>\r\n<h3 data-start=\"4685\" data-end=\"4726\">4. <strong data-start=\"4692\" data-end=\"4724\">Behebung / Wiederherstellung</strong></h3>\r\n<p data-start=\"4727\" data-end=\"4795\">&ndash; Beseitigung von Schadsoftware, Datenwiederherstellung, Absicherung</p>\r\n<h3 data-start=\"4797\" data-end=\"4823\">5. <strong data-start=\"4804\" data-end=\"4821\">Dokumentation</strong></h3>\r\n<p data-start=\"4824\" data-end=\"4931\">&ndash; Protokollierung aller Schritte im Vorfall-Management-System<br data-start=\"4885\" data-end=\"4888\">&ndash; Beteiligung des DSB bei Datenschutzf&auml;llen</p>\r\n<h3 data-start=\"4933\" data-end=\"4977\">6. <strong data-start=\"4940\" data-end=\"4975\">Nachbereitung / Lessons Learned</strong></h3>\r\n<p data-start=\"4978\" data-end=\"5069\">&ndash; Abschlussbericht (inkl. Ursachen, Wirkung, Ma&szlig;nahmen)<br data-start=\"5033\" data-end=\"5036\">&ndash; Ableitung pr&auml;ventiver Ma&szlig;nahmen</p>\r\n<hr data-start=\"5071\" data-end=\"5074\">\r\n<h2 data-start=\"5076\" data-end=\"5125\"><strong data-start=\"5079\" data-end=\"5125\">9. Klassifikation von Sicherheitsvorf&auml;llen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5127\" data-end=\"5542\">\r\n<thead data-start=\"5127\" data-end=\"5166\">\r\n<tr data-start=\"5127\" data-end=\"5166\">\r\n<th data-start=\"5127\" data-end=\"5139\" data-col-size=\"sm\">Priorit&auml;t</th>\r\n<th data-start=\"5139\" data-end=\"5154\" data-col-size=\"md\">Beschreibung</th>\r\n<th data-start=\"5154\" data-end=\"5166\" data-col-size=\"md\">Beispiel</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5207\" data-end=\"5542\">\r\n<tr data-start=\"5207\" data-end=\"5334\">\r\n<td data-start=\"5207\" data-end=\"5223\" data-col-size=\"sm\"><strong data-start=\"5209\" data-end=\"5222\">Hoch (P1)</strong></td>\r\n<td data-start=\"5223\" data-end=\"5283\" data-col-size=\"md\">Kritischer Vorfall mit hohem Schaden oder Gesetzesversto&szlig;</td>\r\n<td data-col-size=\"md\" data-start=\"5283\" data-end=\"5334\">Ransomware, Datenabfluss, Datenschutzverletzung</td>\r\n</tr>\r\n<tr data-start=\"5335\" data-end=\"5428\">\r\n<td data-start=\"5335\" data-end=\"5353\" data-col-size=\"sm\"><strong data-start=\"5337\" data-end=\"5352\">Mittel (P2)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5353\" data-end=\"5393\">Eingeschr&auml;nkte Auswirkung auf Betrieb</td>\r\n<td data-col-size=\"md\" data-start=\"5393\" data-end=\"5428\">Virenfund, verd&auml;chtige Zugriffe</td>\r\n</tr>\r\n<tr data-start=\"5429\" data-end=\"5542\">\r\n<td data-start=\"5429\" data-end=\"5448\" data-col-size=\"sm\"><strong data-start=\"5431\" data-end=\"5447\">Niedrig (P3)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5448\" data-end=\"5499\">Kein direkter Schaden, aber Analyse erforderlich</td>\r\n<td data-col-size=\"md\" data-start=\"5499\" data-end=\"5542\">Fehlkonfiguration, ungew&ouml;hnliche Logins</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5544\" data-end=\"5547\">\r\n<h2 data-start=\"5549\" data-end=\"5588\"><strong data-start=\"5552\" data-end=\"5588\">10. Kommunikation und Eskalation</strong></h2>\r\n<ul data-start=\"5590\" data-end=\"5885\">\r\n<li data-start=\"5590\" data-end=\"5682\">\r\n<p data-start=\"5592\" data-end=\"5682\">Kommunikationskan&auml;le werden je nach Kritikalit&auml;t festgelegt (Telefon, E-Mail, Crisis Call)</p>\r\n</li>\r\n<li data-start=\"5683\" data-end=\"5808\">\r\n<p data-start=\"5685\" data-end=\"5703\">Eskalationsstufen:</p>\r\n<ul data-start=\"5706\" data-end=\"5808\">\r\n<li data-start=\"5706\" data-end=\"5753\">\r\n<p data-start=\"5708\" data-end=\"5753\"><strong data-start=\"5708\" data-end=\"5721\">Technisch</strong> (Helpdesk &rarr; ISIRT &rarr; IT-Leitung)</p>\r\n</li>\r\n<li data-start=\"5756\" data-end=\"5808\">\r\n<p data-start=\"5758\" data-end=\"5808\"><strong data-start=\"5758\" data-end=\"5777\">Organisatorisch</strong> (ISB &rarr; Gesch&auml;ftsf&uuml;hrung / DSB)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"5809\" data-end=\"5885\">\r\n<p data-start=\"5811\" data-end=\"5885\">Bei externen Meldungen: Nur freigegebene Sprecher (z. B. GF, Pressestelle)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5887\" data-end=\"5890\">\r\n<h2 data-start=\"5892\" data-end=\"5934\"><strong data-start=\"5895\" data-end=\"5934\">11. Dokumentation &amp; Nachweisf&uuml;hrung</strong></h2>\r\n<ul data-start=\"5936\" data-end=\"6164\">\r\n<li data-start=\"5936\" data-end=\"5998\">\r\n<p data-start=\"5938\" data-end=\"5998\">Jeder Vorfall wird im <strong data-start=\"5960\" data-end=\"5990\">Incident-Management-System</strong> erfasst</p>\r\n</li>\r\n<li data-start=\"5999\" data-end=\"6105\">\r\n<p data-start=\"6001\" data-end=\"6022\">Mindestens enthalten:</p>\r\n<ul data-start=\"6025\" data-end=\"6105\">\r\n<li data-start=\"6025\" data-end=\"6105\">\r\n<p data-start=\"6027\" data-end=\"6105\">ID / Datum / Melder / Beschreibung / Beteiligte Systeme / Ma&szlig;nahmen / Ergebnis</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"6106\" data-end=\"6164\">\r\n<p data-start=\"6108\" data-end=\"6164\"><strong data-start=\"6108\" data-end=\"6124\">Aufbewahrung</strong>: min. 3 Jahre (DSGVO-F&auml;lle ggf. l&auml;nger)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6166\" data-end=\"6169\">\r\n<h2 data-start=\"6171\" data-end=\"6220\"><strong data-start=\"6174\" data-end=\"6220\">12. Schnittstellen zu weiteren Richtlinien</strong></h2>\r\n<p data-start=\"6222\" data-end=\"6247\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"6249\" data-end=\"6411\">\r\n<li data-start=\"6249\" data-end=\"6288\">\r\n<p data-start=\"6251\" data-end=\"6288\"><strong data-start=\"6251\" data-end=\"6288\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6289\" data-end=\"6316\">\r\n<p data-start=\"6291\" data-end=\"6316\"><strong data-start=\"6291\" data-end=\"6316\">Datenschutzrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6317\" data-end=\"6362\">\r\n<p data-start=\"6319\" data-end=\"6362\"><strong data-start=\"6319\" data-end=\"6362\">Notfallmanagement / Business Continuity</strong></p>\r\n</li>\r\n<li data-start=\"6363\" data-end=\"6387\">\r\n<p data-start=\"6365\" data-end=\"6387\"><strong data-start=\"6365\" data-end=\"6387\">Zugriffsmanagement</strong></p>\r\n</li>\r\n<li data-start=\"6388\" data-end=\"6411\">\r\n<p data-start=\"6390\" data-end=\"6411\"><strong data-start=\"6390\" data-end=\"6411\">Change-Management</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6413\" data-end=\"6416\">\r\n<h2 data-start=\"6418\" data-end=\"6458\"><strong data-start=\"6421\" data-end=\"6458\">13. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6460\" data-end=\"6695\">\r\n<thead data-start=\"6460\" data-end=\"6488\">\r\n<tr data-start=\"6460\" data-end=\"6488\">\r\n<th data-start=\"6460\" data-end=\"6478\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6478\" data-end=\"6488\" data-col-size=\"md\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6518\" data-end=\"6695\">\r\n<tr data-start=\"6518\" data-end=\"6577\">\r\n<td data-start=\"6518\" data-end=\"6538\" data-col-size=\"sm\"><strong data-start=\"6520\" data-end=\"6537\">ISO/IEC 27001</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6538\" data-end=\"6577\">A.5.24&ndash;A.5.26 &ndash; Incident Management</td>\r\n</tr>\r\n<tr data-start=\"6578\" data-end=\"6630\">\r\n<td data-start=\"6578\" data-end=\"6603\" data-col-size=\"sm\"><strong data-start=\"6580\" data-end=\"6602\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6603\" data-end=\"6630\">OPS.1.3.2, CON.9, ORP.3</td>\r\n</tr>\r\n<tr data-start=\"6631\" data-end=\"6695\">\r\n<td data-start=\"6631\" data-end=\"6646\" data-col-size=\"sm\"><strong data-start=\"6633\" data-end=\"6645\">EU-DSGVO</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6646\" data-end=\"6695\">Art. 33 &ndash; Meldung von Datenschutzverletzungen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-04-12', 0, 0, 0, 0, NULL, 0, '', '<h2><strong><span>1. Purpose of the Directive</span></strong></h2>\n<p><span>The aim of this guideline is to create uniform requirements for the </span><strong><span>detection, reporting, handling and documentation of information security incidents</span></strong><span> in order to minimize damage, analyze causes and prevent recurrence.</span></p>\n<hr/>\n<h2><strong><span>2. Scope</span></strong></h2>\n<p><span>This policy applies to:</span></p>\n<ul>\n<li>\n<p><strong><span>All employees</span></strong><span> , service providers and external partners who use IT resources or have access to information</span></p>\n</li>\n<li>\n<p><strong><span>All systems and applications</span></strong><span> within the organization (including cloud services, networks, end devices, etc.)</span></p>\n</li>\n<li>\n<p><strong><span>All incidents</span></strong><span> affecting information security: confidentiality, integrity, availability</span></p>\n</li>\n</ul>\n<hr/>\n<h2><strong><span>3. Definitions</span></strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th><span>Expression</span></th>\n<th><span>Meaning</span></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong><span>Security Incident</span></strong></td>\n<td><span>An event that could lead to, or has led to, a breach of information security.</span></td>\n</tr>\n<tr>\n<td><strong><span>Security event</span></strong></td>\n<td><span>A conspicuous event without (necessary) safety-relevant consequences.</span></td>\n</tr>\n<tr>\n<td><strong><span>ISIRT</span></strong></td>\n<td><span>Information Security Incident Response Team – Group for handling incidents</span></td>\n</tr>\n<tr>\n<td><strong><span>Crisis Management Team</span></strong></td>\n<td><span>Management level for handling serious incidents</span></td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong><span>4. Examples of security incidents</span></strong></h2>\n<ul>\n<li>\n<p><span>Loss or theft of IT equipment, data carriers or documents</span></p>\n</li>\n<li>\n<p><span>Suspected malware infection, ransomware, phishing</span></p>\n</li>\n<li>\n<p><span>Unauthorized access to systems, data, or applications</span></p>\n</li>\n<li>\n<p><span>Violation of data protection (e.g., sending an email to the wrong recipient containing sensitive data)</span></p>\n</li>\n<li>\n<p><span>Abuse of user accounts, admin rights</span></p>\n</li>\n<li>\n<p><span>Manipulation or deletion of data</span></p>\n</li>\n<li>\n<p><span>Failure of critical systems due to cyberattacks</span></p>\n</li>\n</ul>\n<hr/>\n<h2><strong><span>5. Principles of Incident Management</span></strong></h2>\n<ul>\n<li>\n<p><strong><span>Immediate reporting</span></strong><span> : Every incident must be reported </span><strong><span>immediately.</span></strong></p>\n</li>\n<li>\n<p><strong><span>No blame is assigned</span></strong><span> : the goal is </span><strong><span>to clarify the error, not to punish it.</span></strong></p>\n</li>\n<li>\n<p><strong><span>Rapid response</span></strong><span> : ISIRT responds according to a priority-based escalation plan.</span></p>\n</li>\n<li>\n<p><strong><span>Complete documentation</span></strong><span> : All steps are recorded in a traceable manner.</span></p>\n</li>\n<li>\n<p><strong><span>Lessons Learned</span></strong><span> : Every incident is used for improvement.</span></p>\n</li>\n</ul>\n<hr/>\n<h2><strong><span>6. Roles and responsibilities</span></strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th><span>role</span></th>\n<th><span>Tasks</span></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong><span>All employees</span></strong></td>\n<td><span>Reporting incidents to defined reporting points</span></td>\n</tr>\n<tr>\n<td><strong><span>Helpdesk / 1st-Level Support</span></strong></td>\n<td><span>Receipt, initial assessment, forwarding</span></td>\n</tr>\n<tr>\n<td><strong><span>ISIRT</span></strong></td>\n<td><span>Investigation, assessment, coordination of the response</span></td>\n</tr>\n<tr>\n<td><strong><span>ISB / CISO</span></strong></td>\n<td><span>Process monitoring, documentation, communication</span></td>\n</tr>\n<tr>\n<td><strong><span>IT department</span></strong></td>\n<td><span>Technical analysis, recovery, logging</span></td>\n</tr>\n<tr>\n<td><strong><span>Data Protection Officer</span></strong></td>\n<td><span>Assessment of data protection incidents, including, if necessary, notification to the supervisory authority.</span></td>\n</tr>\n<tr>\n<td><strong><span>Management / Crisis Team</span></strong></td>\n<td><span>Decision in the event of serious incidents (e.g., reportable data breaches)</span></td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong><span>7. Reporting obligations and reporting mechanisms</span></strong></h2>\n<h3><span>7.1 Internal reporting channels</span></h3>\n<ul>\n<li>\n<p><span>Incidents </span><strong><span>must be reported immediately</span></strong><span> to:</span></p>\n<ul>\n<li>\n<p><span>IT support / helpdesk (telephone / ticket system / email)</span></p>\n</li>\n<li>\n<p><span>ISB or IT Security Officer</span></p>\n</li>\n</ul>\n</li>\n</ul>\n<h3><span>7.2 Contents of the message</span></h3>\n<ul>\n<li>\n<p><span>What happened?</span></p>\n</li>\n<li>\n<p><span>When was it discovered?</span></p>\n</li>\n<li>\n<p><span>Which systems/people are affected?</span></p>\n</li>\n<li>\n<p><span>Who reported it?</span></p>\n</li>\n</ul>\n<h3><span>7.3 Data breaches (Art. 33 GDPR)</span></h3>\n<ul>\n<li>\n<p><span>Report to the supervisory authority within </span><strong><span>72 hours</span></strong><span> of becoming aware of the issue.</span></p>\n</li>\n<li>\n<p><span>DSB decides on reporting obligations in cooperation with ISB and management.</span></p>\n</li>\n</ul>\n<hr/>\n<h2><strong><span>8. Incident Management Process Flow</span></strong></h2>\n<h3><span>1. </span><strong><span>Detection &amp; Notification</span></strong></h3>\n<p><span>– Initial contact via support or directly with the ISB / IT</span><br/><span>– Initial prioritization and opening of an incident ticket</span></p>\n<h3><span>2. </span><strong><span>Assessment &amp; Analysis</span></strong></h3>\n<p><span>– Root cause analysis by ISIRT / IT security</span><br/><span>– Determination of severity and impact</span></p>\n<h3><span>3. </span><strong><span>Response / Containment</span></strong></h3>\n<p><span>– Immediate measures: e.g., disconnecting from the network, password lock, deactivating the account</span></p>\n<h3><span>4. </span><strong><span>Fix / Restoration</span></strong></h3>\n<p><span>– Malware removal, data recovery, security</span></p>\n<h3><span>5. </span><strong><span>Documentation</span></strong></h3>\n<p><span>– Logging of all steps in the incident management system</span><br/><span>– Involvement of the Data Protection Officer in data protection cases</span></p>\n<h3><span>6. </span><strong><span>Follow-up / Lessons Learned</span></strong></h3>\n<p><span>– Final report (including causes, effects, and measures)</span><br/><span>– Derivation of preventive measures</span></p>\n<hr/>\n<h2><strong><span>9. Classification of security incidents</span></strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th><span>priority</span></th>\n<th><span>Description</span></th>\n<th><span>Example</span></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong><span>High (P1)</span></strong></td>\n<td><span>Critical incident involving significant damage or violation of the law</span></td>\n<td><span>Ransomware, data leakage, data breach</span></td>\n</tr>\n<tr>\n<td><strong><span>Medium (P2)</span></strong></td>\n<td><span>Limited impact on operations</span></td>\n<td><span>Virus detected, suspicious access attempts</span></td>\n</tr>\n<tr>\n<td><strong><span>Low (P3)</span></strong></td>\n<td><span>No direct damage, but analysis is required.</span></td>\n<td><span>Misconfiguration, unusual logins</span></td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong><span>10. Communication and Escalation</span></strong></h2>\n<ul>\n<li>\n<p><span>Communication channels are determined according to criticality (telephone, email, crisis call).</span></p>\n</li>\n<li>\n<p><span>Escalation levels:</span></p>\n<ul>\n<li>\n<p><strong><span>Technical</span></strong><span> (Helpdesk → ISIRT → IT Management)</span></p>\n</li>\n<li>\n<p><strong><span>Organizational</span></strong><span> (ISB → Management / DSB)</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p><span>For external announcements: Only approved spokespeople (e.g., CEO, press office)</span></p>\n</li>\n</ul>\n<hr/>\n<h2><strong><span>11. Documentation &amp; Evidence Recognition</span></strong></h2>\n<ul>\n<li>\n<p><span>Every incident is recorded in the </span><strong><span>incident management system.</span></strong></p>\n</li>\n<li>\n<p><span>Minimum contents:</span></p>\n<ul>\n<li>\n<p><span>ID / Date / Reporter / Description / Systems Involved / Actions / Result</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong><span>Storage period</span></strong><span> : min. 3 years (longer in GDPR cases)</span></p>\n</li>\n</ul>\n<hr/>\n<h2><strong><span>12. Interfaces to other guidelines</span></strong></h2>\n<p><span>This policy supplements:</span></p>\n<ul>\n<li>\n<p><strong><span>Information Security Policy</span></strong></p>\n</li>\n<li>\n<p><strong><span>Privacy Policy</span></strong></p>\n</li>\n<li>\n<p><strong><span>Emergency Management / Business Continuity</span></strong></p>\n</li>\n<li>\n<p><strong><span>Access management</span></strong></p>\n</li>\n<li>\n<p><strong><span>Change Management</span></strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong><span>13. Relation to norms and standards</span></strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th><span>Norm / Standard</span></th>\n<th><span>Contents</span></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong><span>ISO/IEC 27001</span></strong></td>\n<td><span>A.5.24–A.5.26 – Incident Management</span></td>\n</tr>\n<tr>\n<td><strong><span>BSI IT Baseline Protection</span></strong></td>\n<td><span>OPS.1.3.2, CON.9, ORP.3</span></td>\n</tr>\n<tr>\n<td><strong><span>EU GDPR</span></strong></td>\n<td><span>Article 33 – Notification of data breaches</span></td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 'Richtlinien', 'öffentlich', '1', 1, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(13, 'DOK-0013', 'Logging & Monitoring', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"774\" data-end=\"804\"><strong data-start=\"777\" data-end=\"804\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"806\" data-end=\"998\">Diese Richtlinie legt verbindliche Anforderungen f&uuml;r die <strong data-start=\"863\" data-end=\"892\">Protokollierung (Logging)</strong> und <strong data-start=\"897\" data-end=\"925\">&Uuml;berwachung (Monitoring)</strong> von IT-Systemen und sicherheitsrelevanten Aktivit&auml;ten fest. Ziel ist es:</p>\r\n<ul data-start=\"1000\" data-end=\"1237\">\r\n<li data-start=\"1000\" data-end=\"1045\">\r\n<p data-start=\"1002\" data-end=\"1045\">Sicherheitsvorf&auml;lle fr&uuml;hzeitig zu erkennen,</p>\r\n</li>\r\n<li data-start=\"1046\" data-end=\"1103\">\r\n<p data-start=\"1048\" data-end=\"1103\">die Ursachen von Ereignissen nachvollziehbar zu machen,</p>\r\n</li>\r\n<li data-start=\"1104\" data-end=\"1173\">\r\n<p data-start=\"1106\" data-end=\"1173\">gesetzliche Nachweispflichten zu erf&uuml;llen (z. B. DSGVO, HGB, GoBD),</p>\r\n</li>\r\n<li data-start=\"1174\" data-end=\"1237\">\r\n<p data-start=\"1176\" data-end=\"1237\">und Missbrauch, Datenverlust oder Manipulation zu verhindern.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1239\" data-end=\"1242\">\r\n<h2 data-start=\"1244\" data-end=\"1269\"><strong data-start=\"1247\" data-end=\"1269\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1271\" data-end=\"1297\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1299\" data-end=\"1615\">\r\n<li data-start=\"1299\" data-end=\"1431\">\r\n<p data-start=\"1301\" data-end=\"1431\"><strong data-start=\"1301\" data-end=\"1345\">Alle IT-Systeme, Anwendungen und Dienste</strong>, die personenbezogene, vertrauliche oder gesch&auml;ftskritische Informationen verarbeiten</p>\r\n</li>\r\n<li data-start=\"1432\" data-end=\"1517\">\r\n<p data-start=\"1434\" data-end=\"1517\"><strong data-start=\"1434\" data-end=\"1457\">Alle Benutzer*innen</strong>, einschlie&szlig;lich interner, externer und technischer Accounts</p>\r\n</li>\r\n<li data-start=\"1518\" data-end=\"1615\">\r\n<p data-start=\"1520\" data-end=\"1615\"><strong data-start=\"1520\" data-end=\"1583\">Alle Standorte, Rechenzentren, Cloud-Services und Netzwerke</strong>, die Teil der Organisation sind</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1617\" data-end=\"1620\">\r\n<h2 data-start=\"1622\" data-end=\"1662\"><strong data-start=\"1625\" data-end=\"1662\">3. Grunds&auml;tze der Protokollierung</strong></h2>\r\n<ul data-start=\"1664\" data-end=\"2076\">\r\n<li data-start=\"1664\" data-end=\"1770\">\r\n<p data-start=\"1666\" data-end=\"1770\">Es werden <strong data-start=\"1676\" data-end=\"1732\">nur notwendige und datenschutzkonforme Informationen</strong> protokolliert (&bdquo;Privacy by Design&ldquo;)</p>\r\n</li>\r\n<li data-start=\"1771\" data-end=\"1848\">\r\n<p data-start=\"1773\" data-end=\"1848\">Protokollierung erfolgt <strong data-start=\"1797\" data-end=\"1848\">vollst&auml;ndig, unver&auml;nderlich und nachvollziehbar</strong></p>\r\n</li>\r\n<li data-start=\"1849\" data-end=\"1926\">\r\n<p data-start=\"1851\" data-end=\"1926\">Protokolle sind vor <strong data-start=\"1871\" data-end=\"1914\">unberechtigtem Zugriff und Manipulation</strong> zu sch&uuml;tzen</p>\r\n</li>\r\n<li data-start=\"1927\" data-end=\"2002\">\r\n<p data-start=\"1929\" data-end=\"2002\"><strong data-start=\"1929\" data-end=\"1955\">Regelm&auml;&szlig;ige Auswertung</strong> (automatisiert oder manuell) ist verpflichtend</p>\r\n</li>\r\n<li data-start=\"2003\" data-end=\"2076\">\r\n<p data-start=\"2005\" data-end=\"2076\">L&ouml;schfristen und Speicherfristen sind <strong data-start=\"2043\" data-end=\"2062\">gesetzeskonform</strong> zu definieren</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2078\" data-end=\"2081\">\r\n<h2 data-start=\"2083\" data-end=\"2135\"><strong data-start=\"2086\" data-end=\"2135\">4. Arten von zu protokollierenden Ereignissen</strong></h2>\r\n<h3 data-start=\"2137\" data-end=\"2164\">4.1 Benutzeraktivit&auml;ten</h3>\r\n<ul data-start=\"2166\" data-end=\"2321\">\r\n<li data-start=\"2166\" data-end=\"2195\">\r\n<p data-start=\"2168\" data-end=\"2195\">Anmeldungen (Login, Logout)</p>\r\n</li>\r\n<li data-start=\"2196\" data-end=\"2228\">\r\n<p data-start=\"2198\" data-end=\"2228\">fehlgeschlagene Login-Versuche</p>\r\n</li>\r\n<li data-start=\"2229\" data-end=\"2277\">\r\n<p data-start=\"2231\" data-end=\"2277\">Benutzerkontenerstellung, -&auml;nderung, -l&ouml;schung</p>\r\n</li>\r\n<li data-start=\"2278\" data-end=\"2321\">\r\n<p data-start=\"2280\" data-end=\"2321\">&Auml;nderungen an Zugriffsrechten oder Rollen</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2323\" data-end=\"2347\">4.2 Systemereignisse</h3>\r\n<ul data-start=\"2349\" data-end=\"2502\">\r\n<li data-start=\"2349\" data-end=\"2394\">\r\n<p data-start=\"2351\" data-end=\"2394\">Starten / Beenden von Systemen und Diensten</p>\r\n</li>\r\n<li data-start=\"2395\" data-end=\"2421\">\r\n<p data-start=\"2397\" data-end=\"2421\">Konfigurations&auml;nderungen</p>\r\n</li>\r\n<li data-start=\"2422\" data-end=\"2467\">\r\n<p data-start=\"2424\" data-end=\"2467\">sicherheitsrelevante Softwareinstallationen</p>\r\n</li>\r\n<li data-start=\"2468\" data-end=\"2502\">\r\n<p data-start=\"2470\" data-end=\"2502\">Systemabst&uuml;rze, Fehlerereignisse</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2504\" data-end=\"2525\">4.3 Datenzugriffe</h3>\r\n<ul data-start=\"2527\" data-end=\"2709\">\r\n<li data-start=\"2527\" data-end=\"2582\">\r\n<p data-start=\"2529\" data-end=\"2582\">Zugriffe auf vertrauliche oder personenbezogene Daten</p>\r\n</li>\r\n<li data-start=\"2583\" data-end=\"2652\">\r\n<p data-start=\"2585\" data-end=\"2652\">&Auml;nderungen oder L&ouml;schungen von Daten (insb. in kritischen Systemen)</p>\r\n</li>\r\n<li data-start=\"2653\" data-end=\"2709\">\r\n<p data-start=\"2655\" data-end=\"2709\">Exporte von Daten (z. B. CSV-Exporte, Datenbank-Dumps)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2711\" data-end=\"2738\">4.4 Netzwerkaktivit&auml;ten</h3>\r\n<ul data-start=\"2740\" data-end=\"2873\">\r\n<li data-start=\"2740\" data-end=\"2775\">\r\n<p data-start=\"2742\" data-end=\"2775\">Firewall-Logs, IDS/IPS-Ereignisse</p>\r\n</li>\r\n<li data-start=\"2776\" data-end=\"2803\">\r\n<p data-start=\"2778\" data-end=\"2803\">VPN-Nutzung, Fernzugriffe</p>\r\n</li>\r\n<li data-start=\"2804\" data-end=\"2873\">\r\n<p data-start=\"2806\" data-end=\"2873\">verd&auml;chtiger Traffic (Port-Scans, Brute Force, Malware-Indikatoren)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2875\" data-end=\"2878\">\r\n<h2 data-start=\"2880\" data-end=\"2921\"><strong data-start=\"2883\" data-end=\"2921\">5. Anforderungen an Protokolldaten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2923\" data-end=\"3278\">\r\n<thead data-start=\"2923\" data-end=\"2956\">\r\n<tr data-start=\"2923\" data-end=\"2956\">\r\n<th data-start=\"2923\" data-end=\"2941\" data-col-size=\"sm\">Merkmal</th>\r\n<th data-start=\"2941\" data-end=\"2956\" data-col-size=\"md\">Anforderung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2991\" data-end=\"3278\">\r\n<tr data-start=\"2991\" data-end=\"3056\">\r\n<td data-start=\"2991\" data-end=\"3009\" data-col-size=\"sm\"><strong data-start=\"2993\" data-end=\"3008\">Zeitstempel</strong></td>\r\n<td data-start=\"3009\" data-end=\"3056\" data-col-size=\"md\">Standardisiert, Zeitsynchronisation via NTP</td>\r\n</tr>\r\n<tr data-start=\"3057\" data-end=\"3121\">\r\n<td data-start=\"3057\" data-end=\"3075\" data-col-size=\"sm\"><strong data-start=\"3059\" data-end=\"3074\">Benutzer-ID</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3075\" data-end=\"3121\">Eindeutig zuordenbar (kein Shared Account)</td>\r\n</tr>\r\n<tr data-start=\"3122\" data-end=\"3185\">\r\n<td data-start=\"3122\" data-end=\"3140\" data-col-size=\"sm\"><strong data-start=\"3124\" data-end=\"3134\">Aktion</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3140\" data-end=\"3185\">Beschreibung der durchgef&uuml;hrten Aktivit&auml;t</td>\r\n</tr>\r\n<tr data-start=\"3186\" data-end=\"3232\">\r\n<td data-start=\"3186\" data-end=\"3208\" data-col-size=\"sm\"><strong data-start=\"3188\" data-end=\"3207\">System / Dienst</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3208\" data-end=\"3232\">Klar identifizierbar</td>\r\n</tr>\r\n<tr data-start=\"3233\" data-end=\"3278\">\r\n<td data-start=\"3233\" data-end=\"3251\" data-col-size=\"sm\"><strong data-start=\"3235\" data-end=\"3247\">Ergebnis</strong></td>\r\n<td data-start=\"3251\" data-end=\"3278\" data-col-size=\"md\">Erfolg, Fehler, Abbruch</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3280\" data-end=\"3283\">\r\n<h2 data-start=\"3285\" data-end=\"3331\"><strong data-start=\"3288\" data-end=\"3331\">6. Schutz und Integrit&auml;t der Protokolle</strong></h2>\r\n<ul data-start=\"3333\" data-end=\"3630\">\r\n<li data-start=\"3333\" data-end=\"3436\">\r\n<p data-start=\"3335\" data-end=\"3436\">Protokolle sind in <strong data-start=\"3354\" data-end=\"3390\">gesch&uuml;tzten Bereichen / Systemen</strong> zu speichern (z. B. SIEM, zentrale Logserver)</p>\r\n</li>\r\n<li data-start=\"3437\" data-end=\"3498\">\r\n<p data-start=\"3439\" data-end=\"3498\">Schreibschutz und Pr&uuml;fsummen zur <strong data-start=\"3472\" data-end=\"3498\">Manipulationssicherung</strong></p>\r\n</li>\r\n<li data-start=\"3499\" data-end=\"3572\">\r\n<p data-start=\"3501\" data-end=\"3572\">Zugriff nur f&uuml;r <strong data-start=\"3517\" data-end=\"3542\">autorisierte Personen</strong> (z. B. IT-Security-Team, ISB)</p>\r\n</li>\r\n<li data-start=\"3573\" data-end=\"3630\">\r\n<p data-start=\"3575\" data-end=\"3630\"><strong data-start=\"3575\" data-end=\"3602\">Zugriffsprotokollierung</strong> auch f&uuml;r Log-Dateien selbst</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3632\" data-end=\"3635\">\r\n<h2 data-start=\"3637\" data-end=\"3667\"><strong data-start=\"3640\" data-end=\"3667\">7. Aufbewahrungsfristen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3669\" data-end=\"4102\">\r\n<thead data-start=\"3669\" data-end=\"3716\">\r\n<tr data-start=\"3669\" data-end=\"3716\">\r\n<th data-start=\"3669\" data-end=\"3694\" data-col-size=\"md\">Protokollart</th>\r\n<th data-start=\"3694\" data-end=\"3716\" data-col-size=\"md\">Aufbewahrungsdauer</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3765\" data-end=\"4102\">\r\n<tr data-start=\"3765\" data-end=\"3833\">\r\n<td data-start=\"3765\" data-end=\"3815\" data-col-size=\"md\">sicherheitsrelevante Logs (z. B. Adminzugriffe)</td>\r\n<td data-col-size=\"md\" data-start=\"3815\" data-end=\"3833\">min. 12 Monate</td>\r\n</tr>\r\n<tr data-start=\"3834\" data-end=\"3903\">\r\n<td data-start=\"3834\" data-end=\"3888\" data-col-size=\"md\">Login-/Logout-Informationen</td>\r\n<td data-col-size=\"md\" data-start=\"3888\" data-end=\"3903\">6&ndash;12 Monate</td>\r\n</tr>\r\n<tr data-start=\"3904\" data-end=\"4011\">\r\n<td data-start=\"3904\" data-end=\"3958\" data-col-size=\"md\">DSGVO-relevante Zugriffe auf personenbezogene Daten</td>\r\n<td data-col-size=\"md\" data-start=\"3958\" data-end=\"4011\">gem&auml;&szlig; Art. 5 DSGVO: nur so lange wie erforderlich</td>\r\n</tr>\r\n<tr data-start=\"4012\" data-end=\"4102\">\r\n<td data-start=\"4012\" data-end=\"4068\" data-col-size=\"md\">Finanzsysteme / GoBD</td>\r\n<td data-col-size=\"md\" data-start=\"4068\" data-end=\"4102\">bis zu 10 Jahre gem&auml;&szlig; HGB / AO</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4104\" data-end=\"4107\">\r\n<h2 data-start=\"4109\" data-end=\"4144\"><strong data-start=\"4112\" data-end=\"4144\">8. Auswertung und Monitoring</strong></h2>\r\n<h3 data-start=\"4146\" data-end=\"4180\">8.1 Automatisiertes Monitoring</h3>\r\n<ul data-start=\"4182\" data-end=\"4431\">\r\n<li data-start=\"4182\" data-end=\"4257\">\r\n<p data-start=\"4184\" data-end=\"4257\">Einsatz geeigneter <strong data-start=\"4203\" data-end=\"4235\">Monitoring- und SIEM-Systeme</strong> zur zentralen Analyse</p>\r\n</li>\r\n<li data-start=\"4258\" data-end=\"4316\">\r\n<p data-start=\"4260\" data-end=\"4316\">Erkennung von <strong data-start=\"4274\" data-end=\"4316\">Auff&auml;lligkeiten, Anomalien und Mustern</strong></p>\r\n</li>\r\n<li data-start=\"4317\" data-end=\"4431\">\r\n<p data-start=\"4319\" data-end=\"4431\">Automatisierte <strong data-start=\"4334\" data-end=\"4374\">Alerts bei Schwellwert&uuml;berschreitung</strong> oder Indikatoren f&uuml;r Angriffe (Indicators of Compromise)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4433\" data-end=\"4460\">8.2 Manuelle Auswertung</h3>\r\n<ul data-start=\"4462\" data-end=\"4582\">\r\n<li data-start=\"4462\" data-end=\"4528\">\r\n<p data-start=\"4464\" data-end=\"4528\">Regelm&auml;&szlig;ige <strong data-start=\"4476\" data-end=\"4528\">manuelle Kontrolle sicherheitsrelevanter Systeme</strong></p>\r\n</li>\r\n<li data-start=\"4529\" data-end=\"4582\">\r\n<p data-start=\"4531\" data-end=\"4582\"><strong data-start=\"4531\" data-end=\"4555\">Stichprobenpr&uuml;fungen</strong> durch ISB oder IT-Security</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4584\" data-end=\"4602\">8.3 Eskalation</h3>\r\n<ul data-start=\"4604\" data-end=\"4731\">\r\n<li data-start=\"4604\" data-end=\"4667\">\r\n<p data-start=\"4606\" data-end=\"4667\">Verdachtsf&auml;lle werden gem&auml;&szlig; <strong data-start=\"4634\" data-end=\"4657\">Incident Management</strong> behandelt</p>\r\n</li>\r\n<li data-start=\"4668\" data-end=\"4731\">\r\n<p data-start=\"4670\" data-end=\"4731\">Monitoring-Alerts l&ouml;sen standardisierte Reaktionsprozesse aus</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4733\" data-end=\"4736\">\r\n<h2 data-start=\"4738\" data-end=\"4783\"><strong data-start=\"4741\" data-end=\"4783\">9. Datenschutz und rechtliche Vorgaben</strong></h2>\r\n<ul data-start=\"4785\" data-end=\"5122\">\r\n<li data-start=\"4785\" data-end=\"4869\">\r\n<p data-start=\"4787\" data-end=\"4869\">Protokollierung erfolgt <strong data-start=\"4811\" data-end=\"4840\">im Einklang mit der DSGVO</strong>, dem BDSG und ggf. dem TTDSG</p>\r\n</li>\r\n<li data-start=\"4870\" data-end=\"4955\">\r\n<p data-start=\"4872\" data-end=\"4955\">Betroffene Personen sind &uuml;ber Art und Umfang der Protokollierung zu <strong data-start=\"4940\" data-end=\"4955\">informieren</strong></p>\r\n</li>\r\n<li data-start=\"4956\" data-end=\"5038\">\r\n<p data-start=\"4958\" data-end=\"5038\"><strong data-start=\"4958\" data-end=\"4974\">Zweckbindung</strong> und <strong data-start=\"4979\" data-end=\"5002\">Verh&auml;ltnism&auml;&szlig;igkeit</strong> der Protokolle sind sicherzustellen</p>\r\n</li>\r\n<li data-start=\"5039\" data-end=\"5122\">\r\n<p data-start=\"5041\" data-end=\"5122\">Technische und organisatorische Ma&szlig;nahmen (TOMs) sichern die Datenverarbeitung ab</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5124\" data-end=\"5127\">\r\n<h2 data-start=\"5129\" data-end=\"5160\"><strong data-start=\"5132\" data-end=\"5160\">10. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5162\" data-end=\"5633\">\r\n<thead data-start=\"5162\" data-end=\"5198\">\r\n<tr data-start=\"5162\" data-end=\"5198\">\r\n<th data-start=\"5162\" data-end=\"5186\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5186\" data-end=\"5198\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5236\" data-end=\"5633\">\r\n<tr data-start=\"5236\" data-end=\"5313\">\r\n<td data-start=\"5236\" data-end=\"5262\" data-col-size=\"sm\"><strong data-start=\"5238\" data-end=\"5254\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5262\" data-end=\"5313\">Einrichtung, Betrieb und Pflege von Logsystemen</td>\r\n</tr>\r\n<tr data-start=\"5314\" data-end=\"5410\">\r\n<td data-start=\"5314\" data-end=\"5340\" data-col-size=\"sm\"><strong data-start=\"5316\" data-end=\"5330\">ISB / CISO</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5340\" data-end=\"5410\">Kontrolle der Sicherheitsanforderungen, Freigabe von Logstrategien</td>\r\n</tr>\r\n<tr data-start=\"5411\" data-end=\"5482\">\r\n<td data-start=\"5411\" data-end=\"5439\" data-col-size=\"sm\"><strong data-start=\"5413\" data-end=\"5438\">Systemverantwortliche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5439\" data-end=\"5482\">Konfiguration protokollierender Systeme</td>\r\n</tr>\r\n<tr data-start=\"5483\" data-end=\"5547\">\r\n<td data-start=\"5483\" data-end=\"5509\" data-col-size=\"sm\"><strong data-start=\"5485\" data-end=\"5492\">DSB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5509\" data-end=\"5547\">Pr&uuml;fung auf Datenschutzkonformit&auml;t</td>\r\n</tr>\r\n<tr data-start=\"5548\" data-end=\"5633\">\r\n<td data-start=\"5548\" data-end=\"5574\" data-col-size=\"sm\"><strong data-start=\"5550\" data-end=\"5573\">F&uuml;hrungskr&auml;fte / GF</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5574\" data-end=\"5633\">Verantwortung f&uuml;r Umsetzung und Freigabe der Richtlinie</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5635\" data-end=\"5638\">\r\n<h2 data-start=\"5640\" data-end=\"5689\"><strong data-start=\"5643\" data-end=\"5689\">11. Schnittstellen zu weiteren Richtlinien</strong></h2>\r\n<p data-start=\"5691\" data-end=\"5716\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"5718\" data-end=\"5911\">\r\n<li data-start=\"5718\" data-end=\"5761\">\r\n<p data-start=\"5720\" data-end=\"5761\"><strong data-start=\"5720\" data-end=\"5761\">Richtlinie zur Informationssicherheit</strong></p>\r\n</li>\r\n<li data-start=\"5762\" data-end=\"5802\">\r\n<p data-start=\"5764\" data-end=\"5802\"><strong data-start=\"5764\" data-end=\"5802\">Richtlinie zum Incident Management</strong></p>\r\n</li>\r\n<li data-start=\"5803\" data-end=\"5837\">\r\n<p data-start=\"5805\" data-end=\"5837\"><strong data-start=\"5805\" data-end=\"5837\">Zugriffsmanagementrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"5838\" data-end=\"5865\">\r\n<p data-start=\"5840\" data-end=\"5865\"><strong data-start=\"5840\" data-end=\"5865\">Datenschutzrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"5866\" data-end=\"5911\">\r\n<p data-start=\"5868\" data-end=\"5911\"><strong data-start=\"5868\" data-end=\"5911\">Notfallmanagement / Business Continuity</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5913\" data-end=\"5916\">\r\n<h2 data-start=\"5918\" data-end=\"5958\"><strong data-start=\"5921\" data-end=\"5958\">12. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5960\" data-end=\"6421\">\r\n<thead data-start=\"5960\" data-end=\"5988\">\r\n<tr data-start=\"5960\" data-end=\"5988\">\r\n<th data-start=\"5960\" data-end=\"5978\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"5978\" data-end=\"5988\" data-col-size=\"lg\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6018\" data-end=\"6421\">\r\n<tr data-start=\"6018\" data-end=\"6146\">\r\n<td data-start=\"6018\" data-end=\"6038\" data-col-size=\"sm\"><strong data-start=\"6020\" data-end=\"6037\">ISO/IEC 27001</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6038\" data-end=\"6146\">A.8.15 (Protokollierung), A.8.16 (&Uuml;berwachung), A.8.17 (Synchronisierung), A.5.23 (Verantwortlichkeiten)</td>\r\n</tr>\r\n<tr data-start=\"6147\" data-end=\"6249\">\r\n<td data-start=\"6147\" data-end=\"6172\" data-col-size=\"sm\"><strong data-start=\"6149\" data-end=\"6171\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6172\" data-end=\"6249\">OPS.1.3.1 (Protokollierung), DET.1 (Detektion), CON.9 (Notfallbehandlung)</td>\r\n</tr>\r\n<tr data-start=\"6250\" data-end=\"6346\">\r\n<td data-start=\"6250\" data-end=\"6265\" data-col-size=\"sm\"><strong data-start=\"6252\" data-end=\"6264\">EU-DSGVO</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6265\" data-end=\"6346\">Art. 5, 6, 32 &ndash; Vertraulichkeit, Zweckbindung, Schutz personenbezogener Daten</td>\r\n</tr>\r\n<tr data-start=\"6347\" data-end=\"6421\">\r\n<td data-start=\"6347\" data-end=\"6369\" data-col-size=\"sm\"><strong data-start=\"6349\" data-end=\"6368\">GoBD / HGB / AO</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6369\" data-end=\"6421\">Aufbewahrungspflichten f&uuml;r steuerrelevante Daten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(14, 'DOK-0014', 'Netzwerk & Verschlüsselungssicherheit', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"877\" data-end=\"907\"><strong data-start=\"880\" data-end=\"907\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"909\" data-end=\"1189\">Diese Richtlinie legt Anforderungen zur Absicherung der <strong data-start=\"965\" data-end=\"990\">Netzwerkinfrastruktur</strong> und zur Anwendung von <strong data-start=\"1013\" data-end=\"1029\">Kryptografie</strong> innerhalb der Organisation fest. Ziel ist der Schutz aller Daten und Dienste, die &uuml;ber Netzwerke verarbeitet, gespeichert oder &uuml;bertragen werden, insbesondere:</p>\r\n<ul data-start=\"1191\" data-end=\"1366\">\r\n<li data-start=\"1191\" data-end=\"1235\">\r\n<p data-start=\"1193\" data-end=\"1235\">Schutz vor unbefugtem Zugriff und Abh&ouml;ren,</p>\r\n</li>\r\n<li data-start=\"1236\" data-end=\"1291\">\r\n<p data-start=\"1238\" data-end=\"1291\">Absicherung interner und externer Kommunikationswege,</p>\r\n</li>\r\n<li data-start=\"1292\" data-end=\"1366\">\r\n<p data-start=\"1294\" data-end=\"1366\">Einsatz wirksamer Verschl&uuml;sselung zur Sicherung sensibler Informationen.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1368\" data-end=\"1371\">\r\n<h2 data-start=\"1373\" data-end=\"1398\"><strong data-start=\"1376\" data-end=\"1398\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1400\" data-end=\"1426\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1428\" data-end=\"1768\">\r\n<li data-start=\"1428\" data-end=\"1509\">\r\n<p data-start=\"1430\" data-end=\"1509\"><strong data-start=\"1430\" data-end=\"1458\">Alle Netzwerkkomponenten</strong> (Router, Switches, Firewalls, Access Points, VPNs)</p>\r\n</li>\r\n<li data-start=\"1510\" data-end=\"1578\">\r\n<p data-start=\"1512\" data-end=\"1578\"><strong data-start=\"1512\" data-end=\"1534\">Alle Netzwerkzonen</strong> (LAN, WLAN, DMZ, Internet, Cloud-Anbindung)</p>\r\n</li>\r\n<li data-start=\"1579\" data-end=\"1674\">\r\n<p data-start=\"1581\" data-end=\"1674\"><strong data-start=\"1581\" data-end=\"1638\">Alle Mitarbeiter*innen, Externen, Systeme und Dienste</strong>, die Netzwerkinfrastrukturen nutzen</p>\r\n</li>\r\n<li data-start=\"1675\" data-end=\"1768\">\r\n<p data-start=\"1677\" data-end=\"1768\"><strong data-start=\"1677\" data-end=\"1711\">Alle Verschl&uuml;sselungsma&szlig;nahmen</strong> f&uuml;r Daten&uuml;bertragung, -speicherung und Authentifizierung</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1770\" data-end=\"1773\">\r\n<h2 data-start=\"1775\" data-end=\"1795\"><strong data-start=\"1778\" data-end=\"1795\">3. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"1797\" data-end=\"2207\">\r\n<li data-start=\"1797\" data-end=\"1905\">\r\n<p data-start=\"1799\" data-end=\"1905\"><strong data-start=\"1799\" data-end=\"1905\">Vertrauliche Daten d&uuml;rfen nur &uuml;ber abgesicherte Netzwerke und verschl&uuml;sselte Kan&auml;le &uuml;bertragen werden.</strong></p>\r\n</li>\r\n<li data-start=\"1906\" data-end=\"2013\">\r\n<p data-start=\"1908\" data-end=\"2013\"><strong data-start=\"1908\" data-end=\"2013\">Zug&auml;nge zu Netzwerken sind zu kontrollieren, zu protokollieren und auf das Notwendige zu beschr&auml;nken.</strong></p>\r\n</li>\r\n<li data-start=\"2014\" data-end=\"2120\">\r\n<p data-start=\"2016\" data-end=\"2120\"><strong data-start=\"2016\" data-end=\"2120\">Kryptographische Verfahren m&uuml;ssen dem Stand der Technik entsprechen und regelm&auml;&szlig;ig &uuml;berpr&uuml;ft werden.</strong></p>\r\n</li>\r\n<li data-start=\"2121\" data-end=\"2207\">\r\n<p data-start=\"2123\" data-end=\"2207\"><strong data-start=\"2123\" data-end=\"2207\">Verschl&uuml;sselungsschl&uuml;ssel sind vertraulich zu behandeln und sicher zu verwalten.</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2209\" data-end=\"2212\">\r\n<h2 data-start=\"2214\" data-end=\"2259\"><strong data-start=\"2217\" data-end=\"2259\">4. Anforderungen an Netzwerksicherheit</strong></h2>\r\n<h3 data-start=\"2261\" data-end=\"2290\">4.1 Netzwerksegmentierung</h3>\r\n<ul data-start=\"2292\" data-end=\"2593\">\r\n<li data-start=\"2292\" data-end=\"2396\">\r\n<p data-start=\"2294\" data-end=\"2396\">Interne Netze sind in <strong data-start=\"2316\" data-end=\"2355\">sicherheitszonenbasierten Segmenten</strong> aufzubauen (z. B. B&uuml;ro, Produktion, DMZ)</p>\r\n</li>\r\n<li data-start=\"2397\" data-end=\"2500\">\r\n<p data-start=\"2399\" data-end=\"2500\">Kritische Systeme (z. B. ERP, Active Directory, Steuerungsanlagen) sind in eigenen VLANs zu betreiben</p>\r\n</li>\r\n<li data-start=\"2501\" data-end=\"2593\">\r\n<p data-start=\"2503\" data-end=\"2593\">Kommunikation zwischen Zonen erfolgt ausschlie&szlig;lich &uuml;ber <strong data-start=\"2560\" data-end=\"2593\">kontrollierte Firewall-Regeln</strong></p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2595\" data-end=\"2630\">4.2 Firewall- und Zugangsschutz</h3>\r\n<ul data-start=\"2632\" data-end=\"2906\">\r\n<li data-start=\"2632\" data-end=\"2708\">\r\n<p data-start=\"2634\" data-end=\"2708\">Alle ein- und ausgehenden Verbindungen werden durch <strong data-start=\"2686\" data-end=\"2699\">Firewalls</strong> geregelt</p>\r\n</li>\r\n<li data-start=\"2709\" data-end=\"2778\">\r\n<p data-start=\"2711\" data-end=\"2778\">Firewalls sind zentral zu verwalten und regelm&auml;&szlig;ig zu aktualisieren</p>\r\n</li>\r\n<li data-start=\"2779\" data-end=\"2855\">\r\n<p data-start=\"2781\" data-end=\"2855\"><strong data-start=\"2781\" data-end=\"2805\">Default-Deny-Prinzip</strong>: nur explizit erlaubte Verbindungen sind zul&auml;ssig</p>\r\n</li>\r\n<li data-start=\"2856\" data-end=\"2906\">\r\n<p data-start=\"2858\" data-end=\"2906\">Regelm&auml;&szlig;ige <strong data-start=\"2870\" data-end=\"2889\">Firewall-Review</strong> (mind. j&auml;hrlich)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2908\" data-end=\"2931\">4.3 WLAN-Sicherheit</h3>\r\n<ul data-start=\"2933\" data-end=\"3134\">\r\n<li data-start=\"2933\" data-end=\"3022\">\r\n<p data-start=\"2935\" data-end=\"3022\">Unternehmens-WLAN ist mit <strong data-start=\"2961\" data-end=\"3010\">WPA3 oder mindestens WPA2 Enterprise (802.1X)</strong> abzusichern</p>\r\n</li>\r\n<li data-start=\"3023\" data-end=\"3074\">\r\n<p data-start=\"3025\" data-end=\"3074\">Gast-WLANs sind <strong data-start=\"3041\" data-end=\"3074\">vom Unternehmensnetz getrennt</strong></p>\r\n</li>\r\n<li data-start=\"3075\" data-end=\"3134\">\r\n<p data-start=\"3077\" data-end=\"3134\">SSIDs und Zugriffsberechtigungen werden zentral verwaltet</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3136\" data-end=\"3164\">4.4 Fernzugriffe und VPN</h3>\r\n<ul data-start=\"3166\" data-end=\"3395\">\r\n<li data-start=\"3166\" data-end=\"3262\">\r\n<p data-start=\"3168\" data-end=\"3262\">Remote-Zugriffe erfolgen ausschlie&szlig;lich &uuml;ber <strong data-start=\"3213\" data-end=\"3262\">VPN mit starker Authentifizierung (mind. 2FA)</strong></p>\r\n</li>\r\n<li data-start=\"3263\" data-end=\"3334\">\r\n<p data-start=\"3265\" data-end=\"3334\">Fernzugriffsverbindungen sind <strong data-start=\"3295\" data-end=\"3334\">zeitlich begrenzt und protokolliert</strong></p>\r\n</li>\r\n<li data-start=\"3335\" data-end=\"3395\">\r\n<p data-start=\"3337\" data-end=\"3395\">Kein direkter Zugriff auf produktive Systeme ohne Freigabe</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3397\" data-end=\"3400\">\r\n<h2 data-start=\"3402\" data-end=\"3454\"><strong data-start=\"3405\" data-end=\"3454\">5. Verschl&uuml;sselung &ndash; Allgemeine Anforderungen</strong></h2>\r\n<h3 data-start=\"3456\" data-end=\"3479\">5.1 Einsatzbereiche</h3>\r\n<p data-start=\"3481\" data-end=\"3519\">Verschl&uuml;sselung ist verpflichtend bei:</p>\r\n<ul data-start=\"3521\" data-end=\"3801\">\r\n<li data-start=\"3521\" data-end=\"3617\">\r\n<p data-start=\"3523\" data-end=\"3617\">&Uuml;bertragung vertraulicher oder personenbezogener Daten &uuml;ber &ouml;ffentliche Netze (z. B. Internet)</p>\r\n</li>\r\n<li data-start=\"3618\" data-end=\"3691\">\r\n<p data-start=\"3620\" data-end=\"3691\">Speicherung sensibler Daten auf mobilen Ger&auml;ten, Wechselmedien, Laptops</p>\r\n</li>\r\n<li data-start=\"3692\" data-end=\"3745\">\r\n<p data-start=\"3694\" data-end=\"3745\">Sicherung von Passw&ouml;rtern, Schl&uuml;sseln, Zugangsdaten</p>\r\n</li>\r\n<li data-start=\"3746\" data-end=\"3801\">\r\n<p data-start=\"3748\" data-end=\"3801\">Archivierung von Informationen mit hohem Schutzbedarf</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3803\" data-end=\"3833\">5.2 &Uuml;bertragungssicherheit</h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3835\" data-end=\"4308\">\r\n<thead data-start=\"3835\" data-end=\"3861\">\r\n<tr data-start=\"3835\" data-end=\"3861\">\r\n<th data-start=\"3835\" data-end=\"3846\" data-col-size=\"sm\">Szenario</th>\r\n<th data-start=\"3846\" data-end=\"3861\" data-col-size=\"lg\">Anforderung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3889\" data-end=\"4308\">\r\n<tr data-start=\"3889\" data-end=\"3984\">\r\n<td data-start=\"3889\" data-end=\"3903\" data-col-size=\"sm\">Webzugriffe</td>\r\n<td data-col-size=\"lg\" data-start=\"3903\" data-end=\"3984\"><strong data-start=\"3905\" data-end=\"3926\">HTTPS (TLS &ge; 1.2)</strong> zwingend, keine unsicheren Protokolle (z. B. HTTP, FTP)</td>\r\n</tr>\r\n<tr data-start=\"3985\" data-end=\"4141\">\r\n<td data-start=\"3985\" data-end=\"4002\" data-col-size=\"sm\">E-Mail-Verkehr</td>\r\n<td data-col-size=\"lg\" data-start=\"4002\" data-end=\"4141\">TLS-Verschl&uuml;sselung (MTA-STS, DANE empfohlen), vertrauliche Inhalte zus&auml;tzlich per <strong data-start=\"4087\" data-end=\"4139\">Ende-zu-Ende-Verschl&uuml;sselung (z. B. S/MIME, PGP)</strong></td>\r\n</tr>\r\n<tr data-start=\"4142\" data-end=\"4229\">\r\n<td data-start=\"4142\" data-end=\"4160\" data-col-size=\"sm\">Remote-Zugriffe</td>\r\n<td data-col-size=\"lg\" data-start=\"4160\" data-end=\"4229\">VPN mit starker Verschl&uuml;sselung (z. B. IPsec, OpenVPN, WireGuard)</td>\r\n</tr>\r\n<tr data-start=\"4230\" data-end=\"4308\">\r\n<td data-start=\"4230\" data-end=\"4249\" data-col-size=\"sm\">Datei&uuml;bertragung</td>\r\n<td data-col-size=\"lg\" data-start=\"4249\" data-end=\"4308\">Nur verschl&uuml;sselte Protokolle (z. B. SFTP, HTTPS, FTPS)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<h3 data-start=\"4310\" data-end=\"4349\">5.3 Datenspeicherung (Data at Rest)</h3>\r\n<ul data-start=\"4351\" data-end=\"4735\">\r\n<li data-start=\"4351\" data-end=\"4501\">\r\n<p data-start=\"4353\" data-end=\"4501\"><strong data-start=\"4353\" data-end=\"4375\">Vertrauliche Daten</strong> auf mobilen Ger&auml;ten, USB-Sticks oder Notebooks m&uuml;ssen per <strong data-start=\"4434\" data-end=\"4457\">Vollverschl&uuml;sselung</strong> (z. B. BitLocker, FileVault) gesch&uuml;tzt sein</p>\r\n</li>\r\n<li data-start=\"4502\" data-end=\"4622\">\r\n<p data-start=\"4504\" data-end=\"4622\">Verschl&uuml;sselte Container oder Dateiverschl&uuml;sselung bei sensiblen Daten im Dateisystem (z. B. VeraCrypt, 7-Zip AES-256)</p>\r\n</li>\r\n<li data-start=\"4623\" data-end=\"4735\">\r\n<p data-start=\"4625\" data-end=\"4735\">Cloud-Speicher: <strong data-start=\"4641\" data-end=\"4711\">Ende-zu-Ende-Verschl&uuml;sselung oder Anbieterkonforme Verschl&uuml;sselung</strong> mit Schl&uuml;sselmanagement</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4737\" data-end=\"4740\">\r\n<h2 data-start=\"4742\" data-end=\"4802\"><strong data-start=\"4745\" data-end=\"4802\">6. Kryptographische Verfahren und Schl&uuml;sselmanagement</strong></h2>\r\n<h3 data-start=\"4804\" data-end=\"4847\">6.1 Zul&auml;ssige Algorithmen und Verfahren</h3>\r\n<ul data-start=\"4849\" data-end=\"5142\">\r\n<li data-start=\"4849\" data-end=\"5073\">\r\n<p data-start=\"4851\" data-end=\"4929\">Nur <strong data-start=\"4855\" data-end=\"4919\">anerkannte und dem Stand der Technik entsprechende Verfahren</strong> zul&auml;ssig:</p>\r\n<ul data-start=\"4932\" data-end=\"5073\">\r\n<li data-start=\"4932\" data-end=\"4970\">\r\n<p data-start=\"4934\" data-end=\"4970\">Symmetrisch: <strong data-start=\"4947\" data-end=\"4970\">AES (mind. 256 Bit)</strong></p>\r\n</li>\r\n<li data-start=\"4973\" data-end=\"5037\">\r\n<p data-start=\"4975\" data-end=\"5037\">Asymmetrisch: <strong data-start=\"4989\" data-end=\"5037\">RSA (&ge; 2048 Bit), ECC (mind. 256 Bit Kurven)</strong></p>\r\n</li>\r\n<li data-start=\"5040\" data-end=\"5073\">\r\n<p data-start=\"5042\" data-end=\"5073\">Hashes: <strong data-start=\"5050\" data-end=\"5073\">SHA-256 oder besser</strong></p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"5074\" data-end=\"5142\">\r\n<p data-start=\"5076\" data-end=\"5142\">Unsichere Verfahren wie <strong data-start=\"5100\" data-end=\"5124\">MD5, SHA-1, DES, RC4</strong> sind <strong data-start=\"5130\" data-end=\"5142\">verboten</strong></p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"5144\" data-end=\"5171\">6.2 Schl&uuml;sselmanagement</h3>\r\n<ul data-start=\"5173\" data-end=\"5550\">\r\n<li data-start=\"5173\" data-end=\"5397\">\r\n<p data-start=\"5175\" data-end=\"5206\">Kryptografische Schl&uuml;ssel sind:</p>\r\n<ul data-start=\"5209\" data-end=\"5397\">\r\n<li data-start=\"5209\" data-end=\"5240\">\r\n<p data-start=\"5211\" data-end=\"5240\"><strong data-start=\"5211\" data-end=\"5226\">vertraulich</strong> zu behandeln,</p>\r\n</li>\r\n<li data-start=\"5243\" data-end=\"5337\">\r\n<p data-start=\"5245\" data-end=\"5337\">in <strong data-start=\"5248\" data-end=\"5288\">sicheren HSMs oder Passwort-Tresoren</strong> zu speichern (z. B. HashiCorp Vault, KeePassXC),</p>\r\n</li>\r\n<li data-start=\"5340\" data-end=\"5397\">\r\n<p data-start=\"5342\" data-end=\"5397\">mit <strong data-start=\"5346\" data-end=\"5361\">Ablaufdatum</strong> versehen und regelm&auml;&szlig;ig zu rotieren</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"5398\" data-end=\"5466\">\r\n<p data-start=\"5400\" data-end=\"5466\"><strong data-start=\"5400\" data-end=\"5444\">Schl&uuml;sselvergabe, -nutzung und -l&ouml;schung</strong> sind zu dokumentieren</p>\r\n</li>\r\n<li data-start=\"5467\" data-end=\"5550\">\r\n<p data-start=\"5469\" data-end=\"5550\"><strong data-start=\"5469\" data-end=\"5528\">Private Keys d&uuml;rfen niemals unverschl&uuml;sselt gespeichert</strong> oder versendet werden</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5552\" data-end=\"5555\">\r\n<h2 data-start=\"5557\" data-end=\"5590\"><strong data-start=\"5560\" data-end=\"5590\">7. &Uuml;berwachung und Logging</strong></h2>\r\n<ul data-start=\"5592\" data-end=\"5877\">\r\n<li data-start=\"5592\" data-end=\"5714\">\r\n<p data-start=\"5594\" data-end=\"5714\">Sicherheitsrelevante Netzwerkaktivit&auml;ten werden <strong data-start=\"5642\" data-end=\"5659\">protokolliert</strong> (z. B. Firewall-Logs, VPN-Nutzung, IDS/IPS-Ereignisse)</p>\r\n</li>\r\n<li data-start=\"5715\" data-end=\"5795\">\r\n<p data-start=\"5717\" data-end=\"5795\">Zugriff auf verschl&uuml;sselte Daten wird protokolliert und regelm&auml;&szlig;ig ausgewertet</p>\r\n</li>\r\n<li data-start=\"5796\" data-end=\"5877\">\r\n<p data-start=\"5798\" data-end=\"5877\">Auff&auml;llige oder unautorisierte Netzwerkaktivit&auml;ten l&ouml;sen <strong data-start=\"5855\" data-end=\"5873\">Alarme im SIEM</strong> aus</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5879\" data-end=\"5882\">\r\n<h2 data-start=\"5884\" data-end=\"5914\"><strong data-start=\"5887\" data-end=\"5914\">8. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5916\" data-end=\"6479\">\r\n<thead data-start=\"5916\" data-end=\"5950\">\r\n<tr data-start=\"5916\" data-end=\"5950\">\r\n<th data-start=\"5916\" data-end=\"5938\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5938\" data-end=\"5950\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5986\" data-end=\"6479\">\r\n<tr data-start=\"5986\" data-end=\"6085\">\r\n<td data-start=\"5986\" data-end=\"6021\" data-col-size=\"sm\"><strong data-start=\"5988\" data-end=\"6020\">IT-Abteilung / Netzwerkadmin</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6021\" data-end=\"6085\">Einrichtung, Betrieb und Kontrolle der Netzwerkinfrastruktur</td>\r\n</tr>\r\n<tr data-start=\"6086\" data-end=\"6189\">\r\n<td data-start=\"6086\" data-end=\"6111\" data-col-size=\"sm\"><strong data-start=\"6088\" data-end=\"6109\">ISB / IT-Security</strong></td>\r\n<td data-start=\"6111\" data-end=\"6189\" data-col-size=\"md\">Kontrolle der Sicherheitsma&szlig;nahmen, Freigabe von Verschl&uuml;sselungsverfahren</td>\r\n</tr>\r\n<tr data-start=\"6190\" data-end=\"6287\">\r\n<td data-start=\"6190\" data-end=\"6227\" data-col-size=\"sm\"><strong data-start=\"6192\" data-end=\"6226\">DSB (Datenschutzbeauftragte*r)</strong></td>\r\n<td data-start=\"6227\" data-end=\"6287\" data-col-size=\"md\">Freigabe von Verschl&uuml;sselung bei personenbezogenen Daten</td>\r\n</tr>\r\n<tr data-start=\"6288\" data-end=\"6394\">\r\n<td data-start=\"6288\" data-end=\"6316\" data-col-size=\"sm\"><strong data-start=\"6290\" data-end=\"6315\">Systemverantwortliche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6316\" data-end=\"6394\">Sicherstellung der Anwendung der Vorgaben im eigenen Verantwortungsbereich</td>\r\n</tr>\r\n<tr data-start=\"6395\" data-end=\"6479\">\r\n<td data-start=\"6395\" data-end=\"6419\" data-col-size=\"sm\"><strong data-start=\"6397\" data-end=\"6418\">Alle Nutzer*innen</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6419\" data-end=\"6479\">Sicherer Umgang mit Netzverbindungen und sensiblen Daten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"6481\" data-end=\"6484\">\r\n<h2 data-start=\"6486\" data-end=\"6534\"><strong data-start=\"6489\" data-end=\"6534\">9. Schnittstellen zu weiteren Richtlinien</strong></h2>\r\n<p data-start=\"6536\" data-end=\"6561\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"6563\" data-end=\"6737\">\r\n<li data-start=\"6563\" data-end=\"6602\">\r\n<p data-start=\"6565\" data-end=\"6602\"><strong data-start=\"6565\" data-end=\"6602\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6603\" data-end=\"6627\">\r\n<p data-start=\"6605\" data-end=\"6627\"><strong data-start=\"6605\" data-end=\"6627\">Zugriffsmanagement</strong></p>\r\n</li>\r\n<li data-start=\"6628\" data-end=\"6660\">\r\n<p data-start=\"6630\" data-end=\"6660\"><strong data-start=\"6630\" data-end=\"6660\">Backup &amp; Wiederherstellung</strong></p>\r\n</li>\r\n<li data-start=\"6661\" data-end=\"6695\">\r\n<p data-start=\"6663\" data-end=\"6695\"><strong data-start=\"6663\" data-end=\"6695\">Security Incident Management</strong></p>\r\n</li>\r\n<li data-start=\"6696\" data-end=\"6737\">\r\n<p data-start=\"6698\" data-end=\"6737\"><strong data-start=\"6698\" data-end=\"6737\">Cloud- und Mobile Device-Richtlinie</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6739\" data-end=\"6742\">\r\n<h2 data-start=\"6744\" data-end=\"6784\"><strong data-start=\"6747\" data-end=\"6784\">10. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6786\" data-end=\"7222\">\r\n<thead data-start=\"6786\" data-end=\"6822\">\r\n<tr data-start=\"6786\" data-end=\"6822\">\r\n<th data-start=\"6786\" data-end=\"6812\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6812\" data-end=\"6822\" data-col-size=\"lg\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6861\" data-end=\"7222\">\r\n<tr data-start=\"6861\" data-end=\"6994\">\r\n<td data-start=\"6861\" data-end=\"6888\" data-col-size=\"sm\"><strong data-start=\"6863\" data-end=\"6880\">ISO/IEC 27001</strong></td>\r\n<td data-start=\"6888\" data-end=\"6994\" data-col-size=\"lg\">A.8.20 (Netzwerkzugriffskontrolle), A.10.1 (Kryptografische Ma&szlig;nahmen), A.8.23 (Netzwerksegmentierung)</td>\r\n</tr>\r\n<tr data-start=\"6995\" data-end=\"7108\">\r\n<td data-start=\"6995\" data-end=\"7022\" data-col-size=\"sm\"><strong data-start=\"6997\" data-end=\"7019\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"7022\" data-end=\"7108\">NET.1, NET.2 (Netze), SYS.1.1 (Server), OPS.1.2.2 (VPN), OPS.1.1.3 (Kryptokonzept)</td>\r\n</tr>\r\n<tr data-start=\"7109\" data-end=\"7222\">\r\n<td data-start=\"7109\" data-end=\"7136\" data-col-size=\"sm\"><strong data-start=\"7111\" data-end=\"7128\">DSGVO Art. 32</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"7136\" data-end=\"7222\">Sicherheit der Verarbeitung &ndash; insbesondere Verschl&uuml;sselung personenbezogener Daten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(15, 'DOK-0015', 'Physische Sicherheit', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"805\" data-end=\"835\"><strong data-start=\"808\" data-end=\"835\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"837\" data-end=\"1151\">Ziel dieser Richtlinie ist der Schutz von <strong data-start=\"879\" data-end=\"945\">Mitarbeitenden, Informationen, IT-Systemen und Infrastrukturen</strong> vor <strong data-start=\"950\" data-end=\"976\">physischen Bedrohungen</strong> wie unbefugtem Zutritt, Diebstahl, Vandalismus, Brand oder Wassersch&auml;den. Sie definiert verbindliche Vorgaben f&uuml;r den sicheren Betrieb physischer Einrichtungen, insbesondere:</p>\r\n<ul data-start=\"1153\" data-end=\"1288\">\r\n<li data-start=\"1153\" data-end=\"1166\">\r\n<p data-start=\"1155\" data-end=\"1166\">B&uuml;ror&auml;ume</p>\r\n</li>\r\n<li data-start=\"1167\" data-end=\"1201\">\r\n<p data-start=\"1169\" data-end=\"1201\">Serverr&auml;ume und Technikfl&auml;chen</p>\r\n</li>\r\n<li data-start=\"1202\" data-end=\"1219\">\r\n<p data-start=\"1204\" data-end=\"1219\">Rechenzentren</p>\r\n</li>\r\n<li data-start=\"1220\" data-end=\"1246\">\r\n<p data-start=\"1222\" data-end=\"1246\">Archiv- und Lagerr&auml;ume</p>\r\n</li>\r\n<li data-start=\"1247\" data-end=\"1288\">\r\n<p data-start=\"1249\" data-end=\"1288\">Zugangswege und Zutrittskontrollsysteme</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1290\" data-end=\"1293\">\r\n<h2 data-start=\"1295\" data-end=\"1320\"><strong data-start=\"1298\" data-end=\"1320\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1322\" data-end=\"1348\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1350\" data-end=\"1639\">\r\n<li data-start=\"1350\" data-end=\"1445\">\r\n<p data-start=\"1352\" data-end=\"1445\"><strong data-start=\"1352\" data-end=\"1404\">Alle Geb&auml;ude, R&auml;umlichkeiten und Infrastrukturen</strong>, die von der Organisation genutzt werden</p>\r\n</li>\r\n<li data-start=\"1446\" data-end=\"1548\">\r\n<p data-start=\"1448\" data-end=\"1548\"><strong data-start=\"1448\" data-end=\"1508\">Alle Mitarbeitenden, Besucher, Dienstleister und Externe</strong>, die sich in diesen Bereichen aufhalten</p>\r\n</li>\r\n<li data-start=\"1549\" data-end=\"1639\">\r\n<p data-start=\"1551\" data-end=\"1639\"><strong data-start=\"1551\" data-end=\"1577\">Alle physischen Assets</strong> (Server, Clients, Netzwerktechnik, Drucker, Datentr&auml;ger etc.)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1641\" data-end=\"1644\">\r\n<h2 data-start=\"1646\" data-end=\"1666\"><strong data-start=\"1649\" data-end=\"1666\">3. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"1668\" data-end=\"2074\">\r\n<li data-start=\"1668\" data-end=\"1779\">\r\n<p data-start=\"1670\" data-end=\"1779\"><strong data-start=\"1670\" data-end=\"1779\">Physischer Zugang zu sch&uuml;tzenswerten Bereichen ist zu kontrollieren, zu protokollieren und zu beschr&auml;nken</strong></p>\r\n</li>\r\n<li data-start=\"1780\" data-end=\"1865\">\r\n<p data-start=\"1782\" data-end=\"1865\">Nur autorisierte Personen d&uuml;rfen Zugang zu sicherheitsrelevanten Bereichen erhalten</p>\r\n</li>\r\n<li data-start=\"1866\" data-end=\"1972\">\r\n<p data-start=\"1868\" data-end=\"1972\">Schutzziele: <strong data-start=\"1881\" data-end=\"1900\">Vertraulichkeit</strong>, <strong data-start=\"1902\" data-end=\"1919\">Verf&uuml;gbarkeit</strong> und <strong data-start=\"1924\" data-end=\"1938\">Integrit&auml;t</strong> von Informationen und IT-Systemen</p>\r\n</li>\r\n<li data-start=\"1973\" data-end=\"2074\">\r\n<p data-start=\"1975\" data-end=\"2074\">Physische Sicherheitsma&szlig;nahmen orientieren sich am <strong data-start=\"2026\" data-end=\"2074\">Schutzbedarf der verarbeiteten Informationen</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2076\" data-end=\"2079\">\r\n<h2 data-start=\"2081\" data-end=\"2126\"><strong data-start=\"2084\" data-end=\"2126\">4. Zutrittskontrolle und Zugangsschutz</strong></h2>\r\n<h3 data-start=\"2128\" data-end=\"2149\">4.1 Zutrittszonen</h3>\r\n<p data-start=\"2151\" data-end=\"2208\">R&auml;umlichkeiten werden in <strong data-start=\"2176\" data-end=\"2196\">Sicherheitszonen</strong> eingeteilt:</p>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2210\" data-end=\"2596\">\r\n<thead data-start=\"2210\" data-end=\"2242\">\r\n<tr data-start=\"2210\" data-end=\"2242\">\r\n<th data-start=\"2210\" data-end=\"2217\" data-col-size=\"sm\">Zone</th>\r\n<th data-start=\"2217\" data-end=\"2232\" data-col-size=\"md\">Beschreibung</th>\r\n<th data-start=\"2232\" data-end=\"2242\" data-col-size=\"sm\">Zugang</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2276\" data-end=\"2596\">\r\n<tr data-start=\"2276\" data-end=\"2349\">\r\n<td data-start=\"2276\" data-end=\"2289\" data-col-size=\"sm\">&Ouml;ffentlich</td>\r\n<td data-start=\"2289\" data-end=\"2325\" data-col-size=\"md\">Empfang, Besprechungsr&auml;ume, Lobby</td>\r\n<td data-col-size=\"sm\" data-start=\"2325\" data-end=\"2349\">frei / mit Anmeldung</td>\r\n</tr>\r\n<tr data-start=\"2350\" data-end=\"2412\">\r\n<td data-start=\"2350\" data-end=\"2359\" data-col-size=\"sm\">Intern</td>\r\n<td data-start=\"2359\" data-end=\"2390\" data-col-size=\"md\">B&uuml;rofl&auml;chen, Arbeitsbereiche</td>\r\n<td data-col-size=\"sm\" data-start=\"2390\" data-end=\"2412\">Mitarbeiterausweis</td>\r\n</tr>\r\n<tr data-start=\"2413\" data-end=\"2489\">\r\n<td data-start=\"2413\" data-end=\"2424\" data-col-size=\"sm\">Sensitiv</td>\r\n<td data-col-size=\"md\" data-start=\"2424\" data-end=\"2460\">Serverr&auml;ume, Archiv, Technikr&auml;ume</td>\r\n<td data-col-size=\"sm\" data-start=\"2460\" data-end=\"2489\">nur autorisierte Personen</td>\r\n</tr>\r\n<tr data-start=\"2490\" data-end=\"2596\">\r\n<td data-start=\"2490\" data-end=\"2503\" data-col-size=\"sm\">Hochsicher</td>\r\n<td data-col-size=\"md\" data-start=\"2503\" data-end=\"2553\">Rechenzentrum, Backup-Lager, Sicherheitsarchive</td>\r\n<td data-col-size=\"sm\" data-start=\"2553\" data-end=\"2596\">nur freigegebene Personen, ggf. mit 2FA</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<h3 data-start=\"2598\" data-end=\"2628\">4.2 Zugangskontrollsysteme</h3>\r\n<ul data-start=\"2630\" data-end=\"2879\">\r\n<li data-start=\"2630\" data-end=\"2728\">\r\n<p data-start=\"2632\" data-end=\"2728\">Elektronische Zutrittssysteme mit Protokollierung (z. B. Ausweissysteme, Karten, PIN, Biometrie)</p>\r\n</li>\r\n<li data-start=\"2729\" data-end=\"2803\">\r\n<p data-start=\"2731\" data-end=\"2803\">Besucherausweise und <strong data-start=\"2752\" data-end=\"2770\">Begleitpflicht</strong> f&uuml;r G&auml;ste in sensiblen Bereichen</p>\r\n</li>\r\n<li data-start=\"2804\" data-end=\"2879\">\r\n<p data-start=\"2806\" data-end=\"2879\">Regelm&auml;&szlig;ige <strong data-start=\"2818\" data-end=\"2879\">&Uuml;berpr&uuml;fung und Aktualisierung der Zutrittsberechtigungen</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2881\" data-end=\"2884\">\r\n<h2 data-start=\"2886\" data-end=\"2921\"><strong data-start=\"2889\" data-end=\"2921\">5. Schutz sensibler Bereiche</strong></h2>\r\n<h3 data-start=\"2923\" data-end=\"2958\">5.1 Serverr&auml;ume / Rechenzentren</h3>\r\n<ul data-start=\"2960\" data-end=\"3225\">\r\n<li data-start=\"2960\" data-end=\"3021\">\r\n<p data-start=\"2962\" data-end=\"3021\"><strong data-start=\"2962\" data-end=\"2990\">Zutritt stark beschr&auml;nkt</strong> (nur nach vorheriger Freigabe)</p>\r\n</li>\r\n<li data-start=\"3022\" data-end=\"3091\">\r\n<p data-start=\"3024\" data-end=\"3091\"><strong data-start=\"3024\" data-end=\"3048\">Massiver Brandschutz</strong> (Brandmelder, L&ouml;schanlage, Brandabschnitt)</p>\r\n</li>\r\n<li data-start=\"3092\" data-end=\"3143\">\r\n<p data-start=\"3094\" data-end=\"3143\"><strong data-start=\"3094\" data-end=\"3143\">Klimatisierung und Luftfeuchtigkeitskontrolle</strong></p>\r\n</li>\r\n<li data-start=\"3144\" data-end=\"3176\">\r\n<p data-start=\"3146\" data-end=\"3176\"><strong data-start=\"3146\" data-end=\"3176\">USV und Notstromversorgung</strong></p>\r\n</li>\r\n<li data-start=\"3177\" data-end=\"3225\">\r\n<p data-start=\"3179\" data-end=\"3225\"><strong data-start=\"3179\" data-end=\"3225\">&Uuml;berwachung durch Kamera oder Alarmsysteme</strong></p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3227\" data-end=\"3244\">5.2 B&uuml;ror&auml;ume</h3>\r\n<ul data-start=\"3246\" data-end=\"3500\">\r\n<li data-start=\"3246\" data-end=\"3330\">\r\n<p data-start=\"3248\" data-end=\"3330\">T&uuml;ren und Fenster m&uuml;ssen bei Verlassen <strong data-start=\"3287\" data-end=\"3325\">geschlossen und ggf. abgeschlossen</strong> sein</p>\r\n</li>\r\n<li data-start=\"3331\" data-end=\"3407\">\r\n<p data-start=\"3333\" data-end=\"3407\">Zugriff auf Arbeitspl&auml;tze au&szlig;erhalb der Arbeitszeiten nur bei Berechtigung</p>\r\n</li>\r\n<li data-start=\"3408\" data-end=\"3500\">\r\n<p data-start=\"3410\" data-end=\"3500\">Bildschirmarbeitspl&auml;tze mit Sichtschutz bei vertraulichen Daten (Privacy Filter empfohlen)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3502\" data-end=\"3505\">\r\n<h2 data-start=\"3507\" data-end=\"3537\"><strong data-start=\"3510\" data-end=\"3537\">6. Umgang mit Besuchern</strong></h2>\r\n<ul data-start=\"3539\" data-end=\"3765\">\r\n<li data-start=\"3539\" data-end=\"3590\">\r\n<p data-start=\"3541\" data-end=\"3590\">Besucher sind <strong data-start=\"3555\" data-end=\"3569\">anzumelden</strong> und zu <strong data-start=\"3577\" data-end=\"3590\">begleiten</strong></p>\r\n</li>\r\n<li data-start=\"3591\" data-end=\"3650\">\r\n<p data-start=\"3593\" data-end=\"3650\">Besucher erhalten <strong data-start=\"3611\" data-end=\"3650\">zeitlich begrenzte Besucherausweise</strong></p>\r\n</li>\r\n<li data-start=\"3651\" data-end=\"3713\">\r\n<p data-start=\"3653\" data-end=\"3713\">Keine Einsicht in vertrauliche Informationen oder IT-Systeme</p>\r\n</li>\r\n<li data-start=\"3714\" data-end=\"3765\">\r\n<p data-start=\"3716\" data-end=\"3765\">Besucherliste ist <strong data-start=\"3734\" data-end=\"3765\">zu f&uuml;hren und aufzubewahren</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3767\" data-end=\"3770\">\r\n<h2 data-start=\"3772\" data-end=\"3806\"><strong data-start=\"3775\" data-end=\"3806\">7. Schutz physischer Assets</strong></h2>\r\n<ul data-start=\"3808\" data-end=\"4088\">\r\n<li data-start=\"3808\" data-end=\"3909\">\r\n<p data-start=\"3810\" data-end=\"3909\">Server, Notebooks, Switches etc. sind <strong data-start=\"3848\" data-end=\"3868\">gegen Entwendung</strong> zu sichern (z. B. Schr&auml;nke, Ankerpunkte)</p>\r\n</li>\r\n<li data-start=\"3910\" data-end=\"3977\">\r\n<p data-start=\"3912\" data-end=\"3977\">Keine <strong data-start=\"3918\" data-end=\"3954\">offene Lagerung von Datentr&auml;gern</strong> mit sensiblen Inhalten</p>\r\n</li>\r\n<li data-start=\"3978\" data-end=\"4088\">\r\n<p data-start=\"3980\" data-end=\"4088\"><strong data-start=\"3980\" data-end=\"4002\">Sichere Entsorgung</strong> alter Ger&auml;te und Datentr&auml;ger gem&auml;&szlig; L&ouml;schrichtlinie / BSI-Empfehlungen (z. B. M 2.167)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4090\" data-end=\"4093\">\r\n<h2 data-start=\"4095\" data-end=\"4130\"><strong data-start=\"4098\" data-end=\"4130\">8. Schutz vor Umweltgefahren</strong></h2>\r\n<ul data-start=\"4132\" data-end=\"4386\">\r\n<li data-start=\"4132\" data-end=\"4317\">\r\n<p data-start=\"4134\" data-end=\"4158\">Risikominimierung durch:</p>\r\n<ul data-start=\"4161\" data-end=\"4317\">\r\n<li data-start=\"4161\" data-end=\"4183\">\r\n<p data-start=\"4163\" data-end=\"4183\">Brandschutzma&szlig;nahmen</p>\r\n</li>\r\n<li data-start=\"4186\" data-end=\"4221\">\r\n<p data-start=\"4188\" data-end=\"4221\">Wassermelder in kritischen R&auml;umen</p>\r\n</li>\r\n<li data-start=\"4224\" data-end=\"4280\">\r\n<p data-start=\"4226\" data-end=\"4280\">Zugang zu Technikr&auml;umen oberhalb von Hochwassergrenzen</p>\r\n</li>\r\n<li data-start=\"4283\" data-end=\"4317\">\r\n<p data-start=\"4285\" data-end=\"4317\">Blitzschutz, &Uuml;berspannungsschutz</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"4319\" data-end=\"4386\">\r\n<p data-start=\"4321\" data-end=\"4386\">J&auml;hrliche <strong data-start=\"4331\" data-end=\"4354\">Sicherheitsbegehung</strong> durch Facility Management / ISB</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4388\" data-end=\"4391\">\r\n<h2 data-start=\"4393\" data-end=\"4437\"><strong data-start=\"4396\" data-end=\"4437\">9. Mobile und tempor&auml;re Arbeitspl&auml;tze</strong></h2>\r\n<ul data-start=\"4439\" data-end=\"4709\">\r\n<li data-start=\"4439\" data-end=\"4542\">\r\n<p data-start=\"4441\" data-end=\"4477\">Sicherheitsvorgaben gelten auch f&uuml;r:</p>\r\n<ul data-start=\"4480\" data-end=\"4542\">\r\n<li data-start=\"4480\" data-end=\"4492\">\r\n<p data-start=\"4482\" data-end=\"4492\">Homeoffice</p>\r\n</li>\r\n<li data-start=\"4495\" data-end=\"4513\">\r\n<p data-start=\"4497\" data-end=\"4513\">Coworking Spaces</p>\r\n</li>\r\n<li data-start=\"4516\" data-end=\"4542\">\r\n<p data-start=\"4518\" data-end=\"4542\">Externe Projektstandorte</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"4544\" data-end=\"4600\">\r\n<p data-start=\"4546\" data-end=\"4600\">Arbeitsger&auml;te sind <strong data-start=\"4565\" data-end=\"4590\">nicht unbeaufsichtigt</strong> zu lassen</p>\r\n</li>\r\n<li data-start=\"4601\" data-end=\"4653\">\r\n<p data-start=\"4603\" data-end=\"4653\">Vertrauliche Dokumente <strong data-start=\"4626\" data-end=\"4653\">unter Verschluss halten</strong></p>\r\n</li>\r\n<li data-start=\"4654\" data-end=\"4709\">\r\n<p data-start=\"4656\" data-end=\"4709\"><strong data-start=\"4656\" data-end=\"4676\">Bildschirmsperre</strong> bei Verlassen des Arbeitsplatzes</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4711\" data-end=\"4714\">\r\n<h2 data-start=\"4716\" data-end=\"4752\"><strong data-start=\"4719\" data-end=\"4752\">10. &Uuml;berwachung und Kontrolle</strong></h2>\r\n<ul data-start=\"4754\" data-end=\"5009\">\r\n<li data-start=\"4754\" data-end=\"4835\">\r\n<p data-start=\"4756\" data-end=\"4835\">Zutritte zu sensiblen Bereichen werden <strong data-start=\"4795\" data-end=\"4835\">protokolliert und regelm&auml;&szlig;ig gepr&uuml;ft</strong></p>\r\n</li>\r\n<li data-start=\"4836\" data-end=\"4912\">\r\n<p data-start=\"4838\" data-end=\"4912\">Kameras nur in definierten Bereichen und unter Beachtung des Datenschutzes</p>\r\n</li>\r\n<li data-start=\"4913\" data-end=\"5009\">\r\n<p data-start=\"4915\" data-end=\"5009\">Unregelm&auml;&szlig;igkeiten (z. B. aufgebrochene T&uuml;ren, verd&auml;chtige Personen) sind <strong data-start=\"4989\" data-end=\"5009\">sofort zu melden</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5011\" data-end=\"5014\">\r\n<h2 data-start=\"5016\" data-end=\"5047\"><strong data-start=\"5019\" data-end=\"5047\">11. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5049\" data-end=\"5514\">\r\n<thead data-start=\"5049\" data-end=\"5069\">\r\n<tr data-start=\"5049\" data-end=\"5069\">\r\n<th data-start=\"5049\" data-end=\"5057\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5057\" data-end=\"5069\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5091\" data-end=\"5514\">\r\n<tr data-start=\"5091\" data-end=\"5193\">\r\n<td data-start=\"5091\" data-end=\"5117\" data-col-size=\"sm\"><strong data-start=\"5093\" data-end=\"5116\">Facility Management</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5117\" data-end=\"5193\">Betrieb und Wartung der Zugangssysteme, physische Sicherheit der Geb&auml;ude</td>\r\n</tr>\r\n<tr data-start=\"5194\" data-end=\"5289\">\r\n<td data-start=\"5194\" data-end=\"5220\" data-col-size=\"sm\"><strong data-start=\"5196\" data-end=\"5219\">ISB / IT-Sicherheit</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5220\" data-end=\"5289\">Definition sicherheitsrelevanter Anforderungen, Kontrollma&szlig;nahmen</td>\r\n</tr>\r\n<tr data-start=\"5290\" data-end=\"5363\">\r\n<td data-start=\"5290\" data-end=\"5311\" data-col-size=\"sm\"><strong data-start=\"5292\" data-end=\"5310\">F&uuml;hrungskr&auml;fte</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5311\" data-end=\"5363\">Genehmigung von Zutrittsrechten, Vorbildfunktion</td>\r\n</tr>\r\n<tr data-start=\"5364\" data-end=\"5442\">\r\n<td data-start=\"5364\" data-end=\"5390\" data-col-size=\"sm\"><strong data-start=\"5366\" data-end=\"5389\">Alle Mitarbeitenden</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5390\" data-end=\"5442\">Einhaltung der Regelungen, Meldung von Vorf&auml;llen</td>\r\n</tr>\r\n<tr data-start=\"5443\" data-end=\"5514\">\r\n<td data-start=\"5443\" data-end=\"5466\" data-col-size=\"sm\"><strong data-start=\"5445\" data-end=\"5465\">Empfang / Pforte</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5466\" data-end=\"5514\">Besucherregistrierung, Ausgabe von Ausweisen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5516\" data-end=\"5519\">\r\n<h2 data-start=\"5521\" data-end=\"5570\"><strong data-start=\"5524\" data-end=\"5570\">12. Schnittstellen zu weiteren Richtlinien</strong></h2>\r\n<p data-start=\"5572\" data-end=\"5597\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"5599\" data-end=\"5755\">\r\n<li data-start=\"5599\" data-end=\"5638\">\r\n<p data-start=\"5601\" data-end=\"5638\"><strong data-start=\"5601\" data-end=\"5638\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"5639\" data-end=\"5663\">\r\n<p data-start=\"5641\" data-end=\"5663\"><strong data-start=\"5641\" data-end=\"5663\">Zugriffsmanagement</strong></p>\r\n</li>\r\n<li data-start=\"5664\" data-end=\"5686\">\r\n<p data-start=\"5666\" data-end=\"5686\"><strong data-start=\"5666\" data-end=\"5686\">Asset Management</strong></p>\r\n</li>\r\n<li data-start=\"5687\" data-end=\"5710\">\r\n<p data-start=\"5689\" data-end=\"5710\"><strong data-start=\"5689\" data-end=\"5710\">Notfallmanagement</strong></p>\r\n</li>\r\n<li data-start=\"5711\" data-end=\"5755\">\r\n<p data-start=\"5713\" data-end=\"5755\"><strong data-start=\"5713\" data-end=\"5755\">Homeoffice- und Mobile-Work-Richtlinie</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5757\" data-end=\"5760\">\r\n<h2 data-start=\"5762\" data-end=\"5802\"><strong data-start=\"5765\" data-end=\"5802\">13. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5804\" data-end=\"6144\">\r\n<thead data-start=\"5804\" data-end=\"5832\">\r\n<tr data-start=\"5804\" data-end=\"5832\">\r\n<th data-start=\"5804\" data-end=\"5822\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"5822\" data-end=\"5832\" data-col-size=\"md\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5862\" data-end=\"6144\">\r\n<tr data-start=\"5862\" data-end=\"5940\">\r\n<td data-start=\"5862\" data-end=\"5887\" data-col-size=\"sm\"><strong data-start=\"5864\" data-end=\"5886\">ISO/IEC 27001:2022</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5887\" data-end=\"5940\">A.7.1 &ndash; A.7.5 &ndash; Physische Sicherheit und Umgebung</td>\r\n</tr>\r\n<tr data-start=\"5941\" data-end=\"6062\">\r\n<td data-start=\"5941\" data-end=\"5966\" data-col-size=\"sm\"><strong data-start=\"5943\" data-end=\"5965\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5966\" data-end=\"6062\">INF.1 (Geb&auml;ude), INF.2 (Serverraum), INF.3 (Rechenzentrum), INF.5 (Informationsverarbeitung)</td>\r\n</tr>\r\n<tr data-start=\"6063\" data-end=\"6144\">\r\n<td data-start=\"6063\" data-end=\"6082\" data-col-size=\"sm\"><strong data-start=\"6065\" data-end=\"6081\">DSGVO / BDSG</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6082\" data-end=\"6144\">Zutrittskontrolle als Bestandteil der TOMs (Art. 32 DSGVO)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(16, 'DOK-0016', 'Secure Software Development', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"907\" data-end=\"937\"><strong data-start=\"910\" data-end=\"937\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"939\" data-end=\"1160\">Ziel dieser Richtlinie ist es, die Entwicklung, Pflege und Integration von Softwarel&ouml;sungen so zu gestalten, dass sie den Prinzipien der <strong data-start=\"1076\" data-end=\"1102\">Informationssicherheit</strong> entsprechen. Dies beinhaltet insbesondere den Schutz vor:</p>\r\n<ul data-start=\"1162\" data-end=\"1316\">\r\n<li data-start=\"1162\" data-end=\"1208\">\r\n<p data-start=\"1164\" data-end=\"1208\">Schwachstellen (z. B. Injection, XSS, CSRF),</p>\r\n</li>\r\n<li data-start=\"1209\" data-end=\"1234\">\r\n<p data-start=\"1211\" data-end=\"1234\">Manipulation von Daten,</p>\r\n</li>\r\n<li data-start=\"1235\" data-end=\"1259\">\r\n<p data-start=\"1237\" data-end=\"1259\">unbefugtem Zugriff und</p>\r\n</li>\r\n<li data-start=\"1260\" data-end=\"1316\">\r\n<p data-start=\"1262\" data-end=\"1316\">Verst&ouml;&szlig;en gegen Datenschutz- oder Compliance-Vorgaben.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1318\" data-end=\"1321\">\r\n<h2 data-start=\"1323\" data-end=\"1348\"><strong data-start=\"1326\" data-end=\"1348\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1350\" data-end=\"1376\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1378\" data-end=\"1672\">\r\n<li data-start=\"1378\" data-end=\"1443\">\r\n<p data-start=\"1380\" data-end=\"1443\"><strong data-start=\"1380\" data-end=\"1443\">Alle internen und extern beauftragten Softwareentwicklungen</strong></p>\r\n</li>\r\n<li data-start=\"1444\" data-end=\"1506\">\r\n<p data-start=\"1446\" data-end=\"1506\"><strong data-start=\"1446\" data-end=\"1500\">Webanwendungen, mobile Apps, APIs, Skripte, Makros</strong>, etc.</p>\r\n</li>\r\n<li data-start=\"1507\" data-end=\"1572\">\r\n<p data-start=\"1509\" data-end=\"1572\"><strong data-start=\"1509\" data-end=\"1572\">Entwicklungs-, Test-, Integrations- und Produktivumgebungen</strong></p>\r\n</li>\r\n<li data-start=\"1573\" data-end=\"1672\">\r\n<p data-start=\"1575\" data-end=\"1672\"><strong data-start=\"1575\" data-end=\"1602\">Alle beteiligten Rollen</strong> (Entwicklung, Architektur, QA, DevOps, IT-Sicherheit, Projektleitung)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1674\" data-end=\"1677\">\r\n<h2 data-start=\"1679\" data-end=\"1732\"><strong data-start=\"1682\" data-end=\"1732\">3. Grunds&auml;tze der sicheren Softwareentwicklung</strong></h2>\r\n<ul data-start=\"1734\" data-end=\"2165\">\r\n<li data-start=\"1734\" data-end=\"1839\">\r\n<p data-start=\"1736\" data-end=\"1839\">Sicherheit ist <strong data-start=\"1751\" data-end=\"1805\">Bestandteil des gesamten Entwicklungszyklus (SDLC)</strong> &ndash; von der Planung bis zum Betrieb</p>\r\n</li>\r\n<li data-start=\"1840\" data-end=\"1978\">\r\n<p data-start=\"1842\" data-end=\"1978\">Anforderungen der <strong data-start=\"1860\" data-end=\"1908\">Informationssicherheit und des Datenschutzes</strong> sind <strong data-start=\"1914\" data-end=\"1928\">fr&uuml;hzeitig</strong> zu ber&uuml;cksichtigen (Security by Design &amp; Default)</p>\r\n</li>\r\n<li data-start=\"1979\" data-end=\"2076\">\r\n<p data-start=\"1981\" data-end=\"2076\">Alle Entwicklungen m&uuml;ssen <strong data-start=\"2007\" data-end=\"2066\">Standards, Richtlinien und Frameworks f&uuml;r Secure Coding</strong> einhalten</p>\r\n</li>\r\n<li data-start=\"2077\" data-end=\"2165\">\r\n<p data-start=\"2079\" data-end=\"2165\">Es gelten Prinzipien wie <strong data-start=\"2104\" data-end=\"2123\">Least Privilege</strong>, <strong data-start=\"2125\" data-end=\"2145\">Defense in Depth</strong> und <strong data-start=\"2150\" data-end=\"2165\">Fail Secure</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2167\" data-end=\"2170\">\r\n<h2 data-start=\"2172\" data-end=\"2222\"><strong data-start=\"2175\" data-end=\"2222\">4. Anforderungen an den Entwicklungsprozess</strong></h2>\r\n<h3 data-start=\"2224\" data-end=\"2283\">4.1 Sicherheitsanforderungen in der Spezifikationsphase</h3>\r\n<ul data-start=\"2285\" data-end=\"2640\">\r\n<li data-start=\"2285\" data-end=\"2396\">\r\n<p data-start=\"2287\" data-end=\"2396\">Sicherheitsanforderungen m&uuml;ssen <strong data-start=\"2319\" data-end=\"2347\">schriftlich dokumentiert</strong> und in die Anforderungsanalyse integriert werden</p>\r\n</li>\r\n<li data-start=\"2397\" data-end=\"2640\">\r\n<p data-start=\"2399\" data-end=\"2420\">Ber&uuml;cksichtigung von:</p>\r\n<ul data-start=\"2423\" data-end=\"2640\">\r\n<li data-start=\"2423\" data-end=\"2496\">\r\n<p data-start=\"2425\" data-end=\"2496\">Schutzbedarf der Anwendung (Vertraulichkeit, Integrit&auml;t, Verf&uuml;gbarkeit)</p>\r\n</li>\r\n<li data-start=\"2499\" data-end=\"2575\">\r\n<p data-start=\"2501\" data-end=\"2575\">gesetzlicher und regulatorischer Anforderungen (z. B. DSGVO, Urheberrecht)</p>\r\n</li>\r\n<li data-start=\"2578\" data-end=\"2640\">\r\n<p data-start=\"2580\" data-end=\"2640\">Angriffsszenarien (Bedrohungsmodellierung / Threat Modeling)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2642\" data-end=\"2661\">4.2 Entwicklung</h3>\r\n<ul data-start=\"2663\" data-end=\"3071\">\r\n<li data-start=\"2663\" data-end=\"2751\">\r\n<p data-start=\"2665\" data-end=\"2751\">Nutzung sicherer Programmierstandards (z. B. OWASP Secure Coding Guidelines, SEI CERT)</p>\r\n</li>\r\n<li data-start=\"2752\" data-end=\"2809\">\r\n<p data-start=\"2754\" data-end=\"2809\">Verwendung <strong data-start=\"2765\" data-end=\"2809\">zugelassener Frameworks und Bibliotheken</strong></p>\r\n</li>\r\n<li data-start=\"2810\" data-end=\"2885\">\r\n<p data-start=\"2812\" data-end=\"2885\">Pr&uuml;fung und Pflege von <strong data-start=\"2835\" data-end=\"2885\">Third-Party-Komponenten / Open Source Software</strong></p>\r\n</li>\r\n<li data-start=\"2886\" data-end=\"2965\">\r\n<p data-start=\"2888\" data-end=\"2965\">Verbot von <strong data-start=\"2899\" data-end=\"2924\">unsicheren Funktionen</strong> (z. B. <code data-start=\"2932\" data-end=\"2940\">eval()</code>, direkte SQL-Konstrukte)</p>\r\n</li>\r\n<li data-start=\"2966\" data-end=\"3071\">\r\n<p data-start=\"2968\" data-end=\"3071\">Logging sensibler Daten nur <strong data-start=\"2996\" data-end=\"3018\">datenschutzkonform</strong> (z. B. keine Passw&ouml;rter, keine vollst&auml;ndigen Tokens)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3073\" data-end=\"3109\">4.3 Code- und Qualit&auml;tssicherung</h3>\r\n<ul data-start=\"3111\" data-end=\"3387\">\r\n<li data-start=\"3111\" data-end=\"3200\">\r\n<p data-start=\"3113\" data-end=\"3200\"><strong data-start=\"3113\" data-end=\"3129\">Peer Reviews</strong> oder <strong data-start=\"3135\" data-end=\"3154\">4-Augen-Prinzip</strong> verpflichtend f&uuml;r sicherheitskritische Module</p>\r\n</li>\r\n<li data-start=\"3201\" data-end=\"3260\">\r\n<p data-start=\"3203\" data-end=\"3260\">Statische Codeanalyse mit Tools (z. B. SonarQube, CodeQL)</p>\r\n</li>\r\n<li data-start=\"3261\" data-end=\"3322\">\r\n<p data-start=\"3263\" data-end=\"3322\">Nutzung automatisierter Tests (Unit, Integration, Security)</p>\r\n</li>\r\n<li data-start=\"3323\" data-end=\"3387\">\r\n<p data-start=\"3325\" data-end=\"3387\">Erstellung eines <strong data-start=\"3342\" data-end=\"3372\">Sicherheits-Release-Checks</strong> vor Deployment</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3389\" data-end=\"3392\">\r\n<h2 data-start=\"3394\" data-end=\"3425\"><strong data-start=\"3397\" data-end=\"3425\">5. Testen auf Sicherheit</strong></h2>\r\n<ul data-start=\"3427\" data-end=\"3769\">\r\n<li data-start=\"3427\" data-end=\"3583\">\r\n<p data-start=\"3429\" data-end=\"3465\">Durchf&uuml;hrung von <strong data-start=\"3446\" data-end=\"3464\">Security Tests</strong>:</p>\r\n<ul data-start=\"3468\" data-end=\"3583\">\r\n<li data-start=\"3468\" data-end=\"3503\">\r\n<p data-start=\"3470\" data-end=\"3503\">Blackbox-Tests (z. B. Pentesting)</p>\r\n</li>\r\n<li data-start=\"3506\" data-end=\"3547\">\r\n<p data-start=\"3508\" data-end=\"3547\">Whitebox-Tests (z. B. Quellcodeanalyse)</p>\r\n</li>\r\n<li data-start=\"3550\" data-end=\"3583\">\r\n<p data-start=\"3552\" data-end=\"3583\">Fuzzing bei Eingabeverarbeitung</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"3584\" data-end=\"3636\">\r\n<p data-start=\"3586\" data-end=\"3636\">Verifikation auf <strong data-start=\"3603\" data-end=\"3636\">Top-Risiken nach OWASP Top 10</strong></p>\r\n</li>\r\n<li data-start=\"3637\" data-end=\"3769\">\r\n<p data-start=\"3639\" data-end=\"3666\">Wiederholung der Tests bei:</p>\r\n<ul data-start=\"3669\" data-end=\"3769\">\r\n<li data-start=\"3669\" data-end=\"3690\">\r\n<p data-start=\"3671\" data-end=\"3690\">Funktions&auml;nderungen</p>\r\n</li>\r\n<li data-start=\"3693\" data-end=\"3724\">\r\n<p data-start=\"3695\" data-end=\"3724\">Integration neuer Komponenten</p>\r\n</li>\r\n<li data-start=\"3727\" data-end=\"3769\">\r\n<p data-start=\"3729\" data-end=\"3769\">Festgestellten Schwachstellen im Betrieb</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3771\" data-end=\"3774\">\r\n<h2 data-start=\"3776\" data-end=\"3806\"><strong data-start=\"3779\" data-end=\"3806\">6. Deployment &amp; Betrieb</strong></h2>\r\n<ul data-start=\"3808\" data-end=\"4065\">\r\n<li data-start=\"3808\" data-end=\"3869\">\r\n<p data-start=\"3810\" data-end=\"3869\"><strong data-start=\"3810\" data-end=\"3869\">Trennung von Entwicklungs-, Test- und Produktivumgebung</strong></p>\r\n</li>\r\n<li data-start=\"3870\" data-end=\"3931\">\r\n<p data-start=\"3872\" data-end=\"3931\">Keine Testdaten oder Debug-Informationen im Produktivsystem</p>\r\n</li>\r\n<li data-start=\"3932\" data-end=\"4003\">\r\n<p data-start=\"3934\" data-end=\"4003\">Deployment-Prozess muss nachvollziehbar dokumentiert und gepr&uuml;ft sein</p>\r\n</li>\r\n<li data-start=\"4004\" data-end=\"4065\">\r\n<p data-start=\"4006\" data-end=\"4065\">Rollback-M&ouml;glichkeit bei fehlerhaftem Release sicherstellen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4067\" data-end=\"4070\">\r\n<h2 data-start=\"4072\" data-end=\"4106\"><strong data-start=\"4075\" data-end=\"4106\">7. Schwachstellenmanagement</strong></h2>\r\n<ul data-start=\"4108\" data-end=\"4483\">\r\n<li data-start=\"4108\" data-end=\"4198\">\r\n<p data-start=\"4110\" data-end=\"4198\">Gefundene Schwachstellen m&uuml;ssen <strong data-start=\"4142\" data-end=\"4191\">zeitnah dokumentiert, priorisiert und behoben</strong> werden</p>\r\n</li>\r\n<li data-start=\"4199\" data-end=\"4318\">\r\n<p data-start=\"4201\" data-end=\"4318\">Kritische Schwachstellen sind <strong data-start=\"4231\" data-end=\"4277\">innerhalb definierter Fristen zu schlie&szlig;en</strong> (z. B. CVSS &ge; 7: innerhalb von 14 Tagen)</p>\r\n</li>\r\n<li data-start=\"4319\" data-end=\"4397\">\r\n<p data-start=\"4321\" data-end=\"4397\">Meldung und Behandlung gem&auml;&szlig; Richtlinie f&uuml;r <strong data-start=\"4365\" data-end=\"4397\">Security Incident Management</strong></p>\r\n</li>\r\n<li data-start=\"4398\" data-end=\"4483\">\r\n<p data-start=\"4400\" data-end=\"4483\">Pflicht zur Durchf&uuml;hrung von <strong data-start=\"4429\" data-end=\"4448\">Lessons Learned</strong> bei schwerwiegenden Schwachstellen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4485\" data-end=\"4488\">\r\n<h2 data-start=\"4490\" data-end=\"4535\"><strong data-start=\"4493\" data-end=\"4535\">8. Dokumentation &amp; Nachvollziehbarkeit</strong></h2>\r\n<ul data-start=\"4537\" data-end=\"4823\">\r\n<li data-start=\"4537\" data-end=\"4672\">\r\n<p data-start=\"4539\" data-end=\"4672\">Sicherheitsanforderungen, Architekturentscheidungen, verwendete Bibliotheken und Abh&auml;ngigkeiten sind <strong data-start=\"4640\" data-end=\"4672\">vollst&auml;ndig zu dokumentieren</strong></p>\r\n</li>\r\n<li data-start=\"4673\" data-end=\"4746\">\r\n<p data-start=\"4675\" data-end=\"4746\">Versionsst&auml;nde und &Auml;nderungen sind <strong data-start=\"4710\" data-end=\"4746\">revisionssicher nachzuvollziehen</strong></p>\r\n</li>\r\n<li data-start=\"4747\" data-end=\"4823\">\r\n<p data-start=\"4749\" data-end=\"4823\">Quellcode ist &uuml;ber <strong data-start=\"4768\" data-end=\"4810\">Versionsverwaltungssysteme (z. B. Git)</strong> zu verwalten</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4825\" data-end=\"4828\">\r\n<h2 data-start=\"4830\" data-end=\"4862\"><strong data-start=\"4833\" data-end=\"4862\">9. Schulung und Awareness</strong></h2>\r\n<ul data-start=\"4864\" data-end=\"5124\">\r\n<li data-start=\"4864\" data-end=\"5040\">\r\n<p data-start=\"4866\" data-end=\"4924\">Entwickler*innen m&uuml;ssen <strong data-start=\"4890\" data-end=\"4913\">regelm&auml;&szlig;ig geschult</strong> werden zu:</p>\r\n<ul data-start=\"4927\" data-end=\"5040\">\r\n<li data-start=\"4927\" data-end=\"4967\">\r\n<p data-start=\"4929\" data-end=\"4967\">Secure Coding-Prinzipien (z. B. OWASP)</p>\r\n</li>\r\n<li data-start=\"4970\" data-end=\"4993\">\r\n<p data-start=\"4972\" data-end=\"4993\">aktuellen Bedrohungen</p>\r\n</li>\r\n<li data-start=\"4996\" data-end=\"5040\">\r\n<p data-start=\"4998\" data-end=\"5040\">sicherer Konfiguration und Verschl&uuml;sselung</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"5041\" data-end=\"5124\">\r\n<p data-start=\"5043\" data-end=\"5124\">Schulungen erfolgen <strong data-start=\"5063\" data-end=\"5086\">mindestens j&auml;hrlich</strong> oder bei neuen Technologien / Risiken</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5126\" data-end=\"5129\">\r\n<h2 data-start=\"5131\" data-end=\"5162\"><strong data-start=\"5134\" data-end=\"5162\">10. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5164\" data-end=\"5722\">\r\n<thead data-start=\"5164\" data-end=\"5201\">\r\n<tr data-start=\"5164\" data-end=\"5201\">\r\n<th data-start=\"5164\" data-end=\"5189\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5189\" data-end=\"5201\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5240\" data-end=\"5722\">\r\n<tr data-start=\"5240\" data-end=\"5314\">\r\n<td data-start=\"5240\" data-end=\"5266\" data-col-size=\"sm\"><strong data-start=\"5242\" data-end=\"5262\">Entwicklungsteam</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5266\" data-end=\"5314\">Umsetzung sicherer Entwicklung, Codequalit&auml;t</td>\r\n</tr>\r\n<tr data-start=\"5315\" data-end=\"5417\">\r\n<td data-start=\"5315\" data-end=\"5355\" data-col-size=\"sm\"><strong data-start=\"5317\" data-end=\"5354\">IT-Sicherheitsbeauftragte*r (ISB)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5355\" data-end=\"5417\">Kontrolle der Sicherheitsanforderungen, Beratung, Freigabe</td>\r\n</tr>\r\n<tr data-start=\"5418\" data-end=\"5491\">\r\n<td data-start=\"5418\" data-end=\"5444\" data-col-size=\"sm\"><strong data-start=\"5420\" data-end=\"5438\">Projektleitung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5444\" data-end=\"5491\">Einhaltung der Richtlinie im Projektverlauf</td>\r\n</tr>\r\n<tr data-start=\"5492\" data-end=\"5561\">\r\n<td data-start=\"5492\" data-end=\"5518\" data-col-size=\"sm\"><strong data-start=\"5494\" data-end=\"5516\">Qualit&auml;tssicherung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5518\" data-end=\"5561\">Durchf&uuml;hrung sicherheitsbezogener Tests</td>\r\n</tr>\r\n<tr data-start=\"5562\" data-end=\"5634\">\r\n<td data-start=\"5562\" data-end=\"5588\" data-col-size=\"sm\"><strong data-start=\"5564\" data-end=\"5584\">DevOps / Betrieb</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5588\" data-end=\"5634\">Sicheres Deployment, Konfigurationsh&auml;rtung</td>\r\n</tr>\r\n<tr data-start=\"5635\" data-end=\"5722\">\r\n<td data-start=\"5635\" data-end=\"5661\" data-col-size=\"sm\"><strong data-start=\"5637\" data-end=\"5659\">Externe Entwickler</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5661\" data-end=\"5722\">Einhaltung dieser Richtlinie &uuml;ber vertragliche Regelungen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5724\" data-end=\"5727\">\r\n<h2 data-start=\"5729\" data-end=\"5778\"><strong data-start=\"5732\" data-end=\"5778\">11. Schnittstellen zu weiteren Richtlinien</strong></h2>\r\n<p data-start=\"5780\" data-end=\"5805\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"5807\" data-end=\"6022\">\r\n<li data-start=\"5807\" data-end=\"5846\">\r\n<p data-start=\"5809\" data-end=\"5846\"><strong data-start=\"5809\" data-end=\"5846\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"5847\" data-end=\"5881\">\r\n<p data-start=\"5849\" data-end=\"5881\"><strong data-start=\"5849\" data-end=\"5881\">Patch- &amp; &Auml;nderungsmanagement</strong></p>\r\n</li>\r\n<li data-start=\"5882\" data-end=\"5923\">\r\n<p data-start=\"5884\" data-end=\"5923\"><strong data-start=\"5884\" data-end=\"5923\">Richtlinie f&uuml;r Logging &amp; Monitoring</strong></p>\r\n</li>\r\n<li data-start=\"5924\" data-end=\"5948\">\r\n<p data-start=\"5926\" data-end=\"5948\"><strong data-start=\"5926\" data-end=\"5948\">Zugriffsmanagement</strong></p>\r\n</li>\r\n<li data-start=\"5949\" data-end=\"5994\">\r\n<p data-start=\"5951\" data-end=\"5994\"><strong data-start=\"5951\" data-end=\"5994\">Richtlinie f&uuml;r Schwachstellenmanagement</strong></p>\r\n</li>\r\n<li data-start=\"5995\" data-end=\"6022\">\r\n<p data-start=\"5997\" data-end=\"6022\"><strong data-start=\"5997\" data-end=\"6022\">Datenschutzrichtlinie</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6024\" data-end=\"6027\">\r\n<h2 data-start=\"6029\" data-end=\"6069\"><strong data-start=\"6032\" data-end=\"6069\">12. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6071\" data-end=\"6496\">\r\n<thead data-start=\"6071\" data-end=\"6101\">\r\n<tr data-start=\"6071\" data-end=\"6101\">\r\n<th data-start=\"6071\" data-end=\"6089\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6089\" data-end=\"6101\" data-col-size=\"md\">Relevanz</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6134\" data-end=\"6496\">\r\n<tr data-start=\"6134\" data-end=\"6264\">\r\n<td data-start=\"6134\" data-end=\"6154\" data-col-size=\"sm\"><strong data-start=\"6136\" data-end=\"6153\">ISO/IEC 27001</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6154\" data-end=\"6264\">A.8.25 &ndash; Sicherer Entwicklungslebenszyklus<br>A.8.26 &ndash; Sicheres Programmieren<br>A.8.27 &ndash; Sicherheitstests</td>\r\n</tr>\r\n<tr data-start=\"6265\" data-end=\"6347\">\r\n<td data-start=\"6265\" data-end=\"6290\" data-col-size=\"sm\"><strong data-start=\"6267\" data-end=\"6289\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6290\" data-end=\"6347\">APP.2, APP.4 &ndash; Anwendungsentwicklung und -integration</td>\r\n</tr>\r\n<tr data-start=\"6348\" data-end=\"6416\">\r\n<td data-start=\"6348\" data-end=\"6367\" data-col-size=\"sm\"><strong data-start=\"6350\" data-end=\"6366\">OWASP Top 10</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6367\" data-end=\"6416\">Industriestandard f&uuml;r Webanwendungssicherheit</td>\r\n</tr>\r\n<tr data-start=\"6417\" data-end=\"6496\">\r\n<td data-start=\"6417\" data-end=\"6437\" data-col-size=\"sm\"><strong data-start=\"6419\" data-end=\"6436\">DSGVO Art. 25</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6437\" data-end=\"6496\">Datenschutz durch Technikgestaltung (Privacy by Design)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(17, 'DOK-0017', 'Lieferantenmanagement', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"827\" data-end=\"857\"><strong data-start=\"830\" data-end=\"857\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"859\" data-end=\"1102\">Diese Richtlinie regelt den sicheren und nachvollziehbaren Umgang mit <strong data-start=\"929\" data-end=\"999\">externen Lieferanten, Dienstleistern, Partnern und Cloud-Anbietern</strong>, die Zugang zu Informationen, IT-Systemen oder kritischen Gesch&auml;ftsprozessen erhalten. Sie dient dazu:</p>\r\n<ul data-start=\"1104\" data-end=\"1319\">\r\n<li data-start=\"1104\" data-end=\"1168\">\r\n<p data-start=\"1106\" data-end=\"1168\">Sicherheitsanforderungen bei der Zusammenarbeit zu definieren,</p>\r\n</li>\r\n<li data-start=\"1169\" data-end=\"1238\">\r\n<p data-start=\"1171\" data-end=\"1238\">Risiken durch externe Parteien zu identifizieren und zu minimieren,</p>\r\n</li>\r\n<li data-start=\"1239\" data-end=\"1319\">\r\n<p data-start=\"1241\" data-end=\"1319\">die Einhaltung gesetzlicher Vorgaben (z. B. DSGVO, ISO 27001) sicherzustellen.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1321\" data-end=\"1324\">\r\n<h2 data-start=\"1326\" data-end=\"1351\"><strong data-start=\"1329\" data-end=\"1351\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1353\" data-end=\"1379\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1381\" data-end=\"1711\">\r\n<li data-start=\"1381\" data-end=\"1503\">\r\n<p data-start=\"1383\" data-end=\"1503\"><strong data-start=\"1383\" data-end=\"1415\">Alle externen Organisationen</strong>, die im Auftrag der Organisation Leistungen erbringen oder IT-Komponenten bereitstellen</p>\r\n</li>\r\n<li data-start=\"1504\" data-end=\"1604\">\r\n<p data-start=\"1506\" data-end=\"1604\"><strong data-start=\"1506\" data-end=\"1529\">Alle Mitarbeitenden</strong>, die Lieferanten beauftragen, betreuen oder Leistungen technisch betreiben</p>\r\n</li>\r\n<li data-start=\"1605\" data-end=\"1711\">\r\n<p data-start=\"1607\" data-end=\"1711\"><strong data-start=\"1607\" data-end=\"1629\">Alle Dienstleister</strong>, die Zugang zu sensiblen Informationen, Systemen oder physischen Standorten haben</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1713\" data-end=\"1716\">\r\n<h2 data-start=\"1718\" data-end=\"1736\"><strong data-start=\"1721\" data-end=\"1736\">3. Begriffe</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1738\" data-end=\"2319\">\r\n<thead data-start=\"1738\" data-end=\"1772\">\r\n<tr data-start=\"1738\" data-end=\"1772\">\r\n<th data-start=\"1738\" data-end=\"1756\" data-col-size=\"sm\">Begriff</th>\r\n<th data-start=\"1756\" data-end=\"1772\" data-col-size=\"md\">Beschreibung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1807\" data-end=\"2319\">\r\n<tr data-start=\"1807\" data-end=\"1928\">\r\n<td data-start=\"1807\" data-end=\"1825\" data-col-size=\"sm\"><strong data-start=\"1809\" data-end=\"1822\">Lieferant</strong></td>\r\n<td data-start=\"1825\" data-end=\"1928\" data-col-size=\"md\">Externe Organisation oder Einzelperson, die G&uuml;ter, Dienstleistungen oder IT-Leistungen bereitstellt</td>\r\n</tr>\r\n<tr data-start=\"1929\" data-end=\"2051\">\r\n<td data-start=\"1929\" data-end=\"1956\" data-col-size=\"sm\"><strong data-start=\"1931\" data-end=\"1955\">Kritischer Lieferant</strong></td>\r\n<td data-start=\"1956\" data-end=\"2051\" data-col-size=\"md\">Anbieter, dessen Leistung Einfluss auf Informationssicherheit oder Gesch&auml;ftskontinuit&auml;t hat</td>\r\n</tr>\r\n<tr data-start=\"2052\" data-end=\"2169\">\r\n<td data-start=\"2052\" data-end=\"2078\" data-col-size=\"sm\"><strong data-start=\"2054\" data-end=\"2077\">Auftragsverarbeiter</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2078\" data-end=\"2169\">Dienstleister im Sinne der DSGVO mit Zugriff auf personenbezogene Daten (Art. 28 DSGVO)</td>\r\n</tr>\r\n<tr data-start=\"2170\" data-end=\"2268\">\r\n<td data-start=\"2170\" data-end=\"2206\" data-col-size=\"sm\"><strong data-start=\"2172\" data-end=\"2205\">SLA (Service Level Agreement)</strong></td>\r\n<td data-start=\"2206\" data-end=\"2268\" data-col-size=\"md\">Vereinbarung &uuml;ber Leistungsmerkmale und Qualit&auml;tsstandards</td>\r\n</tr>\r\n<tr data-start=\"2269\" data-end=\"2319\">\r\n<td data-start=\"2269\" data-end=\"2279\" data-col-size=\"sm\"><strong data-start=\"2271\" data-end=\"2278\">ISB</strong></td>\r\n<td data-start=\"2279\" data-end=\"2319\" data-col-size=\"md\">Informationssicherheitsbeauftragte*r</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2321\" data-end=\"2324\">\r\n<h2 data-start=\"2326\" data-end=\"2373\"><strong data-start=\"2329\" data-end=\"2373\">4. Grunds&auml;tze des Lieferantenmanagements</strong></h2>\r\n<ul data-start=\"2375\" data-end=\"2827\">\r\n<li data-start=\"2375\" data-end=\"2497\">\r\n<p data-start=\"2377\" data-end=\"2497\">Informationssicherheit ist Bestandteil jeder <strong data-start=\"2422\" data-end=\"2446\">Lieferantenbeziehung</strong>, insbesondere bei Outsourcing oder Cloud-Nutzung</p>\r\n</li>\r\n<li data-start=\"2498\" data-end=\"2557\">\r\n<p data-start=\"2500\" data-end=\"2557\">Sicherheitsanforderungen sind <strong data-start=\"2530\" data-end=\"2555\">vertraglich zu regeln</strong></p>\r\n</li>\r\n<li data-start=\"2558\" data-end=\"2668\">\r\n<p data-start=\"2560\" data-end=\"2668\">Risiken werden anhand von <strong data-start=\"2586\" data-end=\"2615\">klassifizierten Kriterien</strong> bewertet (z. B. Zugriff, Kritikalit&auml;t, Datenarten)</p>\r\n</li>\r\n<li data-start=\"2669\" data-end=\"2743\">\r\n<p data-start=\"2671\" data-end=\"2743\">Lieferanten unterliegen einer <strong data-start=\"2701\" data-end=\"2741\">regelm&auml;&szlig;igen Kontrolle und Bewertung</strong></p>\r\n</li>\r\n<li data-start=\"2744\" data-end=\"2827\">\r\n<p data-start=\"2746\" data-end=\"2827\">Bei Datenschutzbezug: <strong data-start=\"2768\" data-end=\"2827\">Abschluss einer Auftragsverarbeitungsvereinbarung (AVV)</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2829\" data-end=\"2832\">\r\n<h2 data-start=\"2834\" data-end=\"2881\"><strong data-start=\"2837\" data-end=\"2881\">5. Lebenszyklus im Lieferantenmanagement</strong></h2>\r\n<h3 data-start=\"2883\" data-end=\"2903\">5.1 Auswahlphase</h3>\r\n<ul data-start=\"2905\" data-end=\"3289\">\r\n<li data-start=\"2905\" data-end=\"3184\">\r\n<p data-start=\"2907\" data-end=\"2961\">Lieferanten werden <strong data-start=\"2926\" data-end=\"2960\">vor Vertragsabschluss bewertet</strong>:</p>\r\n<ul data-start=\"2964\" data-end=\"3184\">\r\n<li data-start=\"2964\" data-end=\"3025\">\r\n<p data-start=\"2966\" data-end=\"3025\">Technische und organisatorische Sicherheitsma&szlig;nahmen (TOMs)</p>\r\n</li>\r\n<li data-start=\"3028\" data-end=\"3075\">\r\n<p data-start=\"3030\" data-end=\"3075\">Zertifizierungen (z. B. ISO 27001, TISAX, C5)</p>\r\n</li>\r\n<li data-start=\"3078\" data-end=\"3132\">\r\n<p data-start=\"3080\" data-end=\"3132\">Referenzen / Erfahrungen mit &auml;hnlichen Anforderungen</p>\r\n</li>\r\n<li data-start=\"3135\" data-end=\"3184\">\r\n<p data-start=\"3137\" data-end=\"3184\">DSGVO-Konformit&auml;t (bei personenbezogenen Daten)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"3186\" data-end=\"3289\">\r\n<p data-start=\"3188\" data-end=\"3289\">Kritische Lieferanten m&uuml;ssen ein <strong data-start=\"3221\" data-end=\"3279\">Selbstaudit oder Fragebogen zur Informationssicherheit</strong> ausf&uuml;llen</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3291\" data-end=\"3317\">5.2 Vertragsgestaltung</h3>\r\n<ul data-start=\"3319\" data-end=\"3790\">\r\n<li data-start=\"3319\" data-end=\"3605\">\r\n<p data-start=\"3321\" data-end=\"3406\">Sicherheitsanforderungen sind <strong data-start=\"3351\" data-end=\"3398\">schriftlich im Vertrag oder SLA festzulegen</strong>, z. B.:</p>\r\n<ul data-start=\"3409\" data-end=\"3605\">\r\n<li data-start=\"3409\" data-end=\"3440\">\r\n<p data-start=\"3411\" data-end=\"3440\">Geheimhaltungspflichten (NDA)</p>\r\n</li>\r\n<li data-start=\"3443\" data-end=\"3506\">\r\n<p data-start=\"3445\" data-end=\"3506\">Sicherheitsniveau (z. B. Verschl&uuml;sselung, Zugriffskontrollen)</p>\r\n</li>\r\n<li data-start=\"3509\" data-end=\"3548\">\r\n<p data-start=\"3511\" data-end=\"3548\">Umgang mit Vorf&auml;llen / Meldepflichten</p>\r\n</li>\r\n<li data-start=\"3551\" data-end=\"3575\">\r\n<p data-start=\"3553\" data-end=\"3575\">Subunternehmerregelung</p>\r\n</li>\r\n<li data-start=\"3578\" data-end=\"3605\">\r\n<p data-start=\"3580\" data-end=\"3605\">Kontroll- und Auditrechte</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"3607\" data-end=\"3790\">\r\n<p data-start=\"3609\" data-end=\"3648\">Bei Zugriff auf personenbezogene Daten:</p>\r\n<ul data-start=\"3651\" data-end=\"3790\">\r\n<li data-start=\"3651\" data-end=\"3728\">\r\n<p data-start=\"3653\" data-end=\"3728\"><strong data-start=\"3653\" data-end=\"3691\">Auftragsverarbeitungsvertrag (AVV)</strong> nach Art. 28 DSGVO ist verpflichtend</p>\r\n</li>\r\n<li data-start=\"3731\" data-end=\"3790\">\r\n<p data-start=\"3733\" data-end=\"3790\">Dokumentation im Verzeichnis der Verarbeitungst&auml;tigkeiten</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3792\" data-end=\"3813\">5.3 Betriebsphase</h3>\r\n<ul data-start=\"3815\" data-end=\"4150\">\r\n<li data-start=\"3815\" data-end=\"3915\">\r\n<p data-start=\"3817\" data-end=\"3915\">Regelm&auml;&szlig;ige <strong data-start=\"3829\" data-end=\"3868\">Sicherheits&uuml;berpr&uuml;fungen und Audits</strong> (z. B. j&auml;hrlich bei kritischen Dienstleistern)</p>\r\n</li>\r\n<li data-start=\"3916\" data-end=\"4007\">\r\n<p data-start=\"3918\" data-end=\"4007\">Nachweis der Einhaltung von Sicherheitsma&szlig;nahmen (z. B. durch Auditberichte, Zertifikate)</p>\r\n</li>\r\n<li data-start=\"4008\" data-end=\"4086\">\r\n<p data-start=\"4010\" data-end=\"4086\">Meldepflicht bei <strong data-start=\"4027\" data-end=\"4051\">Sicherheitsvorf&auml;llen</strong>, Datenverlust oder Rechtsverst&ouml;&szlig;en</p>\r\n</li>\r\n<li data-start=\"4087\" data-end=\"4150\">\r\n<p data-start=\"4089\" data-end=\"4150\">&Uuml;berpr&uuml;fung von SLAs und vertraglich zugesicherten Leistungen</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4152\" data-end=\"4189\">5.4 Beendigung der Zusammenarbeit</h3>\r\n<ul data-start=\"4191\" data-end=\"4477\">\r\n<li data-start=\"4191\" data-end=\"4245\">\r\n<p data-start=\"4193\" data-end=\"4245\">Klare Regelungen zur <strong data-start=\"4214\" data-end=\"4245\">Datenr&uuml;ckgabe und -l&ouml;schung</strong></p>\r\n</li>\r\n<li data-start=\"4246\" data-end=\"4313\">\r\n<p data-start=\"4248\" data-end=\"4313\">Zugang zu IT-Systemen und R&auml;umlichkeiten wird <strong data-start=\"4294\" data-end=\"4313\">sofort entzogen</strong></p>\r\n</li>\r\n<li data-start=\"4314\" data-end=\"4409\">\r\n<p data-start=\"4316\" data-end=\"4409\">L&ouml;schung oder R&uuml;ckgabe von Datentr&auml;gern, Zugangscodes und Dokumenten ist <strong data-start=\"4389\" data-end=\"4409\">zu dokumentieren</strong></p>\r\n</li>\r\n<li data-start=\"4410\" data-end=\"4477\">\r\n<p data-start=\"4412\" data-end=\"4477\">Datenschutzrechtliche Pflichten bestehen &uuml;ber Vertragsende hinaus</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4479\" data-end=\"4482\">\r\n<h2 data-start=\"4484\" data-end=\"4538\"><strong data-start=\"4487\" data-end=\"4538\">6. Bewertung und Klassifikation von Lieferanten</strong></h2>\r\n<p data-start=\"4540\" data-end=\"4603\">Lieferanten werden auf Basis folgender Kriterien klassifiziert:</p>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4605\" data-end=\"4946\">\r\n<thead data-start=\"4605\" data-end=\"4629\">\r\n<tr data-start=\"4605\" data-end=\"4629\">\r\n<th data-start=\"4605\" data-end=\"4617\" data-col-size=\"sm\">Kriterium</th>\r\n<th data-start=\"4617\" data-end=\"4629\" data-col-size=\"sm\">Beispiel</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4654\" data-end=\"4946\">\r\n<tr data-start=\"4654\" data-end=\"4733\">\r\n<td data-start=\"4654\" data-end=\"4692\" data-col-size=\"sm\"><strong data-start=\"4656\" data-end=\"4691\">Kritikalit&auml;t der Dienstleistung</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"4692\" data-end=\"4733\">IT-Hosting, ERP-Support, Cloud-Backup</td>\r\n</tr>\r\n<tr data-start=\"4734\" data-end=\"4800\">\r\n<td data-start=\"4734\" data-end=\"4771\" data-col-size=\"sm\"><strong data-start=\"4736\" data-end=\"4770\">Zugriff auf Systeme oder Daten</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"4771\" data-end=\"4800\">Admin-Zugang, Fernwartung</td>\r\n</tr>\r\n<tr data-start=\"4801\" data-end=\"4877\">\r\n<td data-start=\"4801\" data-end=\"4835\" data-col-size=\"sm\"><strong data-start=\"4803\" data-end=\"4834\">Art der verarbeiteten Daten</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"4835\" data-end=\"4877\">personenbezogen, vertraulich, kritisch</td>\r\n</tr>\r\n<tr data-start=\"4878\" data-end=\"4946\">\r\n<td data-start=\"4878\" data-end=\"4912\" data-col-size=\"sm\"><strong data-start=\"4880\" data-end=\"4911\">Standort des Dienstleisters</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"4912\" data-end=\"4946\">EU / Drittstaat / Risikoregion</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"4948\" data-end=\"4963\"><strong data-start=\"4948\" data-end=\"4963\">Einstufung:</strong></p>\r\n<ul data-start=\"4964\" data-end=\"5160\">\r\n<li data-start=\"4964\" data-end=\"5026\">\r\n<p data-start=\"4966\" data-end=\"5026\"><strong data-start=\"4966\" data-end=\"4986\">Niedriges Risiko</strong>: keine sicherheitsrelevanten Leistungen</p>\r\n</li>\r\n<li data-start=\"5027\" data-end=\"5090\">\r\n<p data-start=\"5029\" data-end=\"5090\"><strong data-start=\"5029\" data-end=\"5049\">Mittleres Risiko</strong>: technischer Zugriff auf interne Systeme</p>\r\n</li>\r\n<li data-start=\"5091\" data-end=\"5160\">\r\n<p data-start=\"5093\" data-end=\"5160\"><strong data-start=\"5093\" data-end=\"5109\">Hohes Risiko</strong>: Zugriff auf personenbezogene oder kritische Daten</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5162\" data-end=\"5243\">Je nach Einstufung sind <strong data-start=\"5186\" data-end=\"5229\">intensivere Pr&uuml;f- und Kontrollma&szlig;nahmen</strong> erforderlich.</p>\r\n<hr data-start=\"5245\" data-end=\"5248\">\r\n<h2 data-start=\"5250\" data-end=\"5285\"><strong data-start=\"5253\" data-end=\"5285\">7. Kontrolle und &Uuml;berwachung</strong></h2>\r\n<ul data-start=\"5287\" data-end=\"5612\">\r\n<li data-start=\"5287\" data-end=\"5371\">\r\n<p data-start=\"5289\" data-end=\"5371\">Verantwortlich f&uuml;r die &Uuml;berwachung sind die <strong data-start=\"5333\" data-end=\"5371\">Fachbereiche gemeinsam mit dem ISB</strong></p>\r\n</li>\r\n<li data-start=\"5372\" data-end=\"5504\">\r\n<p data-start=\"5374\" data-end=\"5391\">Durchf&uuml;hrung von:</p>\r\n<ul data-start=\"5394\" data-end=\"5504\">\r\n<li data-start=\"5394\" data-end=\"5434\">\r\n<p data-start=\"5396\" data-end=\"5434\"><strong data-start=\"5396\" data-end=\"5434\">Sicherheitsaudits / Selbstauskunft</strong></p>\r\n</li>\r\n<li data-start=\"5437\" data-end=\"5454\">\r\n<p data-start=\"5439\" data-end=\"5454\"><strong data-start=\"5439\" data-end=\"5454\">SLA-Reviews</strong></p>\r\n</li>\r\n<li data-start=\"5457\" data-end=\"5504\">\r\n<p data-start=\"5459\" data-end=\"5504\"><strong data-start=\"5459\" data-end=\"5504\">&Uuml;berpr&uuml;fung von Zertifikaten / Nachweisen</strong></p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"5506\" data-end=\"5612\">\r\n<p data-start=\"5508\" data-end=\"5612\">Auff&auml;lligkeiten oder Sicherheitsvorf&auml;lle sind dem <strong data-start=\"5558\" data-end=\"5602\">ISB und ggf. dem Datenschutzbeauftragten</strong> zu melden</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5614\" data-end=\"5617\">\r\n<h2 data-start=\"5619\" data-end=\"5668\"><strong data-start=\"5622\" data-end=\"5668\">8. Lieferantenbezogene Sicherheitsvorf&auml;lle</strong></h2>\r\n<ul data-start=\"5670\" data-end=\"5910\">\r\n<li data-start=\"5670\" data-end=\"5749\">\r\n<p data-start=\"5672\" data-end=\"5749\">Lieferanten sind verpflichtet, <strong data-start=\"5703\" data-end=\"5749\">Sicherheitsvorf&auml;lle unverz&uuml;glich zu melden</strong></p>\r\n</li>\r\n<li data-start=\"5750\" data-end=\"5828\">\r\n<p data-start=\"5752\" data-end=\"5828\">Behandlung erfolgt gem&auml;&szlig; der <strong data-start=\"5781\" data-end=\"5828\">Richtlinie zum Security Incident Management</strong></p>\r\n</li>\r\n<li data-start=\"5829\" data-end=\"5910\">\r\n<p data-start=\"5831\" data-end=\"5910\">Bei groben Verst&ouml;&szlig;en: Eskalation an Gesch&auml;ftsf&uuml;hrung und ggf. Vertragsk&uuml;ndigung</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5912\" data-end=\"5915\">\r\n<h2 data-start=\"5917\" data-end=\"5947\"><strong data-start=\"5920\" data-end=\"5947\">9. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5949\" data-end=\"6378\">\r\n<thead data-start=\"5949\" data-end=\"5969\">\r\n<tr data-start=\"5949\" data-end=\"5969\">\r\n<th data-start=\"5949\" data-end=\"5957\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5957\" data-end=\"5969\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5991\" data-end=\"6378\">\r\n<tr data-start=\"5991\" data-end=\"6066\">\r\n<td data-start=\"5991\" data-end=\"6020\" data-col-size=\"sm\"><strong data-start=\"5993\" data-end=\"6019\">Fachbereiche / Einkauf</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6020\" data-end=\"6066\">Auswahl, Vertragsgestaltung, Erstbewertung</td>\r\n</tr>\r\n<tr data-start=\"6067\" data-end=\"6148\">\r\n<td data-start=\"6067\" data-end=\"6077\" data-col-size=\"sm\"><strong data-start=\"6069\" data-end=\"6076\">ISB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6077\" data-end=\"6148\">Sicherheitsanforderungen definieren, Pr&uuml;fung kritischer Lieferanten</td>\r\n</tr>\r\n<tr data-start=\"6149\" data-end=\"6213\">\r\n<td data-start=\"6149\" data-end=\"6159\" data-col-size=\"sm\"><strong data-start=\"6151\" data-end=\"6158\">DSB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6159\" data-end=\"6213\">Pr&uuml;fung und Genehmigung von Auftragsverarbeitungen</td>\r\n</tr>\r\n<tr data-start=\"6214\" data-end=\"6283\">\r\n<td data-start=\"6214\" data-end=\"6233\" data-col-size=\"sm\"><strong data-start=\"6216\" data-end=\"6232\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6233\" data-end=\"6283\">Technische Kontrolle und Zugriffskonfiguration</td>\r\n</tr>\r\n<tr data-start=\"6284\" data-end=\"6378\">\r\n<td data-start=\"6284\" data-end=\"6317\" data-col-size=\"sm\"><strong data-start=\"6286\" data-end=\"6316\">Lieferantenverantwortliche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6317\" data-end=\"6378\">Pflege der Lieferantenbeziehung, Eskalation bei Vorf&auml;llen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"6380\" data-end=\"6383\">\r\n<h2 data-start=\"6385\" data-end=\"6434\"><strong data-start=\"6388\" data-end=\"6434\">10. Schnittstellen zu weiteren Richtlinien</strong></h2>\r\n<p data-start=\"6436\" data-end=\"6461\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"6463\" data-end=\"6637\">\r\n<li data-start=\"6463\" data-end=\"6502\">\r\n<p data-start=\"6465\" data-end=\"6502\"><strong data-start=\"6465\" data-end=\"6502\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6503\" data-end=\"6530\">\r\n<p data-start=\"6505\" data-end=\"6530\"><strong data-start=\"6505\" data-end=\"6530\">Datenschutzrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6531\" data-end=\"6556\">\r\n<p data-start=\"6533\" data-end=\"6556\"><strong data-start=\"6533\" data-end=\"6556\">Incident Management</strong></p>\r\n</li>\r\n<li data-start=\"6557\" data-end=\"6581\">\r\n<p data-start=\"6559\" data-end=\"6581\"><strong data-start=\"6559\" data-end=\"6581\">Zugriffsmanagement</strong></p>\r\n</li>\r\n<li data-start=\"6582\" data-end=\"6612\">\r\n<p data-start=\"6584\" data-end=\"6612\"><strong data-start=\"6584\" data-end=\"6612\">Cloud-Nutzungsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6613\" data-end=\"6637\">\r\n<p data-start=\"6615\" data-end=\"6637\"><strong data-start=\"6615\" data-end=\"6637\">Vertragsmanagement</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6639\" data-end=\"6642\">\r\n<h2 data-start=\"6644\" data-end=\"6684\"><strong data-start=\"6647\" data-end=\"6684\">11. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6686\" data-end=\"7068\">\r\n<thead data-start=\"6686\" data-end=\"6714\">\r\n<tr data-start=\"6686\" data-end=\"6714\">\r\n<th data-start=\"6686\" data-end=\"6704\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6704\" data-end=\"6714\" data-col-size=\"lg\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6745\" data-end=\"7068\">\r\n<tr data-start=\"6745\" data-end=\"6902\">\r\n<td data-start=\"6745\" data-end=\"6765\" data-col-size=\"sm\"><strong data-start=\"6747\" data-end=\"6764\">ISO/IEC 27001</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6765\" data-end=\"6902\">A.5.19 &ndash; Steuerung der Lieferantenbeziehungen<br>A.5.20 &ndash; Sicherheit bei Lieferantenzugriffen<br>A.5.21 &ndash; &Uuml;berwachung von Lieferanten</td>\r\n</tr>\r\n<tr data-start=\"6903\" data-end=\"7021\">\r\n<td data-start=\"6903\" data-end=\"6928\" data-col-size=\"sm\"><strong data-start=\"6905\" data-end=\"6927\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6928\" data-end=\"7021\">ORP.2.2 (Fremdbezogene IT-Dienstleistungen), DER.3 (Fernwartung), CON.8 (Cloud Computing)</td>\r\n</tr>\r\n<tr data-start=\"7022\" data-end=\"7068\">\r\n<td data-start=\"7022\" data-end=\"7034\" data-col-size=\"sm\"><strong data-start=\"7024\" data-end=\"7033\">DSGVO</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"7034\" data-end=\"7068\">Art. 28 &ndash; Auftragsverarbeitung</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(18, 'DOK-0018', 'Patch & Schwachstellenmanagement', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"947\" data-end=\"977\"><strong data-start=\"950\" data-end=\"977\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"979\" data-end=\"1232\">Ziel dieser Richtlinie ist es, die Informationssicherheit durch ein strukturiertes Verfahren zur <strong data-start=\"1076\" data-end=\"1149\">Erkennung, Bewertung, Behandlung und Dokumentation von Schwachstellen</strong> sowie durch die <strong data-start=\"1166\" data-end=\"1220\">zeitnahe Einspielung sicherheitsrelevanter Patches</strong> zu st&auml;rken.</p>\r\n<hr data-start=\"1234\" data-end=\"1237\">\r\n<h2 data-start=\"1239\" data-end=\"1264\"><strong data-start=\"1242\" data-end=\"1264\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1266\" data-end=\"1292\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1294\" data-end=\"1543\">\r\n<li data-start=\"1294\" data-end=\"1384\">\r\n<p data-start=\"1296\" data-end=\"1384\"><strong data-start=\"1296\" data-end=\"1344\">Alle IT-Systeme, Anwendungen und Komponenten</strong>, die im Unternehmen eingesetzt werden</p>\r\n</li>\r\n<li data-start=\"1385\" data-end=\"1439\">\r\n<p data-start=\"1387\" data-end=\"1439\"><strong data-start=\"1387\" data-end=\"1406\">Alle Umgebungen</strong>: Produktion, Test, Entwicklung</p>\r\n</li>\r\n<li data-start=\"1440\" data-end=\"1543\">\r\n<p data-start=\"1442\" data-end=\"1543\"><strong data-start=\"1442\" data-end=\"1487\">Alle Nutzer<em data-start=\"1455\" data-end=\"1480\">innen und Administrator</em>innen</strong>, die an Betrieb, Pflege oder Entwicklung beteiligt sind</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1545\" data-end=\"1548\">\r\n<h2 data-start=\"1550\" data-end=\"1570\"><strong data-start=\"1553\" data-end=\"1570\">3. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"1572\" data-end=\"1905\">\r\n<li data-start=\"1572\" data-end=\"1646\">\r\n<p data-start=\"1574\" data-end=\"1646\">Schwachstellen werden <strong data-start=\"1596\" data-end=\"1646\">systematisch erfasst, bewertet und priorisiert</strong></p>\r\n</li>\r\n<li data-start=\"1647\" data-end=\"1741\">\r\n<p data-start=\"1649\" data-end=\"1741\">Sicherheitsupdates und Patches sind <strong data-start=\"1685\" data-end=\"1728\">zeitnah, risikobasiert und dokumentiert</strong> einzuspielen</p>\r\n</li>\r\n<li data-start=\"1742\" data-end=\"1813\">\r\n<p data-start=\"1744\" data-end=\"1813\">&Auml;nderungen erfolgen im Einklang mit dem <strong data-start=\"1784\" data-end=\"1813\">Change-Management-Prozess</strong></p>\r\n</li>\r\n<li data-start=\"1814\" data-end=\"1905\">\r\n<p data-start=\"1816\" data-end=\"1905\">Es gilt das Prinzip <strong data-start=\"1836\" data-end=\"1858\">&bdquo;Know your assets&ldquo;</strong> &ndash; nur bekannte Systeme k&ouml;nnen gesch&uuml;tzt werden</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1907\" data-end=\"1910\">\r\n<h2 data-start=\"1912\" data-end=\"1953\"><strong data-start=\"1915\" data-end=\"1953\">4. Schwachstellenmanagementprozess</strong></h2>\r\n<h3 data-start=\"1955\" data-end=\"1986\">4.1 Schwachstellenerkennung</h3>\r\n<ul data-start=\"1988\" data-end=\"2281\">\r\n<li data-start=\"1988\" data-end=\"2069\">\r\n<p data-start=\"1990\" data-end=\"2069\">Einsatz automatisierter Schwachstellenscanner (z. B. Nessus, Greenbone, Qualys)</p>\r\n</li>\r\n<li data-start=\"2070\" data-end=\"2123\">\r\n<p data-start=\"2072\" data-end=\"2123\">Regelm&auml;&szlig;ige Sicherheitsanalysen / Penetrationstests</p>\r\n</li>\r\n<li data-start=\"2124\" data-end=\"2229\">\r\n<p data-start=\"2126\" data-end=\"2173\">Beobachtung von relevanten Informationsquellen:</p>\r\n<ul data-start=\"2176\" data-end=\"2229\">\r\n<li data-start=\"2176\" data-end=\"2229\">\r\n<p data-start=\"2178\" data-end=\"2229\">BSI CERT-Bund, CVE-Datenbank, Hersteller-Newsletter</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"2230\" data-end=\"2281\">\r\n<p data-start=\"2232\" data-end=\"2281\">Meldung durch interne IT, User oder Dienstleister</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2283\" data-end=\"2317\">4.2 Bewertung &amp; Klassifikation</h3>\r\n<ul data-start=\"2319\" data-end=\"2615\">\r\n<li data-start=\"2319\" data-end=\"2508\">\r\n<p data-start=\"2321\" data-end=\"2412\">Bewertung von Schwachstellen basierend auf <strong data-start=\"2364\" data-end=\"2410\">CVSS (Common Vulnerability Scoring System)</strong></p>\r\n<ul data-start=\"2415\" data-end=\"2508\">\r\n<li data-start=\"2415\" data-end=\"2440\">\r\n<p data-start=\"2417\" data-end=\"2440\">Kritisch (CVSS &ge; 9.0)</p>\r\n</li>\r\n<li data-start=\"2443\" data-end=\"2463\">\r\n<p data-start=\"2445\" data-end=\"2463\">Hoch (7.0 &ndash; 8.9)</p>\r\n</li>\r\n<li data-start=\"2466\" data-end=\"2488\">\r\n<p data-start=\"2468\" data-end=\"2488\">Mittel (4.0 &ndash; 6.9)</p>\r\n</li>\r\n<li data-start=\"2491\" data-end=\"2508\">\r\n<p data-start=\"2493\" data-end=\"2508\">Niedrig (&lt; 4.0)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"2510\" data-end=\"2615\">\r\n<p data-start=\"2512\" data-end=\"2615\">Ber&uuml;cksichtigung des <strong data-start=\"2533\" data-end=\"2565\">konkreten Risikos im Kontext</strong> (z. B. Netzsegment, Exponiertheit, Benutzerkreis)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2617\" data-end=\"2638\">4.3 Priorisierung</h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2640\" data-end=\"2910\">\r\n<thead data-start=\"2640\" data-end=\"2667\">\r\n<tr data-start=\"2640\" data-end=\"2667\">\r\n<th data-start=\"2640\" data-end=\"2655\" data-col-size=\"sm\">Kritikalit&auml;t</th>\r\n<th data-start=\"2655\" data-end=\"2667\" data-col-size=\"md\">Reaktion</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2696\" data-end=\"2910\">\r\n<tr data-start=\"2696\" data-end=\"2745\">\r\n<td data-start=\"2696\" data-end=\"2712\" data-col-size=\"sm\"><strong data-start=\"2698\" data-end=\"2710\">Kritisch</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2712\" data-end=\"2745\">Behebung binnen 3&ndash;5 Werktagen</td>\r\n</tr>\r\n<tr data-start=\"2746\" data-end=\"2794\">\r\n<td data-start=\"2746\" data-end=\"2762\" data-col-size=\"sm\"><strong data-start=\"2748\" data-end=\"2756\">Hoch</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2762\" data-end=\"2794\">Behebung binnen 10 Werktagen</td>\r\n</tr>\r\n<tr data-start=\"2795\" data-end=\"2841\">\r\n<td data-start=\"2795\" data-end=\"2811\" data-col-size=\"sm\"><strong data-start=\"2797\" data-end=\"2807\">Mittel</strong></td>\r\n<td data-start=\"2811\" data-end=\"2841\" data-col-size=\"md\">Planung innerhalb 30 Tagen</td>\r\n</tr>\r\n<tr data-start=\"2842\" data-end=\"2910\">\r\n<td data-start=\"2842\" data-end=\"2858\" data-col-size=\"sm\"><strong data-start=\"2844\" data-end=\"2855\">Niedrig</strong></td>\r\n<td data-start=\"2858\" data-end=\"2910\" data-col-size=\"md\">Nach Bedarf, sp&auml;testens im n&auml;chsten Patch-Zyklus</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2912\" data-end=\"2915\">\r\n<h2 data-start=\"2917\" data-end=\"2949\"><strong data-start=\"2920\" data-end=\"2949\">5. Patchmanagementprozess</strong></h2>\r\n<h3 data-start=\"2951\" data-end=\"2979\">5.1 Quellen &amp; Monitoring</h3>\r\n<ul data-start=\"2981\" data-end=\"3156\">\r\n<li data-start=\"2981\" data-end=\"3072\">\r\n<p data-start=\"2983\" data-end=\"3072\"><strong data-start=\"2983\" data-end=\"3031\">Patch-Informationen werden zentral gesammelt</strong> von Herstellern, Abos, externen Partnern</p>\r\n</li>\r\n<li data-start=\"3073\" data-end=\"3156\">\r\n<p data-start=\"3075\" data-end=\"3156\">&Uuml;berwachung der <strong data-start=\"3091\" data-end=\"3120\">Lifecycle-/Supportfristen</strong> (End-of-Life-Komponenten vermeiden)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3158\" data-end=\"3181\">5.2 Test &amp; Freigabe</h3>\r\n<ul data-start=\"3183\" data-end=\"3421\">\r\n<li data-start=\"3183\" data-end=\"3242\">\r\n<p data-start=\"3185\" data-end=\"3242\">Patches werden <strong data-start=\"3200\" data-end=\"3242\">zun&auml;chst in einer Testumgebung gepr&uuml;ft</strong></p>\r\n</li>\r\n<li data-start=\"3243\" data-end=\"3348\">\r\n<p data-start=\"3245\" data-end=\"3348\">Kritische Patches d&uuml;rfen nur nach <strong data-start=\"3279\" data-end=\"3329\">technischer und sicherheitsrelevanter Freigabe</strong> eingespielt werden</p>\r\n</li>\r\n<li data-start=\"3349\" data-end=\"3421\">\r\n<p data-start=\"3351\" data-end=\"3421\">Bei potenziellen Nebenwirkungen ist ein <strong data-start=\"3391\" data-end=\"3421\">Rollback-Plan erforderlich</strong></p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3423\" data-end=\"3458\">5.3 Einspielung &amp; Dokumentation</h3>\r\n<ul data-start=\"3460\" data-end=\"3701\">\r\n<li data-start=\"3460\" data-end=\"3553\">\r\n<p data-start=\"3462\" data-end=\"3553\">Sicherheitsrelevante Updates werden bevorzugt <strong data-start=\"3508\" data-end=\"3540\">au&szlig;erhalb der Betriebszeiten</strong> durchgef&uuml;hrt</p>\r\n</li>\r\n<li data-start=\"3554\" data-end=\"3630\">\r\n<p data-start=\"3556\" data-end=\"3630\">Alle &Auml;nderungen werden im <strong data-start=\"3582\" data-end=\"3630\">Change-/Patch-Management-System dokumentiert</strong></p>\r\n</li>\r\n<li data-start=\"3631\" data-end=\"3701\">\r\n<p data-start=\"3633\" data-end=\"3701\">Erfolgreiches Update wird <strong data-start=\"3659\" data-end=\"3693\">&uuml;ber Monitoring / Verifikation</strong> gepr&uuml;ft</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3703\" data-end=\"3706\">\r\n<h2 data-start=\"3708\" data-end=\"3741\"><strong data-start=\"3711\" data-end=\"3741\">6. Automatisierung &amp; Tools</strong></h2>\r\n<ul data-start=\"3743\" data-end=\"3987\">\r\n<li data-start=\"3743\" data-end=\"3844\">\r\n<p data-start=\"3745\" data-end=\"3844\">Verwendung zentraler Patch-Management-Systeme (z. B. WSUS, SCCM, Ansible, Linux-Repos, MDM-Systeme)</p>\r\n</li>\r\n<li data-start=\"3845\" data-end=\"3925\">\r\n<p data-start=\"3847\" data-end=\"3925\">Automatisches Reporting und <strong data-start=\"3875\" data-end=\"3906\">&Uuml;bersicht &uuml;ber Patch-St&auml;nde</strong> je System / Gruppe</p>\r\n</li>\r\n<li data-start=\"3926\" data-end=\"3987\">\r\n<p data-start=\"3928\" data-end=\"3987\">Automatisierte Alarmierung bei fehlenden kritischen Patches</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3989\" data-end=\"3992\">\r\n<h2 data-start=\"3994\" data-end=\"4040\"><strong data-start=\"3997\" data-end=\"4040\">7. Umgang mit nicht patchbaren Systemen</strong></h2>\r\n<ul data-start=\"4042\" data-end=\"4355\">\r\n<li data-start=\"4042\" data-end=\"4355\">\r\n<p data-start=\"4044\" data-end=\"4109\">Wenn Patching technisch nicht m&ouml;glich ist (z. B. Legacy-Systeme):</p>\r\n<ul data-start=\"4112\" data-end=\"4355\">\r\n<li data-start=\"4112\" data-end=\"4147\">\r\n<p data-start=\"4114\" data-end=\"4147\">Risikoanalyse mit ISB durchf&uuml;hren</p>\r\n</li>\r\n<li data-start=\"4150\" data-end=\"4195\">\r\n<p data-start=\"4152\" data-end=\"4195\">Ersatz- oder Migrationsstrategie entwickeln</p>\r\n</li>\r\n<li data-start=\"4198\" data-end=\"4355\">\r\n<p data-start=\"4200\" data-end=\"4238\"><strong data-start=\"4200\" data-end=\"4228\">Kompensierende Ma&szlig;nahmen</strong> umsetzen:</p>\r\n<ul data-start=\"4243\" data-end=\"4355\">\r\n<li data-start=\"4243\" data-end=\"4262\">\r\n<p data-start=\"4245\" data-end=\"4262\">Netzsegmentierung</p>\r\n</li>\r\n<li data-start=\"4267\" data-end=\"4292\">\r\n<p data-start=\"4269\" data-end=\"4292\">Firewalleinschr&auml;nkungen</p>\r\n</li>\r\n<li data-start=\"4297\" data-end=\"4327\">\r\n<p data-start=\"4299\" data-end=\"4327\">Abschalten unn&ouml;tiger Dienste</p>\r\n</li>\r\n<li data-start=\"4332\" data-end=\"4355\">\r\n<p data-start=\"4334\" data-end=\"4355\">&Uuml;berwachung / Logging</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4357\" data-end=\"4360\">\r\n<h2 data-start=\"4362\" data-end=\"4394\"><strong data-start=\"4365\" data-end=\"4394\">8. Kommunikation &amp; Rollen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4396\" data-end=\"4900\">\r\n<thead data-start=\"4396\" data-end=\"4421\">\r\n<tr data-start=\"4396\" data-end=\"4421\">\r\n<th data-start=\"4396\" data-end=\"4404\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"4404\" data-end=\"4421\" data-col-size=\"md\">Verantwortung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4449\" data-end=\"4900\">\r\n<tr data-start=\"4449\" data-end=\"4543\">\r\n<td data-start=\"4449\" data-end=\"4491\" data-col-size=\"sm\"><strong data-start=\"4451\" data-end=\"4490\">IT-Abteilung / Systemadministration</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4491\" data-end=\"4543\">Durchf&uuml;hrung von Scans, Patch-Tests, Einspielung</td>\r\n</tr>\r\n<tr data-start=\"4544\" data-end=\"4640\">\r\n<td data-start=\"4544\" data-end=\"4584\" data-col-size=\"sm\"><strong data-start=\"4546\" data-end=\"4583\">IT-Sicherheitsbeauftragte*r (ISB)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4584\" data-end=\"4640\">Vorgaben zur Bewertung, Risikoeinsch&auml;tzung, Freigabe</td>\r\n</tr>\r\n<tr data-start=\"4641\" data-end=\"4722\">\r\n<td data-start=\"4641\" data-end=\"4675\" data-col-size=\"sm\"><strong data-start=\"4643\" data-end=\"4674\">Change Advisory Board (CAB)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4675\" data-end=\"4722\">Koordination gr&ouml;&szlig;erer &Auml;nderungen / Rollouts</td>\r\n</tr>\r\n<tr data-start=\"4723\" data-end=\"4806\">\r\n<td data-start=\"4723\" data-end=\"4751\" data-col-size=\"sm\"><strong data-start=\"4725\" data-end=\"4750\">Externe Dienstleister</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4751\" data-end=\"4806\">Patchen im Rahmen vertraglich definierter Pflichten</td>\r\n</tr>\r\n<tr data-start=\"4807\" data-end=\"4900\">\r\n<td data-start=\"4807\" data-end=\"4850\" data-col-size=\"sm\"><strong data-start=\"4809\" data-end=\"4849\">Fachbereiche / Systemverantwortliche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4850\" data-end=\"4900\">R&uuml;ckmeldung zu Tests, Auswirkungen auf Betrieb</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4902\" data-end=\"4905\">\r\n<h2 data-start=\"4907\" data-end=\"4954\"><strong data-start=\"4910\" data-end=\"4954\">9. Schnittstellen zu anderen Richtlinien</strong></h2>\r\n<p data-start=\"4956\" data-end=\"4981\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"4983\" data-end=\"5147\">\r\n<li data-start=\"4983\" data-end=\"5017\">\r\n<p data-start=\"4985\" data-end=\"5017\"><strong data-start=\"4985\" data-end=\"5017\">Change-Management-Richtlinie</strong></p>\r\n</li>\r\n<li data-start=\"5018\" data-end=\"5043\">\r\n<p data-start=\"5020\" data-end=\"5043\"><strong data-start=\"5020\" data-end=\"5043\">Incident Management</strong></p>\r\n</li>\r\n<li data-start=\"5044\" data-end=\"5083\">\r\n<p data-start=\"5046\" data-end=\"5083\"><strong data-start=\"5046\" data-end=\"5083\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"5084\" data-end=\"5113\">\r\n<p data-start=\"5086\" data-end=\"5113\"><strong data-start=\"5086\" data-end=\"5113\">Asset Management / CMDB</strong></p>\r\n</li>\r\n<li data-start=\"5114\" data-end=\"5147\">\r\n<p data-start=\"5116\" data-end=\"5147\"><strong data-start=\"5116\" data-end=\"5147\">Secure Software Development</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5149\" data-end=\"5152\">\r\n<h2 data-start=\"5154\" data-end=\"5194\"><strong data-start=\"5157\" data-end=\"5194\">10. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5196\" data-end=\"5584\">\r\n<thead data-start=\"5196\" data-end=\"5235\">\r\n<tr data-start=\"5196\" data-end=\"5235\">\r\n<th data-start=\"5196\" data-end=\"5214\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"5214\" data-end=\"5235\" data-col-size=\"md\">Relevante Inhalte</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5278\" data-end=\"5584\">\r\n<tr data-start=\"5278\" data-end=\"5395\">\r\n<td data-start=\"5278\" data-end=\"5303\" data-col-size=\"sm\"><strong data-start=\"5280\" data-end=\"5302\">ISO/IEC 27001:2022</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5303\" data-end=\"5395\">A.8.7 (Sichere Konfiguration), A.8.8 (Malware-Schutz), A.8.9 (Technische Schwachstellen)</td>\r\n</tr>\r\n<tr data-start=\"5396\" data-end=\"5514\">\r\n<td data-start=\"5396\" data-end=\"5421\" data-col-size=\"sm\"><strong data-start=\"5398\" data-end=\"5420\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5421\" data-end=\"5514\">OPS.1.1.2 (Patch- und &Auml;nderungsmanagement), OPS.1.3.4 (Schwachstellenmanagement), ORP.4.1</td>\r\n</tr>\r\n<tr data-start=\"5515\" data-end=\"5584\">\r\n<td data-start=\"5515\" data-end=\"5535\" data-col-size=\"sm\"><strong data-start=\"5517\" data-end=\"5534\">DSGVO Art. 32</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5535\" data-end=\"5584\">Sicherheit der Verarbeitung &ndash; Patchen als TOM</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(19, 'DOK-0019', 'Sichere Konfiguration & IT Betrieb', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"995\" data-end=\"1025\"><strong data-start=\"998\" data-end=\"1025\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"1027\" data-end=\"1185\">Diese Richtlinie legt verbindliche Anforderungen f&uuml;r den <strong data-start=\"1084\" data-end=\"1120\">sicheren Betrieb von IT-Systemen</strong> und die <strong data-start=\"1129\" data-end=\"1166\">H&auml;rtung von Systemkonfigurationen</strong> fest. Ziel ist es:</p>\r\n<ul data-start=\"1187\" data-end=\"1386\">\r\n<li data-start=\"1187\" data-end=\"1276\">\r\n<p data-start=\"1189\" data-end=\"1276\">Risiken durch Fehlkonfiguration, veraltete Systeme und Standardzug&auml;nge zu minimieren,</p>\r\n</li>\r\n<li data-start=\"1277\" data-end=\"1318\">\r\n<p data-start=\"1279\" data-end=\"1318\">die Systemh&auml;rtung zu standardisieren,</p>\r\n</li>\r\n<li data-start=\"1319\" data-end=\"1386\">\r\n<p data-start=\"1321\" data-end=\"1386\">und einen stabilen, nachvollziehbaren IT-Betrieb sicherzustellen.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1388\" data-end=\"1391\">\r\n<h2 data-start=\"1393\" data-end=\"1418\"><strong data-start=\"1396\" data-end=\"1418\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1420\" data-end=\"1446\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1448\" data-end=\"1711\">\r\n<li data-start=\"1448\" data-end=\"1578\">\r\n<p data-start=\"1450\" data-end=\"1578\"><strong data-start=\"1450\" data-end=\"1538\">Alle Server, Clients, mobilen Ger&auml;te, Netzkomponenten, Cloud-Dienste und IoT-Systeme</strong>, die im Unternehmen eingesetzt werden</p>\r\n</li>\r\n<li data-start=\"1579\" data-end=\"1658\">\r\n<p data-start=\"1581\" data-end=\"1658\"><strong data-start=\"1581\" data-end=\"1656\">Alle IT-Administratoren, DevOps-, IT-Operations- und Infrastrukturteams</strong></p>\r\n</li>\r\n<li data-start=\"1659\" data-end=\"1711\">\r\n<p data-start=\"1661\" data-end=\"1711\"><strong data-start=\"1661\" data-end=\"1680\">Alle Umgebungen</strong>: Entwicklung, Test, Produktion</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1713\" data-end=\"1716\">\r\n<h2 data-start=\"1718\" data-end=\"1738\"><strong data-start=\"1721\" data-end=\"1738\">3. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"1740\" data-end=\"2081\">\r\n<li data-start=\"1740\" data-end=\"1838\">\r\n<p data-start=\"1742\" data-end=\"1838\"><strong data-start=\"1742\" data-end=\"1767\">Sichere Konfiguration</strong> ist Standard &ndash; Systeme werden nicht mit Werkseinstellungen betrieben</p>\r\n</li>\r\n<li data-start=\"1839\" data-end=\"1927\">\r\n<p data-start=\"1841\" data-end=\"1927\">Der <strong data-start=\"1845\" data-end=\"1925\">IT-Betrieb erfolgt kontrolliert, dokumentiert und nach definierten Prozessen</strong></p>\r\n</li>\r\n<li data-start=\"1928\" data-end=\"2024\">\r\n<p data-start=\"1930\" data-end=\"2024\"><strong data-start=\"1930\" data-end=\"1947\">Systemh&auml;rtung</strong> basiert auf anerkannten Standards (z. B. CIS Benchmarks, BSI-Empfehlungen)</p>\r\n</li>\r\n<li data-start=\"2025\" data-end=\"2081\">\r\n<p data-start=\"2027\" data-end=\"2081\">&Auml;nderungen erfolgen nur &uuml;ber das <strong data-start=\"2060\" data-end=\"2081\">Change Management</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2083\" data-end=\"2086\">\r\n<h2 data-start=\"2088\" data-end=\"2136\"><strong data-start=\"2091\" data-end=\"2136\">4. Anforderungen an sichere Konfiguration</strong></h2>\r\n<h3 data-start=\"2138\" data-end=\"2164\">4.1 Basisanforderungen</h3>\r\n<ul data-start=\"2166\" data-end=\"2480\">\r\n<li data-start=\"2166\" data-end=\"2243\">\r\n<p data-start=\"2168\" data-end=\"2243\"><strong data-start=\"2168\" data-end=\"2241\">Deaktivierung unn&ouml;tiger Dienste, Ports, Benutzerkonten und Funktionen</strong></p>\r\n</li>\r\n<li data-start=\"2244\" data-end=\"2319\">\r\n<p data-start=\"2246\" data-end=\"2319\">Entfernen oder Absichern von <strong data-start=\"2275\" data-end=\"2317\">Standardpassw&ouml;rtern / Default-Zug&auml;ngen</strong></p>\r\n</li>\r\n<li data-start=\"2320\" data-end=\"2380\">\r\n<p data-start=\"2322\" data-end=\"2380\">Konfiguration nach dem Prinzip <strong data-start=\"2353\" data-end=\"2378\">\"Least Functionality\"</strong></p>\r\n</li>\r\n<li data-start=\"2381\" data-end=\"2480\">\r\n<p data-start=\"2383\" data-end=\"2480\">Einsatz sicherer Protokolle: z. B. <strong data-start=\"2418\" data-end=\"2438\">SSH statt Telnet</strong>, <strong data-start=\"2440\" data-end=\"2460\">HTTPS statt HTTP</strong>, <strong data-start=\"2462\" data-end=\"2480\">SFTP statt FTP</strong></p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2482\" data-end=\"2510\">4.2 H&auml;rtung von Systemen</h3>\r\n<ul data-start=\"2512\" data-end=\"2833\">\r\n<li data-start=\"2512\" data-end=\"2675\">\r\n<p data-start=\"2514\" data-end=\"2558\">Anwendung etablierter <strong data-start=\"2536\" data-end=\"2557\">H&auml;rtungsleitf&auml;den</strong>:</p>\r\n<ul data-start=\"2561\" data-end=\"2675\">\r\n<li data-start=\"2561\" data-end=\"2579\">\r\n<p data-start=\"2563\" data-end=\"2579\">CIS Benchmarks</p>\r\n</li>\r\n<li data-start=\"2582\" data-end=\"2602\">\r\n<p data-start=\"2584\" data-end=\"2602\">BSI-Empfehlungen</p>\r\n</li>\r\n<li data-start=\"2605\" data-end=\"2675\">\r\n<p data-start=\"2607\" data-end=\"2675\">Herstellerleitlinien (z. B. Microsoft, VMware, Linux-Distributionen)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"2677\" data-end=\"2774\">\r\n<p data-start=\"2679\" data-end=\"2774\"><strong data-start=\"2679\" data-end=\"2698\">Automatisierung</strong> &uuml;ber Konfigurationsmanagement-Tools (z. B. Ansible, Puppet, Intune, GPOs)</p>\r\n</li>\r\n<li data-start=\"2775\" data-end=\"2833\">\r\n<p data-start=\"2777\" data-end=\"2833\">J&auml;hrliche &Uuml;berpr&uuml;fung aller Konfigurationen mit Nachweis</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"2835\" data-end=\"2867\">4.3 Konfigurations&auml;nderungen</h3>\r\n<ul data-start=\"2869\" data-end=\"3113\">\r\n<li data-start=\"2869\" data-end=\"3113\">\r\n<p data-start=\"2871\" data-end=\"2906\">Alle &Auml;nderungen an Konfigurationen:</p>\r\n<ul data-start=\"2909\" data-end=\"3113\">\r\n<li data-start=\"2909\" data-end=\"2957\">\r\n<p data-start=\"2911\" data-end=\"2957\">erfolgen gem&auml;&szlig; <strong data-start=\"2926\" data-end=\"2955\">Change-Management-Prozess</strong></p>\r\n</li>\r\n<li data-start=\"2960\" data-end=\"3046\">\r\n<p data-start=\"2962\" data-end=\"3046\">werden <strong data-start=\"2969\" data-end=\"3017\">dokumentiert, r&uuml;ckverfolgbar und versioniert</strong> (z. B. Git, Ticket-System)</p>\r\n</li>\r\n<li data-start=\"3049\" data-end=\"3113\">\r\n<p data-start=\"3051\" data-end=\"3113\">unterliegen dem <strong data-start=\"3067\" data-end=\"3089\">Vier-Augen-Prinzip</strong> bei kritischen Systemen</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3115\" data-end=\"3118\">\r\n<h2 data-start=\"3120\" data-end=\"3161\"><strong data-start=\"3123\" data-end=\"3161\">5. Anforderungen an den IT-Betrieb</strong></h2>\r\n<h3 data-start=\"3163\" data-end=\"3190\">5.1 Allgemeiner Betrieb</h3>\r\n<ul data-start=\"3192\" data-end=\"3541\">\r\n<li data-start=\"3192\" data-end=\"3283\">\r\n<p data-start=\"3194\" data-end=\"3283\">Systeme werden nach dem Prinzip <strong data-start=\"3226\" data-end=\"3271\">&bdquo;Standardisierung vor Individualisierung&ldquo;</strong> betrieben</p>\r\n</li>\r\n<li data-start=\"3284\" data-end=\"3356\">\r\n<p data-start=\"3286\" data-end=\"3356\">Einsatz von <strong data-start=\"3298\" data-end=\"3339\">aktuellen und unterst&uuml;tzten Versionen</strong> (kein EOL/EOS)</p>\r\n</li>\r\n<li data-start=\"3357\" data-end=\"3439\">\r\n<p data-start=\"3359\" data-end=\"3439\">Nutzung von <strong data-start=\"3371\" data-end=\"3415\">zertifizierten oder freigegebenen Images</strong> bei Neuinstallationen</p>\r\n</li>\r\n<li data-start=\"3440\" data-end=\"3541\">\r\n<p data-start=\"3442\" data-end=\"3478\">Regelm&auml;&szlig;ige <strong data-start=\"3454\" data-end=\"3471\">Systemwartung</strong> inkl.:</p>\r\n<ul data-start=\"3481\" data-end=\"3541\">\r\n<li data-start=\"3481\" data-end=\"3502\">\r\n<p data-start=\"3483\" data-end=\"3502\">Updates / Patches</p>\r\n</li>\r\n<li data-start=\"3505\" data-end=\"3521\">\r\n<p data-start=\"3507\" data-end=\"3521\">Backup-Tests</p>\r\n</li>\r\n<li data-start=\"3524\" data-end=\"3541\">\r\n<p data-start=\"3526\" data-end=\"3541\">Protokollpflege</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3543\" data-end=\"3575\">5.2 &Uuml;berwachung &amp; Monitoring</h3>\r\n<ul data-start=\"3577\" data-end=\"3854\">\r\n<li data-start=\"3577\" data-end=\"3658\">\r\n<p data-start=\"3579\" data-end=\"3658\">Einsatz zentraler Monitoring-Systeme (z. B. Zabbix, Icinga, PRTG, CloudWatch)</p>\r\n</li>\r\n<li data-start=\"3659\" data-end=\"3786\">\r\n<p data-start=\"3661\" data-end=\"3677\">&Uuml;berwachung von:</p>\r\n<ul data-start=\"3680\" data-end=\"3786\">\r\n<li data-start=\"3680\" data-end=\"3697\">\r\n<p data-start=\"3682\" data-end=\"3697\">Verf&uuml;gbarkeit</p>\r\n</li>\r\n<li data-start=\"3700\" data-end=\"3715\">\r\n<p data-start=\"3702\" data-end=\"3715\">Performance</p>\r\n</li>\r\n<li data-start=\"3718\" data-end=\"3755\">\r\n<p data-start=\"3720\" data-end=\"3755\">sicherheitsrelevanten Ereignissen</p>\r\n</li>\r\n<li data-start=\"3758\" data-end=\"3786\">\r\n<p data-start=\"3760\" data-end=\"3786\">Konfigurationsabweichungen</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"3788\" data-end=\"3854\">\r\n<p data-start=\"3790\" data-end=\"3854\">Warn- und Eskalationsmechanismen bei St&ouml;rungen / Auff&auml;lligkeiten</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3856\" data-end=\"3871\">5.3 Logging</h3>\r\n<ul data-start=\"3873\" data-end=\"4056\">\r\n<li data-start=\"3873\" data-end=\"3959\">\r\n<p data-start=\"3875\" data-end=\"3959\">Zentrale Protokollierung sicherheitsrelevanter Ereignisse gem&auml;&szlig; Logging-Richtlinie</p>\r\n</li>\r\n<li data-start=\"3960\" data-end=\"4056\">\r\n<p data-start=\"3962\" data-end=\"4056\">Konfigurations&auml;nderungen und administrative T&auml;tigkeiten sind <strong data-start=\"4023\" data-end=\"4056\">vollst&auml;ndig zu protokollieren</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4058\" data-end=\"4061\">\r\n<h2 data-start=\"4063\" data-end=\"4111\"><strong data-start=\"4066\" data-end=\"4111\">6. Schutzma&szlig;nahmen bei Systeminstallation</strong></h2>\r\n<ul data-start=\"4113\" data-end=\"4343\">\r\n<li data-start=\"4113\" data-end=\"4343\">\r\n<p data-start=\"4115\" data-end=\"4156\">Alle Systeme erhalten vor Inbetriebnahme:</p>\r\n<ul data-start=\"4159\" data-end=\"4343\">\r\n<li data-start=\"4159\" data-end=\"4190\">\r\n<p data-start=\"4161\" data-end=\"4190\">aktuelle Sicherheitspatches</p>\r\n</li>\r\n<li data-start=\"4193\" data-end=\"4218\">\r\n<p data-start=\"4195\" data-end=\"4218\">H&auml;rtung nach Vorgaben</p>\r\n</li>\r\n<li data-start=\"4221\" data-end=\"4262\">\r\n<p data-start=\"4223\" data-end=\"4262\">Dokumentation im <strong data-start=\"4240\" data-end=\"4260\">Asset Management</strong></p>\r\n</li>\r\n<li data-start=\"4265\" data-end=\"4301\">\r\n<p data-start=\"4267\" data-end=\"4301\">Aufnahme ins Monitoring &amp; Backup</p>\r\n</li>\r\n<li data-start=\"4304\" data-end=\"4343\">\r\n<p data-start=\"4306\" data-end=\"4343\">Aufnahme in die Schwachstellenpr&uuml;fung</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4345\" data-end=\"4348\">\r\n<h2 data-start=\"4350\" data-end=\"4380\"><strong data-start=\"4353\" data-end=\"4380\">7. Technische Standards</strong></h2>\r\n<h3 data-start=\"4382\" data-end=\"4405\">7.1 Betriebssysteme</h3>\r\n<ul data-start=\"4407\" data-end=\"4654\">\r\n<li data-start=\"4407\" data-end=\"4475\">\r\n<p data-start=\"4409\" data-end=\"4475\">Nur aktuell unterst&uuml;tzte Versionen (Hersteller-Support oder LTS)</p>\r\n</li>\r\n<li data-start=\"4476\" data-end=\"4527\">\r\n<p data-start=\"4478\" data-end=\"4527\">Automatische Updates, sofern m&ouml;glich, aktiviert</p>\r\n</li>\r\n<li data-start=\"4528\" data-end=\"4654\">\r\n<p data-start=\"4530\" data-end=\"4572\">Aktivierung von Sicherheitsfunktionen wie:</p>\r\n<ul data-start=\"4575\" data-end=\"4654\">\r\n<li data-start=\"4575\" data-end=\"4607\">\r\n<p data-start=\"4577\" data-end=\"4607\">BitLocker / LUKS / FileVault</p>\r\n</li>\r\n<li data-start=\"4610\" data-end=\"4625\">\r\n<p data-start=\"4612\" data-end=\"4625\">Secure Boot</p>\r\n</li>\r\n<li data-start=\"4628\" data-end=\"4654\">\r\n<p data-start=\"4630\" data-end=\"4654\">Antivirus / EDR-Software</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4656\" data-end=\"4688\">7.2 Clients &amp; Mobile Devices</h3>\r\n<ul data-start=\"4690\" data-end=\"4921\">\r\n<li data-start=\"4690\" data-end=\"4762\">\r\n<p data-start=\"4692\" data-end=\"4762\">Einrichtung &uuml;ber zentrale Verwaltung (MDM, Intune, Endpoint Manager)</p>\r\n</li>\r\n<li data-start=\"4763\" data-end=\"4807\">\r\n<p data-start=\"4765\" data-end=\"4807\">Keine lokalen Admin-Rechte f&uuml;r Endnutzer</p>\r\n</li>\r\n<li data-start=\"4808\" data-end=\"4867\">\r\n<p data-start=\"4810\" data-end=\"4867\">Ger&auml;teverschl&uuml;sselung und Sperrbildschirm verpflichtend</p>\r\n</li>\r\n<li data-start=\"4868\" data-end=\"4921\">\r\n<p data-start=\"4870\" data-end=\"4921\">Zugriffe nur auf definierte Netze und Cloud-Dienste</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4923\" data-end=\"4959\">7.3 Netzkomponenten &amp; Appliances</h3>\r\n<ul data-start=\"4961\" data-end=\"5170\">\r\n<li data-start=\"4961\" data-end=\"5005\">\r\n<p data-start=\"4963\" data-end=\"5005\">Konfigurationsbackups regelm&auml;&szlig;ig sichern</p>\r\n</li>\r\n<li data-start=\"5006\" data-end=\"5055\">\r\n<p data-start=\"5008\" data-end=\"5055\">Absicherung &uuml;ber ACLs, VPN, Authentifizierung</p>\r\n</li>\r\n<li data-start=\"5056\" data-end=\"5127\">\r\n<p data-start=\"5058\" data-end=\"5127\">Fernzugriffe nur verschl&uuml;sselt (z. B. SSH mit Schl&uuml;ssel, IPsec-VPN)</p>\r\n</li>\r\n<li data-start=\"5128\" data-end=\"5170\">\r\n<p data-start=\"5130\" data-end=\"5170\">Keine webbasierte Konfiguration ohne TLS</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5172\" data-end=\"5175\">\r\n<h2 data-start=\"5177\" data-end=\"5213\"><strong data-start=\"5180\" data-end=\"5213\">8. Umgang mit Legacy-Systemen</strong></h2>\r\n<ul data-start=\"5215\" data-end=\"5453\">\r\n<li data-start=\"5215\" data-end=\"5304\">\r\n<p data-start=\"5217\" data-end=\"5304\">Legacy-Systeme sind <strong data-start=\"5237\" data-end=\"5265\">explizit zu kennzeichnen</strong> und im Asset Management zu vermerken</p>\r\n</li>\r\n<li data-start=\"5305\" data-end=\"5453\">\r\n<p data-start=\"5307\" data-end=\"5345\"><strong data-start=\"5307\" data-end=\"5335\">Kompensierende Ma&szlig;nahmen</strong> umsetzen:</p>\r\n<ul data-start=\"5348\" data-end=\"5453\">\r\n<li data-start=\"5348\" data-end=\"5365\">\r\n<p data-start=\"5350\" data-end=\"5365\">Segmentierung</p>\r\n</li>\r\n<li data-start=\"5368\" data-end=\"5392\">\r\n<p data-start=\"5370\" data-end=\"5392\">Zugriffsbeschr&auml;nkung</p>\r\n</li>\r\n<li data-start=\"5395\" data-end=\"5409\">\r\n<p data-start=\"5397\" data-end=\"5409\">Monitoring</p>\r\n</li>\r\n<li data-start=\"5412\" data-end=\"5453\">\r\n<p data-start=\"5414\" data-end=\"5453\">Ersatzplanung / Auslaufdatum definieren</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5455\" data-end=\"5458\">\r\n<h2 data-start=\"5460\" data-end=\"5492\"><strong data-start=\"5463\" data-end=\"5492\">9. Schulung und Awareness</strong></h2>\r\n<ul data-start=\"5494\" data-end=\"5718\">\r\n<li data-start=\"5494\" data-end=\"5718\">\r\n<p data-start=\"5496\" data-end=\"5587\">Administrator*innen und IT-Betriebspersonal sind regelm&auml;&szlig;ig zu folgenden Themen zu schulen:</p>\r\n<ul data-start=\"5590\" data-end=\"5718\">\r\n<li data-start=\"5590\" data-end=\"5607\">\r\n<p data-start=\"5592\" data-end=\"5607\">Systemh&auml;rtung</p>\r\n</li>\r\n<li data-start=\"5610\" data-end=\"5638\">\r\n<p data-start=\"5612\" data-end=\"5638\">Konfigurationsmanagement</p>\r\n</li>\r\n<li data-start=\"5641\" data-end=\"5675\">\r\n<p data-start=\"5643\" data-end=\"5675\">Umgang mit kritischen Systemen</p>\r\n</li>\r\n<li data-start=\"5678\" data-end=\"5718\">\r\n<p data-start=\"5680\" data-end=\"5718\">Neuerungen in Betriebssystemen / Tools</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5720\" data-end=\"5723\">\r\n<h2 data-start=\"5725\" data-end=\"5756\"><strong data-start=\"5728\" data-end=\"5756\">10. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5758\" data-end=\"6191\">\r\n<thead data-start=\"5758\" data-end=\"5778\">\r\n<tr data-start=\"5758\" data-end=\"5778\">\r\n<th data-start=\"5758\" data-end=\"5766\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5766\" data-end=\"5778\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5800\" data-end=\"6191\">\r\n<tr data-start=\"5800\" data-end=\"5905\">\r\n<td data-start=\"5800\" data-end=\"5840\" data-col-size=\"sm\"><strong data-start=\"5802\" data-end=\"5839\">IT-Betrieb / Systemadministration</strong></td>\r\n<td data-start=\"5840\" data-end=\"5905\" data-col-size=\"md\">Umsetzung der Konfigurationsvorgaben, Betrieb und &Uuml;berwachung</td>\r\n</tr>\r\n<tr data-start=\"5906\" data-end=\"5969\">\r\n<td data-start=\"5906\" data-end=\"5916\" data-col-size=\"sm\"><strong data-start=\"5908\" data-end=\"5915\">ISB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5916\" data-end=\"5969\">Sicherheitsfreigabe und &Uuml;berwachung der Umsetzung</td>\r\n</tr>\r\n<tr data-start=\"5970\" data-end=\"6052\">\r\n<td data-start=\"5970\" data-end=\"6004\" data-col-size=\"sm\"><strong data-start=\"5972\" data-end=\"6003\">Change Advisory Board (CAB)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6004\" data-end=\"6052\">Bewertung und Freigabe kritischer &Auml;nderungen</td>\r\n</tr>\r\n<tr data-start=\"6053\" data-end=\"6122\">\r\n<td data-start=\"6053\" data-end=\"6073\" data-col-size=\"sm\"><strong data-start=\"6055\" data-end=\"6072\">Asset Manager</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6073\" data-end=\"6122\">Dokumentation der Systeme und Konfigurationen</td>\r\n</tr>\r\n<tr data-start=\"6123\" data-end=\"6191\">\r\n<td data-start=\"6123\" data-end=\"6142\" data-col-size=\"sm\"><strong data-start=\"6125\" data-end=\"6141\">Fachbereiche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6142\" data-end=\"6191\">R&uuml;ckmeldung zu Ausf&auml;llen oder Systemproblemen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"6193\" data-end=\"6196\">\r\n<h2 data-start=\"6198\" data-end=\"6246\"><strong data-start=\"6201\" data-end=\"6246\">11. Schnittstellen zu anderen Richtlinien</strong></h2>\r\n<p data-start=\"6248\" data-end=\"6273\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"6275\" data-end=\"6471\">\r\n<li data-start=\"6275\" data-end=\"6316\">\r\n<p data-start=\"6277\" data-end=\"6316\"><strong data-start=\"6277\" data-end=\"6314\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6317\" data-end=\"6353\">\r\n<p data-start=\"6319\" data-end=\"6353\"><strong data-start=\"6319\" data-end=\"6351\">Change-Management-Richtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6354\" data-end=\"6395\">\r\n<p data-start=\"6356\" data-end=\"6395\"><strong data-start=\"6356\" data-end=\"6393\">Patch- &amp; Schwachstellenmanagement</strong></p>\r\n</li>\r\n<li data-start=\"6396\" data-end=\"6444\">\r\n<p data-start=\"6398\" data-end=\"6444\"><strong data-start=\"6398\" data-end=\"6442\">Backup- und Wiederherstellungsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6445\" data-end=\"6471\">\r\n<p data-start=\"6447\" data-end=\"6471\"><strong data-start=\"6447\" data-end=\"6471\">Logging &amp; Monitoring</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6473\" data-end=\"6476\">\r\n<h2 data-start=\"6478\" data-end=\"6518\"><strong data-start=\"6481\" data-end=\"6518\">12. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6520\" data-end=\"6986\">\r\n<thead data-start=\"6520\" data-end=\"6559\">\r\n<tr data-start=\"6520\" data-end=\"6559\">\r\n<th data-start=\"6520\" data-end=\"6538\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6538\" data-end=\"6559\" data-col-size=\"lg\">Relevante Inhalte</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6600\" data-end=\"6986\">\r\n<tr data-start=\"6600\" data-end=\"6732\">\r\n<td data-start=\"6600\" data-end=\"6625\" data-col-size=\"sm\"><strong data-start=\"6602\" data-end=\"6624\">ISO/IEC 27001:2022</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6625\" data-end=\"6732\">A.5.14 (Sichere Konfiguration), A.8.7 (Sicherer Betrieb), A.8.6 (Technologische Sicherheitsarchitektur)</td>\r\n</tr>\r\n<tr data-start=\"6733\" data-end=\"6883\">\r\n<td data-start=\"6733\" data-end=\"6758\" data-col-size=\"sm\"><strong data-start=\"6735\" data-end=\"6757\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6758\" data-end=\"6883\">SYS.1.1 (Server), SYS.1.2 (Clients), OPS.1.1.3 (Sichere Konfiguration), OPS.1.1.1 (IT-Betrieb), OPS.1.1.5 (Systemh&auml;rtung)</td>\r\n</tr>\r\n<tr data-start=\"6884\" data-end=\"6986\">\r\n<td data-start=\"6884\" data-end=\"6904\" data-col-size=\"sm\"><strong data-start=\"6886\" data-end=\"6903\">DSGVO Art. 32</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6904\" data-end=\"6986\">Technisch-organisatorische Ma&szlig;nahmen (TOM) &ndash; sichere Systeme &amp; Konfigurationen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(20, 'DOK-0020', 'Verfügbarkeitsrichtlinie', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"912\" data-end=\"942\"><strong data-start=\"915\" data-end=\"942\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"944\" data-end=\"1301\">Ziel dieser Richtlinie ist die Sicherstellung der <strong data-start=\"994\" data-end=\"1058\">Verf&uuml;gbarkeit von IT-Systemen, Anwendungen und Informationen</strong>, entsprechend dem definierten <strong data-start=\"1089\" data-end=\"1105\">Schutzbedarf</strong> und den <strong data-start=\"1114\" data-end=\"1156\">betriebswirtschaftlichen Anforderungen</strong>. Sie legt verbindliche Vorgaben und Ma&szlig;nahmen zur <strong data-start=\"1207\" data-end=\"1228\">Ausfallsicherheit</strong>, <strong data-start=\"1230\" data-end=\"1243\">Redundanz</strong>, <strong data-start=\"1245\" data-end=\"1265\">St&ouml;rfallvorsorge</strong> und <strong data-start=\"1270\" data-end=\"1295\">Wiederherstellbarkeit</strong> fest.</p>\r\n<hr data-start=\"1303\" data-end=\"1306\">\r\n<h2 data-start=\"1308\" data-end=\"1333\"><strong data-start=\"1311\" data-end=\"1333\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1335\" data-end=\"1361\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1363\" data-end=\"1731\">\r\n<li data-start=\"1363\" data-end=\"1419\">\r\n<p data-start=\"1365\" data-end=\"1419\"><strong data-start=\"1365\" data-end=\"1417\">Alle gesch&auml;ftskritischen Systeme und Anwendungen</strong></p>\r\n</li>\r\n<li data-start=\"1420\" data-end=\"1504\">\r\n<p data-start=\"1422\" data-end=\"1504\"><strong data-start=\"1422\" data-end=\"1457\">IT-Dienste und -Infrastrukturen</strong>, die f&uuml;r den Gesch&auml;ftsbetrieb notwendig sind</p>\r\n</li>\r\n<li data-start=\"1505\" data-end=\"1639\">\r\n<p data-start=\"1507\" data-end=\"1639\"><strong data-start=\"1507\" data-end=\"1578\">Mitarbeitende der IT, des Notfallmanagements und aller Fachbereiche</strong>, die Verf&uuml;gbarkeitsanforderungen definieren oder betreiben</p>\r\n</li>\r\n<li data-start=\"1640\" data-end=\"1731\">\r\n<p data-start=\"1642\" data-end=\"1731\"><strong data-start=\"1642\" data-end=\"1667\">Externe Dienstleister</strong>, sofern diese zur Aufrechterhaltung der Verf&uuml;gbarkeit beitragen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1733\" data-end=\"1736\">\r\n<h2 data-start=\"1738\" data-end=\"1758\"><strong data-start=\"1741\" data-end=\"1758\">3. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"1760\" data-end=\"2213\">\r\n<li data-start=\"1760\" data-end=\"1908\">\r\n<p data-start=\"1762\" data-end=\"1908\">Die Organisation stellt sicher, dass <strong data-start=\"1799\" data-end=\"1845\">gesch&auml;ftskritische Systeme stets verf&uuml;gbar</strong> sind &ndash; im Regelbetrieb wie auch bei St&ouml;rungen oder Notf&auml;llen</p>\r\n</li>\r\n<li data-start=\"1909\" data-end=\"2055\">\r\n<p data-start=\"1911\" data-end=\"2055\">Die <strong data-start=\"1915\" data-end=\"1938\">Verf&uuml;gbarkeitsziele</strong> (z. B. <strong data-start=\"1946\" data-end=\"1953\">RTO</strong>, <strong data-start=\"1955\" data-end=\"1962\">RPO</strong>, <strong data-start=\"1964\" data-end=\"1972\">MTTR</strong>) werden <strong data-start=\"1981\" data-end=\"2043\">basierend auf Schutzbedarfsfeststellung und Risikoanalysen</strong> definiert</p>\r\n</li>\r\n<li data-start=\"2056\" data-end=\"2150\">\r\n<p data-start=\"2058\" data-end=\"2150\">Die Erf&uuml;llung dieser Ziele wird <strong data-start=\"2090\" data-end=\"2136\">technisch, organisatorisch und vertraglich</strong> abgesichert</p>\r\n</li>\r\n<li data-start=\"2151\" data-end=\"2213\">\r\n<p data-start=\"2153\" data-end=\"2213\">Notfall- und Wiederanlaufma&szlig;nahmen sind regelm&auml;&szlig;ig zu testen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2215\" data-end=\"2218\">\r\n<h2 data-start=\"2220\" data-end=\"2251\"><strong data-start=\"2223\" data-end=\"2251\">4. Verf&uuml;gbarkeitsklassen</strong></h2>\r\n<p data-start=\"2253\" data-end=\"2328\">Anwendungen, Dienste und Systeme werden je nach Kritikalit&auml;t klassifiziert:</p>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2330\" data-end=\"2742\">\r\n<thead data-start=\"2330\" data-end=\"2380\">\r\n<tr data-start=\"2330\" data-end=\"2380\">\r\n<th data-start=\"2330\" data-end=\"2353\" data-col-size=\"sm\">Verf&uuml;gbarkeitsklasse</th>\r\n<th data-start=\"2353\" data-end=\"2368\" data-col-size=\"md\">Beschreibung</th>\r\n<th data-start=\"2368\" data-end=\"2380\" data-col-size=\"sm\">Beispiel</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2432\" data-end=\"2742\">\r\n<tr data-start=\"2432\" data-end=\"2546\">\r\n<td data-start=\"2432\" data-end=\"2455\" data-col-size=\"sm\"><strong data-start=\"2434\" data-end=\"2449\">VK 1 (hoch)</strong></td>\r\n<td data-start=\"2455\" data-end=\"2507\" data-col-size=\"md\">Ausfall beeintr&auml;chtigt Gesch&auml;ftsbetrieb erheblich</td>\r\n<td data-col-size=\"sm\" data-start=\"2507\" data-end=\"2546\">ERP, AD, E-Mail, Produktionssysteme</td>\r\n</tr>\r\n<tr data-start=\"2547\" data-end=\"2643\">\r\n<td data-start=\"2547\" data-end=\"2570\" data-col-size=\"sm\"><strong data-start=\"2549\" data-end=\"2566\">VK 2 (mittel)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2570\" data-end=\"2611\">Ausfall tolerierbar f&uuml;r begrenzte Zeit</td>\r\n<td data-col-size=\"sm\" data-start=\"2611\" data-end=\"2643\">Intranet, Zeiterfassung, DMS</td>\r\n</tr>\r\n<tr data-start=\"2644\" data-end=\"2742\">\r\n<td data-start=\"2644\" data-end=\"2667\" data-col-size=\"sm\"><strong data-start=\"2646\" data-end=\"2664\">VK 3 (niedrig)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2667\" data-end=\"2708\">Ausfall hat keine kritische Auswirkung</td>\r\n<td data-col-size=\"sm\" data-start=\"2708\" data-end=\"2742\">Schulungsportal, Archivsysteme</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"2744\" data-end=\"2846\">F&uuml;r jede Klasse gelten spezifische Anforderungen an Backup, Redundanz, RTO/RPO und Wiederanlaufzeiten.</p>\r\n<hr data-start=\"2848\" data-end=\"2851\">\r\n<h2 data-start=\"2853\" data-end=\"2911\"><strong data-start=\"2856\" data-end=\"2911\">5. Technische Ma&szlig;nahmen zur Verf&uuml;gbarkeitssicherung</strong></h2>\r\n<h3 data-start=\"2913\" data-end=\"2930\">5.1 Redundanz</h3>\r\n<ul data-start=\"2932\" data-end=\"3158\">\r\n<li data-start=\"2932\" data-end=\"3158\">\r\n<p data-start=\"2934\" data-end=\"2978\">Redundante Auslegung kritischer Komponenten:</p>\r\n<ul data-start=\"2981\" data-end=\"3158\">\r\n<li data-start=\"2981\" data-end=\"3009\">\r\n<p data-start=\"2983\" data-end=\"3009\">Server (Cluster, Failover)</p>\r\n</li>\r\n<li data-start=\"3012\" data-end=\"3056\">\r\n<p data-start=\"3014\" data-end=\"3056\">Netzwerk (Load Balancer, doppelte Uplinks)</p>\r\n</li>\r\n<li data-start=\"3059\" data-end=\"3113\">\r\n<p data-start=\"3061\" data-end=\"3113\">Speicher (RAID, SAN, georedundante Speicherl&ouml;sungen)</p>\r\n</li>\r\n<li data-start=\"3116\" data-end=\"3158\">\r\n<p data-start=\"3118\" data-end=\"3158\">Stromversorgung (USV, Notstromaggregate)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3160\" data-end=\"3196\">5.2 Monitoring &amp; Fr&uuml;hwarnsysteme</h3>\r\n<ul data-start=\"3198\" data-end=\"3358\">\r\n<li data-start=\"3198\" data-end=\"3307\">\r\n<p data-start=\"3200\" data-end=\"3307\">Permanente &Uuml;berwachung der Systemverf&uuml;gbarkeit mit automatischer Alarmierung (z. B. Zabbix, Icinga, PRTG)</p>\r\n</li>\r\n<li data-start=\"3308\" data-end=\"3358\">\r\n<p data-start=\"3310\" data-end=\"3358\">Eskalationsprozesse bei Ausf&auml;llen klar definiert</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3360\" data-end=\"3394\">5.3 Patch- und Wartungsfenster</h3>\r\n<ul data-start=\"3396\" data-end=\"3625\">\r\n<li data-start=\"3396\" data-end=\"3463\">\r\n<p data-start=\"3398\" data-end=\"3463\">Wartungsarbeiten erfolgen nur innerhalb definierter Zeitfenster</p>\r\n</li>\r\n<li data-start=\"3464\" data-end=\"3529\">\r\n<p data-start=\"3466\" data-end=\"3529\">Geplante Ausf&auml;lle werden dokumentiert und intern kommuniziert</p>\r\n</li>\r\n<li data-start=\"3530\" data-end=\"3625\">\r\n<p data-start=\"3532\" data-end=\"3625\">Bei kritischen Systemen: Umgehung der Downtime durch <strong data-start=\"3585\" data-end=\"3603\">Live-Migration</strong>, Load-Balancing o. &auml;.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3627\" data-end=\"3630\">\r\n<h2 data-start=\"3632\" data-end=\"3668\"><strong data-start=\"3635\" data-end=\"3668\">6. Organisatorische Ma&szlig;nahmen</strong></h2>\r\n<h3 data-start=\"3670\" data-end=\"3703\">6.1 Schutzbedarfsfeststellung</h3>\r\n<ul data-start=\"3705\" data-end=\"3872\">\r\n<li data-start=\"3705\" data-end=\"3803\">\r\n<p data-start=\"3707\" data-end=\"3803\">Jedes IT-System wird auf seine Verf&uuml;gbarkeitsanforderung gepr&uuml;ft und entsprechend dokumentiert</p>\r\n</li>\r\n<li data-start=\"3804\" data-end=\"3872\">\r\n<p data-start=\"3806\" data-end=\"3872\">Grundlage: BSI-Schutzbedarfskategorien (normal / hoch / sehr hoch)</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3874\" data-end=\"3912\">6.2 Notfallvorsorge &amp; Wiederanlauf</h3>\r\n<ul data-start=\"3914\" data-end=\"4266\">\r\n<li data-start=\"3914\" data-end=\"4009\">\r\n<p data-start=\"3916\" data-end=\"4009\">Integration der Verf&uuml;gbarkeitsanforderungen in das <strong data-start=\"3967\" data-end=\"4007\">Business Continuity Management (BCM)</strong></p>\r\n</li>\r\n<li data-start=\"4010\" data-end=\"4167\">\r\n<p data-start=\"4012\" data-end=\"4027\">Erstellung von:</p>\r\n<ul data-start=\"4030\" data-end=\"4167\">\r\n<li data-start=\"4030\" data-end=\"4054\">\r\n<p data-start=\"4032\" data-end=\"4054\"><strong data-start=\"4032\" data-end=\"4054\">Wiederanlaufpl&auml;nen</strong></p>\r\n</li>\r\n<li data-start=\"4057\" data-end=\"4087\">\r\n<p data-start=\"4059\" data-end=\"4087\"><strong data-start=\"4059\" data-end=\"4087\">Wiederherstellungspl&auml;nen</strong></p>\r\n</li>\r\n<li data-start=\"4090\" data-end=\"4167\">\r\n<p data-start=\"4092\" data-end=\"4167\"><strong data-start=\"4092\" data-end=\"4126\">Betriebsfortf&uuml;hrungsstrategien</strong> (z. B. Workaround-Verfahren, Notbetrieb)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"4169\" data-end=\"4266\">\r\n<p data-start=\"4171\" data-end=\"4203\">Durchf&uuml;hrung regelm&auml;&szlig;iger Tests:</p>\r\n<ul data-start=\"4206\" data-end=\"4266\">\r\n<li data-start=\"4206\" data-end=\"4222\">\r\n<p data-start=\"4208\" data-end=\"4222\">Notfall&uuml;bungen</p>\r\n</li>\r\n<li data-start=\"4225\" data-end=\"4240\">\r\n<p data-start=\"4227\" data-end=\"4240\">Restore-Tests</p>\r\n</li>\r\n<li data-start=\"4243\" data-end=\"4266\">\r\n<p data-start=\"4245\" data-end=\"4266\">Failover-Simulationen</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4268\" data-end=\"4271\">\r\n<h2 data-start=\"4273\" data-end=\"4304\"><strong data-start=\"4276\" data-end=\"4304\">7. Dienstleister &amp; Cloud</strong></h2>\r\n<ul data-start=\"4306\" data-end=\"4608\">\r\n<li data-start=\"4306\" data-end=\"4432\">\r\n<p data-start=\"4308\" data-end=\"4432\">Cloud- und IT-Dienstleister m&uuml;ssen vertraglich zur <strong data-start=\"4359\" data-end=\"4412\">Einhaltung definierter Verf&uuml;gbarkeitsziele (SLAs)</strong> verpflichtet sein</p>\r\n</li>\r\n<li data-start=\"4433\" data-end=\"4521\">\r\n<p data-start=\"4435\" data-end=\"4521\">Risiken durch externe Abh&auml;ngigkeiten sind im <strong data-start=\"4480\" data-end=\"4519\">Risiko- und BCM-Prozess zu bewerten</strong></p>\r\n</li>\r\n<li data-start=\"4522\" data-end=\"4608\">\r\n<p data-start=\"4524\" data-end=\"4608\"><strong data-start=\"4524\" data-end=\"4571\">Multi-Region- und Multi-Provider-Strategien</strong> sind f&uuml;r kritische Dienste zu pr&uuml;fen</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4610\" data-end=\"4613\">\r\n<h2 data-start=\"4615\" data-end=\"4647\"><strong data-start=\"4618\" data-end=\"4647\">8. Metriken und Zielwerte</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4649\" data-end=\"5099\">\r\n<thead data-start=\"4649\" data-end=\"4699\">\r\n<tr data-start=\"4649\" data-end=\"4699\">\r\n<th data-start=\"4649\" data-end=\"4659\" data-col-size=\"sm\">Begriff</th>\r\n<th data-start=\"4659\" data-end=\"4674\" data-col-size=\"sm\">Beschreibung</th>\r\n<th data-start=\"4674\" data-end=\"4699\" data-col-size=\"sm\">Typischer Wert (VK 1)</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4752\" data-end=\"5099\">\r\n<tr data-start=\"4752\" data-end=\"4845\">\r\n<td data-start=\"4752\" data-end=\"4788\" data-col-size=\"sm\"><strong data-start=\"4754\" data-end=\"4761\">RTO</strong> (Recovery Time Objective)</td>\r\n<td data-col-size=\"sm\" data-start=\"4788\" data-end=\"4826\">Max. Zeit bis zur Wiederherstellung</td>\r\n<td data-col-size=\"sm\" data-start=\"4826\" data-end=\"4845\">z. B. 4 Stunden</td>\r\n</tr>\r\n<tr data-start=\"4846\" data-end=\"4931\">\r\n<td data-start=\"4846\" data-end=\"4883\" data-col-size=\"sm\"><strong data-start=\"4848\" data-end=\"4855\">RPO</strong> (Recovery Point Objective)</td>\r\n<td data-col-size=\"sm\" data-start=\"4883\" data-end=\"4911\">Max. Datenverlustzeitraum</td>\r\n<td data-col-size=\"sm\" data-start=\"4911\" data-end=\"4931\">z. B. 15 Minuten</td>\r\n</tr>\r\n<tr data-start=\"4932\" data-end=\"5019\">\r\n<td data-start=\"4932\" data-end=\"4965\" data-col-size=\"sm\"><strong data-start=\"4934\" data-end=\"4942\">MTTR</strong> (Mean Time to Repair)</td>\r\n<td data-col-size=\"sm\" data-start=\"4965\" data-end=\"5000\">Durchschnittliche Reparaturdauer</td>\r\n<td data-col-size=\"sm\" data-start=\"5000\" data-end=\"5019\">z. B. 2 Stunden</td>\r\n</tr>\r\n<tr data-start=\"5020\" data-end=\"5099\">\r\n<td data-start=\"5020\" data-end=\"5045\" data-col-size=\"sm\"><strong data-start=\"5022\" data-end=\"5044\">Verf&uuml;gbarkeitsziel</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"5045\" data-end=\"5081\">Anteil der geplanten Betriebszeit</td>\r\n<td data-col-size=\"sm\" data-start=\"5081\" data-end=\"5099\">z. B. &ge; 99,9 %</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"5101\" data-end=\"5194\">Zielwerte werden system- und dienstespezifisch in <strong data-start=\"5151\" data-end=\"5171\">Servicekatalogen</strong> und SLAs dokumentiert.</p>\r\n<hr data-start=\"5196\" data-end=\"5199\">\r\n<h2 data-start=\"5201\" data-end=\"5234\"><strong data-start=\"5204\" data-end=\"5234\">9. &Uuml;berpr&uuml;fung &amp; Reporting</strong></h2>\r\n<ul data-start=\"5236\" data-end=\"5513\">\r\n<li data-start=\"5236\" data-end=\"5308\">\r\n<p data-start=\"5238\" data-end=\"5308\">Monatliche Reports zu Verf&uuml;gbarkeitskennzahlen f&uuml;r kritische Systeme</p>\r\n</li>\r\n<li data-start=\"5309\" data-end=\"5388\">\r\n<p data-start=\"5311\" data-end=\"5388\">J&auml;hrliche Pr&uuml;fung der Umsetzung technischer und organisatorischer Ma&szlig;nahmen</p>\r\n</li>\r\n<li data-start=\"5389\" data-end=\"5448\">\r\n<p data-start=\"5391\" data-end=\"5448\">Abgleich mit Business Impact Analysen (BIA) aus dem BCM</p>\r\n</li>\r\n<li data-start=\"5449\" data-end=\"5513\">\r\n<p data-start=\"5451\" data-end=\"5513\">Regelm&auml;&szlig;ige Berichte an ISB, IT-Leitung, ggf. Gesch&auml;ftsf&uuml;hrung</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5515\" data-end=\"5518\">\r\n<h2 data-start=\"5520\" data-end=\"5551\"><strong data-start=\"5523\" data-end=\"5551\">10. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5553\" data-end=\"6002\">\r\n<thead data-start=\"5553\" data-end=\"5573\">\r\n<tr data-start=\"5553\" data-end=\"5573\">\r\n<th data-start=\"5553\" data-end=\"5561\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5561\" data-end=\"5573\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5595\" data-end=\"6002\">\r\n<tr data-start=\"5595\" data-end=\"5675\">\r\n<td data-start=\"5595\" data-end=\"5612\" data-col-size=\"sm\"><strong data-start=\"5597\" data-end=\"5611\">IT-Betrieb</strong></td>\r\n<td data-start=\"5612\" data-end=\"5675\" data-col-size=\"md\">&Uuml;berwachung &amp; Umsetzung technischer Ma&szlig;nahmen, Wiederanlauf</td>\r\n</tr>\r\n<tr data-start=\"5676\" data-end=\"5770\">\r\n<td data-start=\"5676\" data-end=\"5686\" data-col-size=\"sm\"><strong data-start=\"5678\" data-end=\"5685\">ISB</strong></td>\r\n<td data-start=\"5686\" data-end=\"5770\" data-col-size=\"md\">Kontrolle &amp; Bewertung der Umsetzung, Unterst&uuml;tzung bei Schutzbedarfsfeststellung</td>\r\n</tr>\r\n<tr data-start=\"5771\" data-end=\"5836\">\r\n<td data-start=\"5771\" data-end=\"5790\" data-col-size=\"sm\"><strong data-start=\"5773\" data-end=\"5789\">Fachbereiche</strong></td>\r\n<td data-start=\"5790\" data-end=\"5836\" data-col-size=\"md\">Definition von Verf&uuml;gbarkeitsanforderungen</td>\r\n</tr>\r\n<tr data-start=\"5837\" data-end=\"5904\">\r\n<td data-start=\"5837\" data-end=\"5852\" data-col-size=\"sm\"><strong data-start=\"5839\" data-end=\"5851\">BCM-Team</strong></td>\r\n<td data-start=\"5852\" data-end=\"5904\" data-col-size=\"md\">Pflege von Notfall- und Wiederherstellungspl&auml;nen</td>\r\n</tr>\r\n<tr data-start=\"5905\" data-end=\"6002\">\r\n<td data-start=\"5905\" data-end=\"5936\" data-col-size=\"sm\"><strong data-start=\"5907\" data-end=\"5935\">IT-Sicherheitsmanagement</strong></td>\r\n<td data-start=\"5936\" data-end=\"6002\" data-col-size=\"md\">Einbindung in Risikoanalysen, Bewertung externer Dienstleister</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"6004\" data-end=\"6007\">\r\n<h2 data-start=\"6009\" data-end=\"6057\"><strong data-start=\"6012\" data-end=\"6057\">11. Schnittstellen zu anderen Richtlinien</strong></h2>\r\n<p data-start=\"6059\" data-end=\"6084\">Diese Richtlinie erg&auml;nzt:</p>\r\n<ul data-start=\"6086\" data-end=\"6305\">\r\n<li data-start=\"6086\" data-end=\"6144\">\r\n<p data-start=\"6088\" data-end=\"6144\"><strong data-start=\"6088\" data-end=\"6142\">Business Continuity &amp; Disaster Recovery Richtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6145\" data-end=\"6193\">\r\n<p data-start=\"6147\" data-end=\"6193\"><strong data-start=\"6147\" data-end=\"6191\">Backup- und Wiederherstellungsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6194\" data-end=\"6235\">\r\n<p data-start=\"6196\" data-end=\"6235\"><strong data-start=\"6196\" data-end=\"6233\">Informationssicherheitsrichtlinie</strong></p>\r\n</li>\r\n<li data-start=\"6236\" data-end=\"6277\">\r\n<p data-start=\"6238\" data-end=\"6277\"><strong data-start=\"6238\" data-end=\"6275\">Patch- &amp; Schwachstellenmanagement</strong></p>\r\n</li>\r\n<li data-start=\"6278\" data-end=\"6305\">\r\n<p data-start=\"6280\" data-end=\"6305\"><strong data-start=\"6280\" data-end=\"6305\">Lieferantenmanagement</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6307\" data-end=\"6310\">\r\n<h2 data-start=\"6312\" data-end=\"6350\"><strong data-start=\"6315\" data-end=\"6350\">12. Bezug zu Normen &amp; Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6352\" data-end=\"6766\">\r\n<thead data-start=\"6352\" data-end=\"6380\">\r\n<tr data-start=\"6352\" data-end=\"6380\">\r\n<th data-start=\"6352\" data-end=\"6370\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6370\" data-end=\"6380\" data-col-size=\"lg\">Inhalt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6411\" data-end=\"6766\">\r\n<tr data-start=\"6411\" data-end=\"6561\">\r\n<td data-start=\"6411\" data-end=\"6436\" data-col-size=\"sm\"><strong data-start=\"6413\" data-end=\"6435\">ISO/IEC 27001:2022</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6436\" data-end=\"6561\">A.5.30 (ICT Readiness for Business Continuity)<br>A.5.22 (Informationssicherheit im BCM)<br>A.5.32 (Resilienz im Betrieb)</td>\r\n</tr>\r\n<tr data-start=\"6562\" data-end=\"6692\">\r\n<td data-start=\"6562\" data-end=\"6587\" data-col-size=\"sm\"><strong data-start=\"6564\" data-end=\"6586\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6587\" data-end=\"6692\">BOP.2.1 (Notfallmanagement), OPS.1.1.4 (Redundanz), INF.3 (Rechenzentrum), DER.1 (Netzwerk-Redundanz)</td>\r\n</tr>\r\n<tr data-start=\"6693\" data-end=\"6766\">\r\n<td data-start=\"6693\" data-end=\"6713\" data-col-size=\"sm\"><strong data-start=\"6695\" data-end=\"6712\">DSGVO Art. 32</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"6713\" data-end=\"6766\">TOMs: Verf&uuml;gbarkeit und Belastbarkeit der Systeme</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(21, 'DOK-0026', 'ISMS Governance & Management', 'Governance', '1', 0, NULL, '<h2 data-start=\"950\" data-end=\"980\"><strong data-start=\"953\" data-end=\"980\">1. Zweck der Richtlinie</strong></h2>\r\n<p data-start=\"982\" data-end=\"1160\">Diese Richtlinie beschreibt die organisatorischen, strategischen und operativen Grundlagen zur <strong data-start=\"1077\" data-end=\"1142\">F&uuml;hrung, Steuerung und kontinuierlichen Verbesserung des ISMS</strong> der Organisation.</p>\r\n<p data-start=\"1162\" data-end=\"1176\">Sie legt fest:</p>\r\n<ul data-start=\"1178\" data-end=\"1353\">\r\n<li data-start=\"1178\" data-end=\"1238\">\r\n<p data-start=\"1180\" data-end=\"1238\">wie Informationssicherheit strategisch eingebettet wird,</p>\r\n</li>\r\n<li data-start=\"1239\" data-end=\"1294\">\r\n<p data-start=\"1241\" data-end=\"1294\">welche Gremien, Rollen und Prozesse beteiligt sind,</p>\r\n</li>\r\n<li data-start=\"1295\" data-end=\"1353\">\r\n<p data-start=\"1297\" data-end=\"1353\">wie Kontrolle, Review und Verbesserung des ISMS erfolgt.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1355\" data-end=\"1358\">\r\n<h2 data-start=\"1360\" data-end=\"1385\"><strong data-start=\"1363\" data-end=\"1385\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1387\" data-end=\"1468\">Diese Richtlinie gilt f&uuml;r den <strong data-start=\"1417\" data-end=\"1454\">gesamten Geltungsbereich des ISMS</strong> und betrifft:</p>\r\n<ul data-start=\"1470\" data-end=\"1650\">\r\n<li data-start=\"1470\" data-end=\"1490\">\r\n<p data-start=\"1472\" data-end=\"1490\">Gesch&auml;ftsf&uuml;hrung</p>\r\n</li>\r\n<li data-start=\"1491\" data-end=\"1539\">\r\n<p data-start=\"1493\" data-end=\"1539\">ISMS-Verantwortliche (ISB, IT, Fachbereiche)</p>\r\n</li>\r\n<li data-start=\"1540\" data-end=\"1596\">\r\n<p data-start=\"1542\" data-end=\"1596\">alle unterst&uuml;tzenden Rollen im Sicherheitsmanagement</p>\r\n</li>\r\n<li data-start=\"1597\" data-end=\"1650\">\r\n<p data-start=\"1599\" data-end=\"1650\">externe Parteien mit sicherheitsrelevanten Aufgaben</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1652\" data-end=\"1655\">\r\n<h2 data-start=\"1657\" data-end=\"1697\"><strong data-start=\"1660\" data-end=\"1697\">3. Prinzipien der ISMS-Governance</strong></h2>\r\n<ul data-start=\"1699\" data-end=\"2120\">\r\n<li data-start=\"1699\" data-end=\"1785\">\r\n<p data-start=\"1701\" data-end=\"1785\">Informationssicherheit ist <strong data-start=\"1728\" data-end=\"1741\">Chefsache</strong> und Bestandteil der Unternehmensstrategie</p>\r\n</li>\r\n<li data-start=\"1786\" data-end=\"1883\">\r\n<p data-start=\"1788\" data-end=\"1883\">Sicherheitsmanagement basiert auf <strong data-start=\"1822\" data-end=\"1881\">Risiken, gesetzlichen Anforderungen und Gesch&auml;ftszielen</strong></p>\r\n</li>\r\n<li data-start=\"1884\" data-end=\"1967\">\r\n<p data-start=\"1886\" data-end=\"1967\">Die Organisation verfolgt einen <strong data-start=\"1918\" data-end=\"1965\">kontinuierlichen Verbesserungsprozess (KVP)</strong></p>\r\n</li>\r\n<li data-start=\"1968\" data-end=\"2045\">\r\n<p data-start=\"1970\" data-end=\"2045\">Das ISMS wird <strong data-start=\"1984\" data-end=\"2033\">ganzheitlich, transparent und nachvollziehbar</strong> gesteuert</p>\r\n</li>\r\n<li data-start=\"2046\" data-end=\"2120\">\r\n<p data-start=\"2048\" data-end=\"2120\"><strong data-start=\"2048\" data-end=\"2101\">Verantwortlichkeiten, Dokumentation und Kontrolle</strong> sind verpflichtend</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2122\" data-end=\"2125\">\r\n<h2 data-start=\"2127\" data-end=\"2163\"><strong data-start=\"2130\" data-end=\"2163\">4. ISMS-Organisationsstruktur</strong></h2>\r\n<h3 data-start=\"2165\" data-end=\"2191\">4.1 Rollen und Gremien</h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2193\" data-end=\"3290\">\r\n<thead data-start=\"2193\" data-end=\"2312\">\r\n<tr data-start=\"2193\" data-end=\"2312\">\r\n<th data-start=\"2193\" data-end=\"2221\" data-col-size=\"sm\"><strong data-start=\"2195\" data-end=\"2206\">Instanz</strong></th>\r\n<th data-start=\"2221\" data-end=\"2312\" data-col-size=\"md\"><strong data-start=\"2223\" data-end=\"2246\">Funktion / Aufgaben</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2434\" data-end=\"3290\">\r\n<tr data-start=\"2434\" data-end=\"2554\">\r\n<td data-start=\"2434\" data-end=\"2462\" data-col-size=\"sm\"><strong data-start=\"2436\" data-end=\"2456\">Gesch&auml;ftsf&uuml;hrung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2462\" data-end=\"2554\">Strategische Steuerung, Freigabe von Ressourcen, Risikoakzeptanz</td>\r\n</tr>\r\n<tr data-start=\"2555\" data-end=\"2675\">\r\n<td data-start=\"2555\" data-end=\"2583\" data-col-size=\"sm\"><strong data-start=\"2557\" data-end=\"2579\">ISMS-Leitung / ISB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2583\" data-end=\"2675\">Operative Leitung des ISMS, Koordination aller Sicherheitsaktivit&auml;ten</td>\r\n</tr>\r\n<tr data-start=\"2676\" data-end=\"2795\">\r\n<td data-start=\"2676\" data-end=\"2704\" data-col-size=\"sm\"><strong data-start=\"2678\" data-end=\"2691\">ISMS-Team</strong></td>\r\n<td data-start=\"2704\" data-end=\"2795\" data-col-size=\"md\">Fachaustausch, Ma&szlig;nahmenverfolgung, Unterst&uuml;tzung bei Umsetzung</td>\r\n</tr>\r\n<tr data-start=\"2796\" data-end=\"2921\">\r\n<td data-start=\"2796\" data-end=\"2835\" data-col-size=\"sm\"><strong data-start=\"2798\" data-end=\"2834\">Informationssicherheitsausschuss</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2835\" data-end=\"2921\">Entscheidungsgremium (ISMS-relevante Fragen, Eskalationen)</td>\r\n</tr>\r\n<tr data-start=\"2922\" data-end=\"3047\">\r\n<td data-start=\"2922\" data-end=\"2955\" data-col-size=\"sm\"><strong data-start=\"2924\" data-end=\"2954\">Fachbereiche / Asset Owner</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2955\" data-end=\"3047\">Umsetzung von Sicherheitsanforderungen in Prozessen, Risikoeinsch&auml;tzung</td>\r\n</tr>\r\n<tr data-start=\"3048\" data-end=\"3167\">\r\n<td data-start=\"3048\" data-end=\"3076\" data-col-size=\"sm\"><strong data-start=\"3050\" data-end=\"3066\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3076\" data-end=\"3167\">Sicherer Betrieb, Umsetzung technischer Ma&szlig;nahmen, Incident Management</td>\r\n</tr>\r\n<tr data-start=\"3168\" data-end=\"3290\">\r\n<td data-start=\"3168\" data-end=\"3201\" data-col-size=\"sm\"><strong data-start=\"3170\" data-end=\"3200\">Revision / interne Pr&uuml;fung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3201\" data-end=\"3290\">Pr&uuml;fung der Wirksamkeit des ISMS, Audits, Kontrollen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3292\" data-end=\"3295\">\r\n<h3 data-start=\"3297\" data-end=\"3321\">4.2 Organigramm ISMS</h3>\r\n<p data-start=\"3323\" data-end=\"3414\">Ein <strong data-start=\"3327\" data-end=\"3360\">Organigramm der ISMS-Struktur</strong> wird als Anhang gepflegt (siehe Abschnitt \"Anh&auml;nge\").</p>\r\n<hr data-start=\"3416\" data-end=\"3419\">\r\n<h2 data-start=\"3421\" data-end=\"3468\"><strong data-start=\"3424\" data-end=\"3468\">5. ISMS-Lebenszyklus (Managementprozess)</strong></h2>\r\n<p data-start=\"3470\" data-end=\"3531\">Das ISMS folgt dem <strong data-start=\"3489\" data-end=\"3530\">PDCA-Zyklus (Plan &ndash; Do &ndash; Check &ndash; Act)</strong>:</p>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3533\" data-end=\"3911\">\r\n<thead data-start=\"3533\" data-end=\"3554\">\r\n<tr data-start=\"3533\" data-end=\"3554\">\r\n<th data-start=\"3533\" data-end=\"3541\" data-col-size=\"sm\">Phase</th>\r\n<th data-start=\"3541\" data-end=\"3554\" data-col-size=\"md\">Ma&szlig;nahmen</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3577\" data-end=\"3911\">\r\n<tr data-start=\"3577\" data-end=\"3666\">\r\n<td data-start=\"3577\" data-end=\"3588\" data-col-size=\"sm\"><strong data-start=\"3579\" data-end=\"3587\">Plan</strong></td>\r\n<td data-start=\"3588\" data-end=\"3666\" data-col-size=\"md\">Kontextanalyse, Schutzbedarfsfeststellung, Risikobewertung, Zieldefinition</td>\r\n</tr>\r\n<tr data-start=\"3667\" data-end=\"3757\">\r\n<td data-start=\"3667\" data-end=\"3676\" data-col-size=\"sm\"><strong data-start=\"3669\" data-end=\"3675\">Do</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3676\" data-end=\"3757\">Umsetzung technischer und organisatorischer Ma&szlig;nahmen, Awareness, Richtlinien</td>\r\n</tr>\r\n<tr data-start=\"3758\" data-end=\"3824\">\r\n<td data-start=\"3758\" data-end=\"3770\" data-col-size=\"sm\"><strong data-start=\"3760\" data-end=\"3769\">Check</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3770\" data-end=\"3824\">Interne Audits, ISMS-Kennzahlen, Management-Review</td>\r\n</tr>\r\n<tr data-start=\"3825\" data-end=\"3911\">\r\n<td data-start=\"3825\" data-end=\"3835\" data-col-size=\"sm\"><strong data-start=\"3827\" data-end=\"3834\">Act</strong></td>\r\n<td data-start=\"3835\" data-end=\"3911\" data-col-size=\"md\">Korrektur- &amp; Verbesserungsma&szlig;nahmen, Lessons Learned, Ma&szlig;nahmenanpassung</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3913\" data-end=\"3916\">\r\n<h2 data-start=\"3918\" data-end=\"3950\"><strong data-start=\"3921\" data-end=\"3950\">6. Strategische Steuerung</strong></h2>\r\n<h3 data-start=\"3952\" data-end=\"3988\">6.1 Informationssicherheitsziele</h3>\r\n<ul data-start=\"3990\" data-end=\"4161\">\r\n<li data-start=\"3990\" data-end=\"4081\">\r\n<p data-start=\"3992\" data-end=\"4081\">Werden j&auml;hrlich definiert und durch das ISMS-Team umgesetzt (siehe separate Richtlinie)</p>\r\n</li>\r\n<li data-start=\"4082\" data-end=\"4161\">\r\n<p data-start=\"4084\" data-end=\"4161\">M&uuml;ssen <strong data-start=\"4091\" data-end=\"4100\">SMART</strong> (spezifisch, messbar, erreichbar, relevant, terminiert) sein</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4163\" data-end=\"4193\">6.2 ISMS-Kennzahlen (KPIs)</h3>\r\n<p data-start=\"4195\" data-end=\"4215\">Typische Kennzahlen:</p>\r\n<ul data-start=\"4217\" data-end=\"4362\">\r\n<li data-start=\"4217\" data-end=\"4235\">\r\n<p data-start=\"4219\" data-end=\"4235\">Schulungsquote</p>\r\n</li>\r\n<li data-start=\"4236\" data-end=\"4266\">\r\n<p data-start=\"4238\" data-end=\"4266\">Anzahl Sicherheitsvorf&auml;lle</p>\r\n</li>\r\n<li data-start=\"4267\" data-end=\"4287\">\r\n<p data-start=\"4269\" data-end=\"4287\">Patch-Compliance</p>\r\n</li>\r\n<li data-start=\"4288\" data-end=\"4313\">\r\n<p data-start=\"4290\" data-end=\"4313\">Risiko-Reduktionsgrad</p>\r\n</li>\r\n<li data-start=\"4314\" data-end=\"4335\">\r\n<p data-start=\"4316\" data-end=\"4335\">Auditabweichungen</p>\r\n</li>\r\n<li data-start=\"4336\" data-end=\"4362\">\r\n<p data-start=\"4338\" data-end=\"4362\">Ma&szlig;nahmenerf&uuml;llungsquote</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4364\" data-end=\"4457\">Kennzahlen werden im Rahmen des <strong data-start=\"4396\" data-end=\"4412\">ISMS-Reviews</strong> ausgewertet und an das Management berichtet.</p>\r\n<hr data-start=\"4459\" data-end=\"4462\">\r\n<h2 data-start=\"4464\" data-end=\"4491\"><strong data-start=\"4467\" data-end=\"4491\">7. Management-Review</strong></h2>\r\n<h3 data-start=\"4493\" data-end=\"4505\">7.1 Ziel</h3>\r\n<p data-start=\"4507\" data-end=\"4598\">Bewertung der <strong data-start=\"4521\" data-end=\"4564\">Wirksamkeit und Angemessenheit des ISMS</strong> durch die oberste Leitung, inkl.:</p>\r\n<ul data-start=\"4600\" data-end=\"4784\">\r\n<li data-start=\"4600\" data-end=\"4634\">\r\n<p data-start=\"4602\" data-end=\"4634\">Erf&uuml;llung der Sicherheitsziele</p>\r\n</li>\r\n<li data-start=\"4635\" data-end=\"4659\">\r\n<p data-start=\"4637\" data-end=\"4659\">Status von Ma&szlig;nahmen</p>\r\n</li>\r\n<li data-start=\"4660\" data-end=\"4685\">\r\n<p data-start=\"4662\" data-end=\"4685\">Ergebnisse von Audits</p>\r\n</li>\r\n<li data-start=\"4686\" data-end=\"4708\">\r\n<p data-start=\"4688\" data-end=\"4708\">Status der Risiken</p>\r\n</li>\r\n<li data-start=\"4709\" data-end=\"4737\">\r\n<p data-start=\"4711\" data-end=\"4737\">&Auml;nderungen des Kontextes</p>\r\n</li>\r\n<li data-start=\"4738\" data-end=\"4758\">\r\n<p data-start=\"4740\" data-end=\"4758\">Ressourcenbedarf</p>\r\n</li>\r\n<li data-start=\"4759\" data-end=\"4784\">\r\n<p data-start=\"4761\" data-end=\"4784\">Verbesserungsvorschl&auml;ge</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"4786\" data-end=\"4806\">7.2 Durchf&uuml;hrung</h3>\r\n<ul data-start=\"4808\" data-end=\"4922\">\r\n<li data-start=\"4808\" data-end=\"4838\">\r\n<p data-start=\"4810\" data-end=\"4838\"><strong data-start=\"4810\" data-end=\"4836\">Mindestens 1&times; j&auml;hrlich</strong></p>\r\n</li>\r\n<li data-start=\"4839\" data-end=\"4877\">\r\n<p data-start=\"4841\" data-end=\"4877\">Protokollierung mit Ma&szlig;nahmenliste</p>\r\n</li>\r\n<li data-start=\"4878\" data-end=\"4922\">\r\n<p data-start=\"4880\" data-end=\"4922\">Ergebnis flie&szlig;t in KVP und Zielplanung ein</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4924\" data-end=\"4927\">\r\n<h2 data-start=\"4929\" data-end=\"4966\"><strong data-start=\"4932\" data-end=\"4966\">8. Dokumentation und Steuerung</strong></h2>\r\n<ul data-start=\"4968\" data-end=\"5287\">\r\n<li data-start=\"4968\" data-end=\"5129\">\r\n<p data-start=\"4970\" data-end=\"5129\">Alle ISMS-Dokumente (Richtlinien, Pl&auml;ne, Analysen) werden in einem <strong data-start=\"5037\" data-end=\"5075\">zentrale ISMS-Dokumentationssystem</strong> verwaltet (z. B. ISMS-Tool, Confluence, SharePoint)</p>\r\n</li>\r\n<li data-start=\"5130\" data-end=\"5201\">\r\n<p data-start=\"5132\" data-end=\"5201\">Versionsmanagement, Freigabeprozesse und Archivierung sind geregelt</p>\r\n</li>\r\n<li data-start=\"5202\" data-end=\"5287\">\r\n<p data-start=\"5204\" data-end=\"5287\"><strong data-start=\"5204\" data-end=\"5226\">&Auml;nderungen am ISMS</strong> werden dokumentiert und j&auml;hrlich im <strong data-start=\"5263\" data-end=\"5278\">ISMS-Review</strong> bewertet</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5289\" data-end=\"5292\">\r\n<h2 data-start=\"5294\" data-end=\"5323\"><strong data-start=\"5297\" data-end=\"5323\">9. Audit und Kontrolle</strong></h2>\r\n<ul data-start=\"5325\" data-end=\"5569\">\r\n<li data-start=\"5325\" data-end=\"5393\">\r\n<p data-start=\"5327\" data-end=\"5393\"><strong data-start=\"5327\" data-end=\"5345\">Interne Audits</strong> des ISMS finden <strong data-start=\"5362\" data-end=\"5385\">mindestens j&auml;hrlich</strong> statt</p>\r\n</li>\r\n<li data-start=\"5394\" data-end=\"5488\">\r\n<p data-start=\"5396\" data-end=\"5488\"><strong data-start=\"5396\" data-end=\"5414\">Externe Audits</strong> (z. B. Zertifizierung ISO 27001) werden durch das ISMS-Team vorbereitet</p>\r\n</li>\r\n<li data-start=\"5489\" data-end=\"5569\">\r\n<p data-start=\"5491\" data-end=\"5569\">Auditabweichungen werden nachverfolgt und <strong data-start=\"5533\" data-end=\"5569\">durch Korrekturma&szlig;nahmen behoben</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5571\" data-end=\"5574\">\r\n<h2 data-start=\"5576\" data-end=\"5620\"><strong data-start=\"5579\" data-end=\"5620\">10. Verbesserung &amp; Korrekturma&szlig;nahmen</strong></h2>\r\n<ul data-start=\"5622\" data-end=\"5861\">\r\n<li data-start=\"5622\" data-end=\"5716\">\r\n<p data-start=\"5624\" data-end=\"5716\">Jede festgestellte Abweichung, jeder Vorfall oder Verbesserungsvorschlag wird dokumentiert</p>\r\n</li>\r\n<li data-start=\"5717\" data-end=\"5758\">\r\n<p data-start=\"5719\" data-end=\"5758\">Bewertung erfolgt durch das ISMS-Team</p>\r\n</li>\r\n<li data-start=\"5759\" data-end=\"5861\">\r\n<p data-start=\"5761\" data-end=\"5861\">Ma&szlig;nahmen werden im <strong data-start=\"5781\" data-end=\"5798\">Ma&szlig;nahmenplan</strong> dokumentiert und <strong data-start=\"5816\" data-end=\"5852\">mit Verantwortlichen und Fristen</strong> verfolgt</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5863\" data-end=\"5866\">\r\n<h2 data-start=\"5868\" data-end=\"5908\"><strong data-start=\"5871\" data-end=\"5908\">11. Rollen &amp; Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5910\" data-end=\"6331\">\r\n<thead data-start=\"5910\" data-end=\"5935\">\r\n<tr data-start=\"5910\" data-end=\"5935\">\r\n<th data-start=\"5910\" data-end=\"5918\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"5918\" data-end=\"5935\" data-col-size=\"md\">Verantwortung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5963\" data-end=\"6331\">\r\n<tr data-start=\"5963\" data-end=\"6049\">\r\n<td data-start=\"5963\" data-end=\"5986\" data-col-size=\"sm\"><strong data-start=\"5965\" data-end=\"5985\">Gesch&auml;ftsf&uuml;hrung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5986\" data-end=\"6049\">Strategische Steuerung, Ressourcenfreigabe, Risikoakzeptanz</td>\r\n</tr>\r\n<tr data-start=\"6050\" data-end=\"6137\">\r\n<td data-start=\"6050\" data-end=\"6075\" data-col-size=\"sm\"><strong data-start=\"6052\" data-end=\"6074\">ISMS-Leitung / ISB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6075\" data-end=\"6137\">Operative Leitung des ISMS, Planung &amp; Review, Koordination</td>\r\n</tr>\r\n<tr data-start=\"6138\" data-end=\"6205\">\r\n<td data-start=\"6138\" data-end=\"6157\" data-col-size=\"sm\"><strong data-start=\"6140\" data-end=\"6156\">Fachbereiche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6157\" data-end=\"6205\">Umsetzung der Anforderungen im Tagesgesch&auml;ft</td>\r\n</tr>\r\n<tr data-start=\"6206\" data-end=\"6264\">\r\n<td data-start=\"6206\" data-end=\"6225\" data-col-size=\"sm\"><strong data-start=\"6208\" data-end=\"6224\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6225\" data-end=\"6264\">Technische Absicherung, IT-Security</td>\r\n</tr>\r\n<tr data-start=\"6265\" data-end=\"6331\">\r\n<td data-start=\"6265\" data-end=\"6280\" data-col-size=\"sm\"><strong data-start=\"6267\" data-end=\"6279\">Revision</strong></td>\r\n<td data-start=\"6280\" data-end=\"6331\" data-col-size=\"md\">Pr&uuml;fung, Auditierung, Bewertung der Wirksamkeit</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"6333\" data-end=\"6336\">\r\n<h2 data-start=\"6338\" data-end=\"6386\"><strong data-start=\"6341\" data-end=\"6386\">12. Schnittstellen zu anderen Richtlinien</strong></h2>\r\n<p data-start=\"6388\" data-end=\"6469\">Diese Governance-Richtlinie bildet den Rahmen f&uuml;r alle ISMS-Elemente und erg&auml;nzt:</p>\r\n<ul data-start=\"6471\" data-end=\"6723\">\r\n<li data-start=\"6471\" data-end=\"6499\">\r\n<p data-start=\"6473\" data-end=\"6499\"><strong data-start=\"6473\" data-end=\"6497\">ISMS Kontext &amp; Scope</strong></p>\r\n</li>\r\n<li data-start=\"6500\" data-end=\"6549\">\r\n<p data-start=\"6502\" data-end=\"6549\"><strong data-start=\"6502\" data-end=\"6547\">Rollen, Verantwortlichkeiten &amp; Befugnisse</strong></p>\r\n</li>\r\n<li data-start=\"6550\" data-end=\"6596\">\r\n<p data-start=\"6552\" data-end=\"6596\"><strong data-start=\"6552\" data-end=\"6594\">Informationssicherheitsziele &amp; Planung</strong></p>\r\n</li>\r\n<li data-start=\"6597\" data-end=\"6632\">\r\n<p data-start=\"6599\" data-end=\"6632\"><strong data-start=\"6599\" data-end=\"6630\">Risikomanagement &amp; Methodik</strong></p>\r\n</li>\r\n<li data-start=\"6633\" data-end=\"6664\">\r\n<p data-start=\"6635\" data-end=\"6664\"><strong data-start=\"6635\" data-end=\"6662\">ISMS-Kommunikationsplan</strong></p>\r\n</li>\r\n<li data-start=\"6665\" data-end=\"6723\">\r\n<p data-start=\"6667\" data-end=\"6723\"><strong data-start=\"6667\" data-end=\"6723\">Sicherheitsrichtlinien (technisch &amp; organisatorisch)</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6725\" data-end=\"6728\">\r\n<h2 data-start=\"6730\" data-end=\"6768\"><strong data-start=\"6733\" data-end=\"6768\">13. Bezug zu Normen &amp; Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6770\" data-end=\"7119\">\r\n<thead data-start=\"6770\" data-end=\"6801\">\r\n<tr data-start=\"6770\" data-end=\"6801\">\r\n<th data-start=\"6770\" data-end=\"6788\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6788\" data-end=\"6801\" data-col-size=\"md\">Abschnitt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6834\" data-end=\"7119\">\r\n<tr data-start=\"6834\" data-end=\"6934\">\r\n<td data-start=\"6834\" data-end=\"6859\" data-col-size=\"sm\"><strong data-start=\"6836\" data-end=\"6858\">ISO/IEC 27001:2022</strong></td>\r\n<td data-start=\"6859\" data-end=\"6934\" data-col-size=\"md\">Kap. 4&ndash;10 (Kontext, F&uuml;hrung, Planung, Betrieb, Bewertung, Verbesserung)</td>\r\n</tr>\r\n<tr data-start=\"6935\" data-end=\"6994\">\r\n<td data-start=\"6935\" data-end=\"6960\" data-col-size=\"sm\"><strong data-start=\"6937\" data-end=\"6959\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6960\" data-end=\"6994\">ORP.3, ORP.4.1, ISMS.1, ISMS.2</td>\r\n</tr>\r\n<tr data-start=\"6995\" data-end=\"7119\">\r\n<td data-start=\"6995\" data-end=\"7028\" data-col-size=\"sm\"><strong data-start=\"6997\" data-end=\"7027\">NIS-2 Richtlinie (Art. 21)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"7028\" data-end=\"7119\">Verpflichtung zur strukturierten Sicherheitssteuerung und kontinuierlichen Verbesserung</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(22, 'DOK-0027', 'Verfahren für Korrektur- und Vorbeugungsmaßnahmen (CAPA)', 'Verfahren', '1', 0, NULL, '<h2 data-start=\"1033\" data-end=\"1048\"><strong data-start=\"1036\" data-end=\"1048\">1. Zweck</strong></h2>\r\n<p data-start=\"1050\" data-end=\"1246\">Ziel dieses Verfahrens ist es, eine <strong data-start=\"1086\" data-end=\"1224\">strukturierte Vorgehensweise zur Behandlung von Nichtkonformit&auml;ten, Sicherheitsvorf&auml;llen, Schwachstellen oder Verbesserungspotenzialen</strong> zu gew&auml;hrleisten, um:</p>\r\n<ul data-start=\"1248\" data-end=\"1445\">\r\n<li data-start=\"1248\" data-end=\"1316\">\r\n<p data-start=\"1250\" data-end=\"1316\">die <strong data-start=\"1254\" data-end=\"1294\">Wirksamkeit und Konformit&auml;t des ISMS</strong> aufrechtzuerhalten,</p>\r\n</li>\r\n<li data-start=\"1317\" data-end=\"1376\">\r\n<p data-start=\"1319\" data-end=\"1376\"><strong data-start=\"1319\" data-end=\"1360\">Wiederholungen und systemische Fehler</strong> zu vermeiden,</p>\r\n</li>\r\n<li data-start=\"1377\" data-end=\"1445\">\r\n<p data-start=\"1379\" data-end=\"1445\"><strong data-start=\"1379\" data-end=\"1398\">Lessons Learned</strong> in die Sicherheitsorganisation zur&uuml;ckzuf&uuml;hren.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1447\" data-end=\"1450\">\r\n<h2 data-start=\"1452\" data-end=\"1477\"><strong data-start=\"1455\" data-end=\"1477\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1479\" data-end=\"1505\">Dieses Verfahren gilt f&uuml;r:</p>\r\n<ul data-start=\"1507\" data-end=\"1824\">\r\n<li data-start=\"1507\" data-end=\"1613\">\r\n<p data-start=\"1509\" data-end=\"1613\">alle festgestellten <strong data-start=\"1529\" data-end=\"1551\">Nichtkonformit&auml;ten</strong> mit Normvorgaben, internen Richtlinien, Gesetzen, Vertr&auml;gen</p>\r\n</li>\r\n<li data-start=\"1614\" data-end=\"1701\">\r\n<p data-start=\"1616\" data-end=\"1701\"><strong data-start=\"1616\" data-end=\"1639\">Sicherheitsvorf&auml;lle</strong> mit Bezug zu Verf&uuml;gbarkeit, Vertraulichkeit oder Integrit&auml;t</p>\r\n</li>\r\n<li data-start=\"1702\" data-end=\"1751\">\r\n<p data-start=\"1704\" data-end=\"1751\">Ergebnisse aus internen / externen <strong data-start=\"1739\" data-end=\"1749\">Audits</strong></p>\r\n</li>\r\n<li data-start=\"1752\" data-end=\"1824\">\r\n<p data-start=\"1754\" data-end=\"1824\">Hinweise auf <strong data-start=\"1767\" data-end=\"1792\">prozessuale Schw&auml;chen</strong> oder <strong data-start=\"1798\" data-end=\"1824\">Optimierungspotenziale</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1826\" data-end=\"1829\">\r\n<h2 data-start=\"1831\" data-end=\"1861\"><strong data-start=\"1834\" data-end=\"1861\">3. Begriffsdefinitionen</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1863\" data-end=\"2394\">\r\n<thead data-start=\"1863\" data-end=\"1886\">\r\n<tr data-start=\"1863\" data-end=\"1886\">\r\n<th data-start=\"1863\" data-end=\"1873\" data-col-size=\"sm\">Begriff</th>\r\n<th data-start=\"1873\" data-end=\"1886\" data-col-size=\"lg\">Bedeutung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1910\" data-end=\"2394\">\r\n<tr data-start=\"1910\" data-end=\"2017\">\r\n<td data-start=\"1910\" data-end=\"1933\" data-col-size=\"sm\"><strong data-start=\"1912\" data-end=\"1932\">Nichtkonformit&auml;t</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"1933\" data-end=\"2017\">Abweichung von festgelegten Anforderungen (z. B. ISO 27001, interne Richtlinien)</td>\r\n</tr>\r\n<tr data-start=\"2018\" data-end=\"2121\">\r\n<td data-start=\"2018\" data-end=\"2042\" data-col-size=\"sm\"><strong data-start=\"2020\" data-end=\"2041\">Korrekturma&szlig;nahme</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"2042\" data-end=\"2121\">Ma&szlig;nahme zur Beseitigung der Ursache einer identifizierten Nichtkonformit&auml;t</td>\r\n</tr>\r\n<tr data-start=\"2122\" data-end=\"2251\">\r\n<td data-start=\"2122\" data-end=\"2148\" data-col-size=\"sm\"><strong data-start=\"2124\" data-end=\"2147\">Vorbeugungsma&szlig;nahme</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"2148\" data-end=\"2251\">Ma&szlig;nahme zur Beseitigung der Ursache einer potenziellen (noch nicht eingetretenen) Nichtkonformit&auml;t</td>\r\n</tr>\r\n<tr data-start=\"2252\" data-end=\"2394\">\r\n<td data-start=\"2252\" data-end=\"2263\" data-col-size=\"sm\"><strong data-start=\"2254\" data-end=\"2262\">CAPA</strong></td>\r\n<td data-col-size=\"lg\" data-start=\"2263\" data-end=\"2394\">Corrective and Preventive Actions &ndash; international gebr&auml;uchlicher Begriff f&uuml;r das Ma&szlig;nahmenmanagement im Managementsystemkontext</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2396\" data-end=\"2399\">\r\n<h2 data-start=\"2401\" data-end=\"2427\"><strong data-start=\"2404\" data-end=\"2427\">4. Prozess&uuml;bersicht</strong></h2>\r\n<div class=\"contain-inline-size rounded-2xl corner-superellipse/1.1 relative bg-token-sidebar-surface-primary\">\r\n<div class=\"@w-xl/main:top-9 sticky top-[calc(--spacing(9)+var(--header-height))]\">\r\n<div class=\"absolute end-0 bottom-0 flex h-9 items-center pe-2\">\r\n<div class=\"bg-token-bg-elevated-secondary text-token-text-secondary flex items-center gap-4 rounded-sm px-2 font-sans text-xs\">&nbsp;</div>\r\n</div>\r\n</div>\r\n<div class=\"overflow-y-auto p-4\" dir=\"ltr\"><code class=\"whitespace-pre! language-mermaid\">flowchart TD\r\nA[Meldung der Nichtkonformit&auml;t / Schwachstelle] --&gt; B[Dokumentation im Ma&szlig;nahmenprotokoll]\r\nB --&gt; C[Analyse der Ursache (Root Cause Analysis)]\r\nC --&gt; D[Festlegung von Korrektur-/Vorbeugungsma&szlig;nahmen]\r\nD --&gt; E[Umsetzung durch Verantwortliche]\r\nE --&gt; F[Wirksamkeitspr&uuml;fung]\r\nF --&gt; G[Dokumentation und Abschluss]\r\n</code></div>\r\n</div>\r\n<hr data-start=\"2763\" data-end=\"2766\">\r\n<h2 data-start=\"2768\" data-end=\"2806\"><strong data-start=\"2771\" data-end=\"2806\">5. Ablaufbeschreibung im Detail</strong></h2>\r\n<h3 data-start=\"2808\" data-end=\"2823\">5.1 Meldung</h3>\r\n<ul data-start=\"2825\" data-end=\"3058\">\r\n<li data-start=\"2825\" data-end=\"3058\">\r\n<p data-start=\"2827\" data-end=\"2920\">Nichtkonformit&auml;ten, Schwachstellen oder Verbesserungsvorschl&auml;ge k&ouml;nnen gemeldet werden durch:</p>\r\n<ul data-start=\"2923\" data-end=\"3058\">\r\n<li data-start=\"2923\" data-end=\"2941\">\r\n<p data-start=\"2925\" data-end=\"2941\">interne Audits</p>\r\n</li>\r\n<li data-start=\"2944\" data-end=\"2965\">\r\n<p data-start=\"2946\" data-end=\"2965\">externe Pr&uuml;fungen</p>\r\n</li>\r\n<li data-start=\"2968\" data-end=\"2985\">\r\n<p data-start=\"2970\" data-end=\"2985\">Mitarbeitende</p>\r\n</li>\r\n<li data-start=\"2988\" data-end=\"3012\">\r\n<p data-start=\"2990\" data-end=\"3012\">das ISMS-Team selbst</p>\r\n</li>\r\n<li data-start=\"3015\" data-end=\"3058\">\r\n<p data-start=\"3017\" data-end=\"3058\">technische Tools (z. B. SIEM, Monitoring)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<blockquote data-start=\"3060\" data-end=\"3129\">\r\n<p data-start=\"3062\" data-end=\"3129\">👉 Meldungen werden zentral im <strong data-start=\"3093\" data-end=\"3120\">ISMS-Ma&szlig;nahmenprotokoll</strong> erfasst.</p>\r\n</blockquote>\r\n<hr data-start=\"3131\" data-end=\"3134\">\r\n<h3 data-start=\"3136\" data-end=\"3169\">5.2 Analyse (Ursachenanalyse)</h3>\r\n<ul data-start=\"3171\" data-end=\"3365\">\r\n<li data-start=\"3171\" data-end=\"3225\">\r\n<p data-start=\"3173\" data-end=\"3225\">Durchf&uuml;hrung durch das <strong data-start=\"3196\" data-end=\"3223\">ISMS-Team / Fachbereich</strong></p>\r\n</li>\r\n<li data-start=\"3226\" data-end=\"3365\">\r\n<p data-start=\"3228\" data-end=\"3279\">Methoden zur Ursachenanalyse (je nach Komplexit&auml;t):</p>\r\n<ul data-start=\"3282\" data-end=\"3365\">\r\n<li data-start=\"3282\" data-end=\"3303\">\r\n<p data-start=\"3284\" data-end=\"3303\"><strong data-start=\"3284\" data-end=\"3301\">5-Why-Methode</strong></p>\r\n</li>\r\n<li data-start=\"3306\" data-end=\"3342\">\r\n<p data-start=\"3308\" data-end=\"3342\"><strong data-start=\"3308\" data-end=\"3340\">Ishikawa-Diagramm (Fishbone)</strong></p>\r\n</li>\r\n<li data-start=\"3345\" data-end=\"3365\">\r\n<p data-start=\"3347\" data-end=\"3365\"><strong data-start=\"3347\" data-end=\"3365\">Pareto-Analyse</strong></p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p data-start=\"3367\" data-end=\"3434\">Ziel: <strong data-start=\"3373\" data-end=\"3405\">Wurzelursache identifizieren</strong>, nicht nur Symptome beheben.</p>\r\n<hr data-start=\"3436\" data-end=\"3439\">\r\n<h3 data-start=\"3441\" data-end=\"3473\">5.3 Festlegung von Ma&szlig;nahmen</h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3475\" data-end=\"3804\">\r\n<thead data-start=\"3475\" data-end=\"3498\">\r\n<tr data-start=\"3475\" data-end=\"3498\">\r\n<th data-start=\"3475\" data-end=\"3490\" data-col-size=\"sm\">Ma&szlig;nahmentyp</th>\r\n<th data-start=\"3490\" data-end=\"3498\" data-col-size=\"md\">Ziel</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3523\" data-end=\"3804\">\r\n<tr data-start=\"3523\" data-end=\"3605\">\r\n<td data-start=\"3523\" data-end=\"3547\" data-col-size=\"sm\"><strong data-start=\"3525\" data-end=\"3546\">Korrekturma&szlig;nahme</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3547\" data-end=\"3605\">Verhindert Wiederholung der identifizierten Abweichung</td>\r\n</tr>\r\n<tr data-start=\"3606\" data-end=\"3698\">\r\n<td data-start=\"3606\" data-end=\"3632\" data-col-size=\"sm\"><strong data-start=\"3608\" data-end=\"3631\">Vorbeugungsma&szlig;nahme</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3632\" data-end=\"3698\">Verhindert erstmaliges Auftreten einer potenziellen Abweichung</td>\r\n</tr>\r\n<tr data-start=\"3699\" data-end=\"3804\">\r\n<td data-start=\"3699\" data-end=\"3731\" data-col-size=\"sm\"><strong data-start=\"3701\" data-end=\"3730\">Sofortma&szlig;nahme (optional)</strong></td>\r\n<td data-start=\"3731\" data-end=\"3804\" data-col-size=\"md\">Behebt kurzfristig ein akutes Problem, ohne die Ursache zu beseitigen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"3806\" data-end=\"3846\"><strong data-start=\"3806\" data-end=\"3846\">Jede Ma&szlig;nahme wird dokumentiert mit:</strong></p>\r\n<ul data-start=\"3848\" data-end=\"3933\">\r\n<li data-start=\"3848\" data-end=\"3864\">\r\n<p data-start=\"3850\" data-end=\"3864\">Beschreibung</p>\r\n</li>\r\n<li data-start=\"3865\" data-end=\"3891\">\r\n<p data-start=\"3867\" data-end=\"3891\">Verantwortliche Person</p>\r\n</li>\r\n<li data-start=\"3892\" data-end=\"3910\">\r\n<p data-start=\"3894\" data-end=\"3910\">Frist / Termin</p>\r\n</li>\r\n<li data-start=\"3911\" data-end=\"3924\">\r\n<p data-start=\"3913\" data-end=\"3924\">Priorit&auml;t</p>\r\n</li>\r\n<li data-start=\"3925\" data-end=\"3933\">\r\n<p data-start=\"3927\" data-end=\"3933\">Status</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3935\" data-end=\"3938\">\r\n<h3 data-start=\"3940\" data-end=\"3957\">5.4 Umsetzung</h3>\r\n<ul data-start=\"3959\" data-end=\"4184\">\r\n<li data-start=\"3959\" data-end=\"4060\">\r\n<p data-start=\"3961\" data-end=\"4060\">Verantwortlichkeiten und Ressourcen werden durch den <strong data-start=\"4014\" data-end=\"4043\">Ma&szlig;nahmenverantwortlichen</strong> sichergestellt</p>\r\n</li>\r\n<li data-start=\"4061\" data-end=\"4123\">\r\n<p data-start=\"4063\" data-end=\"4123\">Fortschritte werden im <strong data-start=\"4086\" data-end=\"4108\">ISMS-Ma&szlig;nahmenplan</strong> dokumentiert</p>\r\n</li>\r\n<li data-start=\"4124\" data-end=\"4184\">\r\n<p data-start=\"4126\" data-end=\"4184\">Blocker oder Verz&ouml;gerungen sind an das ISMS-Team zu melden</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4186\" data-end=\"4189\">\r\n<h3 data-start=\"4191\" data-end=\"4220\">5.5 Wirksamkeitskontrolle</h3>\r\n<ul data-start=\"4222\" data-end=\"4502\">\r\n<li data-start=\"4222\" data-end=\"4298\">\r\n<p data-start=\"4224\" data-end=\"4298\">Erfolgt durch den <strong data-start=\"4242\" data-end=\"4271\">ISB oder interne Revision</strong>, ggf. durch Fachbereiche</p>\r\n</li>\r\n<li data-start=\"4299\" data-end=\"4502\">\r\n<p data-start=\"4301\" data-end=\"4316\">Kontrollfragen:</p>\r\n<ul data-start=\"4319\" data-end=\"4502\">\r\n<li data-start=\"4319\" data-end=\"4364\">\r\n<p data-start=\"4321\" data-end=\"4364\">Wurde die Ma&szlig;nahme vollst&auml;ndig umgesetzt?</p>\r\n</li>\r\n<li data-start=\"4367\" data-end=\"4405\">\r\n<p data-start=\"4369\" data-end=\"4405\">Ist das Problem dauerhaft behoben?</p>\r\n</li>\r\n<li data-start=\"4408\" data-end=\"4462\">\r\n<p data-start=\"4410\" data-end=\"4462\">Ist die Ursache (nicht nur das Symptom) beseitigt?</p>\r\n</li>\r\n<li data-start=\"4465\" data-end=\"4502\">\r\n<p data-start=\"4467\" data-end=\"4502\">Wurden &auml;hnliche Bereiche &uuml;berpr&uuml;ft?</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<blockquote data-start=\"4504\" data-end=\"4598\">\r\n<p data-start=\"4506\" data-end=\"4598\">✅ Die Ma&szlig;nahme wird nur nach bestandener Kontrolle als <strong data-start=\"4561\" data-end=\"4588\">&bdquo;wirksam abgeschlossen&ldquo;</strong> markiert.</p>\r\n</blockquote>\r\n<hr data-start=\"4600\" data-end=\"4603\">\r\n<h3 data-start=\"4605\" data-end=\"4626\">5.6 Dokumentation</h3>\r\n<ul data-start=\"4628\" data-end=\"4807\">\r\n<li data-start=\"4628\" data-end=\"4807\">\r\n<p data-start=\"4630\" data-end=\"4661\">Ma&szlig;nahmenverfolgung erfolgt in:</p>\r\n<ul data-start=\"4664\" data-end=\"4807\">\r\n<li data-start=\"4664\" data-end=\"4710\">\r\n<p data-start=\"4666\" data-end=\"4710\"><strong data-start=\"4666\" data-end=\"4708\">ISMS-Ma&szlig;nahmenprotokoll / CAPA-Logbuch</strong></p>\r\n</li>\r\n<li data-start=\"4713\" data-end=\"4761\">\r\n<p data-start=\"4715\" data-end=\"4761\"><strong data-start=\"4715\" data-end=\"4731\">Auditbericht</strong> (bei auditbezogenen Themen)</p>\r\n</li>\r\n<li data-start=\"4764\" data-end=\"4807\">\r\n<p data-start=\"4766\" data-end=\"4807\"><strong data-start=\"4766\" data-end=\"4787\">Review-Dokumenten</strong> (Management-Review)</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p data-start=\"4809\" data-end=\"4870\">Alle CAPA-Vorg&auml;nge sind <strong data-start=\"4833\" data-end=\"4869\">mindestens 3 Jahre aufzubewahren</strong>.</p>\r\n<hr data-start=\"4872\" data-end=\"4875\">\r\n<h2 data-start=\"4877\" data-end=\"4916\"><strong data-start=\"4880\" data-end=\"4916\">6. Rollen &amp; Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4918\" data-end=\"5346\">\r\n<thead data-start=\"4918\" data-end=\"4938\">\r\n<tr data-start=\"4918\" data-end=\"4938\">\r\n<th data-start=\"4918\" data-end=\"4926\" data-col-size=\"sm\">Rolle</th>\r\n<th data-start=\"4926\" data-end=\"4938\" data-col-size=\"md\">Aufgaben</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4960\" data-end=\"5346\">\r\n<tr data-start=\"4960\" data-end=\"5058\">\r\n<td data-start=\"4960\" data-end=\"4985\" data-col-size=\"sm\"><strong data-start=\"4962\" data-end=\"4984\">ISMS-Leitung / ISB</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4985\" data-end=\"5058\">Koordination des CAPA-Prozesses, Ursachenanalyse, Wirksamkeitspr&uuml;fung</td>\r\n</tr>\r\n<tr data-start=\"5059\" data-end=\"5160\">\r\n<td data-start=\"5059\" data-end=\"5104\" data-col-size=\"sm\"><strong data-start=\"5061\" data-end=\"5103\">Fachbereich / Ma&szlig;nahmenverantwortliche</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5104\" data-end=\"5160\">Umsetzung von Ma&szlig;nahmen, Kommunikation mit ISMS-Team</td>\r\n</tr>\r\n<tr data-start=\"5161\" data-end=\"5246\">\r\n<td data-start=\"5161\" data-end=\"5189\" data-col-size=\"sm\"><strong data-start=\"5163\" data-end=\"5188\">Audit-Team / Revision</strong></td>\r\n<td data-col-size=\"md\" data-start=\"5189\" data-end=\"5246\">Identifikation von Nichtkonformit&auml;ten, Nachverfolgung</td>\r\n</tr>\r\n<tr data-start=\"5247\" data-end=\"5346\">\r\n<td data-start=\"5247\" data-end=\"5283\" data-col-size=\"sm\"><strong data-start=\"5249\" data-end=\"5282\">Gesch&auml;ftsf&uuml;hrung (bei Bedarf)</strong></td>\r\n<td data-start=\"5283\" data-end=\"5346\" data-col-size=\"md\">Entscheidung bei kritischen oder strategischen Abweichungen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5348\" data-end=\"5351\">\r\n<h2 data-start=\"5353\" data-end=\"5386\"><strong data-start=\"5356\" data-end=\"5386\">7. Zeitrahmen &amp; Eskalation</strong></h2>\r\n<ul data-start=\"5388\" data-end=\"5604\">\r\n<li data-start=\"5388\" data-end=\"5460\">\r\n<p data-start=\"5390\" data-end=\"5460\">Korrekturma&szlig;nahmen sollten <strong data-start=\"5417\" data-end=\"5443\">innerhalb von 30 Tagen</strong> umgesetzt sein</p>\r\n</li>\r\n<li data-start=\"5461\" data-end=\"5514\">\r\n<p data-start=\"5463\" data-end=\"5514\">Komplexere Ma&szlig;nahmen erhalten angemessene Fristen</p>\r\n</li>\r\n<li data-start=\"5515\" data-end=\"5604\">\r\n<p data-start=\"5517\" data-end=\"5604\">Bei Frist&uuml;berschreitungen erfolgt <strong data-start=\"5551\" data-end=\"5565\">Eskalation</strong> an das ISMS-Team bzw. Gesch&auml;ftsf&uuml;hrung</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5606\" data-end=\"5609\">\r\n<h2 data-start=\"5611\" data-end=\"5651\"><strong data-start=\"5614\" data-end=\"5651\">8. Lessons Learned &amp; Verbesserung</strong></h2>\r\n<ul data-start=\"5653\" data-end=\"5925\">\r\n<li data-start=\"5653\" data-end=\"5744\">\r\n<p data-start=\"5655\" data-end=\"5744\">Ergebnisse aus Korrekturma&szlig;nahmen werden in <strong data-start=\"5699\" data-end=\"5732\">Lessons-Learned-Dokumentation</strong> &uuml;berf&uuml;hrt</p>\r\n</li>\r\n<li data-start=\"5745\" data-end=\"5824\">\r\n<p data-start=\"5747\" data-end=\"5824\">Wiederkehrende Probleme werden zur <strong data-start=\"5782\" data-end=\"5812\">strukturellen Verbesserung</strong> verwendet</p>\r\n</li>\r\n<li data-start=\"5825\" data-end=\"5925\">\r\n<p data-start=\"5827\" data-end=\"5851\">Erkenntnisse flie&szlig;en in:</p>\r\n<ul data-start=\"5854\" data-end=\"5925\">\r\n<li data-start=\"5854\" data-end=\"5877\">\r\n<p data-start=\"5856\" data-end=\"5877\">Awareness-Ma&szlig;nahmen</p>\r\n</li>\r\n<li data-start=\"5880\" data-end=\"5906\">\r\n<p data-start=\"5882\" data-end=\"5906\">Richtlinienanpassungen</p>\r\n</li>\r\n<li data-start=\"5909\" data-end=\"5925\">\r\n<p data-start=\"5911\" data-end=\"5925\">Risikoanalysen</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5927\" data-end=\"5930\">\r\n<h2 data-start=\"5932\" data-end=\"5972\"><strong data-start=\"5935\" data-end=\"5972\">9. Verkn&uuml;pfung mit ISMS-Prozessen</strong></h2>\r\n<p data-start=\"5974\" data-end=\"6013\">Dieses Verfahren ist eng verbunden mit:</p>\r\n<ul data-start=\"6015\" data-end=\"6143\">\r\n<li data-start=\"6015\" data-end=\"6040\">\r\n<p data-start=\"6017\" data-end=\"6040\"><strong data-start=\"6017\" data-end=\"6038\">ISMS-Auditprozess</strong></p>\r\n</li>\r\n<li data-start=\"6041\" data-end=\"6068\">\r\n<p data-start=\"6043\" data-end=\"6068\"><strong data-start=\"6043\" data-end=\"6066\">Incident Management</strong></p>\r\n</li>\r\n<li data-start=\"6069\" data-end=\"6094\">\r\n<p data-start=\"6071\" data-end=\"6094\"><strong data-start=\"6071\" data-end=\"6092\">Management-Review</strong></p>\r\n</li>\r\n<li data-start=\"6095\" data-end=\"6119\">\r\n<p data-start=\"6097\" data-end=\"6119\"><strong data-start=\"6097\" data-end=\"6117\">Risikomanagement</strong></p>\r\n</li>\r\n<li data-start=\"6120\" data-end=\"6143\">\r\n<p data-start=\"6122\" data-end=\"6143\"><strong data-start=\"6122\" data-end=\"6143\">Change Management</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6145\" data-end=\"6148\">\r\n<h2 data-start=\"6150\" data-end=\"6188\"><strong data-start=\"6153\" data-end=\"6188\">10. Bezug zu Normen &amp; Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6190\" data-end=\"6543\">\r\n<thead data-start=\"6190\" data-end=\"6217\">\r\n<tr data-start=\"6190\" data-end=\"6217\">\r\n<th data-start=\"6190\" data-end=\"6208\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"6208\" data-end=\"6217\" data-col-size=\"md\">Bezug</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6247\" data-end=\"6543\">\r\n<tr data-start=\"6247\" data-end=\"6359\">\r\n<td data-start=\"6247\" data-end=\"6272\" data-col-size=\"sm\"><strong data-start=\"6249\" data-end=\"6271\">ISO/IEC 27001:2022</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6272\" data-end=\"6359\">Kapitel 10.1 &ndash; Nichtkonformit&auml;t &amp; Korrekturma&szlig;nahmen<br>Kapitel 10.2 &ndash; Verbesserung</td>\r\n</tr>\r\n<tr data-start=\"6360\" data-end=\"6458\">\r\n<td data-start=\"6360\" data-end=\"6385\" data-col-size=\"sm\"><strong data-start=\"6362\" data-end=\"6384\">BSI IT-Grundschutz</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6385\" data-end=\"6458\">ORP.4.1 &ndash; ISMS-Betrieb<br>ISMS.1.A6 &ndash; Verbesserungsprozess etablieren</td>\r\n</tr>\r\n<tr data-start=\"6459\" data-end=\"6543\">\r\n<td data-start=\"6459\" data-end=\"6485\" data-col-size=\"sm\"><strong data-start=\"6461\" data-end=\"6484\">ISO 9001 (optional)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"6485\" data-end=\"6543\">Kapitel 10.2 &ndash; Nichtkonformit&auml;t und Korrekturma&szlig;nahmen</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(23, 'DOK-0028', 'ISMS-Personalverfahren (Verfahren zur personalsicherheitsbezogenen Steuerung)', 'Verfahren', '1', 0, NULL, '<h2 data-start=\"894\" data-end=\"909\"><strong data-start=\"897\" data-end=\"909\">1. Zweck</strong></h2>\r\n<p data-start=\"911\" data-end=\"1222\">Ziel dieses Verfahrens ist es, sicherzustellen, dass alle Personen, die f&uuml;r oder im Namen der Organisation t&auml;tig sind, &uuml;ber ihre <strong data-start=\"1040\" data-end=\"1080\">Informationssicherheitsverantwortung</strong> informiert sind und keine <strong data-start=\"1107\" data-end=\"1148\">Gef&auml;hrdung der Informationssicherheit</strong> durch Personal entsteht &ndash; weder vor, w&auml;hrend noch nach der Besch&auml;ftigung.</p>\r\n<hr data-start=\"1224\" data-end=\"1227\">\r\n<h2 data-start=\"1229\" data-end=\"1254\"><strong data-start=\"1232\" data-end=\"1254\">2. Geltungsbereich</strong></h2>\r\n<p data-start=\"1256\" data-end=\"1282\">Dieses Verfahren gilt f&uuml;r:</p>\r\n<ul data-start=\"1284\" data-end=\"1562\">\r\n<li data-start=\"1284\" data-end=\"1346\">\r\n<p data-start=\"1286\" data-end=\"1346\">alle internen Mitarbeitenden (Festangestellte, befristete)</p>\r\n</li>\r\n<li data-start=\"1347\" data-end=\"1459\">\r\n<p data-start=\"1349\" data-end=\"1459\">externe Personen mit System- oder Datenzugriff (z. B. Berater, Praktikanten, Werkstudierende, Dienstleister)</p>\r\n</li>\r\n<li data-start=\"1460\" data-end=\"1562\">\r\n<p data-start=\"1462\" data-end=\"1562\">Dienstleister mit personeller Schnittstelle zum Unternehmen (z. B. Support, Reinigung mit IT-Zugang)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1564\" data-end=\"1567\">\r\n<h2 data-start=\"1569\" data-end=\"1589\"><strong data-start=\"1572\" data-end=\"1589\">3. Grunds&auml;tze</strong></h2>\r\n<ul data-start=\"1591\" data-end=\"1900\">\r\n<li data-start=\"1591\" data-end=\"1669\">\r\n<p data-start=\"1593\" data-end=\"1669\">Informationssicherheit ist <strong data-start=\"1620\" data-end=\"1667\">Bestandteil des gesamten Employee Lifecycle</strong></p>\r\n</li>\r\n<li data-start=\"1670\" data-end=\"1751\">\r\n<p data-start=\"1672\" data-end=\"1751\">Mitarbeitende sind zu <strong data-start=\"1694\" data-end=\"1736\">Vertraulichkeit und sicherem Verhalten</strong> verpflichtet</p>\r\n</li>\r\n<li data-start=\"1752\" data-end=\"1826\">\r\n<p data-start=\"1754\" data-end=\"1826\">Sicherheitsanforderungen gelten <strong data-start=\"1786\" data-end=\"1824\">rollenbasiert und risikoorientiert</strong></p>\r\n</li>\r\n<li data-start=\"1827\" data-end=\"1900\">\r\n<p data-start=\"1829\" data-end=\"1900\"><strong data-start=\"1829\" data-end=\"1841\">Verst&ouml;&szlig;e</strong> gegen Sicherheitsrichtlinien werden systematisch behandelt</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1902\" data-end=\"1905\">\r\n<h2 data-start=\"1907\" data-end=\"1975\"><strong data-start=\"1910\" data-end=\"1975\">4. Ablauf: Sicherheitsrelevante Phasen im Besch&auml;ftigtenzyklus</strong></h2>\r\n<h3 data-start=\"1977\" data-end=\"2010\">4.1 <strong data-start=\"1985\" data-end=\"2010\">Vor der Besch&auml;ftigung</strong></h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2012\" data-end=\"2537\">\r\n<thead data-start=\"2012\" data-end=\"2039\">\r\n<tr data-start=\"2012\" data-end=\"2039\">\r\n<th data-start=\"2012\" data-end=\"2023\" data-col-size=\"md\">Ma&szlig;nahme</th>\r\n<th data-start=\"2023\" data-end=\"2039\" data-col-size=\"md\">Beschreibung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2068\" data-end=\"2537\">\r\n<tr data-start=\"2068\" data-end=\"2170\">\r\n<td data-start=\"2068\" data-end=\"2094\" data-col-size=\"md\"><strong data-start=\"2070\" data-end=\"2093\">Stellenbeschreibung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2094\" data-end=\"2170\">Sicherheitsrelevante Anforderungen werden in Rollenprofilen dokumentiert</td>\r\n</tr>\r\n<tr data-start=\"2171\" data-end=\"2297\">\r\n<td data-start=\"2171\" data-end=\"2224\" data-col-size=\"md\"><strong data-start=\"2173\" data-end=\"2195\">Hintergrundpr&uuml;fung</strong> (sofern rechtlich zul&auml;ssig)</td>\r\n<td data-col-size=\"md\" data-start=\"2224\" data-end=\"2297\">Z. B. F&uuml;hrungszeugnis, Referenzcheck bei sicherheitskritischen Rollen</td>\r\n</tr>\r\n<tr data-start=\"2298\" data-end=\"2423\">\r\n<td data-start=\"2298\" data-end=\"2330\" data-col-size=\"md\"><strong data-start=\"2300\" data-end=\"2329\">Vertraulichkeitserkl&auml;rung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2330\" data-end=\"2423\">Verpflichtung zur Verschwiegenheit bereits vor Beginn (z. B. im Arbeitsvertrag enthalten)</td>\r\n</tr>\r\n<tr data-start=\"2424\" data-end=\"2537\">\r\n<td data-start=\"2424\" data-end=\"2461\" data-col-size=\"md\"><strong data-start=\"2426\" data-end=\"2460\">Risikobasierte Rollenbewertung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2461\" data-end=\"2537\">Sensibilisierung je nach IT-/Datenzugriff bereits bei Onboarding geplant</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2539\" data-end=\"2542\">\r\n<h3 data-start=\"2544\" data-end=\"2581\">4.2 <strong data-start=\"2552\" data-end=\"2581\">W&auml;hrend der Besch&auml;ftigung</strong></h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2583\" data-end=\"3427\">\r\n<thead data-start=\"2583\" data-end=\"2610\">\r\n<tr data-start=\"2583\" data-end=\"2610\">\r\n<th data-start=\"2583\" data-end=\"2594\" data-col-size=\"sm\">Ma&szlig;nahme</th>\r\n<th data-start=\"2594\" data-end=\"2610\" data-col-size=\"md\">Beschreibung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2639\" data-end=\"3427\">\r\n<tr data-start=\"2639\" data-end=\"2738\">\r\n<td data-start=\"2639\" data-end=\"2666\" data-col-size=\"sm\"><strong data-start=\"2641\" data-end=\"2665\">Awareness-Schulungen</strong></td>\r\n<td data-start=\"2666\" data-end=\"2738\" data-col-size=\"md\">Erste Schulung bei Eintritt (Onboarding), danach mindestens j&auml;hrlich</td>\r\n</tr>\r\n<tr data-start=\"2739\" data-end=\"2838\">\r\n<td data-start=\"2739\" data-end=\"2779\" data-col-size=\"sm\"><strong data-start=\"2741\" data-end=\"2778\">Informationssicherheitsrichtlinie</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2779\" data-end=\"2838\">Wird verpflichtend zur Kenntnis genommen und akzeptiert</td>\r\n</tr>\r\n<tr data-start=\"2839\" data-end=\"2950\">\r\n<td data-start=\"2839\" data-end=\"2862\" data-col-size=\"sm\"><strong data-start=\"2841\" data-end=\"2861\">Verhaltensregeln</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2862\" data-end=\"2950\">z. B. Clean Desk, sichere Passwortverwendung, Umgang mit vertraulichen Informationen</td>\r\n</tr>\r\n<tr data-start=\"2951\" data-end=\"3055\">\r\n<td data-start=\"2951\" data-end=\"2975\" data-col-size=\"sm\"><strong data-start=\"2953\" data-end=\"2974\">Pflichtschulungen</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2975\" data-end=\"3055\">z. B. Datenschutz, IT-Security, Notfallverhalten, Meldepflicht bei Vorf&auml;llen</td>\r\n</tr>\r\n<tr data-start=\"3056\" data-end=\"3159\">\r\n<td data-start=\"3056\" data-end=\"3101\" data-col-size=\"sm\"><strong data-start=\"3058\" data-end=\"3100\">Meldung sicherheitsrelevanter Vorf&auml;lle</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3101\" data-end=\"3159\">Verpflichtung zur Meldung von Anomalien oder Verst&ouml;&szlig;en</td>\r\n</tr>\r\n<tr data-start=\"3160\" data-end=\"3297\">\r\n<td data-start=\"3160\" data-end=\"3198\" data-col-size=\"sm\"><strong data-start=\"3162\" data-end=\"3197\">Leistungskontrolle / Eskalation</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3198\" data-end=\"3297\">Umgang mit sicherheitskritischem Verhalten ist geregelt (Abmahnung, Entzug von Zugriffsrechten)</td>\r\n</tr>\r\n<tr data-start=\"3298\" data-end=\"3427\">\r\n<td data-start=\"3298\" data-end=\"3336\" data-col-size=\"sm\"><strong data-start=\"3300\" data-end=\"3335\">Zugriffsberechtigungsmanagement</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3336\" data-end=\"3427\">Rollenbasierte Freigabe und regelm&auml;&szlig;ige &Uuml;berpr&uuml;fung (z. B. Joiner-Mover-Leaver-Prozess)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3429\" data-end=\"3432\">\r\n<h3 data-start=\"3434\" data-end=\"3474\">4.3 <strong data-start=\"3442\" data-end=\"3474\">Beendigung der Besch&auml;ftigung</strong></h3>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3476\" data-end=\"4093\">\r\n<thead data-start=\"3476\" data-end=\"3503\">\r\n<tr data-start=\"3476\" data-end=\"3503\">\r\n<th data-start=\"3476\" data-end=\"3487\" data-col-size=\"sm\">Ma&szlig;nahme</th>\r\n<th data-start=\"3487\" data-end=\"3503\" data-col-size=\"md\">Beschreibung</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3532\" data-end=\"4093\">\r\n<tr data-start=\"3532\" data-end=\"3640\">\r\n<td data-start=\"3532\" data-end=\"3561\" data-col-size=\"sm\"><strong data-start=\"3534\" data-end=\"3560\">Offboarding-Checkliste</strong></td>\r\n<td data-start=\"3561\" data-end=\"3640\" data-col-size=\"md\">Sicherheitsrelevante Punkte werden dokumentiert abgearbeitet (siehe Anhang)</td>\r\n</tr>\r\n<tr data-start=\"3641\" data-end=\"3741\">\r\n<td data-start=\"3641\" data-end=\"3667\" data-col-size=\"sm\"><strong data-start=\"3643\" data-end=\"3666\">R&uuml;ckgabe von Assets</strong></td>\r\n<td data-start=\"3667\" data-end=\"3741\" data-col-size=\"md\">Ger&auml;te, Zutrittskarten, USB-Sticks etc. sind vollst&auml;ndig zur&uuml;ckzugeben</td>\r\n</tr>\r\n<tr data-start=\"3742\" data-end=\"3847\">\r\n<td data-start=\"3742\" data-end=\"3768\" data-col-size=\"sm\"><strong data-start=\"3744\" data-end=\"3767\">Entzug von Zug&auml;ngen</strong></td>\r\n<td data-start=\"3768\" data-end=\"3847\" data-col-size=\"md\">Alle physischen und logischen Zugriffsrechte werden <strong data-start=\"3822\" data-end=\"3845\">zeitnah deaktiviert</strong></td>\r\n</tr>\r\n<tr data-start=\"3848\" data-end=\"3961\">\r\n<td data-start=\"3848\" data-end=\"3872\" data-col-size=\"sm\"><strong data-start=\"3850\" data-end=\"3871\">Abschlussgespr&auml;ch</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3872\" data-end=\"3961\">Erinnerung an Vertraulichkeitspflichten, ggf. Hinweis auf nachvertragliche Regelungen</td>\r\n</tr>\r\n<tr data-start=\"3962\" data-end=\"4093\">\r\n<td data-start=\"3962\" data-end=\"4000\" data-col-size=\"sm\"><strong data-start=\"3964\" data-end=\"3999\">Informationspflicht an ISB / IT</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4000\" data-end=\"4093\">HR informiert relevante Stellen rechtzeitig &uuml;ber Austritte (z. B. per Workflow oder Mail)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4095\" data-end=\"4098\">\r\n<h2 data-start=\"4100\" data-end=\"4130\"><strong data-start=\"4103\" data-end=\"4130\">5. Verantwortlichkeiten</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4132\" data-end=\"4730\">\r\n<thead data-start=\"4132\" data-end=\"4151\">\r\n<tr data-start=\"4132\" data-end=\"4151\">\r\n<th data-start=\"4132\" data-end=\"4140\" data-col-size=\"md\">Rolle</th>\r\n<th data-start=\"4140\" data-end=\"4151\" data-col-size=\"md\">Aufgabe</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4171\" data-end=\"4730\">\r\n<tr data-start=\"4171\" data-end=\"4268\">\r\n<td data-start=\"4171\" data-end=\"4190\" data-col-size=\"md\"><strong data-start=\"4173\" data-end=\"4189\">HR-Abteilung</strong></td>\r\n<td data-start=\"4190\" data-end=\"4268\" data-col-size=\"md\">Personaladministration, Schulungskoordination, Vertraulichkeitserkl&auml;rungen</td>\r\n</tr>\r\n<tr data-start=\"4269\" data-end=\"4353\">\r\n<td data-start=\"4269\" data-end=\"4288\" data-col-size=\"md\"><strong data-start=\"4271\" data-end=\"4287\">Fachbereiche</strong></td>\r\n<td data-start=\"4288\" data-end=\"4353\" data-col-size=\"md\">Information bei Ver&auml;nderungen, Mitwirkung bei Rollenbewertung</td>\r\n</tr>\r\n<tr data-start=\"4354\" data-end=\"4427\">\r\n<td data-start=\"4354\" data-end=\"4373\" data-col-size=\"md\"><strong data-start=\"4356\" data-end=\"4372\">IT-Abteilung</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4373\" data-end=\"4427\">Umsetzung von Berechtigungen (Join / Move / Leave)</td>\r\n</tr>\r\n<tr data-start=\"4428\" data-end=\"4551\">\r\n<td data-start=\"4428\" data-end=\"4477\" data-col-size=\"md\"><strong data-start=\"4430\" data-end=\"4476\">Informationssicherheitsbeauftragte*r (ISB)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"4477\" data-end=\"4551\">Unterst&uuml;tzung bei Schulungen, Kontrolle sicherheitsrelevanter Prozesse</td>\r\n</tr>\r\n<tr data-start=\"4552\" data-end=\"4631\">\r\n<td data-start=\"4552\" data-end=\"4573\" data-col-size=\"md\"><strong data-start=\"4554\" data-end=\"4572\">F&uuml;hrungskr&auml;fte</strong></td>\r\n<td data-start=\"4573\" data-end=\"4631\" data-col-size=\"md\">Einhaltung der Sicherheitsregeln im Team sicherstellen</td>\r\n</tr>\r\n<tr data-start=\"4632\" data-end=\"4730\">\r\n<td data-start=\"4632\" data-end=\"4658\" data-col-size=\"md\"><strong data-start=\"4634\" data-end=\"4657\">Alle Mitarbeitenden</strong></td>\r\n<td data-start=\"4658\" data-end=\"4730\" data-col-size=\"md\">Einhaltung aller geltenden Sicherheitsrichtlinien und Meldepflichten</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4732\" data-end=\"4735\">\r\n<h2 data-start=\"4737\" data-end=\"4772\"><strong data-start=\"4740\" data-end=\"4772\">6. Eskalation und Sanktionen</strong></h2>\r\n<ul data-start=\"4774\" data-end=\"5053\">\r\n<li data-start=\"4774\" data-end=\"4915\">\r\n<p data-start=\"4776\" data-end=\"4853\">Bei <strong data-start=\"4780\" data-end=\"4833\">Verst&ouml;&szlig;en gegen sicherheitsrelevante Vorschriften</strong> erfolgt Meldung an:</p>\r\n<ul data-start=\"4856\" data-end=\"4915\">\r\n<li data-start=\"4856\" data-end=\"4871\">\r\n<p data-start=\"4858\" data-end=\"4871\">Vorgesetzte</p>\r\n</li>\r\n<li data-start=\"4874\" data-end=\"4881\">\r\n<p data-start=\"4876\" data-end=\"4881\">ISB</p>\r\n</li>\r\n<li data-start=\"4884\" data-end=\"4915\">\r\n<p data-start=\"4886\" data-end=\"4915\">ggf. HR oder Gesch&auml;ftsf&uuml;hrung</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"4917\" data-end=\"5053\">\r\n<p data-start=\"4919\" data-end=\"4939\">M&ouml;gliche Sanktionen:</p>\r\n<ul data-start=\"4942\" data-end=\"5053\">\r\n<li data-start=\"4942\" data-end=\"4955\">\r\n<p data-start=\"4944\" data-end=\"4955\">Abmahnung</p>\r\n</li>\r\n<li data-start=\"4958\" data-end=\"4976\">\r\n<p data-start=\"4960\" data-end=\"4976\">Zugriffsentzug</p>\r\n</li>\r\n<li data-start=\"4979\" data-end=\"5000\">\r\n<p data-start=\"4981\" data-end=\"5000\">Schulungsauflagen</p>\r\n</li>\r\n<li data-start=\"5003\" data-end=\"5053\">\r\n<p data-start=\"5005\" data-end=\"5053\">disziplinarische Ma&szlig;nahmen bis hin zur K&uuml;ndigung</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5055\" data-end=\"5058\">\r\n<h2 data-start=\"5060\" data-end=\"5098\"><strong data-start=\"5063\" data-end=\"5098\">7. &Uuml;berpr&uuml;fung &amp; Aktualisierung</strong></h2>\r\n<ul data-start=\"5100\" data-end=\"5265\">\r\n<li data-start=\"5100\" data-end=\"5215\">\r\n<p data-start=\"5102\" data-end=\"5215\">Das Verfahren wird mindestens <strong data-start=\"5132\" data-end=\"5144\">j&auml;hrlich</strong> oder bei <strong data-start=\"5154\" data-end=\"5203\">rechtlichen oder organisatorischen &Auml;nderungen</strong> &uuml;berpr&uuml;ft</p>\r\n</li>\r\n<li data-start=\"5216\" data-end=\"5265\">\r\n<p data-start=\"5218\" data-end=\"5265\">&Auml;nderungen werden dokumentiert und kommuniziert</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5267\" data-end=\"5270\">\r\n<h2 data-start=\"5272\" data-end=\"5311\"><strong data-start=\"5275\" data-end=\"5311\">8. Bezug zu Normen und Standards</strong></h2>\r\n<div class=\"TyagGW_tableContainer\">\r\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5313\" data-end=\"5719\">\r\n<thead data-start=\"5313\" data-end=\"5344\">\r\n<tr data-start=\"5313\" data-end=\"5344\">\r\n<th data-start=\"5313\" data-end=\"5331\" data-col-size=\"sm\">Norm / Standard</th>\r\n<th data-start=\"5331\" data-end=\"5344\" data-col-size=\"md\">Abschnitt</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5378\" data-end=\"5719\">\r\n<tr data-start=\"5378\" data-end=\"5457\">\r\n<td data-start=\"5378\" data-end=\"5403\" data-col-size=\"sm\"><strong data-start=\"5380\" data-end=\"5402\">ISO/IEC 27001:2022</strong></td>\r\n<td data-start=\"5403\" data-end=\"5457\" data-col-size=\"md\">Anhang A.6 &ndash; Personalbezogene Sicherheitsma&szlig;nahmen</td>\r\n</tr>\r\n<tr data-start=\"5458\" data-end=\"5553\">\r\n<td data-start=\"5458\" data-end=\"5483\" data-col-size=\"sm\"><strong data-start=\"5460\" data-end=\"5482\">BSI IT-Grundschutz</strong></td>\r\n<td data-start=\"5483\" data-end=\"5553\" data-col-size=\"md\">ORG.1 &ndash; Personal<br>ORP.3 &ndash; Aufgaben in der Informationssicherheit</td>\r\n</tr>\r\n<tr data-start=\"5554\" data-end=\"5639\">\r\n<td data-start=\"5554\" data-end=\"5566\" data-col-size=\"sm\"><strong data-start=\"5556\" data-end=\"5565\">DSGVO</strong></td>\r\n<td data-start=\"5566\" data-end=\"5639\" data-col-size=\"md\">Art. 32 &ndash; Sicherheit der Verarbeitung (Mitarbeiterzugriffe, Schulung)</td>\r\n</tr>\r\n<tr data-start=\"5640\" data-end=\"5719\">\r\n<td data-start=\"5640\" data-end=\"5652\" data-col-size=\"sm\"><strong data-start=\"5642\" data-end=\"5651\">NIS-2</strong></td>\r\n<td data-start=\"5652\" data-end=\"5719\" data-col-size=\"md\">Anforderungen an Sicherheitskompetenz und Personalverantwortung</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(24, 'DOK-0029', 'Hardwarelebenszyklus im ISMS', 'Verfahren', '1', 0, 'öffentlich', '<h2><strong>1. Zweck</strong></h2>\n<p>Dieses Verfahren beschreibt den <strong>sicherheitskonformen Umgang mit IT-Hardware über deren gesamten Lebenszyklus hinweg</strong> – von der Beschaffung über Nutzung bis zur sicheren Außerbetriebnahme und Entsorgung. Ziel ist es, <strong>Verluste, Manipulationen und Datenabflüsse</strong> zu verhindern und die <strong>Anforderungen des ISMS an Vertraulichkeit, Integrität und Verfügbarkeit</strong> zu erfüllen.</p>\n<hr/>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Dieses Verfahren gilt für alle:</p>\n<ul>\n<li>\n<p>physischen IT-Komponenten (Clients, Server, Laptops, mobile Geräte, Wechseldatenträger, Netzwerktechnik etc.)</p>\n</li>\n<li>\n<p>innerhalb des ISMS-Scopes genutzten Hardware-Assets</p>\n</li>\n<li>\n<p>Standorte, an denen Hardware betrieben, gelagert oder entsorgt wird</p>\n</li>\n<li>\n<p><strong>internen und externen Beteiligten</strong>, die mit Hardware umgehen</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Übersicht: Phasen im Hardwarelebenszyklus</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Phase</th>\n<th>Zielsetzung</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>1. Bedarfsermittlung &amp; Beschaffung</td>\n<td>Auswahl sicherheitskonformer Geräte</td>\n</tr>\n<tr>\n<td>2. Inventarisierung &amp; Zuweisung</td>\n<td>Nachverfolgbarkeit und Assetverantwortung sicherstellen</td>\n</tr>\n<tr>\n<td>3. Nutzung &amp; Betrieb</td>\n<td>Schutz vor Diebstahl, Manipulation, Fehlkonfiguration</td>\n</tr>\n<tr>\n<td>4. Wartung &amp; Austausch</td>\n<td>Sicherheit und Funktionsfähigkeit erhalten</td>\n</tr>\n<tr>\n<td>5. Außerbetriebnahme &amp; Entsorgung</td>\n<td>Schutz vor Datenabfluss und unkontrollierter Weiternutzung</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>4. Ablaufbeschreibung je Lebenszyklusphase</strong></h2>\n<h3>4.1 Bedarfsermittlung &amp; Beschaffung</h3>\n<ul>\n<li>\n<p>Sicherheitsrelevante Anforderungen (z. B. TPM, Festplattenverschlüsselung, BIOS-Schutz) sind <strong>in Einkaufsvorgaben definiert</strong></p>\n</li>\n<li>\n<p><strong>Standardhardware</strong> wird zentral definiert und regelmäßig überprüft</p>\n</li>\n<li>\n<p>Beschaffungen erfolgen <strong>nur durch berechtigte Stellen</strong> (z. B. IT, Einkauf)</p>\n</li>\n</ul>\n<p><strong>Maßnahmen:</strong></p>\n<ul>\n<li>\n<p>Prüfung auf Kompatibilität mit Sicherheitsrichtlinien</p>\n</li>\n<li>\n<p>Abgleich mit Schutzbedarfsanforderungen</p>\n</li>\n<li>\n<p>Lieferantenprüfung (siehe Lieferantenmanagement)</p>\n</li>\n</ul>\n<hr/>\n<h3>4.2 Inventarisierung &amp; Zuweisung</h3>\n<ul>\n<li>\n<p>Jedes Hardware-Asset wird mit eindeutiger ID in einem <strong>Asset-Register</strong> erfasst</p>\n</li>\n<li>\n<p>Angaben im Register:</p>\n<ul>\n<li>\n<p>Gerätename / Typ / Seriennummer</p>\n</li>\n<li>\n<p>Standort</p>\n</li>\n<li>\n<p>Verantwortlicher (Asset Owner / Nutzer)</p>\n</li>\n<li>\n<p>Schutzbedarf (C/I/A)</p>\n</li>\n<li>\n<p>Kauf- / Inbetriebnahmedatum</p>\n</li>\n<li>\n<p>Status (aktiv, defekt, ausgemustert)</p>\n</li>\n</ul>\n</li>\n</ul>\n<p><strong>Maßnahmen:</strong></p>\n<ul>\n<li>\n<p>Inventarisierung durch IT oder zentrale Stelle</p>\n</li>\n<li>\n<p>Sichtbare Kennzeichnung mit Asset-Nummer</p>\n</li>\n<li>\n<p>Zuordnung an verantwortliche Person (Nutzerquittung)</p>\n</li>\n</ul>\n<hr/>\n<h3>4.3 Nutzung &amp; Betrieb</h3>\n<ul>\n<li>\n<p>Geräte werden gemäß Sicherheitsvorgaben betrieben (z. B. aktuelle Patches, Virenschutz, Festplattenverschlüsselung)</p>\n</li>\n<li>\n<p>Zugänge sind personalisiert und durch Authentisierung geschützt</p>\n</li>\n<li>\n<p>Physischer Schutz erfolgt gemäß Schutzbedarf (z. B. Schließfächer, Zugangskontrolle)</p>\n</li>\n</ul>\n<p><strong>Maßnahmen:</strong></p>\n<ul>\n<li>\n<p>Schutz durch Mobile Device Management (MDM)</p>\n</li>\n<li>\n<p>Einschränkung von USB-Ports (je nach Richtlinie)</p>\n</li>\n<li>\n<p>Schulung der Nutzer (z. B. „sicherer Umgang mit Laptops“)</p>\n</li>\n</ul>\n<hr/>\n<h3>4.4 Wartung &amp; Reparatur</h3>\n<ul>\n<li>\n<p>Reparatur oder Austausch erfolgt <strong>nur durch autorisierte Personen / Dienstleister</strong></p>\n</li>\n<li>\n<p>Bei Übergabe an Dritte ist sicherzustellen, dass:</p>\n<ul>\n<li>\n<p>keine sensiblen Daten auf dem Gerät verbleiben</p>\n</li>\n<li>\n<p>ggf. temporäre Maßnahmen (z. B. Verschlüsselung, Image) getroffen werden</p>\n</li>\n</ul>\n</li>\n</ul>\n<p><strong>Maßnahmen:</strong></p>\n<ul>\n<li>\n<p>Dokumentation im Asset-Register</p>\n</li>\n<li>\n<p>Kontrolle nach Rückgabe (z. B. vollständige Wiederherstellung des Zustands)</p>\n</li>\n</ul>\n<hr/>\n<h3>4.5 Außerbetriebnahme &amp; Entsorgung</h3>\n<ul>\n<li>\n<p>Hardware wird <strong>ordnungsgemäß aus dem Betrieb genommen und sicher gelöscht oder vernichtet</strong></p>\n</li>\n<li>\n<p>Vorgehen richtet sich nach <strong>Datenträgertyp und Schutzbedarf</strong></p>\n</li>\n</ul>\n<p><strong>Maßnahmen:</strong></p>\n<ul>\n<li>\n<p><strong>Datenlöschung</strong> nach anerkannten Standards (z. B. DoD 5220.22-M, BSI TR-02102)</p>\n</li>\n<li>\n<p><strong>Protokollierung</strong> der Löschung (inkl. durchführender Person, Zeitpunkt, Methode)</p>\n</li>\n<li>\n<p><strong>Physikalische Vernichtung</strong> bei besonders hohem Schutzbedarf (z. B. Schreddern, Degausser)</p>\n</li>\n<li>\n<p><strong>Entsorgungsnachweis</strong> (z. B. durch zertifizierte Entsorger nach ElektroG)</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>5. Verantwortlichkeiten</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>IT-Abteilung</strong></td>\n<td>Verwaltung des Asset-Registers, Durchführung von Konfiguration, Wartung und Löschung</td>\n</tr>\n<tr>\n<td><strong>Asset Owner / Nutzer</strong></td>\n<td>Sorgsamer Umgang mit zugewiesener Hardware, Meldepflicht bei Verlust/Defekt</td>\n</tr>\n<tr>\n<td><strong>Informationssicherheitsbeauftragte*r (ISB)</strong></td>\n<td>Kontrolle der Einhaltung der Sicherheitsanforderungen</td>\n</tr>\n<tr>\n<td><strong>Einkauf / Beschaffung</strong></td>\n<td>Auswahl konformer Geräte und Lieferanten</td>\n</tr>\n<tr>\n<td><strong>Externe Entsorger (sofern beauftragt)</strong></td>\n<td>Sichere Entsorgung unter Nachweispflicht</td>\n</tr>\n<tr>\n<td><strong>Interne Revision / Audit</strong></td>\n<td>Prüfung der Nachvollziehbarkeit und Konformität des Prozesses</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>6. Dokumentation &amp; Nachweisführung</strong></h2>\n<ul>\n<li>\n<p><strong>Asset-Register</strong> mit vollständiger Lebenszyklus-Historie</p>\n</li>\n<li>\n<p><strong>Löschprotokolle</strong> / Entsorgungsnachweise (mind. 3–5 Jahre aufbewahren)</p>\n</li>\n<li>\n<p><strong>Zuweisungs- und Rückgabequittungen</strong></p>\n</li>\n<li>\n<p><strong>Offboarding-Checklisten</strong> mit Rückgabe aller IT-Assets</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>7. Sicherheit bei Verlust oder Diebstahl</strong></h2>\n<ul>\n<li>\n<p>Meldung <strong>unverzüglich an IT und ISB</strong></p>\n</li>\n<li>\n<p>Maßnahmen:</p>\n<ul>\n<li>\n<p>Sperrung von Benutzerkonten</p>\n</li>\n<li>\n<p>Fernlöschung bei mobilen Geräten (sofern technisch möglich)</p>\n</li>\n<li>\n<p>Sicherheitsvorfall gemäß Incident-Management-Verfahren</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Verknüpfung mit anderen ISMS-Prozessen</strong></h2>\n<ul>\n<li>\n<p><strong>Asset Management</strong></p>\n</li>\n<li>\n<p><strong>Zugriffsmanagement</strong></p>\n</li>\n<li>\n<p><strong>Lieferantenmanagement</strong></p>\n</li>\n<li>\n<p><strong>Incident Management</strong></p>\n</li>\n<li>\n<p><strong>Datenträgerentsorgung</strong></p>\n</li>\n<li>\n<p><strong>Offboarding-Prozess</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Bezug zu Normen &amp; Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Bezug</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001:2022</strong></td>\n<td>A.5.9 – Asset-Nutzung<br/>A.7.10 – Vernichtung von Informationen<br/>A.8 – Asset Management</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>INF.1, SYS.1.1 / 1.2, OPS.1.2 – IT-Systeme &amp; Entsorgung</td>\n</tr>\n<tr>\n<td><strong>DSGVO</strong></td>\n<td>Art. 32 – Sicherheit der Verarbeitung (Zugriff, Löschung)</td>\n</tr>\n<tr>\n<td><strong>ElektroG</strong></td>\n<td>Gesetzliche Vorgaben zur Altgeräteentsorgung (Elektroschrott)</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>10. Inkrafttreten</strong></h2>\n<p>Dieses Verfahren tritt am <strong>[Datum]</strong> in Kraft. Es wird mindestens jährlich überprüft und bei Bedarf angepasst.</p>\n<p><strong>[Ort, Datum]</strong><br/><strong>[Unterschrift ISB / IT-Leitung / Geschäftsführung]</strong></p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-07-18', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 1, '', NULL, NULL, 0, 0, NULL),
(25, 'DOK-0030', 'Management-Review', 'Richtlinien', '1', 0, NULL, '<h2 data-start=\"403\" data-end=\"423\">1. Zweck und Ziel</h2>\r\n<p data-start=\"425\" data-end=\"687\">Ziel dieser Richtlinie ist es, sicherzustellen, dass das <strong data-start=\"482\" data-end=\"533\">Informationssicherheits-Managementsystem (ISMS)</strong> regelm&auml;&szlig;ig durch die oberste Leitung bewertet wird, um dessen <strong data-start=\"596\" data-end=\"669\">Angemessenheit, Eignung, Wirksamkeit und kontinuierliche Verbesserung</strong> zu gew&auml;hrleisten.</p>\r\n<p data-start=\"689\" data-end=\"731\">Das Management-Review stellt sicher, dass:</p>\r\n<ul data-start=\"732\" data-end=\"969\">\r\n<li data-start=\"732\" data-end=\"779\">\r\n<p data-start=\"734\" data-end=\"779\">Informationssicherheitsziele erreicht werden,</p>\r\n</li>\r\n<li data-start=\"780\" data-end=\"818\">\r\n<p data-start=\"782\" data-end=\"818\">Risiken angemessen behandelt werden,</p>\r\n</li>\r\n<li data-start=\"819\" data-end=\"893\">\r\n<p data-start=\"821\" data-end=\"893\">gesetzliche, regulatorische und vertragliche Anforderungen erf&uuml;llt sind,</p>\r\n</li>\r\n<li data-start=\"894\" data-end=\"969\">\r\n<p data-start=\"896\" data-end=\"969\">strategische und operative Entscheidungen faktenbasiert getroffen werden.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"971\" data-end=\"974\">\r\n<h2 data-start=\"976\" data-end=\"997\">2. Geltungsbereich</h2>\r\n<p data-start=\"999\" data-end=\"1025\">Diese Richtlinie gilt f&uuml;r:</p>\r\n<ul data-start=\"1026\" data-end=\"1173\">\r\n<li data-start=\"1026\" data-end=\"1084\">\r\n<p data-start=\"1028\" data-end=\"1084\">das gesamte <strong data-start=\"1040\" data-end=\"1083\">ISMS gem&auml;&szlig; festgelegtem Geltungsbereich</strong>,</p>\r\n</li>\r\n<li data-start=\"1085\" data-end=\"1173\">\r\n<p data-start=\"1087\" data-end=\"1173\">alle Organisationseinheiten, Standorte und Prozesse, die im ISMS-Scope enthalten sind.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1175\" data-end=\"1178\">\r\n<h2 data-start=\"1180\" data-end=\"1206\">3. Normative Grundlagen</h2>\r\n<ul data-start=\"1208\" data-end=\"1404\">\r\n<li data-start=\"1208\" data-end=\"1263\">\r\n<p data-start=\"1210\" data-end=\"1263\">ISO/IEC 27001:2022, Kapitel 9.3 &ndash; <em data-start=\"1244\" data-end=\"1263\">Management Review</em></p>\r\n</li>\r\n<li data-start=\"1264\" data-end=\"1285\">\r\n<p data-start=\"1266\" data-end=\"1285\">ISO/IEC 27000-Reihe</p>\r\n</li>\r\n<li data-start=\"1286\" data-end=\"1363\">\r\n<p data-start=\"1288\" data-end=\"1363\">Relevante gesetzliche und regulatorische Anforderungen (z. B. NIS-2, DSGVO)</p>\r\n</li>\r\n<li data-start=\"1364\" data-end=\"1404\">\r\n<p data-start=\"1366\" data-end=\"1404\">Interne ISMS-Richtlinien und Verfahren</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1406\" data-end=\"1409\">\r\n<h2 data-start=\"1411\" data-end=\"1430\">4. Verantwortung</h2>\r\n<h3 data-start=\"1432\" data-end=\"1455\">4.1 Oberste Leitung</h3>\r\n<p data-start=\"1456\" data-end=\"1476\">Die oberste Leitung:</p>\r\n<ul data-start=\"1477\" data-end=\"1669\">\r\n<li data-start=\"1477\" data-end=\"1540\">\r\n<p data-start=\"1479\" data-end=\"1540\">f&uuml;hrt mindestens einmal j&auml;hrlich ein Management-Review durch,</p>\r\n</li>\r\n<li data-start=\"1541\" data-end=\"1607\">\r\n<p data-start=\"1543\" data-end=\"1607\">genehmigt Ergebnisse, Ma&szlig;nahmen und strategische Entscheidungen,</p>\r\n</li>\r\n<li data-start=\"1608\" data-end=\"1669\">\r\n<p data-start=\"1610\" data-end=\"1669\">tr&auml;gt die Gesamtverantwortung f&uuml;r die Wirksamkeit des ISMS.</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"1671\" data-end=\"1727\">4.2 Informationssicherheitsbeauftragter (ISB / CISO)</h3>\r\n<p data-start=\"1728\" data-end=\"1736\">Der ISB:</p>\r\n<ul data-start=\"1737\" data-end=\"1921\">\r\n<li data-start=\"1737\" data-end=\"1774\">\r\n<p data-start=\"1739\" data-end=\"1774\">bereitet das Management-Review vor,</p>\r\n</li>\r\n<li data-start=\"1775\" data-end=\"1829\">\r\n<p data-start=\"1777\" data-end=\"1829\">stellt erforderliche Berichte und Kennzahlen bereit,</p>\r\n</li>\r\n<li data-start=\"1830\" data-end=\"1870\">\r\n<p data-start=\"1832\" data-end=\"1870\">dokumentiert Ergebnisse und Ma&szlig;nahmen,</p>\r\n</li>\r\n<li data-start=\"1871\" data-end=\"1921\">\r\n<p data-start=\"1873\" data-end=\"1921\">&uuml;berwacht die Umsetzung beschlossener Ma&szlig;nahmen.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1923\" data-end=\"1926\">\r\n<h2 data-start=\"1928\" data-end=\"1955\">5. H&auml;ufigkeit und Anlass</h2>\r\n<p data-start=\"1957\" data-end=\"1979\">Ein Management-Review:</p>\r\n<ul data-start=\"1980\" data-end=\"2274\">\r\n<li data-start=\"1980\" data-end=\"2021\">\r\n<p data-start=\"1982\" data-end=\"2021\">erfolgt <strong data-start=\"1990\" data-end=\"2020\">mindestens einmal j&auml;hrlich</strong>,</p>\r\n</li>\r\n<li data-start=\"2022\" data-end=\"2274\">\r\n<p data-start=\"2024\" data-end=\"2064\">zus&auml;tzlich <strong data-start=\"2035\" data-end=\"2052\">anlassbezogen</strong>, z. B. bei:</p>\r\n<ul data-start=\"2067\" data-end=\"2274\">\r\n<li data-start=\"2067\" data-end=\"2099\">\r\n<p data-start=\"2069\" data-end=\"2099\">schweren Sicherheitsvorf&auml;llen,</p>\r\n</li>\r\n<li data-start=\"2102\" data-end=\"2164\">\r\n<p data-start=\"2104\" data-end=\"2164\">wesentlichen &Auml;nderungen der Organisation oder IT-Landschaft,</p>\r\n</li>\r\n<li data-start=\"2167\" data-end=\"2224\">\r\n<p data-start=\"2169\" data-end=\"2224\">relevanten rechtlichen oder regulatorischen &Auml;nderungen,</p>\r\n</li>\r\n<li data-start=\"2227\" data-end=\"2274\">\r\n<p data-start=\"2229\" data-end=\"2274\">signifikanten Risiken oder Auditabweichungen.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2276\" data-end=\"2279\">\r\n<h2 data-start=\"2281\" data-end=\"2317\">6. Eingaben zum Management-Review</h2>\r\n<p data-start=\"2319\" data-end=\"2385\">Das Management-Review ber&uuml;cksichtigt mindestens folgende Eingaben:</p>\r\n<ul data-start=\"2387\" data-end=\"2902\">\r\n<li data-start=\"2387\" data-end=\"2445\">\r\n<p data-start=\"2389\" data-end=\"2445\">Status der Ma&szlig;nahmen aus vorherigen Management-Reviews</p>\r\n</li>\r\n<li data-start=\"2446\" data-end=\"2515\">\r\n<p data-start=\"2448\" data-end=\"2515\">&Auml;nderungen externer und interner Themen mit Einfluss auf das ISMS</p>\r\n</li>\r\n<li data-start=\"2516\" data-end=\"2559\">\r\n<p data-start=\"2518\" data-end=\"2559\">Ergebnisse interner und externer Audits</p>\r\n</li>\r\n<li data-start=\"2560\" data-end=\"2624\">\r\n<p data-start=\"2562\" data-end=\"2624\">Ergebnisse der Risikoanalysen und des Risikobehandlungsplans</p>\r\n</li>\r\n<li data-start=\"2625\" data-end=\"2678\">\r\n<p data-start=\"2627\" data-end=\"2678\">Status von Informationssicherheitszielen und KPIs</p>\r\n</li>\r\n<li data-start=\"2679\" data-end=\"2738\">\r\n<p data-start=\"2681\" data-end=\"2738\">Sicherheitsvorf&auml;lle, Schwachstellen und Lessons Learned</p>\r\n</li>\r\n<li data-start=\"2739\" data-end=\"2797\">\r\n<p data-start=\"2741\" data-end=\"2797\">Ergebnisse von Lieferanten- und Drittparteibewertungen</p>\r\n</li>\r\n<li data-start=\"2798\" data-end=\"2833\">\r\n<p data-start=\"2800\" data-end=\"2833\">Feedback relevanter Stakeholder</p>\r\n</li>\r\n<li data-start=\"2834\" data-end=\"2902\">\r\n<p data-start=\"2836\" data-end=\"2902\">Ergebnisse von Tests zur Business Continuity und Notfallvorsorge</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2904\" data-end=\"2907\">\r\n<h2 data-start=\"2909\" data-end=\"2948\">7. Ergebnisse des Management-Reviews</h2>\r\n<p data-start=\"2950\" data-end=\"3034\">Das Management-Review f&uuml;hrt mindestens zu Entscheidungen und Ma&szlig;nahmen hinsichtlich:</p>\r\n<ul data-start=\"3036\" data-end=\"3288\">\r\n<li data-start=\"3036\" data-end=\"3079\">\r\n<p data-start=\"3038\" data-end=\"3079\">Verbesserungen der Wirksamkeit des ISMS</p>\r\n</li>\r\n<li data-start=\"3080\" data-end=\"3129\">\r\n<p data-start=\"3082\" data-end=\"3129\">Anpassungen von Informationssicherheitszielen</p>\r\n</li>\r\n<li data-start=\"3130\" data-end=\"3175\">\r\n<p data-start=\"3132\" data-end=\"3175\">Genehmigung oder Anpassung von Ressourcen</p>\r\n</li>\r\n<li data-start=\"3176\" data-end=\"3232\">\r\n<p data-start=\"3178\" data-end=\"3232\">&Auml;nderungen an Richtlinien, Prozessen oder Kontrollen</p>\r\n</li>\r\n<li data-start=\"3233\" data-end=\"3288\">\r\n<p data-start=\"3235\" data-end=\"3288\">Behandlung identifizierter Risiken und Abweichungen</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3290\" data-end=\"3326\">Alle beschlossenen Ma&szlig;nahmen werden:</p>\r\n<ul data-start=\"3327\" data-end=\"3404\">\r\n<li data-start=\"3327\" data-end=\"3342\">\r\n<p data-start=\"3329\" data-end=\"3342\">dokumentiert,</p>\r\n</li>\r\n<li data-start=\"3343\" data-end=\"3373\">\r\n<p data-start=\"3345\" data-end=\"3373\">Verantwortlichen zugewiesen,</p>\r\n</li>\r\n<li data-start=\"3374\" data-end=\"3404\">\r\n<p data-start=\"3376\" data-end=\"3404\">terminiert und nachverfolgt.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3406\" data-end=\"3409\">\r\n<h2 data-start=\"3411\" data-end=\"3450\">8. Dokumentation und Nachweisf&uuml;hrung</h2>\r\n<ul data-start=\"3452\" data-end=\"3752\">\r\n<li data-start=\"3452\" data-end=\"3555\">\r\n<p data-start=\"3454\" data-end=\"3555\">Das Management-Review wird <strong data-start=\"3481\" data-end=\"3509\">vollst&auml;ndig dokumentiert</strong> (z. B. Protokoll, Management-Review-Bericht).</p>\r\n</li>\r\n<li data-start=\"3556\" data-end=\"3668\">\r\n<p data-start=\"3558\" data-end=\"3580\">Die Dokumentation ist:</p>\r\n<ul data-start=\"3583\" data-end=\"3668\">\r\n<li data-start=\"3583\" data-end=\"3601\">\r\n<p data-start=\"3585\" data-end=\"3601\">revisionssicher,</p>\r\n</li>\r\n<li data-start=\"3604\" data-end=\"3622\">\r\n<p data-start=\"3606\" data-end=\"3622\">nachvollziehbar,</p>\r\n</li>\r\n<li data-start=\"3625\" data-end=\"3668\">\r\n<p data-start=\"3627\" data-end=\"3668\">f&uuml;r interne und externe Audits verf&uuml;gbar.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"3669\" data-end=\"3752\">\r\n<p data-start=\"3671\" data-end=\"3752\">Aufbewahrungsfristen richten sich nach den internen Regelungen zur Dokumentation.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3754\" data-end=\"3757\">\r\n<h2 data-start=\"3759\" data-end=\"3780\">9. Vertraulichkeit</h2>\r\n<p data-start=\"3782\" data-end=\"3933\">Alle im Management-Review behandelten Informationen unterliegen der jeweils g&uuml;ltigen <strong data-start=\"3867\" data-end=\"3898\">Informationsklassifizierung</strong> und sind entsprechend zu sch&uuml;tzen.</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '', NULL, NULL, 0, 0, NULL),
(26, 'DOK-0031', 'Richtlinie zur Dokumenten- und Aufzeichnungslenkung', 'Richtlinien', '1', 0, 'öffentlich', '<h2>1. Zweck und Ziel</h2>\n<p>Zweck dieser Richtlinie ist es, sicherzustellen, dass alle <strong>ISMS-relevanten Dokumente und Aufzeichnungen</strong> kontrolliert erstellt, geprüft, genehmigt, verteilt, geändert, aufbewahrt und gelöscht werden.</p>\n<p>Die Dokumenten- und Aufzeichnungslenkung gewährleistet:</p>\n<ul>\n<li>\n<p>Aktualität, Verfügbarkeit und Integrität von ISMS-Informationen</p>\n</li>\n<li>\n<p>Nachvollziehbarkeit von Entscheidungen und Maßnahmen</p>\n</li>\n<li>\n<p>Revisions- und Auditfähigkeit</p>\n</li>\n<li>\n<p>Einhaltung gesetzlicher, regulatorischer und normativer Anforderungen</p>\n</li>\n</ul>\n<hr/>\n<h2>2. Geltungsbereich</h2>\n<p>Diese Richtlinie gilt für:</p>\n<ul>\n<li>\n<p>alle <strong>Dokumente</strong> und <strong>Aufzeichnungen</strong>, die das ISMS betreffen,</p>\n</li>\n<li>\n<p>unabhängig von:</p>\n<ul>\n<li>\n<p>Medium (digital / papierbasiert),</p>\n</li>\n<li>\n<p>Speicherort (lokal, zentral, Cloud),</p>\n</li>\n<li>\n<p>Ersteller (intern / extern),</p>\n</li>\n</ul>\n</li>\n<li>\n<p>für alle Organisationseinheiten im <strong>ISMS-Geltungsbereich</strong>.</p>\n</li>\n</ul>\n<hr/>\n<h2>3. Begriffsdefinitionen</h2>\n<h3>3.1 Dokumente</h3>\n<p>Dokumente sind <strong>lenkende Informationen</strong>, die Vorgaben enthalten, z. B.:</p>\n<ul>\n<li>\n<p>Richtlinien</p>\n</li>\n<li>\n<p>Prozesse</p>\n</li>\n<li>\n<p>Verfahrensanweisungen</p>\n</li>\n<li>\n<p>Konzepte</p>\n</li>\n<li>\n<p>Arbeitsanweisungen</p>\n</li>\n</ul>\n<h3>3.2 Aufzeichnungen</h3>\n<p>Aufzeichnungen sind <strong>Nachweise</strong>, dass Tätigkeiten durchgeführt wurden, z. B.:</p>\n<ul>\n<li>\n<p>Auditberichte</p>\n</li>\n<li>\n<p>Risikoanalysen</p>\n</li>\n<li>\n<p>Protokolle</p>\n</li>\n<li>\n<p>Management-Review-Ergebnisse</p>\n</li>\n<li>\n<p>Schulungsnachweise</p>\n</li>\n</ul>\n<hr/>\n<h2>4. Normative Grundlagen</h2>\n<ul>\n<li>\n<p>ISO/IEC 27001:2022 – Kapitel 7.5 (Documented Information)</p>\n</li>\n<li>\n<p>ISO/IEC 27001:2022 – Kapitel 9 &amp; 10</p>\n</li>\n<li>\n<p>NIS-2-Richtlinie (EU) 2022/2555</p>\n</li>\n<li>\n<p>Interne ISMS-Richtlinien</p>\n</li>\n</ul>\n<hr/>\n<h2>5. Verantwortlichkeiten</h2>\n<h3>5.1 Oberste Leitung</h3>\n<ul>\n<li>\n<p>Genehmigt ISMS-Richtlinien</p>\n</li>\n<li>\n<p>Stellt Ressourcen zur Verfügung</p>\n</li>\n<li>\n<p>Trägt die Gesamtverantwortung</p>\n</li>\n</ul>\n<h3>5.2 Informationssicherheitsbeauftragter (ISB / CISO)</h3>\n<ul>\n<li>\n<p>Definiert Anforderungen an die Dokumentenlenkung</p>\n</li>\n<li>\n<p>Überwacht die Einhaltung dieser Richtlinie</p>\n</li>\n<li>\n<p>Koordiniert Reviews und Freigaben</p>\n</li>\n<li>\n<p>Stellt Audit-Nachweise bereit</p>\n</li>\n</ul>\n<h3>5.3 Dokumentenverantwortliche</h3>\n<ul>\n<li>\n<p>Erstellen und pflegen Dokumente</p>\n</li>\n<li>\n<p>Veranlassen Reviews und Änderungen</p>\n</li>\n<li>\n<p>Stellen Aktualität sicher</p>\n</li>\n</ul>\n<hr/>\n<h2>6. Erstellung und Struktur von Dokumenten</h2>\n<p>ISMS-Dokumente müssen mindestens enthalten:</p>\n<ul>\n<li>\n<p>Titel des Dokuments</p>\n</li>\n<li>\n<p>Dokumententyp (Richtlinie, Prozess, etc.)</p>\n</li>\n<li>\n<p>Versionsnummer</p>\n</li>\n<li>\n<p>Erstellungs- und Freigabedatum</p>\n</li>\n<li>\n<p>Verantwortliche Rolle</p>\n</li>\n<li>\n<p>Geltungsbereich</p>\n</li>\n</ul>\n<p>Empfohlen ist die Verwendung <strong>einheitlicher Vorlagen</strong>.</p>\n<hr/>\n<h2>7. Prüfung und Freigabe</h2>\n<ul>\n<li>\n<p>Jedes ISMS-Dokument ist vor Veröffentlichung:</p>\n<ul>\n<li>\n<p>fachlich zu prüfen,</p>\n</li>\n<li>\n<p>formell freizugeben.</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Die Freigabe erfolgt durch:</p>\n<ul>\n<li>\n<p>den ISB oder</p>\n</li>\n<li>\n<p>die zuständige Führungskraft oder</p>\n</li>\n<li>\n<p>die oberste Leitung (bei Richtlinien).</p>\n</li>\n</ul>\n</li>\n</ul>\n<p>Nicht freigegebene Dokumente dürfen <strong>nicht produktiv verwendet</strong> werden.</p>\n<hr/>\n<h2>8. Versionierung und Änderungsmanagement</h2>\n<ul>\n<li>\n<p>Jede Änderung an einem Dokument führt zu:</p>\n<ul>\n<li>\n<p>einer neuen Versionsnummer,</p>\n</li>\n<li>\n<p>einer nachvollziehbaren Änderungsdokumentation.</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Frühere Versionen sind:</p>\n<ul>\n<li>\n<p>eindeutig als <strong>ungültig</strong> zu kennzeichnen,</p>\n</li>\n<li>\n<p>vor unbeabsichtigter Nutzung zu schützen,</p>\n</li>\n<li>\n<p>revisionssicher aufzubewahren (falls erforderlich).</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2>9. Verteilung und Zugriff</h2>\n<ul>\n<li>\n<p>Dokumente sind nur berechtigten Personen zugänglich zu machen.</p>\n</li>\n<li>\n<p>Zugriffe richten sich nach:</p>\n<ul>\n<li>\n<p>Rolle,</p>\n</li>\n<li>\n<p>Informationsklassifikation,</p>\n</li>\n<li>\n<p>Need-to-know-Prinzip.</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Veraltete oder ungültige Dokumente müssen:</p>\n<ul>\n<li>\n<p>aus produktiven Ablagen entfernt,</p>\n</li>\n<li>\n<p>klar gekennzeichnet werden.</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2>10. Schutz von Dokumenten und Aufzeichnungen</h2>\n<p>Dokumente und Aufzeichnungen sind zu schützen vor:</p>\n<ul>\n<li>\n<p>unbefugtem Zugriff,</p>\n</li>\n<li>\n<p>Verlust,</p>\n</li>\n<li>\n<p>Manipulation,</p>\n</li>\n<li>\n<p>unbeabsichtigter Löschung.</p>\n</li>\n</ul>\n<p>Schutzmaßnahmen umfassen u. a.:</p>\n<ul>\n<li>\n<p>Zugriffsbeschränkungen,</p>\n</li>\n<li>\n<p>Backup-Mechanismen,</p>\n</li>\n<li>\n<p>Integritätsschutz,</p>\n</li>\n<li>\n<p>geeignete Archivierung.</p>\n</li>\n</ul>\n<hr/>\n<h2>11. Aufbewahrung und Löschung</h2>\n<ul>\n<li>\n<p>Aufbewahrungsfristen richten sich nach:</p>\n<ul>\n<li>\n<p>gesetzlichen Anforderungen,</p>\n</li>\n<li>\n<p>regulatorischen Vorgaben,</p>\n</li>\n<li>\n<p>internen Regelungen.</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Nach Ablauf der Frist erfolgt:</p>\n<ul>\n<li>\n<p>sichere Löschung oder</p>\n</li>\n<li>\n<p>datenschutzkonforme Vernichtung.</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Löschungen sind nachvollziehbar zu dokumentieren.</p>\n</li>\n</ul>\n<hr/>\n<h2>12. Umgang mit externen Dokumenten</h2>\n<p>Externe Dokumente (z. B. Normen, Gesetze, Herstellerinformationen):</p>\n<ul>\n<li>\n<p>sind zu identifizieren,</p>\n</li>\n<li>\n<p>aktuell zu halten,</p>\n</li>\n<li>\n<p>hinsichtlich Relevanz zu bewerten,</p>\n</li>\n<li>\n<p>kontrolliert bereitzustellen.</p>\n</li>\n</ul>\n<hr/>\n<h2>13. Überwachung und Wirksamkeitskontrolle</h2>\n<p>Die Einhaltung dieser Richtlinie wird überwacht durch:</p>\n<ul>\n<li>\n<p>interne Audits,</p>\n</li>\n<li>\n<p>Management-Reviews,</p>\n</li>\n<li>\n<p>Stichprobenkontrollen.</p>\n</li>\n</ul>\n<p>Festgestellte Abweichungen werden gemäß dem <strong>Maßnahmen- und Verbesserungsprozess</strong> behandelt.</p>\n<hr/>\n<h2>14. Vertraulichkeit</h2>\n<p>Alle Dokumente und Aufzeichnungen unterliegen der jeweils festgelegten <strong>Informationsklassifizierung</strong> und sind entsprechend zu behandeln.</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-07-07', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 1, '1', NULL, NULL, 0, 0, '');
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(27, 'DOK-0021', 'ISMS Kontext & Scope', 'Governance', '1', 0, 'intern', '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Diese Richtlinie beschreibt die methodische Vorgehensweise zur: </p>\n<ul>\n<li>\n<p>Ermittlung des <strong>Kontextes der Organisation</strong> im Hinblick auf Informationssicherheit,</p>\n</li>\n<li>\n<p>Identifikation <strong>interessierter Parteien und ihrer Anforderungen</strong>,</p>\n</li>\n<li>\n<p>Festlegung und Kommunikation des <strong>Geltungsbereichs des ISMS</strong>.</p>\n</li>\n</ul>\n<p>Die konsequente Bestimmung des Kontextes ist notwendig, um sicherzustellen, dass das ISMS auf die tatsächlichen <strong>Risiken, Anforderungen und Rahmenbedingungen der Organisation</strong> abgestimmt ist.</p>\n<hr/>\n<h2><strong>2. Geltungsbereich dieser Richtlinie</strong></h2>\n<p>Diese Richtlinie gilt für alle Personen und Bereiche, die für die <strong>Planung, Einführung, Steuerung und Weiterentwicklung des ISMS</strong> verantwortlich sind.</p>\n<hr/>\n<h2><strong>3. Kontext der Organisation</strong></h2>\n<p>Gemäß ISO/IEC 27001:2022 Kapitel 4.1 ist der <strong>Kontext der Organisation</strong> wie folgt zu erfassen:</p>\n<h3>3.1 Interne Einflussfaktoren</h3>\n<p>Beispiele:</p>\n<ul>\n<li>\n<p>Organisatorische Struktur und Unternehmensstrategie</p>\n</li>\n<li>\n<p>Art und Umfang von Geschäftsprozessen und IT-Dienstleistungen</p>\n</li>\n<li>\n<p>Sicherheitskultur, Know-how und personelle Ressourcen</p>\n</li>\n<li>\n<p>Bestehende Managementsysteme (z. B. QM, BCM, Datenschutz)</p>\n</li>\n</ul>\n<h3>3.2 Externe Einflussfaktoren</h3>\n<p>Beispiele:</p>\n<ul>\n<li>\n<p>Gesetzliche, regulatorische und vertragliche Anforderungen (z. B. DSGVO, NIS-2, KRITIS-V)</p>\n</li>\n<li>\n<p>Branchenspezifische Standards (z. B. TISAX, BAIT, VAIT)</p>\n</li>\n<li>\n<p>Kundenanforderungen an Informationssicherheit</p>\n</li>\n<li>\n<p>Technologische Entwicklungen und Bedrohungslage (z. B. Cloud, KI, Ransomware)</p>\n</li>\n</ul>\n<p>Diese Faktoren werden jährlich oder bei wesentlichen Änderungen im Rahmen einer <strong>Kontextanalyse</strong> dokumentiert.</p>\n<hr/>\n<h2><strong>4. Interessierte Parteien (Stakeholder)</strong></h2>\n<p>Gemäß ISO 27001 Kapitel 4.2 sind relevante <strong>interessierte Parteien und ihre Anforderungen</strong> zu identifizieren.</p>\n<p>Beispiele:</p>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Partei</th>\n<th>Erwartung / Anforderung</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Geschäftsführung</td>\n<td>Sicherer Geschäftsbetrieb, Risikominimierung, Compliance</td>\n</tr>\n<tr>\n<td>Kunden / Auftraggeber</td>\n<td>Datenschutz, sichere Verarbeitung ihrer Daten</td>\n</tr>\n<tr>\n<td>Aufsichtsbehörden</td>\n<td>Einhaltung gesetzlicher Vorschriften (z. B. DSGVO, NIS-2)</td>\n</tr>\n<tr>\n<td>Lieferanten / Dienstleister</td>\n<td>Klare Sicherheitsanforderungen, vertragliche Vorgaben</td>\n</tr>\n<tr>\n<td>IT-Abteilung</td>\n<td>Klarheit über Verantwortlichkeiten und Prozesse</td>\n</tr>\n<tr>\n<td>Mitarbeitende</td>\n<td>Schulung, einfache Sicherheitsvorgaben, Schutz vor Cyberrisiken</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p>Die Anforderungen der interessierten Parteien werden in das ISMS aufgenommen und regelmäßig (mind. jährlich) überprüft.</p>\n<hr/>\n<h2><strong>5. Festlegung des ISMS-Geltungsbereichs (Scope)</strong></h2>\n<h3>5.1 Definition</h3>\n<p>Der <strong>Geltungsbereich des ISMS</strong> beschreibt:</p>\n<ul>\n<li>\n<p><strong>Was ist abgedeckt?</strong> (z. B. Geschäftsprozesse, IT-Systeme, Standorte)</p>\n</li>\n<li>\n<p><strong>Was ist ausgeschlossen?</strong> (und warum)</p>\n</li>\n<li>\n<p><strong>Warum gilt der Scope genau so?</strong> (z. B. Risiko- oder Strukturgründe)</p>\n</li>\n</ul>\n<h3>5.2 Vorgehen zur Festlegung</h3>\n<ol>\n<li>\n<p>Analyse der Geschäftsprozesse und unterstützenden IT-Strukturen</p>\n</li>\n<li>\n<p>Berücksichtigung relevanter Standorte und Niederlassungen</p>\n</li>\n<li>\n<p>Abgleich mit Anforderungen der Stakeholder</p>\n</li>\n<li>\n<p>Entscheidung durch ISMS-Leitung in Abstimmung mit der Geschäftsführung</p>\n</li>\n<li>\n<p>Dokumentation in der ISMS-Scope-Beschreibung</p>\n</li>\n</ol>\n<h3>5.3 Beispiel für einen Scope (ausformuliert)</h3>\n<blockquote>\n<p><em>„Das ISMS der [Organisation] umfasst alle IT-gestützten Geschäftsprozesse und unterstützenden IT-Systeme an den Standorten [Ort A, Ort B] sowie die in der Cloud betriebenen Services (Microsoft 365, Azure). Ausgenommen sind rein private Endgeräte sowie personenbezogene Verarbeitungsvorgänge außerhalb des Unternehmensnetzwerks.“</em></p>\n</blockquote>\n<hr/>\n<h2><strong>6. Dokumentation</strong></h2>\n<p>Folgende Dokumente sind im Zusammenhang mit dieser Richtlinie zu führen:</p>\n<ul>\n<li>\n<p>Kontextanalyse (inkl. Risiko- und Chancenübersicht)</p>\n</li>\n<li>\n<p>Liste der interessierten Parteien mit Anforderungen</p>\n</li>\n<li>\n<p>Scope-Dokumentation (als eigenständiges Dokument oder im ISMS-Handbuch)</p>\n</li>\n<li>\n<p>Änderungs- und Reviewprotokolle</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>7. Überprüfung und Änderungen</strong></h2>\n<ul>\n<li>\n<p>Die Kontextanalyse und der Scope sind <strong>mindestens einmal jährlich</strong> oder bei:</p>\n<ul>\n<li>\n<p>Organisatorischen Änderungen (Fusionen, Umstrukturierungen)</p>\n</li>\n<li>\n<p>Technologischen Veränderungen (z. B. Einführung neuer Cloudsysteme)</p>\n</li>\n<li>\n<p>Gesetzlichen Änderungen</p>\n</li>\n<li>\n<p>Auftreten neuer Risiken<br/>zu überprüfen und ggf. anzupassen.</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Zuständig für die Überprüfung: <strong>ISB / ISMS-Team</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Verantwortlichkeiten</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISMS-Leitung / ISB</strong></td>\n<td>Durchführung der Kontext- und Scope-Analyse, Pflege der Dokumentation</td>\n</tr>\n<tr>\n<td><strong>Geschäftsführung</strong></td>\n<td>Freigabe des Scopes und strategische Entscheidung</td>\n</tr>\n<tr>\n<td><strong>Fachbereiche</strong></td>\n<td>Lieferung von Informationen zu Risiken und Abhängigkeiten</td>\n</tr>\n<tr>\n<td><strong>Datenschutz / BCM</strong></td>\n<td>Abgleich mit Datenschutz- und Notfallmanagement-Anforderungen</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>9. Schnittstellen zu anderen Richtlinien</strong></h2>\n<p>Diese Richtlinie steht in enger Verbindung zu:</p>\n<ul>\n<li>\n<p><strong>Informationssicherheitsrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>Risikomanagement-Richtlinie</strong></p>\n</li>\n<li>\n<p><strong>BCM-Strategie / Notfallrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>Datenschutzrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>Lieferantenmanagement</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Bezug zu Normen und Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Abschnitt / Bezug</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001:2022</strong></td>\n<td>Kapitel 4.1 – Kontext der Organisation<br/>Kapitel 4.2 – Erfordernisse interessierter Parteien<br/>Kapitel 4.3 – Festlegung des Geltungsbereichs</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>ORP.1.1 – Sicherheitsleitlinie<br/>ORP.4.1 – ISMS initiieren und betreiben</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-03-06', 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 1, '1', NULL, NULL, 0, 0, NULL),
(28, 'DOK-0022', 'Rollen, Verantwortlichkeiten & Befugnisse', 'Governance', '1', 0, NULL, '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Ziel dieser Richtlinie ist die klare Definition von <strong>Rollen, Zuständigkeiten und Befugnissen</strong> im Zusammenhang mit dem <strong>Informationssicherheits-Managementsystem (ISMS)</strong>. Dies ist erforderlich, um:</p>\n<ul>\n<li>\n<p><strong>Verantwortlichkeiten transparent zu machen</strong>,</p>\n</li>\n<li>\n<p><strong>sicherheitsrelevante Aufgaben nachvollziehbar zu steuern</strong>,</p>\n</li>\n<li>\n<p>die <strong>Wirksamkeit des ISMS sicherzustellen</strong>,</p>\n</li>\n<li>\n<p>Anforderungen aus ISO 27001 und BSI IT-Grundschutz zu erfüllen.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Diese Richtlinie gilt für:</p>\n<ul>\n<li>\n<p>Alle organisatorischen Einheiten, die <strong>direkt oder indirekt mit Informationssicherheit</strong> befasst sind</p>\n</li>\n<li>\n<p>Die Rollen innerhalb des <strong>ISMS, der IT-Abteilungen, der Geschäftsführung, der Fachbereiche</strong> sowie externer Partner mit sicherheitsrelevanten Aufgaben</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Grundsätze</strong></h2>\n<ul>\n<li>\n<p>Alle sicherheitsrelevanten Rollen und Aufgaben müssen <strong>benannt, dokumentiert und kommuniziert</strong> werden</p>\n</li>\n<li>\n<p><strong>Doppelzuständigkeiten und Interessenskonflikte</strong> sind möglichst zu vermeiden</p>\n</li>\n<li>\n<p><strong>Vertretungsregelungen</strong> sind sicherzustellen</p>\n</li>\n<li>\n<p>Befugnisse müssen den Aufgaben und Risiken <strong>angemessen</strong> sein</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>4. Rollen im ISMS – Übersicht</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th><strong>Rolle</strong></th>\n<th><strong>Verantwortlichkeiten</strong></th>\n<th><strong>Befugnisse</strong></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Geschäftsführung</strong></td>\n<td>- Festlegung der ISMS-Ziele<br/>- Bereitstellung von Ressourcen<br/>- Freigabe von Richtlinien</td>\n<td>- Weisungsbefugnis gegenüber allen Rollen</td>\n</tr>\n<tr>\n<td><strong>Informationssicherheitsbeauftragte*r (ISB)</strong></td>\n<td>- ISMS-Betrieb und -Weiterentwicklung<br/>- Beratung der Fachbereiche<br/>- Risikomanagement koordinieren<br/>- Audits begleiten</td>\n<td>- Zugang zu allen sicherheitsrelevanten Informationen<br/>- Vorschlagsrecht bei Maßnahmen</td>\n</tr>\n<tr>\n<td><strong>IT-Leitung / IT-Betrieb</strong></td>\n<td>- Sicherer Betrieb von IT-Systemen<br/>- Umsetzung technischer Maßnahmen<br/>- Umsetzung Patching / Logging</td>\n<td>- Konfigurations- und Änderungsbefugnis an Systemen</td>\n</tr>\n<tr>\n<td><strong>Fachbereichsverantwortliche</strong></td>\n<td>- Umsetzung sicherer Prozesse im Tagesgeschäft<br/>- Bewertung von Schutzbedarf<br/>- Meldung von Sicherheitsvorfällen</td>\n<td>- Weisungsbefugnis im eigenen Bereich</td>\n</tr>\n<tr>\n<td><strong>Datenschutzbeauftragte*r (DSB)</strong></td>\n<td>- Überwachung datenschutzrechtlicher Vorgaben<br/>- Beratung zu TOMs<br/>- Prüfung bei AV-Verträgen</td>\n<td>- Unabhängige Prüf- und Beraterfunktion</td>\n</tr>\n<tr>\n<td><strong>IT-Sicherheitskoordinator*in</strong></td>\n<td>- Unterstützung des ISB<br/>- Koordination von Maßnahmen und Projekten<br/>- Schnittstelle zu Technik</td>\n<td>- Zugriff auf sicherheitsrelevante Informationen</td>\n</tr>\n<tr>\n<td><strong>Asset Owner / Systemverantwortliche</strong></td>\n<td>- Klassifizierung von Informationen<br/>- Definition von Zugriffsrechten<br/>- Beteiligung an Risikoanalysen</td>\n<td>- Verwaltung der Systeme/Anwendungen</td>\n</tr>\n<tr>\n<td><strong>Security Incident Manager</strong></td>\n<td>- Bearbeitung von Sicherheitsvorfällen<br/>- Eskalation und Dokumentation<br/>- Lessons Learned</td>\n<td>- Zugriff auf Logs und Benutzerinformationen</td>\n</tr>\n<tr>\n<td><strong>Mitarbeitende</strong></td>\n<td>- Einhaltung der Sicherheitsrichtlinien<br/>- Meldepflicht bei Auffälligkeiten<br/>- Teilnahme an Schulungen</td>\n<td>- Nutzung der Systeme gemäß Rollenprofil</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>5. Rollenübergreifende Querschnittsaufgaben</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Aufgabe</th>\n<th>Verantwortlich</th>\n<th>Unterstützend</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Schutzbedarfsfeststellung</td>\n<td>Fachbereich, ISB</td>\n<td>IT, Datenschutz</td>\n</tr>\n<tr>\n<td>Risikobewertung</td>\n<td>ISB, Asset Owner</td>\n<td>IT, Fachbereich</td>\n</tr>\n<tr>\n<td>Richtlinienmanagement</td>\n<td>ISB</td>\n<td>Qualitätsmanagement, IT</td>\n</tr>\n<tr>\n<td>Notfallvorsorge (BCM/DR)</td>\n<td>BCM-Team, IT</td>\n<td>Fachbereiche, ISB</td>\n</tr>\n<tr>\n<td>Awareness / Schulungen</td>\n<td>ISB, HR</td>\n<td>Fachbereichsleitung</td>\n</tr>\n<tr>\n<td>Überprüfung der Sicherheitsmaßnahmen</td>\n<td>ISB, IT</td>\n<td>interne Revision, ggf. Dritte</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>6. Dokumentation der Rollen</strong></h2>\n<ul>\n<li>\n<p>Alle Rollen, Aufgaben und Befugnisse werden dokumentiert im:</p>\n<ul>\n<li>\n<p><strong>ISMS-Rollen- und Verantwortlichkeitsverzeichnis</strong></p>\n</li>\n<li>\n<p><strong>Organigramm ISMS / Informationssicherheit</strong></p>\n</li>\n<li>\n<p><strong>Stellenbeschreibungen und Prozessdokumentationen</strong></p>\n</li>\n</ul>\n</li>\n<li>\n<p>Änderungen an Rollen und Zuständigkeiten werden versioniert dokumentiert und im ISMS-Tool gepflegt.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>7. Vertretungsregelungen</strong></h2>\n<ul>\n<li>\n<p>Für jede kritische Rolle (z. B. ISB, IT-Leitung, Incident Manager) ist eine <strong>vertretungsberechtigte Person namentlich festzulegen</strong></p>\n</li>\n<li>\n<p>Vertretende Personen müssen ausreichend <strong>eingearbeitet und autorisiert</strong> sein</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Schulung &amp; Befähigung</strong></h2>\n<ul>\n<li>\n<p>Alle Personen mit sicherheitsrelevanten Aufgaben müssen <strong>regelmäßig geschult</strong> werden (mind. jährlich oder bei Rollenübernahme)</p>\n</li>\n<li>\n<p>Schulungsinhalte umfassen:</p>\n<ul>\n<li>\n<p>Grundlagen der Informationssicherheit</p>\n</li>\n<li>\n<p>Aufgaben und Pflichten der jeweiligen Rolle</p>\n</li>\n<li>\n<p>Umgang mit Sicherheitsvorfällen</p>\n</li>\n<li>\n<p>Rechts- und Normenwissen (z. B. ISO 27001, DSGVO)</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Überprüfung &amp; Pflege</strong></h2>\n<ul>\n<li>\n<p>Die Rollen- und Verantwortlichkeitszuordnung wird mindestens <strong>einmal jährlich</strong> im Rahmen der <strong>ISMS-Reviews</strong> überprüft</p>\n</li>\n<li>\n<p>Anlässe für unterjährige Prüfung:</p>\n<ul>\n<li>\n<p>Reorganisation</p>\n</li>\n<li>\n<p>Outsourcing / neue Dienstleister</p>\n</li>\n<li>\n<p>Neue gesetzliche Anforderungen</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Schnittstellen zu weiteren Richtlinien</strong></h2>\n<p>Diese Richtlinie ergänzt insbesondere:</p>\n<ul>\n<li>\n<p><strong>ISMS-Kontext &amp; Scope</strong></p>\n</li>\n<li>\n<p><strong>Informationssicherheitsrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>Security Incident Management</strong></p>\n</li>\n<li>\n<p><strong>Awareness- und Schulungskonzept</strong></p>\n</li>\n<li>\n<p><strong>Change Management</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>11. Bezug zu Normen &amp; Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Abschnitt / Bezug</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001:2022</strong></td>\n<td>Kapitel 5.3 – Rollen, Verantwortlichkeiten und Befugnisse</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>ORP.3 – Informationssicherheitsorganisation<br/>ORP.4.1 – ISMS initiieren und betreiben</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '1', NULL, NULL, 0, 0, NULL),
(29, 'DOK-0023', 'Informationssicherheitsziele & Planung', 'Governance', '1', 0, NULL, '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Diese Richtlinie beschreibt, wie Informationssicherheitsziele:</p>\n<ul>\n<li>\n<p>abgeleitet,</p>\n</li>\n<li>\n<p>dokumentiert,</p>\n</li>\n<li>\n<p>regelmäßig überprüft,</p>\n</li>\n<li>\n<p>und mit konkreten Maßnahmen geplant und umgesetzt werden.</p>\n</li>\n</ul>\n<p>Sie gewährleistet die Umsetzung von <strong>Kapitel 6.2 ISO 27001:2022</strong> und schafft die Basis für <strong>kontinuierliche Verbesserung</strong> der Informationssicherheit.</p>\n<hr/>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Diese Richtlinie gilt für:</p>\n<ul>\n<li>\n<p>die <strong>gesamte Organisation</strong> im Geltungsbereich des ISMS</p>\n</li>\n<li>\n<p>alle Bereiche, in denen <strong>sicherheitsrelevante Prozesse</strong> durchgeführt werden</p>\n</li>\n<li>\n<p>die <strong>ISMS-Verantwortlichen</strong>, die Sicherheitsziele definieren, verfolgen und bewerten</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Grundsätze</strong></h2>\n<ul>\n<li>\n<p>Informationssicherheitsziele müssen <strong>konkret, messbar, erreichbar, relevant und terminiert</strong> sein (SMART-Prinzip)</p>\n</li>\n<li>\n<p>Ziele müssen im Einklang stehen mit:</p>\n<ul>\n<li>\n<p>der <strong>Informationssicherheitsleitlinie</strong></p>\n</li>\n<li>\n<p>den Ergebnissen der <strong>Risikoanalyse</strong></p>\n</li>\n<li>\n<p>den <strong>gesetzlichen Anforderungen</strong> (z. B. DSGVO, NIS-2)</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Ziele werden regelmäßig auf <strong>Wirksamkeit und Fortschritt</strong> überprüft</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>4. Zielableitung und Festlegung</strong></h2>\n<h3>4.1 Herkunft möglicher Zielsetzungen</h3>\n<p>Informationssicherheitsziele können abgeleitet werden aus:</p>\n<ul>\n<li>\n<p>Anforderungen der <strong>interessierten Parteien</strong> (Kunden, Behörden, Partner)</p>\n</li>\n<li>\n<p>Erkenntnissen aus <strong>Risikoanalysen</strong></p>\n</li>\n<li>\n<p><strong>Auditfeststellungen</strong>, internen Kontrollen oder Vorfällen</p>\n</li>\n<li>\n<p>Strategischen Vorgaben der Geschäftsführung</p>\n</li>\n<li>\n<p>Vorgaben aus Normen oder gesetzlichen Rahmenwerken</p>\n</li>\n</ul>\n<h3>4.2 Beispiele für IS-Ziele</h3>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Ziel</th>\n<th>Kennzahl (KPI)</th>\n<th>Zielwert</th>\n<th>Zeitraum</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Alle Mitarbeiter absolvieren Awareness-Training</td>\n<td>Schulungsquote</td>\n<td>≥ 98 %</td>\n<td>jährlich</td>\n</tr>\n<tr>\n<td>Reaktionszeit auf Incidents verkürzen</td>\n<td>Ø Incident-Bearbeitungszeit</td>\n<td>≤ 24 h</td>\n<td>Q1–Q4</td>\n</tr>\n<tr>\n<td>Erhöhung Patch-Compliance kritischer Systeme</td>\n<td>Patchrate (kritisch, ≤ 10 Tage)</td>\n<td>≥ 95 %</td>\n<td>Q1–Q4</td>\n</tr>\n<tr>\n<td>Durchführung Penetrationstest der Webanwendung</td>\n<td>Testbericht</td>\n<td>1x durchgeführt</td>\n<td>bis Q3</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>5. Planung zur Zielerreichung</strong></h2>\n<p>Für jedes Ziel sind laut ISO 27001:2022 folgende Elemente zu dokumentieren:</p>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Punkt</th>\n<th>Beschreibung</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Was</strong></td>\n<td>Beschreibung des Ziels</td>\n</tr>\n<tr>\n<td><strong>Wer</strong></td>\n<td>Verantwortliche Person / Rolle</td>\n</tr>\n<tr>\n<td><strong>Wie</strong></td>\n<td>Maßnahmen zur Umsetzung</td>\n</tr>\n<tr>\n<td><strong>Ressourcen</strong></td>\n<td>Zeit, Budget, Tools, Personal</td>\n</tr>\n<tr>\n<td><strong>Zeitplan</strong></td>\n<td>Start- und Endtermin</td>\n</tr>\n<tr>\n<td><strong>Bewertung</strong></td>\n<td>Methode zur Erfolgskontrolle (z. B. KPI, Review)</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p>Diese Informationen werden zentral im <strong>Ziele- und Maßnahmenplan des ISMS</strong> dokumentiert und regelmäßig gepflegt.</p>\n<hr/>\n<h2><strong>6. Umsetzung und Steuerung</strong></h2>\n<ul>\n<li>\n<p>Die Umsetzung der Ziele wird durch das <strong>ISMS-Team</strong> koordiniert</p>\n</li>\n<li>\n<p>Maßnahmen werden im <strong>ISMS-Maßnahmenplan</strong> (z. B. Excel, ISMS-Tool) festgehalten</p>\n</li>\n<li>\n<p>Fortschritte werden in ISMS-Meetings / Reviews verfolgt (mind. quartalsweise)</p>\n</li>\n<li>\n<p><strong>Abweichungen vom Plan</strong> werden dokumentiert und bewertet</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>7. Überprüfung und Bewertung</strong></h2>\n<ul>\n<li>\n<p>Die Wirksamkeit der Ziele wird regelmäßig bewertet, z. B. durch:</p>\n<ul>\n<li>\n<p><strong>Kennzahlen-Auswertung (KPIs)</strong></p>\n</li>\n<li>\n<p><strong>interne Audits / Managementbewertungen</strong></p>\n</li>\n<li>\n<p><strong>Lessons Learned aus Sicherheitsvorfällen</strong></p>\n</li>\n</ul>\n</li>\n<li>\n<p>Nicht erreichte Ziele führen zur <strong>Anpassung von Maßnahmen, Fristen oder Ressourcen</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Verantwortung</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISMS-Leitung / ISB</strong></td>\n<td>Definition, Koordination, Pflege und Reporting der Ziele</td>\n</tr>\n<tr>\n<td><strong>Fachbereiche</strong></td>\n<td>Umsetzung und Rückmeldung zum Status</td>\n</tr>\n<tr>\n<td><strong>Geschäftsführung</strong></td>\n<td>Freigabe der Ziele, strategische Steuerung</td>\n</tr>\n<tr>\n<td><strong>Revision / Audit</strong></td>\n<td>Überprüfung der Zielerreichung im Rahmen von Audits</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>9. Schnittstellen zu anderen Richtlinien</strong></h2>\n<p>Diese Richtlinie steht im Zusammenhang mit:</p>\n<ul>\n<li>\n<p><strong>Informationssicherheitsleitlinie</strong></p>\n</li>\n<li>\n<p><strong>ISMS-Kontext &amp; Scope</strong></p>\n</li>\n<li>\n<p><strong>Risikomanagement</strong></p>\n</li>\n<li>\n<p><strong>Audit- und Managementbewertungsprozess</strong></p>\n</li>\n<li>\n<p><strong>Awareness- / Schulungsrichtlinie</strong></p>\n</li>\n<li>\n<p><strong>BCM- und Incident-Richtlinie</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Bezug zu Normen und Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Abschnitt / Bezug</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001:2022</strong></td>\n<td>Kapitel 6.2 – Informationssicherheitsziele und Planung zu deren Erreichung</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>ORP.4.1 – ISMS initiieren und betreiben<br/>ORP.3 – Aufgaben in der Informationssicherheit</td>\n</tr>\n<tr>\n<td><strong>NIS-2 / DSGVO</strong></td>\n<td>Risikobasierte Zielsetzungen im Rahmen gesetzlicher Anforderungen</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '1', NULL, NULL, 0, 0, NULL),
(30, 'DOK-0024', 'Risikomanagement & Methodik', 'Governance', '1', 0, NULL, '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Diese Richtlinie beschreibt den Aufbau und Ablauf eines <strong>strukturierten, dokumentierten und kontinuierlichen Risikomanagementprozesses</strong>, mit dem Ziel:</p>\n<ul>\n<li>\n<p><strong>Informationssicherheitsrisiken zu identifizieren</strong>, zu bewerten und angemessen zu behandeln</p>\n</li>\n<li>\n<p>eine objektive Entscheidungsbasis für Maßnahmen zu schaffen</p>\n</li>\n<li>\n<p>die Anforderungen aus <strong>ISO 27001:2022</strong> und <strong>BSI IT-Grundschutz</strong> zu erfüllen</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Diese Richtlinie gilt für alle <strong>Informationswerte (Assets)</strong> im <strong>Scope des ISMS</strong>, insbesondere:</p>\n<ul>\n<li>\n<p>IT-Systeme, Netzwerke, Applikationen</p>\n</li>\n<li>\n<p>Geschäftsprozesse und Dienstleistungen</p>\n</li>\n<li>\n<p>Informationen (digital, papierbasiert, mündlich)</p>\n</li>\n<li>\n<p>Dienstleister und externe Abhängigkeiten</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Grundsätze des Risikomanagements</strong></h2>\n<ul>\n<li>\n<p>Risikomanagement erfolgt <strong>risikobasiert, nachvollziehbar und dokumentiert</strong></p>\n</li>\n<li>\n<p>Die Methode wird <strong>einheitlich</strong> im Unternehmen angewendet</p>\n</li>\n<li>\n<p><strong>Risikoakzeptanzkriterien</strong> sind definiert</p>\n</li>\n<li>\n<p>Risikomanagement ist <strong>ein kontinuierlicher Prozess</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>4. Risikomanagementprozess nach ISO 27001</strong></h2>\n<p>Gemäß ISO/IEC 27001:2022 Kapitel 6.1:</p>\n<ol>\n<li>\n<p><strong>Risiken identifizieren</strong></p>\n</li>\n<li>\n<p><strong>Risiken analysieren und bewerten</strong></p>\n</li>\n<li>\n<p><strong>Behandlungsoptionen auswählen (Risk Treatment)</strong></p>\n</li>\n<li>\n<p><strong>Maßnahmen festlegen und umsetzen</strong></p>\n</li>\n<li>\n<p><strong>Risiken akzeptieren oder weiterverfolgen</strong></p>\n</li>\n<li>\n<p><strong>Risiken regelmäßig überwachen</strong></p>\n</li>\n</ol>\n<hr/>\n<h2><strong>5. Verwendete Risikomethodik</strong></h2>\n<h3>5.1 Methodische Grundlage</h3>\n<p>Die Organisation nutzt wahlweise eine der folgenden <strong>anwendbaren Methoden</strong>:</p>\n<ul>\n<li>\n<p><strong>ISO 27005</strong>-basierte Risikobewertung mit eigenen Kriterien</p>\n</li>\n<li>\n<p><strong>BSI IT-Grundschutz Risikoanalyse</strong> (nach ISMS.2), speziell für:</p>\n<ul>\n<li>\n<p>Schutzbedarf „hoch“ oder „sehr hoch“</p>\n</li>\n<li>\n<p>Abweichungen von Modellierungsvorgaben</p>\n</li>\n</ul>\n</li>\n<li>\n<p><strong>Qualitative Risikobewertung</strong> mit definierten Bewertungsrastern</p>\n</li>\n</ul>\n<blockquote>\n<p>👉 Die Methode wird <strong>im ISMS dokumentiert und jährlich überprüft.</strong></p>\n</blockquote>\n<h3>5.2 Risikomatrix (Beispiel)</h3>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Risikoausprägung</th>\n<th>Wahrscheinlichkeit</th>\n<th>Schaden</th>\n<th>Risikowert</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Kritisch</td>\n<td>hoch</td>\n<td>hoch</td>\n<td>sehr hoch</td>\n</tr>\n<tr>\n<td>Ernst</td>\n<td>mittel</td>\n<td>mittel</td>\n<td>mittel</td>\n</tr>\n<tr>\n<td>Akzeptabel</td>\n<td>gering</td>\n<td>gering</td>\n<td>niedrig</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<blockquote>\n<p>Skalen können an die Unternehmensrealität angepasst werden (z. B. 1–5, Farbcodierung, RAG-Matrix)</p>\n</blockquote>\n<hr/>\n<h2><strong>6. Risikoidentifikation</strong></h2>\n<ul>\n<li>\n<p>Quellen für Risiken:</p>\n<ul>\n<li>\n<p>Schutzbedarfsfeststellung</p>\n</li>\n<li>\n<p>Technische Schwachstellen / Audits</p>\n</li>\n<li>\n<p>Lieferanten- oder Standortabhängigkeiten</p>\n</li>\n<li>\n<p>Gesetzliche oder regulatorische Anforderungen</p>\n</li>\n<li>\n<p>Ergebnisse aus dem BCM / Datenschutz-Folgenabschätzungen</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Typische Risikobereiche:</p>\n<ul>\n<li>\n<p>Verlust von Verfügbarkeit, Integrität, Vertraulichkeit</p>\n</li>\n<li>\n<p>Systemausfälle, Datenverlust, unbefugter Zugriff</p>\n</li>\n<li>\n<p>Menschliches Fehlverhalten, Cyberangriffe</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>7. Risikobewertung</strong></h2>\n<ul>\n<li>\n<p>Risiken werden nach <strong>Wahrscheinlichkeit (Eintritt)</strong> und <strong>Auswirkung (Schaden)</strong> bewertet</p>\n</li>\n<li>\n<p>Dabei wird der <strong>Schutzbedarf des betroffenen Assets</strong> berücksichtigt</p>\n</li>\n<li>\n<p>Die Bewertung wird dokumentiert in der <strong>Risikomatrix / Risikoübersicht</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Risikobehandlung (Risk Treatment)</strong></h2>\n<h3>8.1 Behandlungsoptionen</h3>\n<ul>\n<li>\n<p><strong>Risikovermeidung</strong> (z. B. Abschalten, Nichtdurchführen)</p>\n</li>\n<li>\n<p><strong>Risikoverminderung</strong> (technische / organisatorische Maßnahmen)</p>\n</li>\n<li>\n<p><strong>Risikotransfer</strong> (z. B. Versicherungen, Dienstleister)</p>\n</li>\n<li>\n<p><strong>Risikoakzeptanz</strong> (wenn unterhalb der Akzeptanzschwelle)</p>\n</li>\n</ul>\n<h3>8.2 Auswahl von Maßnahmen</h3>\n<ul>\n<li>\n<p>Maßnahmen zur Risikobehandlung müssen:</p>\n<ul>\n<li>\n<p>Angemessen, wirtschaftlich vertretbar und wirksam sein</p>\n</li>\n<li>\n<p>Aus dem ISO 27001-Anhang A oder BSI-Kompendium abgeleitet werden</p>\n</li>\n<li>\n<p>Mit Verantwortlichkeiten, Fristen und Umsetzungsstatus dokumentiert sein</p>\n</li>\n</ul>\n</li>\n</ul>\n<h3>8.3 Akzeptanz</h3>\n<ul>\n<li>\n<p>Akzeptanzentscheidungen erfolgen durch:</p>\n<ul>\n<li>\n<p><strong>ISB in Abstimmung mit Geschäftsführung</strong></p>\n</li>\n<li>\n<p><strong>dokumentiert mit Begründung</strong></p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Risikoregister / Risikodokumentation</strong></h2>\n<p>Die Risikoanalyse und Maßnahmenumsetzung werden dokumentiert im:</p>\n<ul>\n<li>\n<p><strong>Risikoregister</strong> (Excel, ISMS-Tool, Wiki)</p>\n</li>\n<li>\n<p>inkl.:</p>\n<ul>\n<li>\n<p>Risikobeschreibung</p>\n</li>\n<li>\n<p>Asset/Prozess</p>\n</li>\n<li>\n<p>Schutzbedarf</p>\n</li>\n<li>\n<p>Bewertung (vorher/nachher)</p>\n</li>\n<li>\n<p>Maßnahme(n)</p>\n</li>\n<li>\n<p>Verantwortliche Person</p>\n</li>\n<li>\n<p>Status &amp; Termin</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Überwachung &amp; Review</strong></h2>\n<ul>\n<li>\n<p>Risiken werden mindestens <strong>jährlich</strong> oder bei wesentlichen Änderungen überprüft</p>\n</li>\n<li>\n<p><strong>Anlässe für Zwischenüberprüfung:</strong></p>\n<ul>\n<li>\n<p>Neue Bedrohungen (z. B. Zero-Day-Lücke)</p>\n</li>\n<li>\n<p>Organisatorische / technische Veränderungen</p>\n</li>\n<li>\n<p>Sicherheitsvorfälle</p>\n</li>\n<li>\n<p>Neue rechtliche Anforderungen</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Ergebnisse fließen in:</p>\n<ul>\n<li>\n<p><strong>Managementbewertung</strong></p>\n</li>\n<li>\n<p><strong>interne Audits</strong></p>\n</li>\n<li>\n<p><strong>ISMS-Kennzahlenberichte</strong></p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>11. Rollen &amp; Verantwortlichkeiten</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISB / ISMS-Team</strong></td>\n<td>Steuerung Risikomanagementprozess, Methodik, Bewertung, Reporting</td>\n</tr>\n<tr>\n<td><strong>Asset Owner / Fachbereiche</strong></td>\n<td>Einschätzung der Risiken im Fachkontext, Schutzbedarfsermittlung</td>\n</tr>\n<tr>\n<td><strong>IT-Abteilung</strong></td>\n<td>Bewertung technischer Risiken, Umsetzung von Maßnahmen</td>\n</tr>\n<tr>\n<td><strong>Geschäftsführung</strong></td>\n<td>Freigabe der Methode, Risikoakzeptanz, Budgetentscheidung</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>12. Schnittstellen zu anderen Richtlinien</strong></h2>\n<p>Diese Richtlinie ist eng verbunden mit:</p>\n<ul>\n<li>\n<p><strong>ISMS-Kontext &amp; Scope</strong></p>\n</li>\n<li>\n<p><strong>Informationssicherheitsziele &amp; Planung</strong></p>\n</li>\n<li>\n<p><strong>Asset- &amp; Schutzbedarfsmanagement</strong></p>\n</li>\n<li>\n<p><strong>Change Management</strong></p>\n</li>\n<li>\n<p><strong>Business Continuity Management</strong></p>\n</li>\n<li>\n<p><strong>Lieferantenmanagement</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>13. Bezug zu Normen &amp; Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Abschnitt</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001:2022</strong></td>\n<td>Kapitel 6.1 – Maßnahmen zur Behandlung von Risiken und Chancen</td>\n</tr>\n<tr>\n<td><strong>ISO/IEC 27005</strong></td>\n<td>Leitlinie zur Risikobewertung</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>ISMS.2 – Risikoanalyse<br/>ORP.4.2 – Sicherheitsrisiken behandeln</td>\n</tr>\n<tr>\n<td><strong>NIS-2 Richtlinie (Art. 21)</strong></td>\n<td>Verpflichtung zum risikobasierten Sicherheitsmanagement</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '1', NULL, NULL, 0, 0, NULL),
(31, 'DOK-0025', 'ISMS Kommunikationsplan', 'Governance', '1', 0, NULL, '<h2><strong>1. Zweck der Richtlinie</strong></h2>\n<p>Diese Richtlinie beschreibt, <strong>wann, wie, mit wem und über welche Kanäle</strong> innerhalb des Informationssicherheitsmanagementsystems (ISMS) kommuniziert wird.</p>\n<p>Ziel ist es, sicherzustellen, dass:</p>\n<ul>\n<li>\n<p><strong>sicherheitsrelevante Informationen rechtzeitig und zielgerichtet ausgetauscht</strong> werden,</p>\n</li>\n<li>\n<p>gesetzliche und normative Anforderungen erfüllt sind (z. B. ISO 27001, NIS-2),</p>\n</li>\n<li>\n<p><strong>Awareness und Transparenz</strong> innerhalb der Organisation gefördert werden.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>2. Geltungsbereich</strong></h2>\n<p>Diese Richtlinie gilt für:</p>\n<ul>\n<li>\n<p><strong>alle internen Rollen und Einheiten</strong>, die im ISMS beteiligt sind</p>\n</li>\n<li>\n<p><strong>alle externen Partner, Dienstleister und Behörden</strong>, sofern sie sicherheitsrelevante Informationen erhalten oder bereitstellen müssen</p>\n</li>\n<li>\n<p>alle <strong>Kommunikationsformen</strong>: mündlich, schriftlich, digital</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>3. Grundsätze</strong></h2>\n<ul>\n<li>\n<p>Kommunikation im ISMS erfolgt <strong>strukturiert, geplant, nachvollziehbar und adressatengerecht</strong></p>\n</li>\n<li>\n<p>Vertraulichkeit, Integrität und Verfügbarkeit der Informationen sind bei der Kommunikation stets zu beachten (nach dem <strong>CIA-Prinzip</strong>)</p>\n</li>\n<li>\n<p>Kommunikationsinhalte und -verläufe werden bei Bedarf <strong>dokumentiert und nachverfolgt</strong></p>\n</li>\n</ul>\n<hr/>\n<h2><strong>4. Kommunikationsziele</strong></h2>\n<ul>\n<li>\n<p><strong>Transparenz</strong> über Sicherheitsziele, Maßnahmen und Verantwortlichkeiten schaffen</p>\n</li>\n<li>\n<p><strong>Mitarbeitende sensibilisieren</strong> und regelmäßig informieren (Awareness)</p>\n</li>\n<li>\n<p><strong>Berichtspflichten</strong> gegenüber Management, Aufsichtsbehörden oder Kunden erfüllen</p>\n</li>\n<li>\n<p><strong>Reaktionsfähigkeit im Vorfallmanagement</strong> sicherstellen</p>\n</li>\n<li>\n<p>Anforderungen externer Stakeholder (z. B. Behörden, Zertifizierer, Kunden) erfüllen</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>5. Kommunikationsarten und Inhalte</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th><strong>Kommunikationsanlass</strong></th>\n<th><strong>Inhalt</strong></th>\n<th><strong>Zielgruppe</strong></th>\n<th><strong>Frequenz / Zeitpunkt</strong></th>\n<th><strong>Medium</strong></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Kick-off / Einführung ISMS</td>\n<td>Ziele, Scope, Rollen</td>\n<td>Geschäftsführung, Führungskräfte, ISMS-Team</td>\n<td>Bei ISMS-Start</td>\n<td>Präsenz / MS Teams / Intranet</td>\n</tr>\n<tr>\n<td>Awareness-Kampagne</td>\n<td>Sicherheitsregeln, aktuelle Risiken</td>\n<td>Alle Mitarbeitenden</td>\n<td>Jährlich / bei Bedarf</td>\n<td>E-Mail, Intranet, Poster</td>\n</tr>\n<tr>\n<td>Vorfallkommunikation (Incident)</td>\n<td>Information über Vorfall, Maßnahmen, Status</td>\n<td>ISB, IT, betroffene Fachbereiche</td>\n<td>Ad hoc / unverzüglich</td>\n<td>Telefon, Ticket, E-Mail</td>\n</tr>\n<tr>\n<td>Interne Audit-Informationen</td>\n<td>Audittermine, Auditziele, Ergebnisse</td>\n<td>Fachbereiche, ISB, IT</td>\n<td>Vor / nach Audits</td>\n<td>E-Mail, Auditbericht</td>\n</tr>\n<tr>\n<td>Management-Review</td>\n<td>Status ISMS, KPIs, Risiken, Maßnahmen</td>\n<td>Geschäftsführung, ISMS-Leitung</td>\n<td>Mind. 1× jährlich</td>\n<td>Präsentation / Bericht</td>\n</tr>\n<tr>\n<td>Mitarbeiterschulung</td>\n<td>Grundlagen der Informationssicherheit</td>\n<td>Alle Mitarbeitenden</td>\n<td>Mind. 1× jährlich</td>\n<td>E-Learning, Schulungstool</td>\n</tr>\n<tr>\n<td>Lieferantenkommunikation</td>\n<td>Sicherheitsanforderungen, AV-Verträge</td>\n<td>Externe Dienstleister</td>\n<td>Bei Onboarding / Vertragsänderung</td>\n<td>Vertrag, E-Mail, Fragebogen</td>\n</tr>\n<tr>\n<td>Notfallkommunikation / BCM</td>\n<td>Notfallprozesse, Eskalationswege</td>\n<td>BCM-Team, IT, Geschäftsführung</td>\n<td>Regelmäßig + im Ereignisfall</td>\n<td>Notfallplan, Ruflisten</td>\n</tr>\n<tr>\n<td>Änderungen am ISMS</td>\n<td>Neue Richtlinien, Prozesse, Maßnahmen</td>\n<td>Alle Betroffenen</td>\n<td>Bei Relevanz</td>\n<td>ISMS-News, Intranet, E-Mail</td>\n</tr>\n<tr>\n<td>Zertifizierung / externe Prüfung</td>\n<td>Termine, Ablauf, Anforderungen</td>\n<td>ISMS-Team, relevante Abteilungen</td>\n<td>Vor externem Audit</td>\n<td>Projektkommunikation / Kickoff</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>6. Kommunikationsverantwortlichkeiten</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Rolle</th>\n<th>Aufgaben im Kontext Kommunikation</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISB / ISMS-Leitung</strong></td>\n<td>Koordination und Freigabe sicherheitsbezogener Kommunikation</td>\n</tr>\n<tr>\n<td><strong>IT-Abteilung</strong></td>\n<td>Meldung technischer Vorfälle, Statusberichte</td>\n</tr>\n<tr>\n<td><strong>HR / Schulungsbeauftragte</strong></td>\n<td>Organisation der Awareness-Maßnahmen</td>\n</tr>\n<tr>\n<td><strong>Fachbereiche</strong></td>\n<td>Rückmeldungen zu Anforderungen, Mitwirkung bei Kommunikation</td>\n</tr>\n<tr>\n<td><strong>Geschäftsführung</strong></td>\n<td>Übergeordnete Kommunikation an Stakeholder</td>\n</tr>\n<tr>\n<td><strong>Sicherheitsincident-Manager</strong></td>\n<td>Koordination von Vorfallkommunikation</td>\n</tr>\n<tr>\n<td><strong>Lieferantenmanager</strong></td>\n<td>Kommunikation sicherheitsrelevanter Anforderungen an Dritte</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<hr/>\n<h2><strong>7. Kommunikationskanäle</strong></h2>\n<p>Zugelassene Kanäle (abhängig von Schutzbedarf):</p>\n<ul>\n<li>\n<p><strong>E-Mail</strong> (ggf. mit Verschlüsselung – z. B. S/MIME)</p>\n</li>\n<li>\n<p><strong>Intranet / Wiki</strong> (für Awareness &amp; Richtlinien)</p>\n</li>\n<li>\n<p><strong>ISMS-Tool</strong> (Dokumentation, Maßnahmenverfolgung)</p>\n</li>\n<li>\n<p><strong>Besprechungen (Präsenz / Online)</strong></p>\n</li>\n<li>\n<p><strong>Ticket-Systeme</strong> (z. B. für Vorfälle)</p>\n</li>\n<li>\n<p><strong>Telefonische Kommunikation</strong> (Notfälle, Eskalationen)</p>\n</li>\n<li>\n<p><strong>Vertragliche Kommunikation</strong> (z. B. Lieferantenverträge, SLAs)</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>8. Schutzbedarf bei der Kommunikation</strong></h2>\n<ul>\n<li>\n<p>Bei sicherheitsrelevanten Inhalten sind insbesondere <strong>Vertraulichkeit und Integrität</strong> zu gewährleisten</p>\n</li>\n<li>\n<p>Bei Kommunikation sensibler Informationen sind ggf. folgende Maßnahmen erforderlich:</p>\n<ul>\n<li>\n<p>Transportverschlüsselung (TLS, VPN)</p>\n</li>\n<li>\n<p>Ende-zu-Ende-Verschlüsselung (z. B. PGP, S/MIME)</p>\n</li>\n<li>\n<p>Zugriffskontrolle auf Dokumente</p>\n</li>\n<li>\n<p>Vertraulichkeitsvermerke</p>\n</li>\n</ul>\n</li>\n</ul>\n<hr/>\n<h2><strong>9. Dokumentation und Nachweis</strong></h2>\n<ul>\n<li>\n<p>Wichtige Kommunikationsmaßnahmen sind <strong>nachweisbar zu dokumentieren</strong>:</p>\n<ul>\n<li>\n<p>Schulungsteilnahmen</p>\n</li>\n<li>\n<p>Awareness-Kampagnen</p>\n</li>\n<li>\n<p>Management-Reviews</p>\n</li>\n<li>\n<p>Vorfallberichte</p>\n</li>\n<li>\n<p>Auditkommunikation</p>\n</li>\n</ul>\n</li>\n<li>\n<p>Die <strong>Wirksamkeit der Kommunikation</strong> wird regelmäßig im Rahmen des <strong>ISMS-Reviews</strong> geprüft.</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>10. Überprüfung und Aktualisierung</strong></h2>\n<ul>\n<li>\n<p>Der Kommunikationsplan wird mindestens <strong>jährlich</strong> überprüft, z. B. im Rahmen des <strong>Management-Reviews</strong></p>\n</li>\n<li>\n<p>Bei wesentlichen Änderungen (z. B. neue Stakeholder, neue Systeme, geänderte gesetzliche Anforderungen) ist eine <strong>unterjährige Aktualisierung</strong> erforderlich</p>\n</li>\n</ul>\n<hr/>\n<h2><strong>11. Bezug zu Normen und Standards</strong></h2>\n<div class=\"TyagGW_tableContainer\">\n<div class=\"group TyagGW_tableWrapper flex w-fit flex-col-reverse\">\n<table class=\"w-fit min-w-(--thread-content-width)\">\n<thead>\n<tr>\n<th>Norm / Standard</th>\n<th>Bezug / Abschnitt</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>ISO/IEC 27001:2022</strong></td>\n<td>Kapitel 7.4 – Kommunikation</td>\n</tr>\n<tr>\n<td><strong>BSI IT-Grundschutz</strong></td>\n<td>ORP.3 – Informationssicherheitsorganisation<br/>ORP.1 – Sicherheitsleitlinie</td>\n</tr>\n<tr>\n<td><strong>NIS-2 Richtlinie (Art. 21)</strong></td>\n<td>Verpflichtung zur internen und externen Sicherheitskommunikation</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n<p> </p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 0, NULL, 0, 0, 0, 0, NULL, 0, '', '', NULL, NULL, '1', 0, '1', NULL, NULL, 0, 0, NULL);
INSERT INTO `Dokumente` (`id`, `Dokumentennummer`, `Dokumentenname`, `Typ`, `Status`, `Version`, `Klassifizierung`, `Text`, `Ersteller`, `Pruefer`, `Freigebener`, `erstellt`, `geprueft`, `freigegeben`, `review`, `Änderer`, `geändert`, `Subversion`, `archiviert`, `schreibschutz`, `gibtneueversion`, `Reviewer`, `zupruefen`, `Dokumentenname_en`, `text_en`, `Typ_en`, `Classification`, `Status_en`, `Besitzer`, `bpmn`, `werpruefen`, `werfreigeben`, `freizugeben`, `istfreigegeben`, `dok_verknuepfung`) VALUES
(32, 'DOK-0038', 'KI Richtlinie', 'Richtlinien', '1', 0, 'intern', '<h3>1. Zweck und Geltungsbereich</h3>\n<p>Diese Richtlinie definiert die Anforderungen für den sicheren und verantwortungsvollen Einsatz von Künstlicher Intelligenz (KI) und KI-gestützten Systemen innerhalb der Organisation. Sie gilt für alle Mitarbeiter, Auftragnehmer und Dritte, die KI-Systeme entwickeln, beschaffen, implementieren, betreiben oder nutzen.</p>\n<p>Die Richtlinie unterstützt die Einhaltung der Anforderungen nach ISO 27001:2022 (insbesondere Anhang A Kontrollen A.5.1, A.5.9, A.5.23, A.8.25) sowie der NIS2-Richtlinie (EU) 2022/2555, insbesondere Artikel 21 zu Risikomanagementmaßnahmen.</p>\n<h3>2. Verantwortlichkeiten</h3>\n<ul>\n<li><strong>Geschäftsleitung:</strong> Trägt die Gesamtverantwortung für die Governance von KI-Systemen und stellt ausreichende Ressourcen für deren sichere Implementierung bereit (gemäß NIS2 Art. 20).</li>\n<li><strong>Informationssicherheitsbeauftragter (ISB):</strong> Überwacht die Einhaltung dieser Richtlinie, führt Risikoanalysen für KI-Systeme durch und berichtet an die Geschäftsleitung.</li>\n<li><strong>Datenschutzbeauftragter (DSB):</strong> Bewertet KI-Systeme hinsichtlich datenschutzrechtlicher Anforderungen und führt bei Bedarf Datenschutz-Folgenabschätzungen durch.</li>\n<li><strong>Fachabteilungen/Systemverantwortliche:</strong> Verantworten die ordnungsgemäße Nutzung von KI-Systemen in ihrem Bereich und melden Sicherheitsvorfälle unverzüglich.</li>\n<li><strong>IT-Abteilung:</strong> Stellt die technische Sicherheit von KI-Systemen sicher, einschließlich Zugriffskontrollen, Überwachung und Patch-Management.</li>\n<li><strong>Alle Mitarbeiter:</strong> Nutzen nur freigegebene KI-Systeme und halten die in dieser Richtlinie definierten Vorgaben ein.</li>\n</ul>\n<h3>3. Freigabeverfahren für KI-Systeme</h3>\n<p><strong>Grundsatz:</strong> Es dürfen ausschließlich KI-Systeme und -Anwendungen genutzt werden, die das formale Freigabeverfahren der Organisation durchlaufen haben.</p>\n<h4>3.1 Freigabeprozess</h4>\n<ul>\n<li>Vor der Einführung eines KI-Systems ist ein Antrag auf Freigabe beim ISB einzureichen.</li>\n<li>Eine Risikoanalyse gemäß der Methodik des ISMS ist durchzuführen (A.5.7).</li>\n<li>Die Prüfung umfasst: Informationssicherheit, Datenschutz, rechtliche Compliance und ethische Aspekte.</li>\n<li>Die Freigabe wird im Verzeichnis freigegebener KI-Systeme dokumentiert.</li>\n<li>Regelmäßige Überprüfung der Freigabe erfolgt mindestens jährlich oder bei wesentlichen Änderungen.</li>\n</ul>\n<h4>3.2 Kategorisierung</h4>\n<p>KI-Systeme werden nach ihrem Risikopotenzial kategorisiert:</p>\n<ul>\n<li><strong>Niedrig:</strong> Unterstützende Systeme ohne Zugriff auf vertrauliche Daten</li>\n<li><strong>Mittel:</strong> Systeme mit Zugriff auf interne Informationen</li>\n<li><strong>Hoch:</strong> Systeme mit Zugriff auf vertrauliche oder personenbezogene Daten, autonome Entscheidungssysteme</li>\n</ul>\n<h3>4. Sicherheitsanforderungen</h3>\n<h4>4.1 Technische Maßnahmen</h4>\n<ul>\n<li><strong>Zugriffskontrollen:</strong> Implementierung rollenbasierter Zugriffsrechte nach dem Prinzip der geringsten Berechtigung (A.5.15, A.8.2).</li>\n<li><strong>Protokollierung:</strong> Vollständige Protokollierung aller KI-Interaktionen und -Entscheidungen (A.8.15).</li>\n<li><strong>Verschlüsselung:</strong> Daten in KI-Systemen sind bei Übertragung und Speicherung zu verschlüsseln (A.8.24).</li>\n<li><strong>Netzwerksicherheit:</strong> KI-Systeme sind in gesicherten Netzwerksegmenten zu betreiben (A.8.22).</li>\n<li><strong>Schwachstellenmanagement:</strong> Regelmäßige Sicherheitsupdates und Schwachstellenanalysen (A.8.8).</li>\n</ul>\n<h4>4.2 Organisatorische Maßnahmen</h4>\n<ul>\n<li><strong>Schulung:</strong> Alle Nutzer von KI-Systemen erhalten Schulungen zur sicheren Nutzung (A.6.3).</li>\n<li><strong>Dokumentation:</strong> Alle KI-Systeme, deren Zweck und Datenflüsse sind zu dokumentieren (A.5.9).</li>\n<li><strong>Lieferantenmanagement:</strong> Bei externen KI-Diensten sind Sicherheitsanforderungen vertraglich zu vereinbaren (A.5.19, A.5.21).</li>\n</ul>\n<h3>5. Risikomanagement für KI-Systeme</h3>\n<p>Gemäß NIS2 Art. 21 und ISO 27001 sind für KI-Systeme spezifische Risiken zu identifizieren und zu behandeln:</p>\n<ul>\n<li><strong>Vertraulichkeit:</strong> Risiko der unbeabsichtigten Offenlegung von Informationen durch KI-Systeme</li>\n<li><strong>Integrität:</strong> Risiko von Manipulation oder fehlerhaften Ausgaben (z.B. Halluzinationen)</li>\n<li><strong>Verfügbarkeit:</strong> Abhängigkeit von externen KI-Diensten und deren Ausfallrisiko</li>\n<li><strong>Compliance:</strong> Risiken durch Verstöße gegen Datenschutz oder regulatorische Anforderungen</li>\n<li><strong>Supply Chain:</strong> Risiken in der Lieferkette von KI-Komponenten und -Diensten (NIS2 Art. 21 Abs. 2d)</li>\n</ul>\n<h3>6. Nutzungsregeln</h3>\n<h4>6.1 Zulässige Nutzung</h4>\n<ul>\n<li>Nutzung nur für dienstliche Zwecke und im Rahmen der definierten Anwendungsfälle</li>\n<li>Überprüfung und Validierung von KI-generierten Inhalten vor Verwendung</li>\n<li>Kennzeichnung von KI-generierten Inhalten wo erforderlich</li>\n</ul>\n<h4>6.2 Unzulässige Nutzung</h4>\n<ul>\n<li>Eingabe von vertraulichen Informationen in nicht freigegebene KI-Systeme</li>\n<li>Eingabe von personenbezogenen Daten ohne entsprechende Rechtsgrundlage und technische Absicherung</li>\n<li>Verwendung von KI für automatisierte Entscheidungen ohne menschliche Kontrolle bei relevanten Auswirkungen auf Betroffene</li>\n<li>Umgehung von Sicherheitskontrollen oder Nutzung nicht autorisierter KI-Tools</li>\n</ul>\n<h3>7. Vorfallmanagement</h3>\n<p>Sicherheitsvorfälle im Zusammenhang mit KI-Systemen sind gemäß dem Vorfallmanagement-Prozess zu behandeln (A.5.24, A.5.26). Dies umfasst insbesondere:</p>\n<ul>\n<li>Unverzügliche Meldung von Vorfällen an den ISB</li>\n<li>Dokumentation und Analyse des Vorfalls</li>\n<li>Einleitung von Sofortmaßnahmen zur Schadensbegrenzung</li>\n<li>Bei erheblichen Vorfällen: Meldung an zuständige Behörden gemäß NIS2 Art. 23 (innerhalb von 24 Stunden Frühwarnung, 72 Stunden vollständige Meldung)</li>\n</ul>\n<h3>8. Überprüfung und Verbesserung</h3>\n<p>Diese Richtlinie wird im Rahmen des PDCA-Zyklus kontinuierlich verbessert:</p>\n<ul>\n<li><strong>Plan:</strong> Jährliche Überprüfung und Aktualisierung der Richtlinie</li>\n<li><strong>Do:</strong> Umsetzung der definierten Maßnahmen und Kontrollen</li>\n<li><strong>Check:</strong> Regelmäßige Audits der KI-Nutzung und Wirksamkeitsprüfung der Kontrollen</li>\n<li><strong>Act:</strong> Anpassung bei veränderten Risiken, neuen Technologien oder regulatorischen Anforderungen</li>\n</ul>\n<h3>9. Referenzen</h3>\n<ul>\n<li>ISO/IEC 27001:2022 – Informationssicherheitsmanagementsysteme</li>\n<li>Richtlinie (EU) 2022/2555 (NIS2-Richtlinie)</li>\n<li>EU AI Act (Verordnung über Künstliche Intelligenz)</li>\n<li>DSGVO – Datenschutz-Grundverordnung</li>\n<li>Interne Dokumente: Informationssicherheitsrichtlinie, Risikorichtlinie, Vorfallmanagement-Prozess</li>\n</ul>\n<h3>10. Inkrafttreten und Gültigkeit</h3>\n<p>Diese Richtlinie tritt mit ihrer Freigabe in Kraft und ist für alle Mitarbeiter und relevanten Dritten verbindlich. Die nächste planmäßige Überprüfung erfolgt spätestens 12 Monate nach Inkrafttreten oder bei wesentlichen Änderungen der Risikolage, Technologie oder regulatorischen Anforderungen.</p>', 1, NULL, NULL, '2026-07-18', NULL, NULL, NULL, 1, '2026-07-18', 0, 0, 0, 0, NULL, 0, NULL, NULL, NULL, NULL, '1', 2, NULL, NULL, NULL, 0, 0, NULL);

