--
-- Tabellenstruktur für Tabelle `Risiko`
--

CREATE TABLE `Risiko` (
  `id` int(11) UNSIGNED NOT NULL,
  `Nummer` varchar(64) DEFAULT NULL,
  `Name` varchar(256) DEFAULT NULL,
  `Besitzer` int(11) UNSIGNED DEFAULT 0,
  `Abteilung` varchar(64) DEFAULT NULL,
  `status` varchar(64) DEFAULT NULL,
  `Businessimpact` text DEFAULT NULL,
  `Beschreibung` text DEFAULT NULL,
  `Kategorie` varchar(64) DEFAULT NULL,
  `Maßnahme` text DEFAULT NULL,
  `wahrvm` int(11) NOT NULL DEFAULT 1,
  `auswvm` int(11) NOT NULL DEFAULT 1,
  `wahrnm` int(11) NOT NULL DEFAULT 1,
  `auswnm` int(11) NOT NULL DEFAULT 1,
  `Ersteller` int(11) NOT NULL DEFAULT 0,
  `Erstelldatum` date NOT NULL DEFAULT current_timestamp(),
  `Behandlung` varchar(64) DEFAULT NULL,
  `umgesetzt` tinyint(1) NOT NULL DEFAULT 0,
  `Aenderer` int(11) NOT NULL DEFAULT 0,
  `geaendert` date NOT NULL DEFAULT current_timestamp(),
  `Reviewer` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `review` date NOT NULL DEFAULT current_timestamp(),
  `risiko` varchar(64) DEFAULT NULL,
  `massnahmen` varchar(256) DEFAULT NULL,
  `assets` varchar(256) DEFAULT NULL,
  `archiviert` tinyint(1) NOT NULL DEFAULT 0,
  `ra` varchar(255) DEFAULT NULL,
  `riskscore` int(11) NOT NULL DEFAULT 0,
  `bedrohungen` varchar(255) DEFAULT NULL,
  `schwachstellen` varchar(255) DEFAULT NULL,
  `ausw_vm_detail` varchar(20) DEFAULT NULL COMMENT 'Auswirkung vm je Faktor, kommasepariert (vm0,vm1,vm2,vm3,vm4)',
  `ausw_nm_detail` varchar(20) DEFAULT NULL COMMENT 'Auswirkung nm je Faktor, kommasepariert (nm0,nm1,nm2,nm3,nm4)',
  `dokumente` text DEFAULT NULL COMMENT 'Kommagetrennte IDs verknüpfter Dokumente (aus Tabelle Dokumente)',
  `normen` varchar(256) DEFAULT NULL COMMENT 'Kommagetrennte IDs verknüpfter Normen/Controls (aus Tabelle Normen)',
  `Name_en` text DEFAULT NULL,
  `Beschreibung_en` text DEFAULT NULL,
  `Businessimpact_en` text DEFAULT NULL,
  `Maßnahme_en` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Daten für Tabelle `Risiko`
--

INSERT INTO `Risiko` (`id`, `Nummer`, `Name`, `Besitzer`, `Abteilung`, `status`, `Businessimpact`, `Beschreibung`, `Kategorie`, `Maßnahme`, `wahrvm`, `auswvm`, `wahrnm`, `auswnm`, `Ersteller`, `Erstelldatum`, `Behandlung`, `umgesetzt`, `Aenderer`, `geaendert`, `Reviewer`, `review`, `risiko`, `massnahmen`, `assets`, `archiviert`, `ra`, `riskscore`, `bedrohungen`, `schwachstellen`, `ausw_vm_detail`, `ausw_nm_detail`, `dokumente`, `normen`, `Name_en`, `Beschreibung_en`, `Businessimpact_en`, `Maßnahme_en`) VALUES
(1, 'RSK-0001', 'Phishing', 1, '', 'Bewertet', '<p>- Finanzielle Verluste: Direkte finanzielle Verluste durch betr&uuml;gerische Transaktionen, Anwaltskosten und Kosten f&uuml;r die Behebung der Sicherheitsverletzung<br>- Reputationsschaden: Verlust des Kundenvertrauens, potenzielle Abwanderung und Schwierigkeiten bei der Gewinnung neuer Kunden<br>- Betriebsunterbrechungen: Ausfallzeiten oder Datenverluste, die durch den Zugriff auf Backend-Systeme verursacht werden und zu einer geringeren Kundenzufriedenheit f&uuml;hren.<br>- Probleme bei der Einhaltung gesetzlicher Vorschriften: Bu&szlig;gelder und rechtliche Konsequenzen f&uuml;r die Nichteinhaltung von Datenschutzbestimmungen<br>- Rechtliche Konsequenzen: Klagen von Betroffenen wegen Fahrl&auml;ssigkeit oder Vertragsbruch.<br>- Verlust von Wettbewerbsvorteilen: Diebstahl gesch&uuml;tzter Informationen, der zu einer verminderten Marktposition und einem Wettbewerbsvorteil f&uuml;hrt.</p>', '<p>Risiko des Diebstahls von Daten, der &Uuml;bernahme von Konten oder betr&uuml;gerischer Transaktionen im Namen von Mitarbeitenden. Dies kann zu finanziellen Verlusten, Reputationssch&auml;den, Betriebsunterbrechungen, rechtlichen Konsequenzen und dem Verlust von Wettbewerbsvorteilen f&uuml;hren.</p>', 'Organisatorische Risiken', '<p>Awareness-Training</p>', 4, 5, 1, 1, 1, '2025-12-21', 'Reduzieren', 0, 1, '2026-07-07', 1, '2026-12-28', 'kritisch', '3', '3,4,14,96,97,98,100', 0, '', 20, '3', '5', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(2, 'RSK-0002', 'Randsomware', 26, '', 'behandelt', '<p>Auch wenn Cloud-Speicher einen gewissen Schutz bieten, gibt es nach wie vor Ransomware-Bedrohungen, die sich auf verschiedene Weise auf Unternehmen auswirken. Betriebsunterbrechungen, finanzielle Verluste, Rufsch&auml;digung und Nichteinhaltung gesetzlicher Vorschriften sind die wichtigsten Bereiche, die davon betroffen sind. Betriebsunterbrechungen k&ouml;nnen zu Ausfallzeiten und beeintr&auml;chtigtem Zugang zu wichtigen Systemen f&uuml;hren, was sich auf die Produktivit&auml;t auswirkt. Finanzielle Verluste k&ouml;nnen durch L&ouml;segeldzahlungen, Wiederherstellungskosten und potenzielle Umsatzeinbu&szlig;en aufgrund von Serviceunterbrechungen entstehen. Rufsch&auml;digung kann zu einer Erosion des Vertrauens und der Wettbewerbsf&auml;higkeit f&uuml;hren. Die Nichteinhaltung gesetzlicher Vorschriften kann Strafen und rechtliche Konsequenzen nach sich ziehen.&nbsp;</p>', '<p>Risiko des Datenverlusts oder finanzieller Sch&auml;den durch Erpressung, bei der Daten verschl&uuml;sselt und erst nach Zahlung eines L&ouml;segelds freigegeben werden. Dies kann zu Betriebsunterbrechungen, Umsatzverlusten, Reputationssch&auml;den und rechtlichen Folgen f&uuml;hren.</p>', 'Technische Risiken', '<ul>\r\n<li>MS Defender auf Clientes, Server, Mailserver</li>\r\n<li>ArcticWolf</li>\r\n<li>Verschl&uuml;sselte Protokolle</li>\r\n<li>Softwareverteilung mit bMS</li>\r\n<li>Sicheres Backup</li>\r\n</ul>', 5, 4, 1, 1, 1, '2025-12-21', 'Akzeptieren', 0, 1, '2026-07-07', 1, '2027-01-09', 'niedrig', 'None,5,1,6', '', 0, '', 1, '2', '6,11,15,20', '1,4,3,1,1', '1,1,1,1,1', NULL, NULL, NULL, NULL, NULL, NULL),
(4, 'RSK-0003', 'Malware', 1, '', 'archiviert', '<p>Malware-Angriffe k&ouml;nnen zu Betriebsunterbrechungen, Datenschutzverletzungen, finanziellen Verlusten, Rufsch&auml;digung und Nichteinhaltung gesetzlicher Vorschriften f&uuml;hren. Betriebsunterbrechungen k&ouml;nnen zu Ausfallzeiten, beeintr&auml;chtigtem Zugang zu kritischen Systemen und verminderter Produktivit&auml;t f&uuml;hren. Datenschutzverletzungen k&ouml;nnen zu unbefugtem Zugriff, Diebstahl oder Verschl&uuml;sselung sensibler, in Cloud-Systemen gespeicherter Daten f&uuml;hren, was finanzielle und Rufsch&auml;digung nach sich ziehen kann.</p>', '<p>Risiko von Datenverlusten, Systemausf&auml;llen und Ger&auml;tesch&auml;den durch Schadsoftware, die z. B. &uuml;ber E-Mails, Werbung oder infizierte Anwendungen verbreitet wird. M&ouml;gliche Folgen sind Betriebsunterbrechungen, Datenpannen, finanzielle Verluste, Reputationssch&auml;den und Bu&szlig;gelder.</p>', 'Technische Risiken', '', 4, 5, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-07-07', 1, '2027-01-09', 'niedrig', 'None,1', '98', 0, '', 4, '2', '20', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(5, 'RSK-0004', 'Fehlkonfiguration von Mitarbeiter-Endpunkten', 1, '', 'archiviert', '<p>Diebstahl von Mitarbeiterdaten: Falsch konfigurierte Endpunkte k&ouml;nnen versehentlich Mitarbeiterdaten einem unbefugten Zugriff aussetzen.&nbsp;<br>Auswirkungen: Verletzung der Privatsph&auml;re der Mitarbeiter, potenzielle rechtliche Verpflichtungen, Verlust des Vertrauens der Mitarbeiter und Rufsch&auml;digung des Unternehmens.&nbsp;</p>', '<p>Risiko durch falsch konfigurierte Laptops oder andere Ger&auml;te, was zu Datendiebstahl, Infektionen durch Malware und der &Uuml;bernahme von Benutzerkonten f&uuml;hren kann. Dies beeintr&auml;chtigt die Datensicherheit und kann zu rechtlichen Konsequenzen f&uuml;hren.</p>', 'Technische Risiken', '<p>- Standardimage<br>- Management durch bMS</p>', 3, 4, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 4, '10', '20', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(6, 'RSK-0005', 'Ausnutzung von Mitarbeitereigenen Geräten (BYOD)', 1, '', 'archiviert', '<p>Datenschutzverletzungen und Verlust vertraulicher Informationen:&nbsp;<br>- unbefugter Zugriff auf sensible Unternehmensdaten&nbsp;<br>- finanzielle Verluste durch Bu&szlig;gelder, Anwaltskosten und Vergleiche.&nbsp;</p>\r\n<p>Au&szlig;erdem&nbsp;<br>- Verlust vertraulicher Informationen&nbsp;</p>\r\n<p>Betriebsst&ouml;rungen und Ausfallzeiten:&nbsp;<br>- Sicherheitsverletzungen auf mitarbeitereigenen Ger&auml;ten k&ouml;nnen den Gesch&auml;ftsbetrieb st&ouml;ren und zu Ausfallzeiten f&uuml;hren Verst&ouml;&szlig;e gegen Compliance-Vorschriften und rechtliche Konsequenzen&nbsp;<br>- Nichteinhaltung von Datenschutzbestimmungen, Branchenstandards und vertraglichen Verpflichtungen&nbsp;</p>\r\n<p>Rufsch&auml;digung und Verlust des Kundenvertrauens:&nbsp;<br>- mitarbeitereigene Ger&auml;te k&ouml;nnen den Ruf des Unternehmens sch&auml;digen und das Vertrauen der Kunden untergraben&nbsp;</p>\r\n<p><br>Diebstahl geistigen Eigentums und Wettbewerbsnachteile:&nbsp;<br>- Diebstahl geistigen Eigentums und gesch&uuml;tzter Gesch&auml;ftsinformationen durch b&ouml;swillige Akteure oder Wettbewerber.</p>', '<p>Risiko durch Sicherheitsl&uuml;cken auf privaten Ger&auml;ten von Mitarbeitenden, etwa durch fehlende Schutzma&szlig;nahmen. Dies kann zu Datenlecks, Betriebsunterbrechungen, Regelverst&ouml;&szlig;en und dem Verlust geistigen Eigentums f&uuml;hren.</p>', 'Organisatorische Risiken', '<p>BYOD-Ger&auml;te sind nicht erlaubt. Nur Monitore und Tastaturen im Homeoffice.</p>', 3, 4, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 4, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(7, 'RSK-0006', 'Missbrauch von Firmengeräten durch Mitarbeitende', 1, '', 'archiviert', '<p>- Finanzielle Verluste: Der Diebstahl oder Missbrauch von sensiblen Unternehmensdaten oder Gesch&auml;ftsgeheimnissen kann zu finanziellen Verlusten f&uuml;hren, da die Wettbewerbsf&auml;higkeit sinkt, geistiges Eigentum verloren geht und potenzielle Rechtskosten f&uuml;r Rechtsstreitigkeiten anfallen.&nbsp;<br>- Service: &nbsp;Vorf&auml;lle, bei denen Ger&auml;te entwendet oder missbraucht werden, k&ouml;nnen den normalen Gesch&auml;ftsbetrieb st&ouml;ren, was zu Produktivit&auml;tseinbu&szlig;en, Ausfallzeiten und erh&ouml;hten Betriebskosten im Zusammenhang mit der Reaktion auf Vorf&auml;lle und deren Behebung f&uuml;hrt.&nbsp;<br>- Rechtliche Aspekte: Je nach Art der betroffenen Daten und der geltenden Vorschriften (z. B. GDPR) kann das Unternehmen mit rechtlichen und beh&ouml;rdlichen Konsequenzen konfrontiert werden, wenn es sensible Daten nicht angemessen sch&uuml;tzt. Dazu k&ouml;nnen Geldstrafen, Bu&szlig;gelder und Klagen der betroffenen Parteien geh&ouml;ren.&nbsp;<br>- Ruf: Wenn vertrauliche Informationen oder Gesch&auml;ftsgeheimnisse offengelegt oder missbraucht werden, kann dies den Ruf des Unternehmens sch&auml;digen und das Vertrauen der Kunden untergraben. Negative Publicity im Zusammenhang mit einer Sicherheitsverletzung kann zu einem Verlust von Gesch&auml;ftsm&ouml;glichkeiten und Schwierigkeiten bei der Gewinnung neuer Kunden f&uuml;hren.</p>', '<p>Risiko, dass unzufriedene Mitarbeitende Firmenger&auml;te missbrauchen, um Daten zu stehlen oder Gesch&auml;ftsgeheimnisse weiterzugeben. Dies kann zu finanziellen Verlusten, Betriebsst&ouml;rungen, rechtlichen Konsequenzen und Reputationssch&auml;den f&uuml;hren.</p>', 'Technische Risiken', '<p>Richtlinie und Betriebsvereinbarung Nutzung IT</p>', 3, 3, 1, 3, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 3, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(8, 'RSK-0007', 'Datendiebstahl von Mitarbeitergeräten', 1, '', 'archiviert', '<p>Dieses Szenario kann zu Datenschutzverletzungen f&uuml;hren, bei denen sensible Unternehmens- und Kundendaten preisgegeben werden, was zu erheblichen finanziellen Verlusten durch Bu&szlig;gelder, rechtliche Verpflichtungen und Abhilfekosten f&uuml;hrt. Au&szlig;erdem kann das Unternehmen einen Imageschaden erleiden, der das Vertrauen der Kunden und die Glaubw&uuml;rdigkeit auf dem Markt schw&auml;cht. Wenn Daten auf Ger&auml;ten im Besitz von Mitarbeitern gespeichert werden, die anf&auml;llig f&uuml;r Diebstahl sind, steigt das Risiko des unbefugten Zugriffs und Missbrauchs, was die Integrit&auml;t und Vertraulichkeit der Daten gef&auml;hrdet.</p>', '<p>Risiko, dass vertrauliche Unternehmensdaten auf Laptops oder mobilen Ger&auml;ten in unsicheren &ouml;ffentlichen Bereichen gestohlen werden. Dies kann zu Datenpannen, hohen Bu&szlig;geldern und Reputationsverlust f&uuml;hren.</p>', 'Organisatorische Risiken', '<p>- Verschl&uuml;sselte Festplatten<br>- sicherere Zugangsdaten<br>- MFA mit Yubikey<br>- sofortige Meldung bei Verlust</p>', 3, 4, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 4, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(9, 'RSK-0008', 'Unsichere Entsorgung von Altgeräten', 1, '', 'archiviert', '<p>Dieses Szenario kann zu Datenschutzverletzungen f&uuml;hren, bei denen sensible Unternehmens- und Kundendaten preisgegeben werden, was zu erheblichen finanziellen Verlusten durch Bu&szlig;gelder, rechtliche Verpflichtungen und Sanierungskosten f&uuml;hrt. Au&szlig;erdem kann das Unternehmen einen Imageschaden erleiden, der das Vertrauen der Kunden und die Glaubw&uuml;rdigkeit auf dem Markt untergr&auml;bt. Bei unsachgem&auml;&szlig; entsorgten Verm&ouml;genswerten steigt das Risiko eines unbefugten Zugriffs auf vertrauliche Daten, wodurch die Integrit&auml;t und Vertraulichkeit der Daten gef&auml;hrdet wird.</p>', '<p>Risiko, dass vertrauliche Informationen auf nicht korrekt gel&ouml;schten Ger&auml;ten (z. B. Laptops) in falsche H&auml;nde geraten. Dies kann zu Datenpannen, rechtlichen Konsequenzen und Reputationssch&auml;den f&uuml;hren.</p>', 'Organisatorische Risiken', '<p>Werden &uuml;ber zertifizierten Entsorger entsorgt.<br>M&uuml;ssen beim ServiceDesk abgegeben werden</p>', 3, 4, 1, 1, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 1, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(10, 'RSK-0009', 'Verlust oder Diebstahl von Dienstgeräten', 1, '', 'archiviert', '<p>Dieses Szenario kann zu Datenschutzverletzungen f&uuml;hren, bei denen sensible Unternehmens- und Kundendaten preisgegeben werden, was zu erheblichen finanziellen Verlusten aufgrund von Bu&szlig;geldern, rechtlichen Verpflichtungen und Abhilfekosten f&uuml;hrt. Au&szlig;erdem kann das Unternehmen einen Imageschaden erleiden, der das Vertrauen der Kunden und die Glaubw&uuml;rdigkeit auf dem Markt untergr&auml;bt. Wenn Ger&auml;te mit sensiblen Daten in unbefugte H&auml;nde geraten, steigt das Risiko des unbefugten Zugriffs und des Missbrauchs, was die Integrit&auml;t und Vertraulichkeit der Daten gef&auml;hrdet.</p>', '<p>Risiko, dass sensible Daten durch den Verlust oder Diebstahl von Firmenger&auml;ten in die H&auml;nde Unbefugter gelangen. Folgen k&ouml;nnen Datenlecks, finanzielle Sch&auml;den und Vertrauensverluste sein.</p>', 'Organisatorische Risiken', '<p>- Verschl&uuml;sselte Festplatten<br>- sicherere Zugangsdaten<br>- MFA mit Yubikey<br>- sofortige Meldung bei Verlust</p>', 3, 3, 1, 3, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 3, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(11, 'RSK-0010', 'Insider-Bedrohung', 1, '', 'archiviert', '<p>- Finanzielle Verluste: Der Diebstahl oder Missbrauch von sensiblen Unternehmensdaten oder Gesch&auml;ftsgeheimnissen kann zu finanziellen Verlusten f&uuml;hren, da die Wettbewerbsf&auml;higkeit sinkt, geistiges Eigentum verloren geht und potenzielle Rechtskosten f&uuml;r Rechtsstreitigkeiten anfallen.&nbsp;<br>- Service: &nbsp;Vorf&auml;lle, bei denen Ger&auml;te entwendet oder missbraucht werden, k&ouml;nnen den normalen Gesch&auml;ftsbetrieb st&ouml;ren, was zu Produktivit&auml;tseinbu&szlig;en, Ausfallzeiten und erh&ouml;hten Betriebskosten im Zusammenhang mit der Reaktion auf Vorf&auml;lle und deren Behebung f&uuml;hrt.&nbsp;<br>- Rechtliche Aspekte: Je nach Art der betroffenen Daten und der geltenden Vorschriften (z. B. GDPR) kann das Unternehmen mit rechtlichen und beh&ouml;rdlichen Konsequenzen konfrontiert werden, wenn es sensible Daten nicht angemessen sch&uuml;tzt. Dazu k&ouml;nnen Geldstrafen, Bu&szlig;gelder und Klagen der betroffenen Parteien geh&ouml;ren.&nbsp;<br>- Ruf: Wenn vertrauliche Informationen oder Gesch&auml;ftsgeheimnisse offengelegt oder missbraucht werden, kann dies den Ruf des Unternehmens sch&auml;digen und das Vertrauen der Kunden untergraben. Negative Publicity im Zusammenhang mit einer Sicherheitsverletzung kann zu einem Verlust von Gesch&auml;ftsm&ouml;glichkeiten und Schwierigkeiten bei der Gewinnung neuer Kunden f&uuml;hren.</p>', '<p>Risiko, dass (ehemalige) Mitarbeitende mit b&ouml;swilliger Absicht auf Systeme oder Geb&auml;ude zugreifen, um Schaden anzurichten. Dies kann zu Datenverlust, rechtlichen und finanziellen Konsequenzen sowie Betriebsst&ouml;rungen f&uuml;hren.</p>', 'Betriebliche Risiken', '<ul>\r\n<li>Awareness Trainings</li>\r\n<li>Informationssicherheitsschulung</li>\r\n<li>Klassifizierung</li>\r\n<li>Geheimhaltung Zugangsdaten</li>\r\n</ul>', 1, 1, 1, 1, 1, '2025-12-23', 'Akzeptieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 1, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(12, 'RSK-0011', 'Mangelndes Sicherheitsbewusstsein', 1, '', 'archiviert', '<p>Dieses Szenario kann zu Datenschutzverletzungen f&uuml;hren, bei denen sensible Unternehmens- und Kundendaten preisgegeben werden, was zu erheblichen finanziellen Verlusten aufgrund von Bu&szlig;geldern, rechtlichen Verpflichtungen und Abhilfekosten f&uuml;hrt. Au&szlig;erdem kann das Unternehmen einen Imageschaden erleiden, der das Vertrauen der Kunden und die Glaubw&uuml;rdigkeit auf dem Markt untergr&auml;bt. Da Mitarbeiter anf&auml;llig f&uuml;r Manipulation und Ausnutzung durch Cyberkriminelle sind, steigt das Risiko eines unbefugten Zugriffs auf Systeme und Daten, was die Sicherheit und Integrit&auml;t des Unternehmens gef&auml;hrdet.</p>', '<p>Risiko, dass Mitarbeitende durch Phishing, Social Engineering oder Malware-Angriffe manipuliert werden, weil sie nicht ausreichend geschult sind. Dies kann zu Datenpannen, finanziellen Verlusten und Reputationssch&auml;den f&uuml;hren.</p>', 'Organisatorische Risiken', '<ul>\r\n<li>regelm&auml;&szlig;iges Awareness Trainings</li>\r\n<li>j&auml;hrliche Informationssicherheitsschulung</li>\r\n</ul>', 4, 5, 1, 2, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-07-07', 1, '2027-01-09', 'niedrig', '6,1', NULL, 0, '', 2, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(13, 'RSK-0012', 'Veraltete Richtlinien und Prozesse', 1, '', 'archiviert', '<p>Dieses Szenario kann zu ineffektiver Reaktion auf Vorf&auml;lle, verl&auml;ngerten Wiederherstellungszeiten, erh&ouml;hter Anf&auml;lligkeit f&uuml;r Angriffe und m&ouml;glicher Nichteinhaltung von Vorschriften f&uuml;hren. Dem Unternehmen k&ouml;nnen erhebliche finanzielle Verluste durch Bu&szlig;gelder, rechtliche Verpflichtungen und Betriebsunterbrechungen entstehen. Dar&uuml;ber hinaus kann das Fehlen aktueller und wirksamer Sicherheitskontrollen zu Datenschutzverletzungen f&uuml;hren, die sensible Informationen gef&auml;hrden und den Ruf des Unternehmens sch&auml;digen.</p>', '<p>Risiko, dass das Unternehmen bei Sicherheitsvorf&auml;llen nicht angemessen reagiert, weil Richtlinien und Kontrollen veraltet oder unklar sind. Dies kann zu Angriffen, Bu&szlig;geldern und Imagesch&auml;den f&uuml;hren.</p>', 'Technische Risiken', '<p>Richtlinien und Prozesse werden j&auml;hrlich &uuml;berpr&uuml;ft und wenn n&ouml;tig &uuml;berarbeitet</p>\r\n<p>ISO27001 Zertifizierung III/2026</p>', 4, 4, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 4, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(14, 'RSK-0013', 'Unbeabsichtigte Offenlegung sensibler Kundendaten während des Supports oder anderer Vorgänge', 6, '', 'archiviert', '<p>Dieses Szenario kann zu schwerwiegenden Datenschutzverletzungen f&uuml;hren, die vertrauliche Kundeninformationen preisgeben und Geldbu&szlig;en, rechtliche Verpflichtungen und finanzielle Verluste nach sich ziehen. Das Unternehmen kann auch einen Imageschaden erleiden, der das Vertrauen der Kunden und die Glaubw&uuml;rdigkeit auf dem Markt untergr&auml;bt. Wenn Support-Mitarbeiter unangemessenen Zugang zu sensiblen Daten haben, steigt das Risiko einer versehentlichen Offenlegung, die die Datenintegrit&auml;t und den Datenschutz gef&auml;hrdet. Umfassende Folgen- und Verlustanalysen sind unerl&auml;sslich, um m&ouml;gliche Szenarien zu ermitteln und potenzielle Verluste zu quantifizieren.</p>', '<p>Risiko, dass Mitarbeitende durch fehlende Schulung oder falsche Zugriffsrechte versehentlich vertrauliche Kundendaten weitergeben. Dies kann Datenpannen und rechtliche Konsequenzen nach sich ziehen.</p>', 'Technische Risiken', '<p>Behandlung von Kundendaten w&auml;hrend dess Supports usw. in Richtlinie definiert.</p>', 3, 2, 1, 2, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 2, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(15, 'RSK-0014', 'Behandlung von Kundendaten während des Supports usw. ', 1, '', 'archiviert', '<p>Dieses Szenario kann zu weitreichenden Datenschutzverletzungen f&uuml;hren, die sensible Informationen gef&auml;hrden und erhebliche finanzielle Verluste aufgrund von Bu&szlig;geldern, rechtlichen Verpflichtungen und Abhilfekosten nach sich ziehen. Das Unternehmen kann auch einen Imageschaden erleiden, der das Vertrauen der Kunden und die Glaubw&uuml;rdigkeit auf dem Markt schm&auml;lert. Wenn Drittanbieter Zugang zu vertraulichen Daten haben, steigt das Risiko einer Gef&auml;hrdung, was die Notwendigkeit eines strengen Anbietermanagements und strenger Sicherheitspraktiken verdeutlicht. Umfassende Folgen- und Verlustanalysen sind unerl&auml;sslich, um m&ouml;gliche Szenarien zu identifizieren und potenzielle Verluste zu quantifizieren.</p>', '<p>Risiko von Datenverlust oder -diebstahl durch externe Dienstleister, die Zugriff auf sensible Daten haben. Dies erfordert strikte Vertrags- und Sicherheitskontrollen.</p>', 'Technische Risiken', '<ul>\r\n<li>Lieferanten werden Auditiert (Fragebogen)</li>\r\n<li>Zugriff nur &uuml;ber Citrix</li>\r\n<li>NDA ist Pflicht</li>\r\n</ul>', 4, 4, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 4, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(16, 'RSK-0015', 'Ehemalige oder unzufriedene Mitarbeitende', 1, '', 'archiviert', '<p>Dieses Szenario kann zu Datenschutzverletzungen f&uuml;hren, die sensible Unternehmens- und Kundendaten preisgeben und zu erheblichen finanziellen Verlusten aufgrund von Bu&szlig;geldern, rechtlichen Verpflichtungen und Abhilfekosten f&uuml;hren. Das Unternehmen kann auch einen Imageschaden erleiden, der das Vertrauen der Kunden und die Glaubw&uuml;rdigkeit auf dem Markt untergr&auml;bt. Mit unbefugtem Zugriff k&ouml;nnen ehemalige Mitarbeiter Daten manipulieren oder stehlen und so die Datenintegrit&auml;t und die Betriebskontinuit&auml;t gef&auml;hrden. Eine umfassende Analyse der Auswirkungen und Verluste ist unabdingbar, um m&ouml;gliche Szenarien zu identifizieren und potenzielle Verluste zu quantifizieren.</p>', '<p>Risiko, dass ausgeschiedene Mitarbeitende weiterhin Zugriff auf Systeme haben und Daten entwenden oder manipulieren. Dies kann zu schweren Sicherheitsvorf&auml;llen f&uuml;hren.</p>', 'Technische Risiken', '<ul>\r\n<li>Ger&auml;te m&uuml;ssen beim Verlassen zur&uuml;ckgegeben werden</li>\r\n<li>Useraccount wird gesperrt und deaktiviert</li>\r\n</ul>', 2, 3, 1, 3, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 3, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(17, 'RSK-0016', 'Stromausfälle für physische Einrichtungen (Gebäude, Ausrüstung...)', 1, '', 'archiviert', '<p>As our company is using 100% cloud storage and SaaS software for business processes the impact of a damaged facilities is rather irrelevant.<br>All process could be done immediately from any mobile connection or any place.</p>', '<p>Risiko eines unbefugten Zugriffs w&auml;hrend Stromausf&auml;llen, wenn Sicherheitssysteme (z. B. Zutritt, Alarm) nicht funktionieren.</p>', 'Technische Risiken', '<p>Einsatz redundante Stromversorgung und USV</p>', 2, 3, 1, 3, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 3, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(18, 'RSK-0017', 'Naturkatastrophen für physische Einrichtungen (Gebäude, Ausrüstung...)', 1, '', 'archiviert', '<p>Naturkatastrophen k&ouml;nnen zu pl&ouml;tzlichen und gro&szlig;fl&auml;chigen Ausf&auml;llen physischer Einrichtungen (Geb&auml;ude, Rechenzentren, Produktionsanlagen, Netzwerkinfrastruktur) f&uuml;hren. M&ouml;gliche Folgen sind Zerst&ouml;rung oder Besch&auml;digung von IT‑/OT‑Assets, Unterbrechung kritischer Gesch&auml;ftsprozesse bis hin zum Produktionsstillstand, Datenverlust (z. B. besch&auml;digte Speichermedien), lange Wiederanlaufzeiten sowie rechtliche und finanzielle Konsequenzen. Besonders betroffen ist die Verf&uuml;gbarkeit; je nach Bergung und Schadenslage sind auch Integrit&auml;t und Vertraulichkeit gef&auml;hrdet</p>', '<p>Risiko von Ausf&auml;llen oder Sch&auml;den an Infrastruktur durch Naturereignisse wie &Uuml;berschwemmungen, St&uuml;rme oder Erdbeben.</p>', 'Technische Risiken', '<p>Datensicherung, redundantes Rechenzentrum 4 Km Abstand</p>', 2, 3, 1, 3, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 3, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(19, 'RSK-0018', 'Unfallbedingte Feuer-, Wasser- und Stromschäden an physischen Einrichtungen (Gebäude, Ausrüstung...)', 1, '', 'archiviert', '<p>Unfallbedingte Brand‑, Wasser‑ und Stromsch&auml;den an Geb&auml;uden, Rechenzentrums‑ oder Produktions‑Einrichtungen sowie IT‑Ausr&uuml;stung k&ouml;nnen zu pl&ouml;tzlichen Ausf&auml;llen kritischer Infrastruktur f&uuml;hren. Betroffen sind Server, Netzwerke, Speichermedien, Produktionsanlagen und Zutrittssysteme. Die Folgen sind Betriebsunterbrechungen bis zum Produktionsstillstand, Datenverlust (z. B. durch besch&auml;digte Speichermedien), Verz&ouml;gerungen in der Wiederherstellung sowie rechtliche und finanzielle Konsequenzen. Besonders gef&auml;hrdet ist die Verf&uuml;gbarkeit und &ndash; je nach Art des Schadens und Bergung &ndash; die Integrit&auml;t und Vertraulichkeit von Informationen.</p>', '<p>Risiko von Systemausf&auml;llen durch Brand, Wassersch&auml;den oder Stromprobleme, die die Arbeitsumgebung betreffen.</p>', 'Technische Risiken', '', 1, 2, 1, 1, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 1, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(20, 'RSK-0019', 'Ausnutzung ungepatchter Sicherheitslücken', 1, '', 'archiviert', '<p>In diesem Szenario bleibt eine kritische Sicherheitsl&uuml;cke in einem weit verbreiteten Betriebssystem ungepatcht, so dass Hacker sie ausnutzen und sich unbefugt Zugang zu sensiblen Unternehmensdaten verschaffen k&ouml;nnen. Infolgedessen erleidet das Unternehmen eine erhebliche Datenpanne, die Kundeninformationen und gesch&uuml;tzte Gesch&auml;ftsdaten gef&auml;hrdet. Die Verletzung l&ouml;st beh&ouml;rdliche Untersuchungen aus, die zu erheblichen Geldstrafen und Anwaltskosten f&uuml;hren. Au&szlig;erdem wird der Ruf des Unternehmens besch&auml;digt, was zu einem Vertrauensverlust bei den Kunden und potenziellen Umsatzeinbu&szlig;en f&uuml;hrt. Es kommt zu Betriebsunterbrechungen, w&auml;hrend die IT-Teams daran arbeiten, die Sicherheitsverletzung einzud&auml;mmen und die betroffenen Systeme zu reparieren.</p>', '<p>Risiko, dass bekannte Schwachstellen nicht rechtzeitig gepatcht werden und Angreifern so Zugriff auf sensible Daten erm&ouml;glichen.</p>', 'Technische Risiken', '<ul>\r\n<li>Sicherheitsl&uuml;cken werden w&ouml;chentlich im CSIRT-Meeting besprochen und kategorisiert</li>\r\n<li>Einsatz von MS Defender erm&ouml;glicht fr&uuml;hzeitige Erkennung von Sicherheitsl&uuml;cken<br>Einsatz von bMS erm&ouml;glicht schnelles Patchen von Sicherheitsl&uuml;cken</li>\r\n<li>Einsatz von ArcticWolf erm&ouml;glicht das erkennen der Ausnutzung von Sicherheitsl&uuml;cken</li>\r\n</ul>', 3, 4, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-02-07', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 4, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(21, 'RSK-0020', 'Manipulierte Webseiteninhalte (Defacement)', 26, '', 'behandelt', '<p>Im Falle einer gr&ouml;&szlig;eren Sicherheitsverletzung, bei der besch&auml;digte Dateien von einem b&ouml;swilligen Benutzer ausgenutzt werden, um b&ouml;sartigen Code zu installieren oder vertrauliche Informationen zu stehlen, sind die Folgen schwerwiegend. Dieses Szenario kann zu Datenschutzverletzungen, finanziellen Verlusten durch Bu&szlig;gelder und rechtliche Verpflichtungen, Rufsch&auml;digung und Betriebsunterbrechungen f&uuml;hren. Da besch&auml;digte Dateien als Einfallstor f&uuml;r Angreifer dienen, ist die Integrit&auml;t der sensiblen Daten des Unternehmens gef&auml;hrdet, was das Vertrauen und die Glaubw&uuml;rdigkeit beeintr&auml;chtigt.</p>', '<p>Risiko, dass Unternehmenswebseiten durch Angriffe ver&auml;ndert werden, was zu Reputationsverlust und Vertrauenssch&auml;den f&uuml;hrt.</p>', 'Technische Risiken', '<p>Nutzung Webproxy in Verbindung mit SIEM ArcticWolf</p>', 3, 3, 1, 3, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-04-10', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 3, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(22, 'RSK-0021', 'Denial-of-Service-Angriff (DoS)', 26, '', 'behandelt', '<p>Dieses Szenario kann zu erheblichen finanziellen Verlusten f&uuml;hren, da der Gesch&auml;ftsbetrieb unterbrochen wird, der Ruf leidet und die Kunden unzufrieden sind. Wenn wichtige Dienste und Systeme nicht mehr zug&auml;nglich sind, kann das Unternehmen die Service-Level-Vereinbarungen nicht mehr einhalten, was zu weiteren finanziellen Strafen und rechtlichen Verpflichtungen f&uuml;hrt. Dar&uuml;ber hinaus kann der Ruf des Unternehmens langfristig gesch&auml;digt werden, was zu Kundenabwanderung und dem Verlust von Marktanteilen f&uuml;hrt.</p>', '<p>Risiko von Systemausf&auml;llen durch gezielte &Uuml;berlastung von Servern oder Diensten, was den Betrieb und Kundenservice beeintr&auml;chtigt.</p>', 'Technische Risiken', '<p>1. Netzwerk- und Infrastrukturma&szlig;nahmen<br>2. Anwendungsebene<br>3. Monitoring &amp; Erkennung<br>4. Skalierung &amp; Resilienz<br>5. Zusammenarbeit &amp; externe Dienste<br>6. Notfallplan</p>', 4, 4, 1, 4, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-04-10', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 4, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(23, 'RSK-0022', 'Brute-Force-Angriff', 1, '', 'behandelt', '<p>Das Risiko eines Brute-Force-Angriffs, bei dem ein b&ouml;swilliger Benutzer versucht, sich durch Ausprobieren unbefugten Zugang zu Passw&ouml;rtern zu verschaffen, hat erhebliche Auswirkungen auf das Unternehmen und birgt ein erhebliches Verlustpotenzial, das insbesondere f&uuml;r die Analyse von Sicherheitszertifikaten relevant ist. Im Falle eines gr&ouml;&szlig;eren Sicherheitsversto&szlig;es infolge eines erfolgreichen Brute-Force-Angriffs sind die Folgen gravierend. Da Passw&ouml;rter als prim&auml;rer Authentifizierungsmechanismus f&uuml;r den Zugriff auf sensible Systeme und Daten dienen, sind die Integrit&auml;t und die Vertraulichkeit der Informationen des Unternehmens gef&auml;hrdet.</p>', '<p>Risiko, dass Angreifer durch Ausprobieren von Passw&ouml;rtern Zugriff auf Systeme erhalten und dadurch vertrauliche Informationen gef&auml;hrdet sind.</p>', 'Technische Risiken', '<p>1. Starke Authentifizierung<br>2. Rate-Limiting &amp; Sperrmechanismen<br>3. Monitoring &amp; Erkennung<br>4. Netzwerk- und Protokollschutz<br>5. Organisatorische Ma&szlig;nahmen</p>', 3, 4, 1, 3, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-07-06', 1, '2027-01-09', 'niedrig', NULL, NULL, 0, '', 3, '', '', '1,4,4,1,1', '1,3,3,1,1', NULL, NULL, NULL, NULL, NULL, NULL),
(24, 'RSK-0023', 'Shadow IT', 26, '', 'behandelt', '<p>Dieses Szenario k&ouml;nnte zu Datenschutzverletzungen f&uuml;hren, da sensible Informationen &uuml;ber ungesicherte Kan&auml;le gespeichert oder &uuml;bertragen werden, und Schwachstellen schaffen, die die Cybersicherheit des Unternehmens gef&auml;hrden. Wenn Mitarbeiter au&szlig;erhalb der genehmigten IT-Umgebung arbeiten, steht das Unternehmen vor der Herausforderung, die Einhaltung von Vorschriften zu gew&auml;hrleisten, die Datenintegrit&auml;t sicherzustellen und unbefugten Zugriff zu verhindern. Zu den finanziellen Auswirkungen geh&ouml;ren potenzielle Bu&szlig;gelder, erh&ouml;hte IT-Supportkosten und rechtliche Verpflichtungen. Dar&uuml;ber hinaus k&ouml;nnen die durch nicht &uuml;berwachte und potenziell inkompatible Software verursachten Betriebsst&ouml;rungen die Produktivit&auml;t beeintr&auml;chtigen und erhebliche Sicherheitsl&uuml;cken schaffen.</p>', '<p>Risiko, dass Mitarbeiter aufgrund einer schwachen BYOD-Richtlinie ihre eigene, nicht genehmigte Software installieren und so eine Schatten-IT-Umgebung schaffen</p>', 'Technische Risiken', '<ul>\r\n<li>BYOD ist nicht erlaubt</li>\r\n<li>Softwareinstallation nur &uuml;ber bMS und auf Antrag</li>\r\n<li>Netzwerk wir st&auml;ndig nach unbekannte Devices &uuml;berwacht</li>\r\n<li>Zugriff Netzwerk nur f&uuml;r bekannte Ger&auml;te&nbsp;</li>\r\n</ul>', 2, 5, 1, 2, 1, '2025-12-23', 'Reduzieren', 0, 1, '2026-07-10', 1, '2027-01-09', 'niedrig', '23', '', 0, '', 2, '', '', NULL, NULL, '', '', NULL, NULL, NULL, NULL);

